"""
Agent Compiler - Export evolved Nodes as deployable Python capsules.

Compiles single Nodes or ensembles into self-contained .py files with:
- Embedded base64 weights (_BRAIN_DATA)
- Traits JSON (_TRAITS)
- VP config (_VP_CONFIG)
- CapsuleBrain class matching KEY's Brain interface

Supports:
- Single agent export
- Ensemble voting (majority, confidence, fitness_weighted)
- Export to .pt/.onnx formats
- Self-replication with updated weights
"""

import base64
import json
import pickle
import gzip
import hashlib
from pathlib import Path
from typing import List, Dict, Any, Optional, Union
from dataclasses import dataclass
import numpy as np
from datetime import datetime
import asyncio

# ═══════════════════════════════════════════════════════════════════════════
# ═══════════════════════════════════════════════════════════════════════════
# INFINITY-EMB: Universal Model Invocation
# High-throughput inference for embeddings, reranking, CLIP, CLAP, classification
# ═══════════════════════════════════════════════════════════════════════════
try:
    from infinity_emb import AsyncEngineArray, EngineArgs, AsyncEmbeddingEngine
    INFINITY_AVAILABLE = True
except ImportError:
    INFINITY_AVAILABLE = False
    AsyncEngineArray = None
    EngineArgs = None
    AsyncEmbeddingEngine = None

# Global infinity engine cache (lazy initialization)
_INFINITY_ENGINES: Dict[str, Any] = {}
_INFINITY_LOCK = None  # Will be asyncio.Lock() when needed


def _get_infinity_lock():
    """Get or create the async lock for infinity engine access."""
    global _INFINITY_LOCK
    if _INFINITY_LOCK is None:
        try:
            _INFINITY_LOCK = asyncio.Lock()
        except RuntimeError:
            # No event loop - create a placeholder that will be replaced
            _INFINITY_LOCK = None
    return _INFINITY_LOCK


async def _get_infinity_engine(model_id: str, engine_type: str = "torch") -> Optional[Any]:
    """
    Get or create an infinity-emb engine for a model.

    Engines are cached for reuse. Thread-safe via async lock.

    Args:
        model_id: HuggingFace model ID or local path
        engine_type: 'torch' (default), 'onnx', or 'tensorrt'

    Returns:
        AsyncEmbeddingEngine instance or None if infinity not available
    """
    if not INFINITY_AVAILABLE:
        return None

    cache_key = f"{model_id}:{engine_type}"

    if cache_key in _INFINITY_ENGINES:
        engine = _INFINITY_ENGINES[cache_key]
        # Ensure engine is started
        if not engine._is_started:
            await engine.astart()
        return engine

    lock = _get_infinity_lock()
    if lock:
        async with lock:
            # Double-check after acquiring lock
            if cache_key in _INFINITY_ENGINES:
                return _INFINITY_ENGINES[cache_key]

            try:
                engine_args = EngineArgs(
                    model_name_or_path=model_id,
                    engine=engine_type,
                    embedding_dtype="float32",
                    dtype="auto"
                )
                engine = AsyncEmbeddingEngine.from_args(engine_args)
                await engine.astart()
                _INFINITY_ENGINES[cache_key] = engine
                return engine
            except Exception as e:
                print(f"[infinity-emb] Failed to create engine for {model_id}: {e}")
                return None
    else:
        # No lock available, create without caching
        try:
            engine_args = EngineArgs(
                model_name_or_path=model_id,
                engine=engine_type,
                embedding_dtype="float32",
                dtype="auto"
            )
            engine = AsyncEmbeddingEngine.from_args(engine_args)
            await engine.astart()
            return engine
        except Exception as e:
            print(f"[infinity-emb] Failed to create engine for {model_id}: {e}")
            return None


async def infinity_embed(model_id: str, texts: Union[str, List[str]], engine_type: str = "torch") -> Optional[np.ndarray]:
    """
    Embed text(s) using infinity-emb.

    Args:
        model_id: HuggingFace model ID (e.g., 'BAAI/bge-small-en-v1.5')
        texts: Single string or list of strings to embed
        engine_type: 'torch', 'onnx', or 'tensorrt'

    Returns:
        numpy array of embeddings, or None on failure
    """
    engine = await _get_infinity_engine(model_id, engine_type)
    if engine is None:
        return None

    if isinstance(texts, str):
        texts = [texts]

    try:
        embeddings, usage = await engine.embed(sentences=texts)
        return np.array(embeddings)
    except Exception as e:
        print(f"[infinity-emb] Embed failed: {e}")
        return None


async def infinity_rerank(model_id: str, query: str, documents: List[str], engine_type: str = "torch") -> Optional[List[tuple]]:
    """
    Rerank documents by relevance to query using infinity-emb.

    Args:
        model_id: Reranker model ID (e.g., 'mixedbread-ai/mxbai-rerank-xsmall-v1')
        query: The query string
        documents: List of document strings to rank
        engine_type: 'torch', 'onnx', or 'tensorrt'

    Returns:
        List of (score, doc_index) tuples sorted by relevance, or None on failure
    """
    engine = await _get_infinity_engine(model_id, engine_type)
    if engine is None:
        return None

    try:
        rankings, usage = await engine.rerank(query=query, docs=documents)
        return rankings
    except Exception as e:
        print(f"[infinity-emb] Rerank failed: {e}")
        return None


async def infinity_classify(model_id: str, texts: Union[str, List[str]], engine_type: str = "torch") -> Optional[List[Dict]]:
    """
    Classify text(s) using infinity-emb.

    Args:
        model_id: Classification model ID (e.g., 'SamLowe/roberta-base-go_emotions')
        texts: Single string or list of strings to classify
        engine_type: 'torch', 'onnx', or 'tensorrt'

    Returns:
        List of classification results, or None on failure
    """
    engine = await _get_infinity_engine(model_id, engine_type)
    if engine is None:
        return None

    if isinstance(texts, str):
        texts = [texts]

    try:
        predictions, usage = await engine.classify(sentences=texts)
        return predictions
    except Exception as e:
        print(f"[infinity-emb] Classify failed: {e}")
        return None


async def infinity_image_embed(model_id: str, images: Union[str, List[str]], engine_type: str = "torch") -> Optional[np.ndarray]:
    """
    Embed image(s) using CLIP via infinity-emb.

    Args:
        model_id: CLIP model ID (e.g., 'openai/clip-vit-base-patch32')
        images: URL(s) or path(s) to images
        engine_type: 'torch', 'onnx', or 'tensorrt'

    Returns:
        numpy array of image embeddings, or None on failure
    """
    engine = await _get_infinity_engine(model_id, engine_type)
    if engine is None:
        return None

    if isinstance(images, str):
        images = [images]

    try:
        embeddings, usage = await engine.image_embed(images=images)
        return np.array(embeddings)
    except Exception as e:
        print(f"[infinity-emb] Image embed failed: {e}")
        return None


def infinity_embed_sync(model_id: str, texts: Union[str, List[str]], engine_type: str = "torch") -> Optional[np.ndarray]:
    """Synchronous wrapper for infinity_embed."""
    try:
        loop = asyncio.get_event_loop()
        if loop.is_running():
            # We're in an async context, need to use run_coroutine_threadsafe or similar
            import concurrent.futures
            with concurrent.futures.ThreadPoolExecutor() as pool:
                future = pool.submit(asyncio.run, infinity_embed(model_id, texts, engine_type))
                return future.result(timeout=60)
        else:
            return loop.run_until_complete(infinity_embed(model_id, texts, engine_type))
    except RuntimeError:
        # No event loop, create one
        return asyncio.run(infinity_embed(model_id, texts, engine_type))


def infinity_rerank_sync(model_id: str, query: str, documents: List[str], engine_type: str = "torch") -> Optional[List[tuple]]:
    """Synchronous wrapper for infinity_rerank."""
    try:
        loop = asyncio.get_event_loop()
        if loop.is_running():
            import concurrent.futures
            with concurrent.futures.ThreadPoolExecutor() as pool:
                future = pool.submit(asyncio.run, infinity_rerank(model_id, query, documents, engine_type))
                return future.result(timeout=60)
        else:
            return loop.run_until_complete(infinity_rerank(model_id, query, documents, engine_type))
    except RuntimeError:
        return asyncio.run(infinity_rerank(model_id, query, documents, engine_type))


def infinity_classify_sync(model_id: str, texts: Union[str, List[str]], engine_type: str = "torch") -> Optional[List[Dict]]:
