def _json_to_python(obj: Any) -> str:
    """
    Convert object to Python literal string (not JSON).
    JSON uses null/true/false, Python uses None/True/False.
    """
    if obj is None:
        return "None"
    elif isinstance(obj, bool):
        return "True" if obj else "False"
    elif isinstance(obj, (int, float)):
        return repr(obj)
    elif isinstance(obj, str):
        return repr(obj)
    elif isinstance(obj, list):
        items = [_json_to_python(item) for item in obj]
        return "[" + ", ".join(items) + "]"
    elif isinstance(obj, dict):
        items = [f"{repr(k)}: {_json_to_python(v)}" for k, v in obj.items()]
        return "{" + ", ".join(items) + "}"
    else:
        return repr(obj)


def _python_literal(obj: Any, indent: int = 0) -> str:
    """
    Convert object to indented Python literal string.
    Handles nested dicts/lists with proper Python syntax.
    """
    ind = "  " * indent
    if obj is None:
        return "None"
    elif isinstance(obj, bool):
        return "True" if obj else "False"
    elif isinstance(obj, (int, float)):
        # Handle nan and inf
        if isinstance(obj, float):
            if np.isnan(obj):
                return "float('nan')"
            elif np.isinf(obj):
                return f"float('{'inf' if obj > 0 else '-inf'}')"
        return repr(obj)
    elif isinstance(obj, str):
        return repr(obj)
    elif isinstance(obj, list):
        if not obj:
            return "[]"
        if len(obj) <= 3 and all(isinstance(x, (int, float, str, bool, type(None))) for x in obj):
            # Short simple lists on one line
            return "[" + ", ".join(_python_literal(x) for x in obj) + "]"
        # Multi-line
        lines = ["["]
        for item in obj:
            lines.append(ind + "  " + _python_literal(item, indent + 1) + ",")
        lines.append(ind + "]")
        return "\n".join(lines)
    elif isinstance(obj, dict):
        if not obj:
            return "{}"
        lines = ["{"]
        for k, v in obj.items():
            val = _python_literal(v, indent + 1)
            lines.append(f'{ind}  {repr(k)}: {val},')
        lines.append(ind + "}")
        return "\n".join(lines)
    else:
        return repr(obj)


def _detect_model_type_runtime(model) -> 'ModelType':
    """
    Unified model type detection.

    Priority order:
    1. _model_type_hint — set by loader from actual config.json / Hub metadata
    2. Class identity — type(model).__name__ from the library that created it
    3. infinity-emb engine detection
    4. hasattr capability probing (last resort for unknown models)
    """
    if model is None:
        return ModelType.GENERIC

    # === PRIORITY 1: Loader hint (ground truth from config.json / Hub API) ===
    hint = getattr(model, '_model_type_hint', None)
    if hint:
        _hint_map = {
            'LLM': ModelType.LLM,
            'EMBEDDING': ModelType.EMBEDDING,
            'RERANKER': ModelType.RERANKER,
            'CLASSIFIER': ModelType.CLASSIFIER,
            'SEQ2SEQ': ModelType.LLM,
            'ASR': ModelType.ASR,
            'TTS': ModelType.TTS,
            'VISION': ModelType.VISION,
            'VLM': ModelType.VLM,
            'AUDIO_LLM': ModelType.AUDIO_LLM,
            'GENERIC': ModelType.GENERIC,
        }
        mapped = _hint_map.get(hint)
        if mapped is not None:
            return mapped

    # === PRIORITY 2: Class identity ===
    model_class = type(model).__name__
    if model_class == 'CrossEncoder':
        return ModelType.RERANKER

    # infinity-emb engines
    if 'AsyncEmbeddingEngine' in model_class or 'InfinityEngine' in model_class:
        model_name = getattr(model, '_model_name_or_path',
                    getattr(model, 'model_name_or_path', '')).lower()
        if 'rerank' in model_name:
            return ModelType.INFINITY_RERANK
        elif 'clip' in model_name:
            return ModelType.INFINITY_CLIP
        elif 'clap' in model_name:
            return ModelType.INFINITY_CLAP
        elif any(x in model_name for x in ['emotion', 'sentiment', 'classify', 'go_emotion']):
            return ModelType.INFINITY_CLASSIFY
        return ModelType.INFINITY_EMBED

    # === PRIORITY 3: hasattr capability probing (last resort) ===
    if hasattr(model, 'transcribe') and callable(getattr(model, 'transcribe', None)):
        return ModelType.ASR
    if hasattr(model, 'synthesize') or hasattr(model, 'tts'):
        return ModelType.TTS
    if hasattr(model, 'generate') and callable(getattr(model, 'generate', None)):
        return ModelType.LLM
    if hasattr(model, 'encode') and callable(getattr(model, 'encode', None)):
        return ModelType.EMBEDDING
    if hasattr(model, 'act') and callable(getattr(model, 'act', None)):
        return ModelType.RL
    if hasattr(model, 'step') and callable(getattr(model, 'step', None)):
        return ModelType.RL
    if hasattr(model, 'detect') and callable(getattr(model, 'detect', None)):
        return ModelType.VISION
    if hasattr(model, 'plan') and callable(getattr(model, 'plan', None)):
        return ModelType.PLANNER
    if hasattr(model, 'update') and hasattr(model, 'get_pose'):
        return ModelType.SLAM
    if hasattr(model, 'control') and callable(getattr(model, 'control', None)):
        return ModelType.CONTROL
    if hasattr(model, 'fuse') and callable(getattr(model, 'fuse', None)):
        return ModelType.SENSOR
    if hasattr(model, 'send') or hasattr(model, 'recv'):
        return ModelType.COMMS
    if hasattr(model, 'tick') and callable(getattr(model, 'tick', None)):
        return ModelType.STATE_MACHINE
    return ModelType.GENERIC


def _read_model_limits(model, tokenizer=None):
    """Read actual token limits from a plugged model's config.
    Returns only what the model actually reports — no guessing.
    """
    limits = {}
    raw = getattr(model, 'model', model)

    # Context window from model config (most authoritative sources first)
    if hasattr(raw, 'config'):
        cfg = raw.config
        for attr in ('max_position_embeddings', 'n_positions', 'max_sequence_length'):
            val = getattr(cfg, attr, None)
            if val and isinstance(val, int) and val > 0:
                limits['context_length'] = val
                break
        ml = getattr(cfg, 'max_length', None)
        if ml and isinstance(ml, int) and ml > 0:
            limits.setdefault('context_length', ml)

    # Tokenizer-level limit (skip absurd 2^63 default some tokenizers report)
    if tokenizer:
        tml = getattr(tokenizer, 'model_max_length', None)
        if tml and isinstance(tml, int) and 0 < tml < 1_000_000:
            limits.setdefault('context_length', tml)
            limits['tokenizer_max_length'] = tml

    # Generation config (the model's own shipped defaults)
    if hasattr(raw, 'generation_config'):
        gc = raw.generation_config
        mnt = getattr(gc, 'max_new_tokens', None)
        if mnt and isinstance(mnt, int) and mnt > 0:
            limits['max_gen_tokens'] = mnt
        gml = getattr(gc, 'max_length', None)
        if gml and isinstance(gml, int) and gml > 0:
            limits['gen_max_length'] = gml

    return limits


def _invoke_model(model, inputs: Dict[str, Any], model_type: 'ModelType') -> Dict[str, Any]:
    """
    Type-aware model invocation with smart output normalization.
    Runtime version that works with ModelType from brain.py.
    """
    if not isinstance(inputs, dict):
        inputs = {'input': inputs}

    text = inputs.get('text', inputs.get('prompt', ''))
    obs = inputs.get('observation', inputs.get('obs', inputs.get('input', None)))
    image = inputs.get('image', inputs.get('frame', None))
    state = inputs.get('state', None)
    goal = inputs.get('goal', inputs.get('target', None))
    sensors = inputs.get('sensors', inputs.get('readings', None))
    context = inputs.get('context', inputs)

    try:
        if model_type == ModelType.LLM:
            prompt = text or (str(obs) if obs is not None else "")
            gen_kwargs = {k: v for k, v in inputs.items() if k in ['max_tokens', 'temperature', 'top_p', 'stop', 'max_length']}
            result = model.generate(prompt, **gen_kwargs) if gen_kwargs else model.generate(prompt)
            if isinstance(result, str):
                return {'output': result, 'text': result, 'type': 'llm'}
            elif isinstance(result, dict):
                result['type'] = 'llm'
                return result
            return {'output': result, 'text': str(result), 'type': 'llm'}

        elif model_type == ModelType.EMBEDDING:
            to_encode = text if text else obs
            result = model.encode(to_encode)
            vec = np.asarray(result)
            return {'output': vec, 'embedding': vec, 'type': 'embedding'}

        elif model_type == ModelType.RERANKER:
            # Cross-encoder reranker — needs sentence pairs, can't process arbitrary input
            query = text if text else (str(obs) if obs is not None else "")
            docs = inputs.get('documents', inputs.get('docs', []))
            if docs and query and hasattr(model, 'predict'):
                pairs = [[query, d] for d in docs]
                scores = model.predict(pairs)
                if hasattr(scores, 'tolist'):
                    scores = scores.tolist()
                return {'output': scores, 'scores': scores, 'type': 'reranker'}
            # No documents provided — hash-based fallback
            import hashlib
            h = hashlib.sha256(query.encode()).digest()
            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
            vec = (hash_bytes / 255.0) * 2 - 1
            vec = np.tile(vec, 12)[:384]
            return {'output': vec, 'embedding': vec, 'type': 'reranker_hash'}

        elif model_type == ModelType.CLASSIFIER:
            # Classifier — needs text input, not numpy arrays
            to_classify = text if text else (str(obs) if obs is not None else "")
            if hasattr(model, 'classify'):
                result = model.classify(to_classify)
            elif hasattr(model, 'predict'):
                result = model.predict([to_classify])
            elif callable(model):
                result = model(to_classify)
            else:
                return {'output': None, 'error': 'Classifier has no predict/classify method', 'type': 'classifier'}
            return {'output': result, 'classification': str(result), 'type': 'classifier'}

        elif model_type == ModelType.RL:
            if hasattr(model, 'act'):
                action = model.act(obs)
            else:
                action = model.step(obs)
            return {'output': action, 'action': action, 'type': 'rl'}

        elif model_type == ModelType.VISION:
            img = image if image is not None else obs
            if hasattr(model, 'detect'):
                detections = model.detect(img)
            else:
                detections = model(img)
            return {'output': detections, 'detections': detections, 'type': 'vision'}

        elif model_type == ModelType.PLANNER:
            trajectory = model.plan(state, goal)
            return {'output': trajectory, 'trajectory': trajectory, 'type': 'planner'}

        elif model_type == ModelType.SLAM:
            model.update(sensors if sensors is not None else obs)
            pose = model.get_pose()
            return {'output': pose, 'pose': pose, 'type': 'slam'}

        elif model_type == ModelType.CONTROL:
            target = goal if goal is not None else inputs.get('setpoint')
            commands = model.control(state, target)
            return {'output': commands, 'commands': commands, 'type': 'control'}

        elif model_type == ModelType.SENSOR:
            fused = model.fuse(sensors if sensors is not None else obs)
            return {'output': fused, 'fused_state': fused, 'type': 'sensor'}

        elif model_type == ModelType.COMMS:
            if 'message' in inputs and hasattr(model, 'send'):
                result = model.send(inputs['message'])
                return {'output': result, 'sent': True, 'type': 'comms'}
            elif hasattr(model, 'recv'):
                message = model.recv()
                return {'output': message, 'message': message, 'type': 'comms'}
            return {'output': None, 'type': 'comms'}

        elif model_type == ModelType.STATE_MACHINE:
            transition = model.tick(context)
            return {'output': transition, 'state': transition, 'type': 'state_machine'}

        # ═══════════════════════════════════════════════════════════════════════
        # INFINITY-EMB: Universal high-throughput model invocation
        # ═══════════════════════════════════════════════════════════════════════
        elif model_type == ModelType.INFINITY_EMBED:
            # Async embedding via infinity-emb
            to_embed = text if text else (str(obs) if obs is not None else "")
            if isinstance(to_embed, str):
                to_embed = [to_embed]

            async def _do_embed():
                embeddings, usage = await model.embed(sentences=to_embed)
                return np.array(embeddings)

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_embed())
                        vec = future.result(timeout=60)
                else:
                    vec = loop.run_until_complete(_do_embed())
            except RuntimeError:
                vec = asyncio.run(_do_embed())

            return {'output': vec, 'embedding': vec, 'type': 'infinity_embed'}

        elif model_type == ModelType.INFINITY_RERANK:
            # Async reranking via infinity-emb
            query = text if text else str(obs)
            docs = inputs.get('documents', inputs.get('docs', []))
            if not docs:
                return {'output': None, 'error': 'No documents provided for reranking', 'type': 'infinity_rerank'}

            async def _do_rerank():
                rankings, usage = await model.rerank(query=query, docs=docs)
                return rankings

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_rerank())
                        rankings = future.result(timeout=60)
                else:
                    rankings = loop.run_until_complete(_do_rerank())
            except RuntimeError:
                rankings = asyncio.run(_do_rerank())

            return {'output': rankings, 'rankings': rankings, 'type': 'infinity_rerank'}

        elif model_type == ModelType.INFINITY_CLASSIFY:
            # Async classification via infinity-emb
            to_classify = text if text else (str(obs) if obs is not None else "")
            if isinstance(to_classify, str):
                to_classify = [to_classify]

            async def _do_classify():
                predictions, usage = await model.classify(sentences=to_classify)
                return predictions

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_classify())
                        preds = future.result(timeout=60)
                else:
                    preds = loop.run_until_complete(_do_classify())
            except RuntimeError:
                preds = asyncio.run(_do_classify())

            return {'output': preds, 'predictions': preds, 'type': 'infinity_classify'}

        elif model_type == ModelType.INFINITY_CLIP:
            # Async image embedding via CLIP through infinity-emb
            images = image if image is not None else inputs.get('images', [])
            if isinstance(images, str):
                images = [images]

            async def _do_image_embed():
                embeddings, usage = await model.image_embed(images=images)
                return np.array(embeddings)

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_image_embed())
                        vec = future.result(timeout=60)
                else:
                    vec = loop.run_until_complete(_do_image_embed())
            except RuntimeError:
                vec = asyncio.run(_do_image_embed())

            return {'output': vec, 'embedding': vec, 'type': 'infinity_clip'}

        elif model_type == ModelType.INFINITY_CLAP:
            # Async audio embedding via CLAP through infinity-emb
            audios = inputs.get('audio', inputs.get('audios', []))
            if isinstance(audios, (str, bytes)):
                audios = [audios]

            async def _do_audio_embed():
                embeddings, usage = await model.audio_embed(audios=audios)
                return np.array(embeddings)

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_audio_embed())
                        vec = future.result(timeout=60)
                else:
                    vec = loop.run_until_complete(_do_audio_embed())
            except RuntimeError:
                vec = asyncio.run(_do_audio_embed())

            return {'output': vec, 'embedding': vec, 'type': 'infinity_clap'}

        else:
            # GENERIC - just call it
            call_input = obs if obs is not None else (text if text else inputs.get('input'))
            if callable(model):
                result = model(call_input)
                if isinstance(result, dict):
                    result['type'] = 'generic'
                    return result
                return {'output': result, 'type': 'generic'}
            return {'output': None, 'type': 'generic'}

    except Exception as e:
        return {'output': None, 'error': str(e), 'type': model_type.name.lower()}


def _load_model_smart(model_id: str, verbose: bool = True) -> tuple:
    """
    Smart model loader that handles all model types.

    FIRST detects model type from HuggingFace Hub config, then routes to correct loader.
    This prevents SentenceTransformer from hanging on LLMs.

    Returns:
        (model, model_type_str, error_msg)
        - model: The loaded model (possibly wrapped for unified interface)
        - model_type_str: 'EMBEDDING', 'LLM', 'SEQ2SEQ', 'VISION', 'HF', or 'ERROR'
        - error_msg: None on success, error string on failure
    """
    import os
    import sys

    # Normalize path if local
    if os.path.exists(model_id):
        # Check for HF cache structure and resolve
        if 'snapshots' in model_id:
            # Already a snapshot path, try to use it
            pass
        elif model_id.endswith('blobs'):
            return None, 'ERROR', "Cannot load from blobs/ directly. Use model ID: plug microsoft/phi-2"

    # Enable HuggingFace download progress bars
    os.environ['HF_HUB_DISABLE_PROGRESS_BARS'] = '0'
    os.environ['TRANSFORMERS_VERBOSITY'] = 'warning'

    if verbose:
        print(f"🔍 Detecting model type for {model_id}...")
        sys.stdout.flush()

    # ========== DETECT MODEL TYPE FIRST ==========
    # This prevents SentenceTransformer from hanging on LLMs
    detected_type = None

    try:
        from huggingface_hub import model_info
        info = model_info(model_id)

        # Check pipeline_tag first (most reliable)
        pipeline_tag = getattr(info, 'pipeline_tag', None) or ''
        pipeline_tag = pipeline_tag.lower()

        if pipeline_tag in ('sentence-similarity', 'feature-extraction', 'text-embedding'):
            detected_type = 'EMBEDDING'
        elif pipeline_tag in ('text-generation', 'conversational', 'text2text-generation'):
            if pipeline_tag == 'text2text-generation':
                detected_type = 'SEQ2SEQ'
            else:
                detected_type = 'LLM'
        elif pipeline_tag in ('image-classification', 'object-detection', 'image-segmentation'):
            detected_type = 'VISION'
        elif pipeline_tag in ('zero-shot-classification', 'text-classification'):
            detected_type = 'CLASSIFIER'
        elif pipeline_tag in ('image-text-to-text', 'visual-question-answering', 'image-to-text'):
            detected_type = 'VLM'
        elif pipeline_tag in ('summarization', 'translation'):
            detected_type = 'SEQ2SEQ'
        elif pipeline_tag in ('automatic-speech-recognition',):
            detected_type = 'ASR'
        elif pipeline_tag in ('text-to-speech',):
            detected_type = 'TTS'
        elif pipeline_tag in ('audio-classification',):
            detected_type = 'AUDIO_CLASSIFIER'

        # Fallback: check model architecture from tags
        if detected_type is None and hasattr(info, 'tags') and info.tags:
            tags_lower = [t.lower() for t in info.tags]
            if any('causal' in t or 'gpt' in t or 'llama' in t or 'phi' in t or 'mistral' in t for t in tags_lower):
                detected_type = 'LLM'
            elif any('t5' in t or 'bart' in t or 'seq2seq' in t for t in tags_lower):
                detected_type = 'SEQ2SEQ'
            elif any('sentence' in t or 'embed' in t or 'sbert' in t for t in tags_lower):
                detected_type = 'EMBEDDING'
            elif any('whisper' in t or 'speech' in t or 'asr' in t for t in tags_lower):
                detected_type = 'ASR'

        if verbose and detected_type:
            print(f"   Detected: {detected_type} (pipeline: {pipeline_tag or 'N/A'})")
            sys.stdout.flush()

    except Exception as e:
        # Can't detect - will try in order but skip SentenceTransformer for safety
        if verbose:
            print(f"   Could not detect type from Hub: {e}")
            sys.stdout.flush()

    # ========== REFINE FROM ACTUAL CONFIG.JSON ==========
    # Hub pipeline_tag is a rough approximation. The actual config.json on disk
    # has architectures, label counts, and model_type — ground truth.
    _local_cfg = None
    try:
        _cfg_path = None
        if os.path.isdir(model_id):
            _cfg_path = os.path.join(model_id, 'config.json')
        else:
            try:
                from huggingface_hub import hf_hub_download
                _cfg_path = hf_hub_download(model_id, 'config.json')
            except Exception:
                pass

        if _cfg_path and os.path.isfile(_cfg_path):
            import json
            with open(_cfg_path, 'r') as _f:
                _local_cfg = json.loads(_f.read())
    except Exception:
        pass

    if _local_cfg:
        _archs = _local_cfg.get('architectures', [])
        _arch_str = ' '.join(_archs).lower()
        _id2label = _local_cfg.get('id2label', {})
        _model_type_name = str(_local_cfg.get('model_type', '') or '').lower()

        # ForSequenceClassification: label count distinguishes reranker from classifier
        # Rerankers have 1 label (relevance score), classifiers have many (categories)
        if 'forsequenceclassification' in _arch_str:
            if len(_id2label) <= 2:
                detected_type = 'RERANKER'
            else:
                detected_type = 'CLASSIFIER'
        elif _model_type_name == 'whisper' or 'whisper' in _arch_str:
            detected_type = 'ASR'
        elif any(_tag in _model_type_name for _tag in ('bark', 'speecht5', 'vits', 'parler_tts', 'xtts')):
            detected_type = 'TTS'
        # VLM: vision_config + LLM backbone (InternVL, H2OVL, LLaVA, Qwen-VL, etc.)
        # Must check BEFORE forcausallm since many VLMs register as CausalLM
        # Require companion LLM/text config to avoid misclassifying pure vision encoders
        elif (_local_cfg.get('vision_config') and (_local_cfg.get('llm_config') or _local_cfg.get('text_config') or _local_cfg.get('language_config'))) or any(k in _model_type_name for k in ('h2ovl', 'internvl', 'llava', 'qwen2_vl', 'paligemma', 'blip')):
            detected_type = 'VLM'
        # ForCausalLM → LLM (override any Hub confusion)
        elif 'forcausallm' in _arch_str:
            detected_type = 'LLM'
        # Seq2Seq architectures
        elif detected_type not in ('ASR', 'TTS') and ('forseq2seqlm' in _arch_str or 'forconditionalgeneration' in _arch_str):
            detected_type = 'SEQ2SEQ'

        if verbose and detected_type:
            print(f"   Refined from config.json: {detected_type} (arch: {_archs[0] if _archs else 'N/A'}, labels: {len(_id2label)})")
            sys.stdout.flush()

    if verbose:
        print(f"⬇️  Loading {model_id}...")
        sys.stdout.flush()

    # ========== ROUTE TO CORRECT LOADER ==========

    # If detected as LLM, skip SentenceTransformer entirely (it hangs on LLMs)
    if detected_type == 'LLM':
        return _load_as_llm(model_id, verbose)
    elif detected_type == 'SEQ2SEQ':
        result = _load_as_seq2seq(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)  # fallback
    elif detected_type == 'VISION':
        return _load_as_vision(model_id, verbose)
    elif detected_type == 'RERANKER':
        result = _load_as_reranker(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)
    elif detected_type == 'EMBEDDING':
        result = _load_as_embedding(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)
    elif detected_type == 'CLASSIFIER':
        return _load_as_classifier(model_id, verbose)
    elif detected_type == 'VLM':
        return _load_as_vlm(model_id, verbose)
    elif detected_type == 'ASR':
        return _load_as_asr(model_id, verbose)
    elif detected_type == 'TTS':
        return _load_as_tts(model_id, verbose)
    elif detected_type == 'AUDIO_CLASSIFIER':
        return _load_as_generic(model_id, verbose)

    # Unknown type - try in safe order (LLM first since SentenceTransformer hangs on LLMs)
    if verbose:
        print(f"   Unknown type, trying loaders in order...")
        sys.stdout.flush()

    # Try LLM first (safer, won't hang)
    result = _load_as_llm(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as LLM")
        return result

    # Try Seq2Seq
    result = _load_as_seq2seq(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as SEQ2SEQ")
        return result

    # Try embedding (only after LLM fails - less likely to hang)
    result = _load_as_embedding(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as EMBEDDING")
        return result

    # Try vision
    result = _load_as_vision(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as VISION")
        return result

    # Try VLM
    result = _load_as_vlm(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as VLM")
        return result

    # Final fallback: generic
    return _load_as_generic(model_id, verbose)


def _load_as_asr(model_id: str, verbose: bool = True) -> tuple:
    """Load model as automatic speech recognition (Whisper, etc.)."""
    try:
        import torch
        from transformers import WhisperForConditionalGeneration, WhisperProcessor
        _device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        _dtype = torch.float16 if _device.type == 'cuda' else torch.float32
        m = WhisperForConditionalGeneration.from_pretrained(model_id, torch_dtype=_dtype, low_cpu_mem_usage=True)
        m.to(_device)
        m.eval()
        p = WhisperProcessor.from_pretrained(model_id)

        class ASRWrapper:
            def __init__(self, model, processor, device, dtype):
                self.model = model
                self.processor = processor
                self.device = device
                self.dtype = dtype
                self._model_type_hint = 'ASR'
                self._is_remote_provider = False
                self._limits = {'context_length': 448, 'max_gen_tokens': 128}
            def transcribe(self, audio_path, language=None, **kwargs):
                import os
                import numpy as np
                def _load_audio_file(path):
                    _path = str(path)
                    _ext = os.path.splitext(_path)[1].lower().lstrip('.')
                    if _ext in ('wav', 'wave'):
                        import scipy.io.wavfile as wav
                        return wav.read(_path)
                    try:
                        import av
                    except Exception as _av_import_err:
                        raise RuntimeError("Audio format '%s' requires PyAV for decode" % (_ext or 'unknown')) from _av_import_err
                    _chunks = []
                    _sample_rate = None
                    with av.open(_path) as _container:
                        _stream = next((s for s in _container.streams if s.type == 'audio'), None)
                        if _stream is None:
                            raise RuntimeError("No audio stream found in '%s'" % _path)
                        for _frame in _container.decode(_stream):
                            _sample_rate = int(getattr(_frame, 'sample_rate', 0) or _sample_rate or 16000)
                            _arr = np.asarray(_frame.to_ndarray())
                            if _arr.ndim > 1:
                                _arr = _arr.mean(axis=0)
                            _chunks.append(_arr.astype(np.float32, copy=False))
                    if not _chunks:
                        raise RuntimeError("No decodable audio frames found in '%s'" % _path)
                    return int(_sample_rate or 16000), np.concatenate(_chunks, axis=0)
                sr, audio = _load_audio_file(audio_path)
                if np.issubdtype(audio.dtype, np.integer):
                    _scale = max(abs(np.iinfo(audio.dtype).min), abs(np.iinfo(audio.dtype).max)) or 1
                    audio = audio.astype(np.float32) / float(_scale)
                else:
                    audio = audio.astype(np.float32)
                    _peak = float(np.max(np.abs(audio))) if audio.size else 0.0
                    if _peak > 1.5:
                        audio = audio / _peak
                if len(audio.shape) > 1:
                    audio = audio.mean(axis=1)
                if sr != 16000:
                    from scipy.signal import resample
                    audio = resample(audio, int(len(audio) * 16000 / sr))
                audio = np.asarray(audio, dtype=np.float32)
                inputs = self.processor(audio, sampling_rate=16000, return_tensors="pt")
                input_features = inputs.input_features.to(device=self.device, dtype=self.dtype)
                gen_kwargs = {'max_new_tokens': min(int(kwargs.get('max_new_tokens', 128) or 128), 128)}
                if language:
                    try:
                        gen_kwargs['forced_decoder_ids'] = self.processor.get_decoder_prompt_ids(language=language, task=kwargs.get('task', 'transcribe'))
                    except Exception:
                        pass
                with torch.no_grad():
                    predicted_ids = self.model.generate(input_features, **gen_kwargs)
                return self.processor.batch_decode(predicted_ids, skip_special_tokens=True)[0].strip()
            def __call__(self, x):
                return self.transcribe(str(x))

        model = ASRWrapper(m, p, _device, _dtype)
        if verbose:
            print(f"✓ Loaded as WhisperForConditionalGeneration (ASR)")
        return model, 'ASR', None
    except Exception as e:
        return None, 'ERROR', str(e)


def _load_as_tts(model_id: str, verbose: bool = True) -> tuple:
    """Load model as text-to-speech (Bark, SpeechT5, etc.)."""
    try:
        import torch
        from transformers import pipeline
        _has_cuda = torch.cuda.is_available()
        _device = 0 if _has_cuda else -1
        _dtype = torch.float16 if _has_cuda else torch.float32
        pipe = pipeline("text-to-speech", model=model_id, device=_device, torch_dtype=_dtype)

        class TTSWrapper:
            def __init__(self, pipe):
                self.pipe = pipe
                self._model_type_hint = 'TTS'
                self._is_remote_provider = False
                self._limits = {'context_length': 600, 'max_gen_tokens': 0}
            def synthesize(self, text, **kwargs):
                import base64, io, struct
                result = self.pipe(text)
                audio = result["audio"]
                sr = result["sampling_rate"]
                import numpy as np
                if isinstance(audio, np.ndarray):
                    audio_int16 = (audio * 32767).astype(np.int16) if audio.dtype == np.float32 else audio
                    buf = io.BytesIO()
                    buf.write(b'RIFF')
                    buf.write(struct.pack('<I', 0))
                    buf.write(b'WAVE')
                    buf.write(b'fmt ')
                    buf.write(struct.pack('<IHHIIHH', 16, 1, 1, sr, sr * 2, 2, 16))
                    buf.write(b'data')
                    raw = audio_int16.tobytes()
                    buf.write(struct.pack('<I', len(raw)))
                    buf.write(raw)
                    total = buf.tell() - 8
                    buf.seek(4)
                    buf.write(struct.pack('<I', total))
                    return {"audio_base64": base64.b64encode(buf.getvalue()).decode(), "sampling_rate": sr, "format": "wav"}
                return {"error": "Unexpected audio output type"}
            def __call__(self, x):
                return self.synthesize(str(x))

        model = TTSWrapper(pipe)
        if verbose:
            print(f"✓ Loaded as TTS pipeline (TTS)")
        return model, 'TTS', None
    except Exception as e:
        return None, 'ERROR', str(e)


