    def compile(self, node: Node, name: str = None, 
                config: CapsuleConfig = None) -> Path:
        """
        Compile a single Node into a capsule file.

        Args:
            node: The evolved Node to compile
            name: Capsule name (default: agent_{node.id})
            config: Capsule configuration

        Returns:
            Path to the generated capsule file
        """
        config = config or CapsuleConfig()
        name = name or f"agent_{node.id}"
        config.name = name

        # Extract data from node
        brain_data = self._serialize_brain(node.brain, config.compress)
        traits_data = json.dumps(node.traits, indent=2)
        vp_config = self._get_vp_config()

        # Get brain type info FIRST - use config override if provided
        brain_type = getattr(config, 'brain_type', None) or "mlp"
        if node.brain and not getattr(config, 'brain_type', None):
            cfg = node.brain.config
            brain_type = getattr(cfg, 'brain_type', type(cfg).__name__.replace('Config', '').lower())

        # === QUINE BRAIN: Merkle hash and self-contained source ===
        quine_hash = self._compute_quine_hash(node.brain, node.traits)
        # Pass brain_type so quine is generated even when brain is None (evolved from checkpoint)
        quine_source = self._generate_quine_source(node.brain, brain_type=brain_type)
        brain_config_dict = {
            "brain_type": brain_type,
            "quine_hash": quine_hash,
        }
        if node.brain:
            cfg = node.brain.config
            if not getattr(config, 'brain_type', None):
                brain_type = getattr(cfg, 'brain_type', type(cfg).__name__.replace('Config', '').lower())
            brain_config_dict.update({
                "brain_type": brain_type,
                "input_keys": getattr(cfg, 'input_keys', []),
                "output_keys": getattr(cfg, 'output_keys', []),
                "hidden_size": getattr(cfg, 'hidden_size', getattr(cfg, 'hidden_dim', 256)),
                "extra": getattr(cfg, 'extra', {}),
                "quine_hash": quine_hash,  # Merkle hash for provenance
            })

            # ScarecrowBrain adapter config
            if brain_type == "scarecrow" and hasattr(node.brain, 'input_dim'):
                brain_config_dict["adapter"] = {
                    "input_dim": node.brain.input_dim,
                    "output_dim": node.brain.output_dim,
                    "adapter_dim": node.brain.adapter_dim,
                }
                # Model type (auto-detected or explicit)
                if hasattr(node.brain, '_model_type'):
                    brain_config_dict["model_type"] = node.brain._model_type.name

            # CouncilBrain config
            if brain_type == "council" and hasattr(node.brain, 'councilors'):
                brain_config_dict["council"] = {
                    "num_councilors": len(node.brain.councilors),
                    "councilor_names": getattr(node.brain, 'councilor_names', []),
                    "councilor_specialties": getattr(node.brain, 'councilor_specialties', []),
                    "consensus_method": getattr(node.brain, 'consensus_method', 'weighted'),
                }

            # Ouroboros multi-modal config - ALL brain faculties
            if brain_type == "ouroboros":
                brain_config_dict["ouroboros"] = {
                    "multi_modal": True,
                    "embedding_foundation": True,
                    "dreamer_world_model": True,
                    "scarecrow_adapter": True,
                    "council_consensus": True,
                    "hold_protocol": True,
                    "cascade_lattice": True,
                    "unified_substrate_dim": 384,
                    "total_latent_dim": 5120,
                    "architecture": "self-consuming serpent",
                    "safety": "provenance integral to function"
                }

            # DreamerBrain LoRA config - critical for capsule reconstruction
            if brain_type == "dreamer" and hasattr(node.brain, 'lora_rank'):
                brain_config_dict["lora"] = {
                    "rank": node.brain.lora_rank,
                    "alpha": node.brain.lora_alpha,
                    "latent_dim": node.brain.latent_dim,
                    "action_dim": node.brain.dreamer_config.action_dim,
                }

            # Universal sandbox/invocation config (all brain types)
            brain_config_dict["sandbox"] = {
                "infinity_emb_default": True,  # infinity-emb is the default sandbox
                "supported_model_types": ["SENTENCE_TRANSFORMER", "LLM", "HUGGINGFACE", 
                                          "INFINITY_EMBED", "INFINITY_RERANK", "INFINITY_CLASSIFY",
                                          "INFINITY_CLIP", "INFINITY_CLAP", "GENERIC"],
                "invocation_methods": ["invoke", "embed", "generate", "classify", "rerank"],
            }

        # === COLLECT DOCUMENTATION ===
        # Only get embedding model for embedding-based brains
        if brain_type in ("dreamer", "mlp", "liquid", "mamba"):
            embedding_model = None
        elif brain_type == "ouroboros":
            # Ouroboros uses embedding foundation for all brain types
            from config import get_embedding_model
            embedding_model = get_embedding_model()
        else:
            from config import get_embedding_model
            embedding_model = get_embedding_model()

        node_doc = self._collect_node_documentation(node, rank=1)
        pop_doc = self._collect_population_documentation()
        config_doc = self._collect_config_documentation()
        readme_text = self._generate_readme([node_doc], pop_doc, config_doc, 
                                             is_ensemble=False, 
                                             embedding_model=embedding_model,
                                             brain_type=brain_type)

        # Ensure fitness is float
        fitness_val = node.fitness
        if isinstance(fitness_val, str):
            try:
                fitness_val = float(fitness_val)
            except (ValueError, TypeError):
                fitness_val = 0.0
        fitness_val = fitness_val or 0.0

        # Use population generation (evolution run) over node generation (lineage depth)
        generation_val = node.generation
        if self._population_context:
            generation_val = self._population_context.generation

        # Generate capsule source with embedded documentation and quine brain
        source = self._generate_capsule_source(
            name=name,
            brain_data=brain_data,
            traits_data=traits_data,
            vp_config=vp_config,
            brain_config=brain_config_dict,
            compressed=config.compress,
            fitness=fitness_val,
            generation=generation_val,
            is_ensemble=False,
            lora_handling=config.lora_handling,
            base_model_path=config.base_model_path,
            node_docs=[node_doc],
            pop_doc=pop_doc,
            config_doc=config_doc,
            readme_text=readme_text,
            quine_source=quine_source,
            quine_hash=quine_hash,
        )

        # Write capsule file
        capsule_path = self.output_dir / f"{name}.py"
        capsule_path.write_text(source, encoding='utf-8')

        # Write requirements if requested
        if config.include_requirements:
            self._write_requirements(capsule_path.parent, brain_type)

        # Write .env.example and .gitignore for standalone deployment
        self._write_env_example(capsule_path.parent)
        self._write_gitignore(capsule_path.parent)

        # === ARCADE PACKAGE GENERATION ===
        if config.arcade:
            arcade_pkg_name = config.arcade_package_name or f"{name}_arcade"
            self._generate_arcade_package(
                capsule_path=capsule_path,
                package_name=arcade_pkg_name,
                brain_config=brain_config_dict,
            )

        return capsule_path

    def compile_ensemble(self, nodes: List[Node], name: str = "ensemble",
                        config: CapsuleConfig = None) -> Path:
        """
        Compile multiple Nodes into an ensemble capsule.

        Args:
            nodes: List of Nodes for the ensemble
            name: Ensemble name
            config: Capsule configuration

        Returns:
            Path to the generated ensemble capsule
        """
        config = config or CapsuleConfig()
        config.name = name

        # Limit ensemble size
        nodes = nodes[:config.max_organisms]

        # Serialize all brains
        organisms_data = []
        for node in nodes:
            # Ensure fitness is float
            fitness_val = node.fitness
            if isinstance(fitness_val, str):
                try:
                    fitness_val = float(fitness_val)
                except (ValueError, TypeError):
                    fitness_val = 0.0
            fitness_val = fitness_val or 0.0

            org_data = {
                "brain_data": self._serialize_brain(node.brain, config.compress),
                "traits": node.traits,
                "fitness": fitness_val,
                "generation": node.generation,
                "id": node.id,
            }
            organisms_data.append(org_data)

