        # Write .env.example and .gitignore for standalone deployment
        self._write_env_example(capsule_path.parent)
        self._write_gitignore(capsule_path.parent)

        return capsule_path


    def _serialize_brain(self, brain: Optional[Brain], compress: bool) -> str:
        """
        Serialize brain to base64 string.

        Uses JSON serialization for DreamerBrain (pickle-free quine compatible).
        This allows capsules to deserialize without needing the full module tree.
        """
        if brain is None:
            return ""

        # For DreamerBrain, serialize the COMPLETE model as JSON
        # Check class-level brain_type FIRST (more reliable than config which can be overwritten)
        brain_type = getattr(brain, 'brain_type', None) or getattr(brain.config, 'brain_type', 'mlp')

        if brain_type == 'dreamer':
            # Use JSON serialization (pickle-free for quine replication)
            if hasattr(brain, 'to_full_dict'):
                full_data = brain.to_full_dict()
                data = json.dumps(full_data).encode('utf-8')
            else:
                # Fallback to pickle if to_full_dict not available
                data = pickle.dumps(brain)
        else:
            # Other brain types - just params as numpy bytes
            params = brain.get_params()
            data = params.tobytes() if hasattr(params, 'tobytes') else pickle.dumps(params)

        if compress:
            data = gzip.compress(data)

        return base64.b64encode(data).decode('ascii')

    def _compute_quine_hash(self, brain: Optional[Brain], traits: Dict) -> str:
        """
        Compute merkle hash for the quine brain.

        This hash uniquely identifies this brain's state and is
        immutably provable - any change to weights, traits, or
        structure will produce a different hash.
        """
        import hashlib

        if brain is None:
            return hashlib.sha256(b"no_brain").hexdigest()[:32]

        # Hash components
        components = []

        # 1. Brain type
        brain_type = getattr(brain.config, 'brain_type', 'mlp')
        components.append(f"type:{brain_type}")

        # 2. Parameters (the actual weights)
        try:
            params = brain.get_params()
            param_bytes = params.tobytes() if hasattr(params, 'tobytes') else pickle.dumps(params)
            param_hash = hashlib.sha256(param_bytes).hexdigest()[:16]
            components.append(f"params:{param_hash}")
        except Exception:
            components.append("params:none")

        # 3. Traits (evolved hyperparameters)
        traits_str = json.dumps(traits, sort_keys=True)
        traits_hash = hashlib.sha256(traits_str.encode()).hexdigest()[:16]
        components.append(f"traits:{traits_hash}")

        # 4. Config structure
        if hasattr(brain, 'config'):
            cfg = brain.config
            cfg_data = {
                'hidden_size': getattr(cfg, 'hidden_size', getattr(cfg, 'hidden_dim', None)),
                'input_keys': getattr(cfg, 'input_keys', []),
                'output_keys': getattr(cfg, 'output_keys', []),
            }
            cfg_hash = hashlib.sha256(json.dumps(cfg_data, sort_keys=True).encode()).hexdigest()[:16]
            components.append(f"config:{cfg_hash}")

        # 5. DreamerBrain-specific: RSSM structure
        if brain_type == 'dreamer' and hasattr(brain, 'dreamer_config'):
            dc = brain.dreamer_config
            dreamer_data = {
                'deter_dim': dc.deter_dim,
                'stoch_dim': dc.stoch_dim,
                'stoch_classes': dc.stoch_classes,
                'action_dim': dc.action_dim,
                'lora_rank': getattr(brain, 'lora_rank', dc.lora_rank),
            }
            dreamer_hash = hashlib.sha256(json.dumps(dreamer_data, sort_keys=True).encode()).hexdigest()[:16]
            components.append(f"dreamer:{dreamer_hash}")

        # Compute final merkle root using CASCADE's hash_input for provable lattice integration
        combined = "|".join(components)
        try:
            # Use CASCADE hash_input if available for lattice-compatible merkle roots
            from cascade.bridge import hash_input
            return hash_input(combined)[:32]
        except ImportError:
            # Fallback to standard SHA256
            return hashlib.sha256(combined.encode()).hexdigest()[:32]

    def _generate_quine_source(self, brain: Optional[Brain], brain_type: str = None) -> str:
        """
        Generate self-contained quine source code for the brain.

        This is the REPLICABLE component - a Python source that can
        reconstruct the exact brain without external dependencies
        on the KEY codebase. Non-malicious by design (pure inference).

        Args:
            brain: The brain object (may be None for checkpoint-loaded evolution)
            brain_type: Override brain type (required when brain is None)
        """
        # Determine brain type - use override first, then class attr, then config, then default
        if brain_type is None:
            if brain is not None:
                # Check class-level brain_type FIRST (more reliable - config can be overwritten by sub-brains)
                brain_type = getattr(brain, 'brain_type', None) or getattr(brain.config, 'brain_type', 'mlp')
            else:
                brain_type = 'mlp'

        # For Ouroboros, generate full template even with no brain object
        if brain_type == 'ouroboros':
            return self._generate_ouroboros_quine(brain)

        if brain is None:
            return '"""\nNo brain embedded.\n"""'

        # Use determined brain_type (not re-detecting from brain.config)

        if brain_type == 'ouroboros':
            return self._generate_ouroboros_quine(brain)
        elif brain_type == 'dreamer':
            return self._generate_dreamer_quine(brain)
        elif brain_type == 'scarecrow':
            return self._generate_scarecrow_quine(brain)
        elif brain_type == 'council':
            return self._generate_council_quine(brain)
        elif brain_type == 'embedding':
            return self._generate_embedding_quine(brain)
        else:
            return self._generate_mlp_quine(brain)

    def _generate_ouroboros_quine(self, brain) -> str:
        """Generate self-contained Ouroboros composite brain quine."""
        # Ouroboros contains ALL brain types - serialize each component
        # Handle case where brain is None (evolved from checkpoint)

        # Get default from config.json
        try:
            from config import load_config, get_embedding_model
            cfg_json = load_config()
            default_slots = cfg_json.get('council_brain', {}).get('evolution_slots', 100)
            embedding_model_name = get_embedding_model()
        except Exception:
            default_slots = 100
            embedding_model_name = 'all-MiniLM-L6-v2'

        # Load embedded dreamerv3 bundle (strict validation; fail fast if invalid)
        try:
            bundle_path = Path(__file__).parent.joinpath('_dreamerv3_bundle.b64')
            dreamerv3_bundle = bundle_path.read_text(encoding='utf-8').strip()
            if not dreamerv3_bundle:
                raise RuntimeError(f"empty bundle at {bundle_path}")
            try:
                bundle_files = pickle.loads(gzip.decompress(base64.b64decode(dreamerv3_bundle)))
            except Exception as decode_err:
                raise RuntimeError(f"decode failed: {decode_err}")
            required_bundle_files = [
                "elements/__init__.py",
                "dreamerv3/__init__.py",
                "dreamerv3/rssm.py",
                "embodied/__init__.py",
                "embodied/jax/__init__.py",
                "embodied/jax/nets.py",
                "embodied/jax/outs.py",
            ]
            missing_bundle_files = [f for f in required_bundle_files if f not in bundle_files]
            if missing_bundle_files:
                raise RuntimeError(f"missing required files: {missing_bundle_files}")
        except Exception as e:
            raise RuntimeError(f"DreamerV3 bundle unavailable or invalid: {e}")

        if brain is not None:
            params = brain.get_params()
            params_b64 = base64.b64encode(params.tobytes()).decode('ascii')
            cfg = brain.config
            num_councilors = getattr(cfg, 'num_councilors', default_slots)
        else:
            # Default empty params - Ouroboros template still works
            params_b64 = base64.b64encode(np.zeros(1024, dtype=np.float32).tobytes()).decode('ascii')
            num_councilors = default_slots

        return f'''
# ═══════════════════════════════════════════════════════════════════════
# 🐍 OUROBOROS QUINE - SELF-CONSUMING SERPENT OF INTELLIGENCE
# Composite AI with ALL brain faculties unified
# ═══════════════════════════════════════════════════════════════════════

_OUROBOROS_PARAMS_B64 = "{params_b64}"

