# EMBEDDED DREAMERV3 - Full DeepMind World Model (no external dependencies)
# ═══════════════════════════════════════════════════════════════════════
_DREAMERV3_BUNDLE = \"\"\"{dreamerv3_bundle}\"\"\"

# Extract dreamerv3 to temp directory on module load
import tempfile
