            self.lora_bias = np.zeros(384, dtype=np.float32)

        self.latent_dim = self.config.get('deter_dim', 256) + self.config.get('stoch_dim', 16) * self.config.get('stoch_classes', 16)
        self.action_dim = self.config.get('action_dim', 8)
        self.lora_rank = self.config.get('lora_rank', 16)
        self.lora_alpha = self.config.get('lora_alpha', 1.0)

        # State
        self._deter = np.zeros(self.config.get('deter_dim', 256), dtype=np.float32)
        self._stoch = np.zeros((self.config.get('stoch_dim', 16), self.config.get('stoch_classes', 16)), dtype=np.float32)

        # RSSM setup
        self._has_real_rssm = has_rssm
        self._rssm = None
        self._rng = None
        self._prev_action = 0
        self._last_imagination = []
