                print(f"[EmbeddedDreamer] RSSM init failed: {{self._rssm_init_error}}")
                self._has_real_rssm = False

    def _init_real_rssm(self):
        \"\"\"Initialize REAL DreamerV3 RSSM.\"\"\"
        from jax import random as jax_random
        self._rng = jax_random.PRNGKey(42)

        # Create action space for RSSM (REQUIRED)
        deter_dim = self.config.get('deter_dim', 4096)
        stoch_dim = self.config.get('stoch_dim', 32)
        stoch_classes = self.config.get('stoch_classes', 32)
        hidden_dim = self.config.get('hidden_dim', 4096)

        self._act_space = {{
            'action': elements.Space(np.int32, (), 0, self.action_dim)
        }}

        # CREATE THE ACTUAL RSSM (not a placeholder!)
        self._rssm = dreamer_rssm.RSSM(
            self._act_space,
            deter=deter_dim,
            hidden=hidden_dim,
            stoch=stoch_dim,
            classes=stoch_classes,
            name='rssm'
        )

        # Define observe function for consistent ninjax state keys
        def _observe_fn(carry, tokens, action, reset_arr):
            return self._rssm.observe(carry, tokens, action, reset_arr, training=False, single=True)
        self._observe_fn = _observe_fn
        self._pure_observe = nj.pure(_observe_fn)

        # Define single-step imagine function ONCE for consistent state keys
        def _imagine_fn_single(carry, action_val=0):
            def _policy(state, a=action_val):
                return {{'action': jnp.array([a], dtype=jnp.int32)}}
            return self._rssm.imagine(carry, _policy, 1, training=False, single=True)
        self._imagine_fn_single = _imagine_fn_single
        self._pure_imagine_single = nj.pure(_imagine_fn_single)

        # RSSM params - lazy init on first call
        self._nj_state = {{}}
        self._rssm_initialized = False

        # Initial RSSM state
        self._deter = np.zeros(deter_dim, dtype=np.float32)
        self._stoch = np.zeros((stoch_dim, stoch_classes), dtype=np.float32)

        print(f"[EmbeddedDreamer] ✓ REAL RSSM: deter={{deter_dim}}, stoch={{stoch_dim}}x{{stoch_classes}}")

    def _ensure_rssm_initialized(self, carry, tokens, action, reset_arr):
        \"\"\"Lazily init RSSM params.\"\"\"
        if self._rssm_initialized:
            return
        self._rng, subkey = jax_random.split(self._rng)
        seed_int = int(subkey[0]) % (2**31)
        init_fn = nj.init(self._observe_fn)
        self._nj_state = init_fn(self._nj_state, carry, tokens, action, reset_arr, seed=seed_int)
        self._rssm_initialized = True
        print(f"[OK] RSSM params: {{len(self._nj_state)}} entries")

        # Also initialize imagine-path keys (prior0, prior0norm, priorlogit)
        try:
            deter_dim = self.config.get('deter_dim', 4096)
            stoch_dim = self.config.get('stoch_dim', 32)
            stoch_classes = self.config.get('stoch_classes', 32)
            imagine_carry = {{
                'deter': jnp.zeros((1, deter_dim), dtype=jnp.bfloat16),
                'stoch': jnp.zeros((1, stoch_dim, stoch_classes), dtype=jnp.bfloat16),
            }}
            self._rng, subkey = jax_random.split(self._rng)
            imagine_seed = int(subkey[0]) % (2**31)
            imagine_init = nj.init(self._imagine_fn_single)
            imagine_state = imagine_init({{}}, imagine_carry, seed=imagine_seed)
            new_keys = 0
            for k, v in imagine_state.items():
                if k not in self._nj_state:
                    self._nj_state[k] = v
                    new_keys += 1
            print(f"[OK] Imagine-path keys merged: {{new_keys}} new, {{len(self._nj_state)}} total")
        except Exception as e:
            print(f"[WARN] Imagine-path init failed (observe still works): {{e}}")

    def _update_rssm_state(self, obs):
        \"\"\"Update RSSM state with observation.\"\"\"
        if not self._has_real_rssm or self._rssm is None:
            return

        # Prepare inputs
        tokens = jnp.array(obs.reshape(1, -1), dtype=jnp.float32)
        action_val = max(0, min(self._prev_action, self.config['action_dim'] - 1))
        action = {{'action': jnp.array([action_val], dtype=jnp.int32)}}
        reset_arr = jnp.array([False], dtype=bool)
        carry = {{
            'deter': jnp.array(self._deter.reshape(1, -1), dtype=jnp.float32),
            'stoch': jnp.array(self._stoch.reshape(1, self.config['stoch_dim'], 
                self.config['stoch_classes']), dtype=jnp.float32),
        }}

        try:
            self._ensure_rssm_initialized(carry, tokens, action, reset_arr)
            self._rng, subkey = jax_random.split(self._rng)
            seed_int = int(subkey[0]) % (2**31)
            self._nj_state, (new_carry, entry, feat) = self._pure_observe(
                self._nj_state, carry, tokens, action, reset_arr,
                seed=seed_int, create=False, modify=True
            )
            self._deter = np.array(new_carry['deter'][0], dtype=np.float32)
            self._stoch = np.array(new_carry['stoch'][0], dtype=np.float32)
        except Exception as e:
            # Fallback: simple state update
            obs_proj = np.zeros(len(self._deter), dtype=np.float32)
            obs_flat = obs.flatten()
            obs_proj[:min(len(obs_flat), len(obs_proj))] = obs_flat[:min(len(obs_flat), len(obs_proj))]
            gate = 1.0 / (1.0 + np.exp(-obs_proj * 0.1))
            self._deter = gate * self._deter + (1 - gate) * obs_proj * 0.01
            self._stoch = self._stoch * 0.99 + np.random.randn(*self._stoch.shape).astype(np.float32) * 0.01

    def forward(self, inputs):
        \"\"\"Forward pass through world model.\"\"\"
        if isinstance(inputs, dict):
            x = inputs.get('obs', inputs.get('embedding', inputs.get('input', np.zeros(384))))
        else:
            x = inputs
        x = np.array(x, dtype=np.float32).flatten()[:384]
        if len(x) < 384:
            x = np.pad(x, (0, 384 - len(x)))

        # Update RSSM state
        self._update_rssm_state(x)

        # Build latent from real state
        latent = np.concatenate([self._deter.flatten(), self._stoch.flatten()])

        # LoRA transform on raw input (384-dim) for output compatibility
        h = x @ self.lora_A
        out = h @ self.lora_B + self.lora_bias

        # Track action
        self._prev_action = int(np.argmax(np.abs(out)))

        return {{
            'output': out,
            'latent': self._deter,
            'stoch': self._stoch.flatten(),
            'has_rssm': self._has_real_rssm
        }}

    def _get_latent_vector(self):
        \"\"\"Get flattened latent state [deter | stoch] = 5120 dims.\"\"\"
        return np.concatenate([self._deter.flatten(), self._stoch.flatten()])

    @staticmethod
    def _copy_nj_state(nj_state):
        \"\"\"Copy ninjax state dict for branch isolation.\"\"\"
        return {{k: v.copy() if hasattr(v, 'copy') else v for k, v in nj_state.items()}}

    def imagine(self, start_state=None, horizon=None, n_actions=None):
        \"\"\"Imagine future trajectories per-action using REAL RSSM.
        Returns list of trajectories, one per action (branching).\"\"\"
        if horizon is None:
            horizon = self.config.get('imagine_horizon', 15)
        if n_actions is None:
            n_actions = self.config.get('action_dim', 8)

        if not (self._has_real_rssm and self._rssm is not None):
            raise RuntimeError("[EmbeddedDreamer] No RSSM available - cannot imagine without real world model")

        deter_dim = self.config.get('deter_dim', 4096)
        stoch_dim = self.config.get('stoch_dim', 32)
        stoch_classes = self.config.get('stoch_classes', 32)

        # Save ALL state before branching
        saved_deter = self._deter.copy()
        saved_stoch = self._stoch.copy()
        saved_nj = self._copy_nj_state(self._nj_state)

        # Handle start_state dimension mismatch
        if start_state is not None:
            start_state = np.asarray(start_state, dtype=np.float32).flatten()
            if len(start_state) < deter_dim:
                state_deter = np.zeros(deter_dim, dtype=np.float32)
                state_deter[:len(start_state)] = start_state
            elif len(start_state) > deter_dim:
                state_deter = start_state[:deter_dim]
            else:
                state_deter = start_state
        else:
            state_deter = self._deter.copy()
        state_stoch = self._stoch.copy()

        # Ensure RSSM is initialized
        if not self._rssm_initialized:
            dummy_carry = {{
                'deter': jnp.zeros((1, deter_dim), dtype=jnp.float32),
                'stoch': jnp.zeros((1, stoch_dim, stoch_classes), dtype=jnp.float32),
            }}
            dummy_tokens = jnp.zeros((1, 64), dtype=jnp.float32)
            dummy_action = {{'action': jnp.zeros((1,), dtype=jnp.int32)}}
            dummy_reset = jnp.array([True], dtype=bool)
            self._ensure_rssm_initialized(dummy_carry, dummy_tokens, dummy_action, dummy_reset)
            saved_nj = self._copy_nj_state(self._nj_state)

        all_trajectories = []
        from jax import random as jax_random

        try:
            for action_idx in range(n_actions):
                # Reset nj_state to saved snapshot for each branch
                self._nj_state = self._copy_nj_state(saved_nj)

                # Build initial carry — bfloat16 to match RSSM COMPUTE_DTYPE
                carry = {{
                    'deter': jnp.array(state_deter.reshape(1, -1), dtype=jnp.bfloat16),
                    'stoch': jnp.array(state_stoch.reshape(1, stoch_dim, stoch_classes), dtype=jnp.bfloat16),
                }}

                trajectory = []
                for step in range(horizon):
                    self._rng, subkey = jax_random.split(self._rng)
                    seed_int = int(subkey[0]) % (2**31)
                    self._nj_state, (new_carry, (feat, action_out)) = self._pure_imagine_single(
                        self._nj_state, carry, action_idx, seed=seed_int, create=False, modify=True
                    )

                    step_deter = np.array(new_carry['deter'][0], dtype=np.float32)
                    step_stoch = np.array(new_carry['stoch'][0], dtype=np.float32)

                    trajectory.append({{
                        'step': step,
                        'action': action_idx,
                        'deter': step_deter.copy(),
                        'stoch': step_stoch.flatten().copy(),
                        'latent_norm': float(np.linalg.norm(step_deter)),
                        'real_rssm': True,
                    }})

                    carry = {{
                        'deter': new_carry['deter'],
                        'stoch': new_carry['stoch'],
                    }}

                all_trajectories.append(trajectory)

        except Exception as e:
            self._deter = saved_deter
            self._stoch = saved_stoch
            self._nj_state = saved_nj
            raise RuntimeError(f"[EmbeddedDreamer] RSSM imagine FAILED: {{e}}") from e

        # Restore ALL state after imagination
        self._deter = saved_deter
        self._stoch = saved_stoch
        self._nj_state = saved_nj

        # Store for training access
        self._last_imagination = all_trajectories

        return all_trajectories

    def reset(self):
        \"\"\"Reset world model state.\"\"\"
        self._deter = np.zeros(self.config.get('deter_dim', 256), dtype=np.float32)
        self._stoch = np.zeros((self.config.get('stoch_dim', 16), self.config.get('stoch_classes', 16)), dtype=np.float32)

