        self._critic_training_count = 0
        self._reward_head = RewardHead(latent_dim=arch['latent_dim'], hidden_dim=arch['reward_head_hidden_dim'])
        self._continue_head = ContinueHead(latent_dim=arch['latent_dim'], hidden_dim=arch['continue_head_hidden_dim'])
        self._last_train_stats = {{}}

        # Load persisted dreamer state (critic weights, training stats)
        self._load_dreamer_state()

        # Initialize CausationHold session
        self._init_causation_hold()

        # Load councilors from embedded data if available, else create default slots
        self.councilors = []
        if '_QUINE_COUNCILOR_DATA' in globals() and _QUINE_COUNCILOR_DATA:
            for data in _QUINE_COUNCILOR_DATA:
                self.councilors.append(QuineCouncilor(data))
        else:
            # Create default empty slots (Scarecrow adapters with NULL PORT)
            # Create QuineSlot class with proper forward method
            class QuineSlot:
                def __init__(self, slot_index, tier=0, role='general'):
                    self.name = f'slot_{{slot_index}}'
                    self.specialty = role
                    self.tier = tier
                    self.role = role
                    self.model = None
                    self._model_source = None
                    self._clones = []
                    self.fitness = 0.0
                    self.param_count = 0
                    self.model_type = None

                def forward(self, inputs):
                    # If no model plugged, return zero output
                    if self.model is None:
                        return {{'output': np.zeros(384), 'confidence': 0.0}}

                    # If model exists, use type-aware invocation
                    try:
                        # Detect model type and use appropriate method
                        model_type = self.model_type
                        if model_type is None:
                            model_type = _detect_model_type_runtime(self.model)
                            self.model_type = model_type

                        # Use type-aware dispatch
                        result = _invoke_model(self.model, inputs if isinstance(inputs, dict) else {{'input': inputs}}, model_type)

                        # Extract output
                        if 'error' in result:
                            return {{'output': np.zeros(384), 'confidence': 0.0}}

                        out_val = result.get('output', result.get('embedding', np.zeros(384)))
                        if hasattr(out_val, '__iter__') and not isinstance(out_val, str):
                            out_vec = np.asarray(out_val, dtype=np.float32).flatten()
                        elif isinstance(out_val, str) and out_val.startswith('['):
                            # Handle numpy array string representation
                            try:
                                out_vec = np.fromstring(out_val.strip('[]'), sep=' ', dtype=np.float32)
                                if len(out_vec) == 0:
                                    out_vec = np.fromstring(out_val.strip('[]'), sep=',', dtype=np.float32)
                            except Exception:
                                out_vec = np.zeros(384, dtype=np.float32)
                        else:
                            try:
                                out_vec = np.array([float(out_val)], dtype=np.float32)
                            except (ValueError, TypeError):
                                out_vec = np.zeros(384, dtype=np.float32)

                        # Confidence from embedding magnitude
                        confidence = float(np.clip(np.linalg.norm(out_vec) / (len(out_vec) + 1e-8), 0, 1))

                        return {{
                            'output': out_vec,
                            'embedding': out_vec,
                            'confidence': confidence,
                            'model_type': model_type.name if hasattr(model_type, 'name') else str(model_type)
                        }}
                    except Exception as e:
                        return {{'output': np.zeros(384), 'confidence': 0.0, 'error': str(e)}}

            default_slots = _OUROBOROS_CONFIG.get('num_councilors', 5)
            for i in range(default_slots):
                tier = 0
                role = 'general'
                if default_slots == 48:
                    if i < 4: tier = 1; role = 'perception'
                    elif i < 20: tier = 2; role = 'primitive'
                    elif i < 28: tier = 3; role = 'synthesis'
                    elif i < 36: tier = 4; role = 'reasoning'
                    elif i < 40: tier = 5; role = 'verification'
                    elif i < 44: tier = 6; role = 'search'
                    elif i < 48: tier = 7; role = 'memory'
                slot = QuineSlot(i, tier=tier, role=role)
                self.councilors.append(slot)

        # For TUI slot display - expose as all_members too
        self.all_members = self.councilors

        print(f"[🐍 Ouroboros] Composite brain loaded: {{len(self._params)}} evolved parameters")
        print(f"[🐍 Ouroboros] Embedding foundation: {{'✓' if self.embedding_foundation else 'ready to plug'}}")
        print(f"[🐍 Ouroboros] Dreamer world model: {{'✓' if self.dreamer_world_model else 'ready to plug'}}")
        print(f"[🐍 Ouroboros] Scarecrow adapter: ✓ (evolved)")
        print(f"[🐍 Ouroboros] Council slots: {{len(self.councilors)}} ({{sum(1 for c in self.councilors if getattr(c, 'model', None))}} plugged)")
        print(f"[🐍 Ouroboros] HOLD protocol: ✓")
        print(f"[🐍 Ouroboros] Cascade-lattice provenance: ✓")
        print(f"[🐍 Ouroboros] Dreamer config loaded: {{len(self._dreamer_config)}} sections")

