    # DREAMER CONFIG - Runtime-tunable reward weights and training params
    # ═══════════════════════════════════════════════════════════════════════

    def _load_dreamer_config(self):
        \"\"\"Load dreamer config from JSON file, merging with defaults.\"\"\"
        import copy
        from pathlib import Path as _P
        config = copy.deepcopy(_DREAMER_CONFIG_DEFAULTS)
        config_path = _P(__file__).parent / 'dreamer_config.json'
        try:
            if config_path.exists():
                with open(config_path, 'r') as f:
                    user_config = json.load(f)
                for section, values in user_config.items():
                    if section in config and isinstance(config[section], dict):
                        config[section].update(values)
                    else:
                        config[section] = values
        except (json.JSONDecodeError, IOError):
            pass  # Use defaults on any error
        self._dreamer_config = config
        try:
            self._dreamer_config_mtime = config_path.stat().st_mtime if config_path.exists() else 0
        except OSError:
            self._dreamer_config_mtime = 0
        return config

    def _get_reward_weight(self, key):
        \"\"\"Get reward weight from config.\"\"\"
        return self._dreamer_config.get('rewards', {{}}).get(key,
               _DREAMER_CONFIG_DEFAULTS['rewards'].get(key, 0.0))

    def _get_training_param(self, key):
        \"\"\"Get training parameter from config.\"\"\"
        return self._dreamer_config.get('training', {{}}).get(key,
               _DREAMER_CONFIG_DEFAULTS['training'].get(key, 0))

    def _capture_reward(self, source_key, event_id='', action=-1, metadata=None):
        \"\"\"Record a reward event using weight from config.\"\"\"
        raw_weight = self._get_reward_weight(source_key)
        if raw_weight == 0.0:
            return

        now = time.time()

        reward = raw_weight
        if self._dreamer_config.get('rewards', {{}}).get('normalize', True):
            reward = float(np.sign(raw_weight) * np.log1p(np.abs(raw_weight)))

        latent = np.zeros(5120, dtype=np.float32)
        if self.dreamer_world_model and hasattr(self.dreamer_world_model, '_get_latent_vector'):
            try:
                latent = self.dreamer_world_model._get_latent_vector()
            except Exception:
                pass

        ctx = f"{{source_key}}:{{event_id}}:{{action}}"
        ctx_hash = hashlib.sha256(ctx.encode()).hexdigest()[:16]

        evt = RewardEvent(
            timestamp=now,
            reward=reward,
            raw_weight=raw_weight,
            source=source_key.split('_')[0] if '_' in source_key else source_key,
            event_id=str(event_id),
            latent=latent.copy(),
            action=max(0, action),
            context_hash=ctx_hash,
            metadata=metadata or {{}},
        )

        self._reward_buffer.append(evt)
        self._reward_count += 1
        self._reward_sum += reward
        self._reward_rate_window.append(now)

        freq = self._get_training_param('critic_frequency')
        if (self._get_training_param('auto_train')
            and len(self._reward_buffer) >= freq
            and self._reward_count % freq == 0):
            try:
                self._train_critic()
            except Exception:
                pass

    # ═══════════════════════════════════════════════════════════════════════
    # DREAMER-HOLD TRANSMISSION — Hold Point Builder
    # ═══════════════════════════════════════════════════════════════════════

    def _dreamer_hold_point(self):
        \"\"\"Build HoldPoint kwargs from dreamer imagination with ASSOCIATIVE data.

        Returns dict compatible with Hold.yield_point() kwargs,
        or None if hold should be skipped (auto-pass due to high confidence).
        \"\"\"
        try:
            wm = self.dreamer_world_model
            if wm is None or not hasattr(wm, 'imagine'):
                return None

            # Get current latent and critic value
            latent = np.zeros(5120, dtype=np.float32)
            if hasattr(wm, '_get_latent_vector'):
                latent = wm._get_latent_vector()
            current_value = self._critic.forward(latent) if hasattr(self, '_critic') else 0.0

            # Run imagination
            config = self._dreamer_config
            horizon = config['imagination']['horizon']
            trajectories = getattr(wm, '_last_imagination', None)
            if not trajectories:
                try:
                    trajectories = wm.imagine(horizon=horizon)
                except Exception:
                    return None
            if not trajectories:
                return None

            gamma = config['training']['gamma']

            # Score each branch via critic + reward head
            branch_values = []
            branch_details = []

            for action_idx, traj in enumerate(trajectories):
                cumulative_value = 0.0
                step_summaries = []
                discount = 1.0
                last_reward = 0.0

                for step in traj:
                    step_latent = np.concatenate([
                        np.array(step.get('deter', np.zeros(4096))).flatten(),
                        np.array(step.get('stoch', np.zeros(1024))).flatten(),
                    ])[:5120]

                    step_value = self._critic.forward(step_latent) if hasattr(self, '_critic') else 0.0
                    step_reward = 0.0
                    if hasattr(self, '_reward_head'):
                        step_reward = self._reward_head.forward(step_latent)

                    cumulative_value += discount * (step_reward + gamma * step_value)
                    discount *= gamma
                    last_reward = step_reward

                    step_summaries.append(
                        f"Step {{step.get('step', '?')}}: "
                        f"value={{round(step_value, 3)}}, "
                        f"pred_reward={{round(step_reward, 3)}}, "
                        f"norm={{round(float(step.get('latent_norm', 0)), 3)}}"
                    )

                branch_values.append(cumulative_value)
                branch_details.append({{
                    'trajectory_summary': step_summaries,
                    'expected_value': round(cumulative_value, 4),
                    'predicted_reward': round(last_reward, 4),
                    'steps': len(traj),
                }})

            if not branch_values:
                return None

            # Softmax normalization to action_probs
            values_arr = np.array(branch_values, dtype=np.float32)
            temp = max(0.1, float(np.std(values_arr))) if len(values_arr) > 1 else 1.0
            exp_vals = np.exp((values_arr - np.max(values_arr)) / temp)
            action_probs = exp_vals / (float(exp_vals.sum()) + 1e-8)

            best_idx = int(np.argmax(values_arr))
            best_confidence = float(action_probs[best_idx])

            # Confidence gate check
            hold_config = config.get('hold', {{}})
            threshold = hold_config.get('confidence_threshold', 0.85)
            if best_confidence >= threshold:
                return None  # Auto-pass

            # Build ASSOCIATIVE imagination dict
            imagination = {{}}
            action_labels = []
            reasoning = []
            max_display = hold_config.get('max_branches_displayed', 4)

            ranked = sorted(range(len(branch_values)),
                            key=lambda i: branch_values[i], reverse=True)

            for rank, aidx in enumerate(ranked[:max_display]):
                detail = branch_details[aidx]
                label = f"branch_{{aidx}}"
                conf = float(action_probs[aidx])

                if detail['expected_value'] > 1.0:
                    risk = "low"
                elif detail['expected_value'] > 0.0:
                    risk = "medium"
                else:
                    risk = "high"

                imagination[aidx] = {{
                    'action_label': label,
                    'trajectory_summary': detail['trajectory_summary'],
                    'expected_value': detail['expected_value'],
                    'predicted_reward': detail['predicted_reward'],
                    'confidence': round(conf, 4),
                    'reasoning': f"Branch {{aidx}}: value={{detail['expected_value']}}, confidence={{round(conf, 3)}}, risk={{risk}}",
                    'risk_level': risk,
                    'steps_to_reward': detail['steps'],
                }}

                action_labels.append(label)
                reasoning.append(imagination[aidx]['reasoning'])

            # World prediction from best branch
            best_detail = branch_details[best_idx]
            world_prediction = {{
                'best_action': best_idx,
                'expected_outcome': f"Best branch {{best_idx}} with value {{best_detail['expected_value']}}",
                'predicted_reward': best_detail['predicted_reward'],
                'horizon_steps': horizon,
                'total_branches_evaluated': len(trajectories),
            }}

            expose = hold_config.get('expose_imagination', True)

            return {{
                'action_probs': action_probs,
                'value': float(current_value),
                'imagination': imagination if expose else None,
                'world_prediction': world_prediction,
                'reasoning': reasoning,
                'action_labels': action_labels,
                'features': {{
                    'latent_norm': float(np.linalg.norm(latent)),
                    'best_branch_value': float(values_arr[best_idx]),
                    'value_spread': float(np.std(values_arr)),
                    'n_branches': len(trajectories),
                }},
                'blocking': hold_config.get('blocking', False),
            }}
        except Exception:
            return None

