    def _init_causation_hold(self):
        \"\"\"Initialize CausationHold session at capsule startup.\"\"\"
        self._causation_hold = None
        self._hold_session = None
        self._hold_step_count = 0
        try:
            from cascade.hold.session import CausationHold
            self._causation_hold = CausationHold()
            self._hold_session = self._causation_hold.begin_session(agent_id="capsule_main")
        except Exception:
            pass

    def _capture_hold_step(self, context, candidates, state_snapshot):
        \"\"\"Capture an inference step in the CausationHold session.\"\"\"
        if self._causation_hold is None:
            return None, None
        try:
            result = self._causation_hold.capture(
                input_context=context,
                candidates=candidates,
                state_snapshot=state_snapshot,
            )
            self._hold_step_count += 1
            return result
        except Exception:
            return None, None

    def _end_causation_hold(self):
        \"\"\"End CausationHold session and return stats.\"\"\"
        if self._causation_hold is None:
            return {{}}
        try:
            return self._causation_hold.end_session()
        except Exception:
            return {{}}

