    @property
    def _dreamer(self):
        \"\"\"Alias for dreamer_world_model (compatibility with OuroborosBrain).\"\"\"
        return self.dreamer_world_model

    @property
    def dreamer_enabled(self):
        \"\"\"Check if dreamer is available (compatibility with OuroborosBrain).\"\"\"
        return self._dreamer_enabled and self.dreamer_world_model is not None

