    def imagine(self, obs, steps: int = 15, horizon: int = None):
        \"\"\"Route to dreamer's imagine() - REAL implementation only.\"\"\"
        # Support both 'steps' and 'horizon' parameter names
        h = horizon if horizon is not None else steps
        if self._dreamer_enabled and self.dreamer_world_model is not None:
            if hasattr(self.dreamer_world_model, 'imagine'):
                return self.dreamer_world_model.imagine(obs, horizon=h)
            elif hasattr(self.dreamer_world_model, 'forward'):
                return self.dreamer_world_model.forward({{'obs': obs, 'horizon': h}})
        # No synthetic fallback: imagination requires a real RSSM world model.
        rssm_reason = None
        if self.dreamer_world_model is not None:
            rssm_reason = getattr(self.dreamer_world_model, '_rssm_init_error', None)
        if not rssm_reason:
            rssm_reason = _RSSM_IMPORT_ERROR or 'Dreamer world model is not initialized'
        raise RuntimeError(f"[EmbeddedDreamer] Real RSSM unavailable - imagination disabled: {{rssm_reason}}")

    def plug_councilor(self, model, slot: int = None, name: str = None):
        \"\"\"Plug a model into a councilor slot for consensus.\"\"\"
        if slot is None:
            # Find first empty slot or append
            slot = next((i for i, c in enumerate(self.councilors) 
                        if getattr(c, 'model', None) is None), len(self.councilors))

        if slot < len(self.councilors):
            # Update existing QuineSlot
            c = self.councilors[slot]
            if hasattr(c, 'model'):
                c.model = model
                c.name = name or getattr(c, 'name', f'councilor_{{slot}}')
                c._model_source = getattr(model, 'name_or_path', type(model).__name__)
            else:
                # Fallback for dict-style slots
                self.councilors[slot] = {{'model': model, 'name': name or f'councilor_{{slot}}', 'slot': slot}}
        else:
            # Create new dict-style councilor for overflow
            self.councilors.append({{'model': model, 'name': name or f'councilor_{{slot}}', 'slot': slot}})

        slot_name = name or f'councilor_{{slot}}'
        print(f"[🐍 Ouroboros] ✓ Councilor {{slot}} plugged: {{slot_name}}")
        # Capture artifacts if HF model
        self._try_capture_artifacts(model, f'councilor_{{slot}}')
        return self

    def _try_capture_artifacts(self, model, source_tag: str):
        \"\"\"Try to capture tokenizer/config artifacts from a model.\"\"\"
        try:
            from pathlib import Path
            artifacts = {{}}

            # Check if model has a tokenizer or config path
            model_path = getattr(model, 'name_or_path', None) or getattr(model, 'model_id', None)
            if model_path and Path(model_path).exists():
                tokenizer_files = ['tokenizer.json', 'tokenizer_config.json', 
                                   'special_tokens_map.json', 'vocab.json', 'merges.txt']
                for fname in tokenizer_files:
                    fpath = Path(model_path) / fname
                    if fpath.exists():
                        artifacts[fname] = fpath.read_text(encoding='utf-8')

                # tokenizer.model (binary)
                tokenizer_model = Path(model_path) / 'tokenizer.model'
                if tokenizer_model.exists():
                    import base64
                    artifacts['tokenizer.model'] = base64.b64encode(tokenizer_model.read_bytes()).decode()

                # generation_config.json
                gen_config = Path(model_path) / 'generation_config.json'
                if gen_config.exists():
                    artifacts['generation_config.json'] = gen_config.read_text(encoding='utf-8')

                # README.md
                readme = Path(model_path) / 'README.md'
                if readme.exists():
                    artifacts['README.md'] = readme.read_text(encoding='utf-8')

            if artifacts:
                self._captured_artifacts[source_tag] = artifacts
                print(f"[🐍 Ouroboros] 📦 Captured {{len(artifacts)}} artifacts from {{source_tag}}")

                # Update global for FelixBag population
                global _OUROBOROS_CAPTURED_ARTIFACTS
                _OUROBOROS_CAPTURED_ARTIFACTS.update({{source_tag: artifacts}})
        except Exception as e:
            pass  # Silent fail - artifacts are optional enrichment

    def get_captured_artifacts(self) -> dict:
        \"\"\"Get all captured model artifacts for FelixBag.\"\"\"
        return self._captured_artifacts

    def forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        """
        Composite brain inference with full accountability.

        Flow: Input → Embedding → Dreamer → Scarecrow → Council → HOLD → Output
        """
        import time
        t0 = time.perf_counter()

        # Stage 1: Embedding foundation (semantic grounding)
        embedded = self._embed_inputs(inputs)
        t1 = time.perf_counter()

        # Stage 2: Dreamer world model (temporal reasoning)
        simulated = self._dreamer_simulate(embedded)
        if self._prev_embedding is not None:
            action = simulated.get('latent_state', embedded)[:8]
            self._obs_buffer.append((self._prev_embedding.copy(), action.copy(), embedded.copy()))
        self._prev_embedding = embedded.copy()
        t2 = time.perf_counter()

        # Stage 3: Scarecrow adapter (universal interface)
        adapted = self._scarecrow_adapt(simulated)
        t3 = time.perf_counter()

        # Stage 4: Council consensus (multi-agent deliberation)
        # Pass original inputs for text access by embedding models
        adapted['text'] = inputs.get('text', inputs.get('query', ''))
        adapted['query'] = inputs.get('query', inputs.get('text', ''))
        consensus = self._council_deliberate(adapted)
        t4 = time.perf_counter()

        # Stage 5: HOLD protocol (human oversight)
        final_output = self._hold_gate(consensus, inputs)
        t5 = time.perf_counter()

        # Periodic training on accumulated observations
        if hasattr(self, '_obs_buffer') and len(self._obs_buffer) >= 32 and len(self._obs_buffer) % 32 == 0:
            try:
                self._train_step()
            except Exception:
                pass

        # === RERUN VISUALIZATION (full inference path) ===
        try:
            import rerun as rr
            # Stage timings (drill into inference bottlenecks)
            rr.log("inference/timing/embed_ms", rr.Scalars([(t1 - t0) * 1000]))
            rr.log("inference/timing/dreamer_ms", rr.Scalars([(t2 - t1) * 1000]))
            rr.log("inference/timing/scarecrow_ms", rr.Scalars([(t3 - t2) * 1000]))
            rr.log("inference/timing/council_ms", rr.Scalars([(t4 - t3) * 1000]))
            rr.log("inference/timing/hold_ms", rr.Scalars([(t5 - t4) * 1000]))
            rr.log("inference/timing/total_ms", rr.Scalars([(t5 - t0) * 1000]))

            # Embedding vector (semantic space view)
            if hasattr(embedded, 'shape'):
                rr.log("inference/embedding", rr.Tensor(embedded.reshape(1, -1)))
                rr.log("inference/embedding_norm", rr.Scalars([float(np.linalg.norm(embedded))]))

            # Dreamer latent state (world model state space)
            latent = simulated.get('latent_state', None)
            if latent is not None and hasattr(latent, 'shape'):
                # Split into deter (4096) and stoch (1024) components
                if len(latent) >= 5120:
                    deter = latent[:4096]
                    stoch = latent[4096:5120]
                    rr.log("inference/dreamer/deter_norm", rr.Scalars([float(np.linalg.norm(deter))]))
                    rr.log("inference/dreamer/stoch_norm", rr.Scalars([float(np.linalg.norm(stoch))]))
                    # Sample projection for visualization (first 64 dims)
                    rr.log("inference/dreamer/deter_sample", rr.BarChart(deter[:64].tolist()))
                    rr.log("inference/dreamer/stoch_sample", rr.BarChart(stoch[:64].tolist()))
                else:
                    rr.log("inference/dreamer/latent_norm", rr.Scalars([float(np.linalg.norm(latent))]))

            # Scarecrow adapted output
            adapted_out = adapted.get('adapted_output', None)
            if adapted_out is not None and hasattr(adapted_out, 'shape'):
                rr.log("inference/scarecrow/output_norm", rr.Scalars([float(np.linalg.norm(adapted_out))]))
                rr.log("inference/scarecrow/output_sample", rr.BarChart(adapted_out[:32].tolist()))

            # Council deliberation (per-councilor votes)
            deliberation = consensus.get('deliberation', {{}})
            if deliberation:
                confidences = []
                for name, vote_info in deliberation.items():
                    conf = vote_info.get('confidence', 0)
                    confidences.append(conf)
                    rr.log(f"inference/council/{{name}}/confidence", rr.Scalars([conf]))
                # Aggregate council metrics
                rr.log("inference/council/num_voters", rr.Scalars([len(deliberation)]))
                if confidences:
                    rr.log("inference/council/avg_confidence", rr.Scalars([sum(confidences) / len(confidences)]))
                    rr.log("inference/council/confidence_spread", rr.BarChart(confidences))

            # Final consensus
            consensus_out = consensus.get('consensus_output', [])
            if consensus_out:
                rr.log("inference/consensus/output_sample", rr.BarChart(consensus_out[:32]))
                rr.log("inference/consensus/output_norm", rr.Scalars([float(np.linalg.norm(consensus_out))]))

            # Provenance hash
            rr.log("inference/provenance", rr.TextLog(f"🔐 {{self._get_provenance_hash()}}"))

            # State Space visualization (slots, embeddings, traits, fitness)
            _log_state_space(self, embedded=embedded, traits=inputs.get('traits'))
        except Exception:
            pass  # Silent fail - visualization is optional

        return {{
            'output': final_output,
            'embedding': embedded,
            'simulation': simulated,
            'adaptation': adapted,
            'consensus': consensus,
            'deliberation': consensus.get('deliberation', {{}}),  # Per-councilor votes
            'provenance': self._get_provenance_hash(),
            'type': 'ouroboros_agi'
        }}

    def _embed_inputs(self, inputs):
        """Stage 1: Semantic embedding foundation."""
        text = inputs.get('text', '')

        # Use REAL embedding model
        if self._embedding_enabled and self.embedding_foundation is not None and isinstance(text, str):
            if hasattr(self.embedding_foundation, 'encode'):
                emb = self.embedding_foundation.encode(text, convert_to_numpy=True)
                return np.asarray(emb, dtype=np.float32).flatten()[:384]

        # Fallback: deterministic hash-based embedding
        if isinstance(text, str):
            text_hash = hash(text) % 1000000
            return np.random.RandomState(text_hash).normal(0, 1, 384).astype(np.float32)
        return np.zeros(384, dtype=np.float32)

    def _dreamer_simulate(self, embedded):
        """Stage 2: Dreamer world model temporal reasoning."""
        # NUMERICAL STABILITY: Sanitize input embedding
        embedded = np.nan_to_num(embedded, nan=0.0, posinf=1.0, neginf=-1.0)
        embedded = np.clip(embedded, -10.0, 10.0)  # Prevent extreme values

        # Use REAL Dreamer if available
        if self._dreamer_enabled and self.dreamer_world_model is not None:
            # Project to dreamer space with numerical stability
            dreamer_input = embedded @ self._embed_to_dreamer
            dreamer_input = np.nan_to_num(dreamer_input, nan=0.0, posinf=1.0, neginf=-1.0)
            dreamer_input = np.clip(dreamer_input, -10.0, 10.0)

            if hasattr(self.dreamer_world_model, 'forward'):
                result = self.dreamer_world_model.forward({{'obs': dreamer_input}})
                if isinstance(result, dict):
                    # Ensure latent_state exists (Dreamer may return 'output' or 'latent' instead)
                    if 'latent_state' not in result:
                        # Build latent_state from RSSM deter+stoch when available
                        if 'latent' in result and 'stoch' in result:
                            deter_arr = np.asarray(result['latent'], dtype=np.float32).flatten()
                            stoch_arr = np.asarray(result['stoch'], dtype=np.float32).flatten()
                            latent = np.concatenate([deter_arr, stoch_arr])
                        else:
                            latent = result.get('output', result.get('latent', embedded))
                            if hasattr(latent, 'flatten'):
                                latent = latent.flatten()
                        latent = np.asarray(latent, dtype=np.float32)
                        # NUMERICAL STABILITY: Sanitize latent state
                        latent = np.nan_to_num(latent, nan=0.0, posinf=1.0, neginf=-1.0)
                        latent = np.clip(latent, -10.0, 10.0)
                        if len(latent) < 5120:
                            latent = np.concatenate([latent, np.zeros(5120 - len(latent))])
                        result['latent_state'] = latent[:5120]
                        result['temporal_reasoning'] = True
                        result['imagination_steps'] = 15
                    else:
                        # Sanitize existing latent_state
                        result['latent_state'] = np.nan_to_num(
                            np.clip(result['latent_state'], -10.0, 10.0),
                            nan=0.0, posinf=1.0, neginf=-1.0
                        )
                    self._imagined_trajectory = result.get('latent_state', None)
                    return result
                # result was not a dict - convert it to a proper latent array
                result_arr = np.asarray(result, dtype=np.float32).flatten()
                result_arr = np.nan_to_num(result_arr, nan=0.0, posinf=1.0, neginf=-1.0)
                result_arr = np.clip(result_arr, -10.0, 10.0)
                if len(result_arr) < 5120:
                    result_arr = np.concatenate([result_arr, np.zeros(5120 - len(result_arr))])
                return {{'latent_state': result_arr[:5120], 'imagination_steps': 15, 'temporal_reasoning': True}}
            elif hasattr(self.dreamer_world_model, 'imagine'):
                result = self.dreamer_world_model.imagine(dreamer_input, horizon=15)
                self._imagined_trajectory = result.get('latent_state', None) if isinstance(result, dict) else None
                return result

        # Fallback: simulated imagination
        latent_state = np.concatenate([embedded, np.zeros(4736)])  # 384 + 4736 = 5120
        return {{
            'latent_state': latent_state,
            'imagination_steps': 15,
            'temporal_reasoning': True
        }}

    def _scarecrow_adapt(self, simulated):
        """Stage 3: Scarecrow universal adapter."""
        # Apply evolved adapter parameters
        adapter_params = self._params[:49536]  # Scarecrow adapter size

        # Safely extract latent_state - handle dict/non-array cases
        latent_state = simulated.get('latent_state', simulated)
        if isinstance(latent_state, dict):
            # latent_state was a nested dict - extract array from it
            latent_state = latent_state.get('output', latent_state.get('latent', latent_state.get('embedding', np.zeros(384))))
        latent_state = np.asarray(latent_state, dtype=np.float32).flatten()

        # NUMERICAL STABILITY: Sanitize latent state
        latent_state = np.nan_to_num(latent_state, nan=0.0, posinf=1.0, neginf=-1.0)
        latent_state = np.clip(latent_state, -10.0, 10.0)

        if len(latent_state) >= 5120:
            adapted = latent_state @ self._latent_projection
        elif len(latent_state) >= 384:
            adapted = latent_state[:384]
        else:
            adapted = np.pad(latent_state, (0, 384 - len(latent_state)))

        # Simple linear adaptation (in real capsule, would be full LoRA)
        if len(adapter_params) >= 384:
            adapted = adapted + adapter_params[:384] * 0.1

        # NUMERICAL STABILITY: Sanitize adapted output
        adapted = np.nan_to_num(adapted, nan=0.0, posinf=1.0, neginf=-1.0)
        adapted = np.clip(adapted, -10.0, 10.0)

        return {{
            'adapted_output': adapted,
            'adapter_applied': True,
            'null_port_ready': True,
            'uncertainty': float(np.std(latent_state[4096:5120])) if len(latent_state) >= 5120 else 0.0
        }}

    def _council_deliberate(self, adapted):
        """Stage 4: Council multi-agent consensus."""
        councilor_votes = []
        vote_details = {{}}  # Track per-councilor votes with names

        # Use plugged councilors if available
        if self.councilors:
            for i, c in enumerate(self.councilors):
                # Support both dict-style and QuineSlot/object-style councilors
                if hasattr(c, 'model'):
                    model = c.model
                    name = getattr(c, 'name', f'councilor_{{i}}')
                elif isinstance(c, dict):
                    model = c.get('model')
                    name = c.get('name', f'councilor_{{i}}')
                else:
                    model = None
                    name = f'councilor_{{i}}'

                # SKIP EMPTY SLOTS - only vote with plugged models
                if model is None:
                    continue

                confidence = 0.5  # Default
                try:
                    if model is not None:
                        # Get model type - detect on the fly if not set
                        model_type = getattr(c, 'model_type', None)
                        if model_type is None:
                            model_type = _detect_model_type_runtime(model)
                            c.model_type = model_type

                        # Check LLM FIRST - they can't handle numpy arrays
                        if model_type == ModelType.LLM:
                            # LLM - use deterministic hash as vote (can't be called with numpy array)
                            import hashlib
                            hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                            h = hashlib.sha256(hash_input.encode()).digest()
                            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                            vote = (hash_bytes / 255.0) * 2 - 1
                            vote = np.tile(vote, 12)[:384]
                            confidence = 0.3
                        # RERANKER - CrossEncoder extends nn.Module, callable but needs sentence pairs
                        elif model_type == ModelType.RERANKER or getattr(model, '_model_type_hint', None) == 'RERANKER':
                            import hashlib
                            hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                            h = hashlib.sha256(hash_input.encode()).digest()
                            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                            vote = (hash_bytes / 255.0) * 2 - 1
                            vote = np.tile(vote, 12)[:384]
                            confidence = 0.3
                        # Check encode FIRST - SentenceTransformers have both forward() and encode()
                        # but forward() expects tokenized input, encode() expects text
                        elif hasattr(model, 'encode') and callable(getattr(model, 'encode', None)):
                            # Embedding model - needs text input
                            text_input = adapted.get('text', adapted.get('query', ''))
                            if not text_input:
                                # Fallback to context if available, NOT the embedding array
                                text_input = adapted.get('context', 'deliberation query')
                            vote = model.encode(text_input)
                            confidence = 0.8  # Embedders are reliable
                        elif hasattr(model, 'forward') and not hasattr(model, 'encode'):
                            # Check if this is a HuggingFace PreTrainedModel - they have 'config' attribute
                            # and expect tokenized tensors, not raw dicts
                            if hasattr(model, 'config') and hasattr(model, 'forward'):
                                # HuggingFace model - use deterministic hash as vote instead of failing
                                import hashlib
                                # Use text for hash, not the embedding array
                                hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                                h = hashlib.sha256(hash_input.encode()).digest()
                                # FIXED: Convert bytes to normalized floats in [-1, 1] range
                                # (raw frombuffer produces NaN/huge exponents from random byte patterns)
                                hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                                vote = (hash_bytes / 255.0) * 2 - 1  # Normalize to [-1, 1]
                                vote = np.tile(vote, 12)[:384]  # Expand to 384 dims (32 bytes * 12 = 384)
                                confidence = 0.4  # Lower confidence for hash-based vote
                            else:
                                result = model.forward({{'input': adapted['adapted_output']}})
                                vote = result.get('output', adapted['adapted_output'])
                                confidence = result.get('confidence', 0.7)
                        elif hasattr(model, 'classify') or getattr(model, '_model_type_hint', None) == 'CLASSIFIER':
                            # Classifier model - use hash-based vote (calling with numpy array crashes)
                            import hashlib
                            hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                            h = hashlib.sha256(hash_input.encode()).digest()
                            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                            vote = (hash_bytes / 255.0) * 2 - 1
                            vote = np.tile(vote, 12)[:384]
                            confidence = 0.5
                        elif callable(model):
                            vote = model(adapted['adapted_output'])
                            confidence = 0.6
                        else:
                            # Model exists but doesn't have encode/forward/callable - use hash fallback
                            import hashlib
                            hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                            h = hashlib.sha256(hash_input.encode()).digest()
                            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                            vote = (hash_bytes / 255.0) * 2 - 1
                            vote = np.tile(vote, 12)[:384]
                            confidence = 0.3
                except Exception as _slot_err:
                    # One bad councilor must not crash the whole council — hash fallback
                    import hashlib
                    hash_input = adapted.get('text', adapted.get('query', 'deliberation'))
                    h = hashlib.sha256(hash_input.encode()).digest()
                    hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                    vote = (hash_bytes / 255.0) * 2 - 1
                    vote = np.tile(vote, 12)[:384]
                    confidence = 0.1

                # Parse vote if it's a string representation of array (JSON serialization)
                if isinstance(vote, str):
                    try:
                        # Try numpy string format '[...]'
                        vote = np.fromstring(vote.strip('[]'), sep=' ', dtype=np.float32)
                    except Exception:
                        try:
                            import json
                            vote = np.array(json.loads(vote), dtype=np.float32)
                        except Exception:
                            # Fallback: hash the string to create deterministic embedding
                            import hashlib
                            h = hashlib.sha256(vote.encode()).digest()
                            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
                            vote = (hash_bytes / 255.0) * 2 - 1
                            vote = np.tile(vote, 12)[:384]

                vote_arr = np.asarray(vote, dtype=np.float32).flatten()[:384]
                # Validate - replace NaN/Inf with zeros
                if np.any(np.isnan(vote_arr)) or np.any(np.isinf(vote_arr)):
                    vote_arr = np.nan_to_num(vote_arr, nan=0.0, posinf=0.0, neginf=0.0)
                councilor_votes.append(vote_arr)
                vote_details[name] = {{
                    'output': vote_arr.tolist(),  # Convert to list for JSON serialization
                    'confidence': float(confidence),
                    'plugged': model is not None
                }}

        # If no councilors were plugged, return error
        if not councilor_votes:
            return {{
                'error': 'No councilors plugged',
                'consensus_output': [],
                'councilor_votes': 0,
                'consensus_method': 'none',
                'plugged_councilors': 0
            }}

        # Weighted average (Bayesian consensus)
        consensus = np.mean(councilor_votes, axis=0)
        # Sanitize any remaining NaN/Inf values
        consensus = np.nan_to_num(consensus, nan=0.0, posinf=0.0, neginf=0.0)

        return {{
            'consensus_output': consensus.tolist(),  # Convert to list for JSON serialization
            'councilor_votes': len(councilor_votes),
            'consensus_method': 'bayesian',
            'debate_rounds': 2,
            'plugged_councilors': sum(
                1 for c in self.councilors
                if (hasattr(c, 'model') and c.model is not None) or
                   (isinstance(c, dict) and c.get('model') is not None)
            ),
            'deliberation': vote_details  # Per-councilor breakdown
        }}

    def _hold_gate(self, consensus, original_inputs):
        """Stage 5: HOLD protocol human oversight with divergence checking."""
        divergence = 0.0
        if hasattr(self, '_imagined_trajectory') and self._imagined_trajectory is not None and hasattr(self, '_prev_embedding') and self._prev_embedding is not None:
            actual = self._prev_embedding
            imagined = np.asarray(self._imagined_trajectory, dtype=np.float32).flatten()
            min_len = min(len(actual), len(imagined))
            if min_len > 0:
                divergence = float(np.mean((actual[:min_len] - imagined[:min_len]) ** 2))

        hold_threshold = getattr(self, '_hold_threshold', 0.5)

        if divergence > hold_threshold:
            return {{
                'final_output': consensus['consensus_output'],
                'human_approved': False,
                'hold_yield': True,
                'divergence': divergence,
                'hold_protocol_active': True,
                'cascade_lattice_hash': self._get_provenance_hash()
            }}
        else:
            return {{
                'final_output': consensus['consensus_output'],
                'human_approved': True,
                'hold_protocol_active': True,
                'divergence': divergence,
                'cascade_lattice_hash': self._get_provenance_hash()
            }}

    def _train_critic(self):
        \"\"\"Train critic on reward buffer via gradient-free perturbation.\"\"\"
        import random as _rnd
        batch_size = self._get_training_param('batch_size')
        gamma = self._get_training_param('gamma')
        noise_scale = self._get_training_param('noise_scale')

        if len(self._reward_buffer) < batch_size:
            return None

        indices = _rnd.sample(range(len(self._reward_buffer) - 1), min(batch_size, len(self._reward_buffer) - 1))

        baseline_loss = 0.0
        for i in indices:
            evt = self._reward_buffer[i]
            next_evt = self._reward_buffer[min(i + 1, len(self._reward_buffer) - 1)]
            pred_value = self._critic.forward(evt.latent)
            target_value = evt.reward + gamma * self._critic.forward_target(next_evt.latent)
            baseline_loss += (pred_value - target_value) ** 2
        baseline_loss /= len(indices)

        original_params = self._critic.get_params().copy()
        noise = np.random.randn(len(original_params)).astype(np.float32) * noise_scale
        self._critic.set_params(original_params + noise)

        perturbed_loss = 0.0
        for i in indices:
            evt = self._reward_buffer[i]
            next_evt = self._reward_buffer[min(i + 1, len(self._reward_buffer) - 1)]
            pred_value = self._critic.forward(evt.latent)
            target_value = evt.reward + gamma * self._critic.forward_target(next_evt.latent)
            perturbed_loss += (pred_value - target_value) ** 2
        perturbed_loss /= len(indices)

        if perturbed_loss < baseline_loss:
            accepted = True
            self._critic.update_target()
        else:
            accepted = False
            self._critic.set_params(original_params)

        self._critic_training_count += 1

        self._last_train_stats = {{
            'critic_baseline_loss': round(baseline_loss, 6),
            'critic_perturbed_loss': round(perturbed_loss, 6),
            'accepted': accepted,
            'training_count': self._critic_training_count,
            'timestamp': time.time(),
        }}
        return self._last_train_stats

    def _train_step(self):
        \"\"\"4-phase training: world model, imagination, critic, actor. All params from config.\"\"\"
        import random as _rnd
        if not self._get_training_param('enabled'):
            return {{}}

        deadline = time.time() + self._get_training_param('timeout_budget_seconds')
        stats = {{}}
        batch_size = self._get_training_param('batch_size')
        noise_scale = self._get_training_param('noise_scale')
        gamma = self._get_training_param('gamma')
        lam = self._get_training_param('lambda_')

        # ═══ PHASE 1: World Model Update (existing perturbation approach) ═══
        if len(self._obs_buffer) >= batch_size:
            batch = _rnd.sample(list(self._obs_buffer), batch_size)
            total_loss = 0.0
            for emb_t, action_t, emb_next in batch:
                dreamer_input = emb_t @ self._embed_to_dreamer
                dreamer_input = np.clip(np.nan_to_num(dreamer_input, nan=0.0), -10.0, 10.0)
                try:
                    result = self.dreamer_world_model.forward({{'obs': dreamer_input}})
                    predicted = result.get('output', result.get('latent', dreamer_input))
                    predicted = np.asarray(predicted, dtype=np.float32).flatten()[:len(emb_next)]
                    total_loss += float(np.mean((predicted - emb_next) ** 2))
                except Exception:
                    total_loss += 1.0
            baseline_loss = total_loss / len(batch)

            dwm = self.dreamer_world_model
            orig_A = dwm.lora_A.copy()
            orig_B = dwm.lora_B.copy()
            orig_bias = dwm.lora_bias.copy()

            dwm.lora_A = orig_A + np.random.randn(*orig_A.shape).astype(np.float32) * noise_scale
            dwm.lora_B = orig_B + np.random.randn(*orig_B.shape).astype(np.float32) * noise_scale
            dwm.lora_bias = orig_bias + np.random.randn(*orig_bias.shape).astype(np.float32) * noise_scale

            perturbed_loss = 0.0
            for emb_t, action_t, emb_next in batch:
                dreamer_input = emb_t @ self._embed_to_dreamer
                dreamer_input = np.clip(np.nan_to_num(dreamer_input, nan=0.0), -10.0, 10.0)
                try:
                    result = dwm.forward({{'obs': dreamer_input}})
                    predicted = result.get('output', result.get('latent', dreamer_input))
                    predicted = np.asarray(predicted, dtype=np.float32).flatten()[:len(emb_next)]
                    perturbed_loss += float(np.mean((predicted - emb_next) ** 2))
                except Exception:
                    perturbed_loss += 1.0
            perturbed_loss = perturbed_loss / len(batch)

            if perturbed_loss >= baseline_loss:
                dwm.lora_A = orig_A
                dwm.lora_B = orig_B
                dwm.lora_bias = orig_bias
                wm_accepted = False
            else:
                wm_accepted = True

            self._fitness = max(0.0, 1.0 - min(baseline_loss if not wm_accepted else perturbed_loss, 1.0))
            stats['world_model'] = {{
                'baseline_loss': baseline_loss, 'perturbed_loss': perturbed_loss,
                'accepted': wm_accepted, 'fitness': self._fitness,
            }}

        # Phase 1b: Train reward head
        if hasattr(self, '_reward_head') and len(self._reward_buffer) >= batch_size:
            sample = _rnd.sample(list(self._reward_buffer), batch_size)
            original = self._reward_head.get_params().copy()
            loss_baseline = sum((self._reward_head.forward(evt.latent) - evt.reward) ** 2 for evt in sample) / batch_size
            self._reward_head.set_params(original + np.random.randn(len(original)).astype(np.float32) * noise_scale)
            loss_perturbed = sum((self._reward_head.forward(evt.latent) - evt.reward) ** 2 for evt in sample) / batch_size
            if loss_perturbed >= loss_baseline:
                self._reward_head.set_params(original)

        if time.time() > deadline:
            self._last_train_stats = stats
            self._training_cycles += 1
            return stats

        # ═══ PHASE 2: Imagination Rollout ═══
        imagined_trajectories = []
        horizon = self._dreamer_config['imagination']['horizon']
        if self.dreamer_world_model:
            try:
                trajectories = self.dreamer_world_model.imagine(horizon=horizon)
                for traj in trajectories:
                    processed = []
                    for step in traj:
                        latent = np.concatenate([
                            np.array(step.get('deter', np.zeros(4096))).flatten(),
                            np.array(step.get('stoch', np.zeros(1024))).flatten(),
                        ])[:5120]
                        pred_reward = self._reward_head.forward(latent) if hasattr(self, '_reward_head') else 0.0
                        critic_value = self._critic.forward(latent) if hasattr(self, '_critic') else 0.0
                        processed.append({{
                            'step': step['step'], 'action': step.get('action', 0),
                            'pred_reward': pred_reward, 'critic_value': critic_value,
                            'latent_norm': step.get('latent_norm', 0),
                        }})
                    imagined_trajectories.append(processed)
            except Exception:
                pass

        if time.time() > deadline:
            self._last_train_stats = stats
            self._training_cycles += 1
            return stats

        # ═══ PHASE 3: Critic Update ═══
        if hasattr(self, '_critic') and len(self._reward_buffer) >= batch_size:
            critic_stats = self._train_critic()
            if critic_stats:
                stats['critic'] = critic_stats

        if time.time() > deadline:
            self._last_train_stats = stats
            self._training_cycles += 1
            return stats

        # ═══ PHASE 4: Actor Update (LoRA perturbation via imagination advantage) ═══
        if imagined_trajectories and hasattr(self, '_critic'):
            actor_score_baseline = 0.0
            for traj in imagined_trajectories:
                returns = []
                G = traj[-1]['critic_value']
                for t in reversed(range(len(traj))):
                    r = traj[t]['pred_reward']
                    v_next = traj[t+1]['critic_value'] if t+1 < len(traj) else G
                    G = r + gamma * ((1 - lam) * v_next + lam * G)
                    returns.insert(0, G)
                for t, step in enumerate(traj):
                    actor_score_baseline += returns[t] - step['critic_value']

            dreamer = self.dreamer_world_model
            orig_A = dreamer.lora_A.copy()
            orig_B = dreamer.lora_B.copy()
            orig_bias = dreamer.lora_bias.copy()
            dreamer.lora_A += np.random.randn(*dreamer.lora_A.shape).astype(np.float32) * noise_scale
            dreamer.lora_B += np.random.randn(*dreamer.lora_B.shape).astype(np.float32) * noise_scale
            dreamer.lora_bias += np.random.randn(*dreamer.lora_bias.shape).astype(np.float32) * noise_scale

            try:
                new_trajs = dreamer.imagine(horizon=horizon)
                actor_score_perturbed = 0.0
                for traj in new_trajs:
                    for step in traj:
                        latent = np.concatenate([
                            np.array(step.get('deter', np.zeros(4096))).flatten(),
                            np.array(step.get('stoch', np.zeros(1024))).flatten(),
                        ])[:5120]
                        v = self._critic.forward(latent)
                        r = self._reward_head.forward(latent) if hasattr(self, '_reward_head') else 0.0
                        actor_score_perturbed += r + gamma * v
                if actor_score_perturbed > actor_score_baseline:
                    stats['actor'] = {{'accepted': True, 'improvement': actor_score_perturbed - actor_score_baseline}}
                else:
                    dreamer.lora_A = orig_A
                    dreamer.lora_B = orig_B
                    dreamer.lora_bias = orig_bias
                    stats['actor'] = {{'accepted': False}}
            except Exception:
                dreamer.lora_A = orig_A
                dreamer.lora_B = orig_B
                dreamer.lora_bias = orig_bias

        self._last_train_stats = stats
        self._training_cycles += 1

        # Persist dreamer state after training
        try:
            self._save_dreamer_state()
        except Exception:
            pass

        try:
            if hasattr(self, '_cascade_events') and self._cascade_events is not None:
                self._cascade_events.append(f"train_step: cycle={{self._training_cycles}} phases={{len(stats)}}")
        except Exception:
            pass

        return stats

