from typing import Dict, Any, List, Optional, Callable
from enum import Enum, auto


class ModelType(Enum):
    """Heterogeneous model types for type-aware dispatch."""
    EMBEDDING = auto()      # .encode() → vector (bi-encoder)
    RERANKER = auto()       # .predict() → relevance score (cross-encoder)
    CLASSIFIER = auto()     # .classify() / .predict() → label (ForSequenceClassification, many labels)
    LLM = auto()            # .generate() → text
    VISION = auto()         # .detect() → detections
    RL = auto()             # .act() / .step() → action
    PLANNER = auto()        # .plan() → trajectory
    SLAM = auto()           # .update() + .get_pose() → pose
    CONTROL = auto()        # .control() → motor commands
    SENSOR = auto()         # .fuse() → fused state
    COMMS = auto()          # .send() / .recv() → message
    STATE_MACHINE = auto()  # .tick() → state transition
    ASR = auto()            # .transcribe() → text from audio
    SEQ2SEQ = auto()        # .generate() → text (encoder-decoder)
    GENERIC = auto()        # __call__() → Any
    # infinity-emb sandbox types
    INFINITY_EMBED = auto()     # AsyncEmbeddingEngine.embed() → embeddings
    INFINITY_RERANK = auto()    # Reranking models
    INFINITY_CLASSIFY = auto()  # Classification models
    INFINITY_CLIP = auto()      # CLIP vision-language
    INFINITY_CLAP = auto()      # CLAP audio-language
    # Multimodal understanding
    VLM = auto()                # Vision-Language: .generate(image, prompt) → text
    AUDIO_LLM = auto()          # Audio understanding: .transcribe(audio) → text
    # Generation
    IMAGE_GEN = auto()          # .generate(prompt) → image
    TTS = auto()                # .synthesize(text) → audio
    MUSIC_GEN = auto()          # .generate(prompt) → audio
    VIDEO_GEN = auto()          # .generate(prompt) → video
    # Spatial / 3D
    DEPTH = auto()              # .estimate(image) → depth_map
    POINT_CLOUD = auto()        # .process(points) → features
    NERF = auto()               # .render(pose) → image
    # World models / Embodied
    WORLD_MODEL = auto()        # .imagine(state, action) → next_state
    POLICY = auto()             # .act(obs, goal) → action


def _detect_model_type(model) -> ModelType:
    """Auto-detect model type by inspecting available methods."""
    if model is None:
        return ModelType.GENERIC

    model_class = type(model).__name__.lower()

    # Infinity-emb engines
    if 'asyncembeddingengine' in model_class or 'infinityengine' in model_class:
        model_name = getattr(model, '_model_name_or_path', 
                    getattr(model, 'model_name_or_path', '')).lower()
        if 'rerank' in model_name:
            return ModelType.INFINITY_RERANK
        elif 'clip' in model_name:
            return ModelType.INFINITY_CLIP
        elif 'clap' in model_name:
            return ModelType.INFINITY_CLAP
        elif any(x in model_name for x in ['emotion', 'sentiment', 'classify']):
            return ModelType.INFINITY_CLASSIFY
        return ModelType.INFINITY_EMBED

    # VLM (check before LLM)
    if hasattr(model, 'generate') and hasattr(model, 'process_images'):
        return ModelType.VLM
    if hasattr(model, 'chat') and ('llava' in model_class or 'qwen' in model_class):
        return ModelType.VLM

    # Audio transcription
    if hasattr(model, 'transcribe') and callable(getattr(model, 'transcribe', None)):
        return ModelType.AUDIO_LLM

    # Image generation
    if 'diffusion' in model_class or 'pipeline' in model_class:
        return ModelType.IMAGE_GEN
    if hasattr(model, 'txt2img'):
        return ModelType.IMAGE_GEN

    # TTS
    if hasattr(model, 'synthesize') or hasattr(model, 'tts'):
        return ModelType.TTS

    # Depth
    if 'depth' in model_class or 'midas' in model_class:
        return ModelType.DEPTH

    # World model
    if hasattr(model, 'imagine') and callable(getattr(model, 'imagine', None)):
        return ModelType.WORLD_MODEL

    # Standard types
    if hasattr(model, 'generate') and callable(getattr(model, 'generate', None)):
        return ModelType.LLM
    if hasattr(model, 'encode') and callable(getattr(model, 'encode', None)):
        return ModelType.EMBEDDING
    if hasattr(model, 'act') and callable(getattr(model, 'act', None)):
        return ModelType.RL
    if hasattr(model, 'step') and callable(getattr(model, 'step', None)):
        return ModelType.RL
    if hasattr(model, 'detect') and callable(getattr(model, 'detect', None)):
        return ModelType.VISION
    if hasattr(model, 'plan') and callable(getattr(model, 'plan', None)):
        return ModelType.PLANNER
    if hasattr(model, 'update') and hasattr(model, 'get_pose'):
        return ModelType.SLAM
    if hasattr(model, 'control') and callable(getattr(model, 'control', None)):
        return ModelType.CONTROL
    if hasattr(model, 'fuse') and callable(getattr(model, 'fuse', None)):
        return ModelType.SENSOR
    if hasattr(model, 'send') or hasattr(model, 'recv'):
        return ModelType.COMMS
    if hasattr(model, 'tick') and callable(getattr(model, 'tick', None)):
        return ModelType.STATE_MACHINE
    return ModelType.GENERIC


