class QuineCouncilor:
    """A single councilor slot with evolved adapter weights."""

    def __init__(self, data: dict):
        self.name = data['name']
        self.specialty = data['specialty']
        self.input_dim = data['input_dim']
        self.output_dim = data['output_dim']
        self.adapter_dim = data['adapter_dim']

        # Load evolved adapter weights
        params = np.frombuffer(base64.b64decode(data['params_b64']), dtype=np.float32)
        in_size = self.input_dim * self.adapter_dim
        out_size = self.adapter_dim * self.output_dim

        self.adapter_in = params[:in_size].reshape(self.input_dim, self.adapter_dim)
        self.adapter_out = params[in_size:in_size + out_size].reshape(self.adapter_dim, self.output_dim)
        self.adapter_bias = params[in_size + out_size:]

        self.model = None  # NULL PORT - plug your model here
        self._model_type = ModelType.GENERIC

    def plug_model(self, model) -> 'QuineCouncilor':
        \"\"\"Plug a model into this councilor slot with auto-detection.\"\"\"
        self.model = model
        self._model_type = _detect_model_type(model)
        # Capture artifacts for FelixBag
        self._capture_model_artifacts(model)
        return self

    def _capture_model_artifacts(self, model):
        \"\"\"Try to capture tokenizer/config artifacts from a model.\"\"\"
        try:
            from pathlib import Path
            artifacts = {{}}
            model_path = getattr(model, 'name_or_path', None) or getattr(model, 'model_id', None)
            if model_path and Path(model_path).exists():
                for fname in ['tokenizer.json', 'tokenizer_config.json', 'special_tokens_map.json', 'vocab.json', 'merges.txt']:
                    fpath = Path(model_path) / fname
                    if fpath.exists():
                        artifacts[fname] = fpath.read_text(encoding='utf-8')
                # tokenizer.model (binary)
                tokenizer_model = Path(model_path) / 'tokenizer.model'
                if tokenizer_model.exists():
                    artifacts['tokenizer.model'] = base64.b64encode(tokenizer_model.read_bytes()).decode()
                # generation_config.json
                gen_config = Path(model_path) / 'generation_config.json'
                if gen_config.exists():
                    artifacts['generation_config.json'] = gen_config.read_text(encoding='utf-8')
            if artifacts:
                global _COUNCIL_CAPTURED_ARTIFACTS
                _COUNCIL_CAPTURED_ARTIFACTS[self.name] = artifacts
                print(f"   📦 Captured {{len(artifacts)}} artifacts from {{self.name}}")
        except Exception:
            pass  # Artifacts are optional enrichment

    @property
    def model_type(self) -> ModelType:
        \"\"\"Detected type of plugged model.\"\"\"
        return self._model_type

    def forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        \"\"\"Forward pass: model (if any) → adapter with smart type dispatch.\"\"\"
        if isinstance(inputs, dict):
            x = inputs.get('embedding', inputs.get('input', np.zeros(self.input_dim)))
        else:
            x = inputs

        # Run model if plugged - use type-aware dispatch
        if self.model is not None:
            model_result = _invoke_model(self.model, inputs if isinstance(inputs, dict) else {{'input': inputs}}, self._model_type)

            # Extract embedding-like output for adapter
            if 'error' not in model_result:
                out_val = model_result.get('output')
                if out_val is not None:
                    # For non-embedding types, try to convert to numeric
                    if self._model_type in (ModelType.LLM,):
                        # LLM output is text - hash to embedding
                        if isinstance(out_val, str):
                            text_hash = hash(out_val) % (2**32)
                            x = np.array([float((text_hash >> i) & 0xFF) / 255.0 for i in range(0, 32, 8)] * (self.input_dim // 4 + 1), dtype=np.float32)[:self.input_dim]
                        else:
                            x = np.asarray(out_val, dtype=np.float32).flatten()
                    elif hasattr(out_val, '__iter__') and not isinstance(out_val, str):
                        x = np.asarray(out_val, dtype=np.float32).flatten()
                    elif isinstance(out_val, str) and out_val.startswith('['):
                        # Handle numpy array string representation
                        try:
                            x = np.fromstring(out_val.strip('[]'), sep=' ', dtype=np.float32)
                            if len(x) == 0:
                                x = np.fromstring(out_val.strip('[]'), sep=',', dtype=np.float32)
                        except Exception:
                            x = np.zeros(self.input_dim, dtype=np.float32)
                    elif isinstance(out_val, (int, float)):
                        x = np.array([float(out_val)], dtype=np.float32)
                    else:
                        # Fallback for other types
                        x = np.zeros(self.input_dim, dtype=np.float32)
                    # Store raw model result for downstream access
                    self._last_model_result = model_result

        x = np.asarray(x, dtype=np.float32).flatten()

        # Dimension handling
        if len(x) < self.input_dim:
            x = np.pad(x, (0, self.input_dim - len(x)))
        else:
            x = x[:self.input_dim]

        # Adapter transform
        h = np.tanh(x @ self.adapter_in)
        out = h @ self.adapter_out + self.adapter_bias

        # Confidence from output magnitude
        confidence = float(np.clip(np.linalg.norm(out) / (len(out) + 1e-8), 0, 1))

        result = {{'output': out, 'embedding': out, 'confidence': confidence, 'model_type': self._model_type.name}}

        # Include raw model output for typed access
        if hasattr(self, '_last_model_result'):
            result['model_result'] = self._last_model_result

        return result

    def get_params(self) -> np.ndarray:
        return np.concatenate([self.adapter_in.flatten(), self.adapter_out.flatten(), self.adapter_bias])


