            for i, (out, conf) in enumerate(zip(outputs, confidences)):
                if i < len(self.councilors):
                    name = getattr(self.councilors[i], 'name', f'councilor_{{i}}')
                    plugged = getattr(self.councilors[i], 'model', None) is not None
                else:
                    idx = i - len(self.councilors)
                    name = self.brain_names[idx] if idx < len(self.brain_names) else f'brain_{{idx}}'
                    plugged = True
                deliberation[name] = {{'output': out, 'confidence': conf, 'plugged': plugged}}
            return {{
                'output': consensus,
                'embedding': consensus,
                'n_councilors': len(outputs),
                'consensus_method': self.consensus_method,
                'uncertainty': uncertainty,
                'deliberation': deliberation,
            }}
        else:
            consensus = self._weighted_consensus(outputs, confidences)

        # Build deliberation breakdown for non-bayesian paths
        deliberation = {{}}
        for i, (out, conf) in enumerate(zip(outputs, confidences)):
            if i < len(self.councilors):
                name = getattr(self.councilors[i], 'name', f'councilor_{{i}}')
                plugged = getattr(self.councilors[i], 'model', None) is not None
            else:
                idx = i - len(self.councilors)
                name = self.brain_names[idx] if idx < len(self.brain_names) else f'brain_{{idx}}'
                plugged = True
            deliberation[name] = {{'output': out, 'confidence': conf, 'plugged': plugged}}

        return {{
            'output': consensus,
            'embedding': consensus,
            'n_councilors': len(outputs),
            'consensus_method': self.consensus_method,
            'deliberation': deliberation,
        }}

    def _weighted_consensus(self, outputs: List[np.ndarray], confidences: List[float]) -> np.ndarray:
        \"\"\"Confidence-weighted average.\"\"\"
        total_conf = sum(confidences) + 1e-8
        weights = [c / total_conf for c in confidences]
        return sum(w * np.asarray(o, dtype=np.float32) for w, o in zip(weights, outputs))

    def _majority_consensus(self, outputs: List[np.ndarray]) -> np.ndarray:
        \"\"\"Simple average (uniform weights).\"\"\"
        return np.mean([np.asarray(o, dtype=np.float32) for o in outputs], axis=0)

    def _debate_consensus(self, inputs: Dict, outputs: List[np.ndarray], 
                          confidences: List[float]) -> np.ndarray:
        \"\"\"Iterative refinement through multiple rounds.\"\"\"
        current = self._weighted_consensus(outputs, confidences)
        for _ in range(self.debate_rounds):
            # Re-run with current consensus as context
            inputs_with_context = {{**inputs, 'council_position': current}}
            new_outputs = []
            new_confs = []
            for councilor in self.councilors:
                # Skip empty slots
                if hasattr(councilor, 'model') and councilor.model is None:
                    continue
                result = councilor.forward(inputs_with_context)
                new_outputs.append(result['output'])
                new_confs.append(result['confidence'])
            current = self._weighted_consensus(new_outputs, new_confs)
        return current

    def _adversarial_consensus(self, outputs: List[np.ndarray], 
                               confidences: List[float]) -> np.ndarray:
        \"\"\"Devil's advocate challenges consensus.\"\"\"
        if not outputs:
            return np.zeros(self.config['output_dim'])

        # Weighted consensus first
        consensus = self._weighted_consensus(outputs, confidences)

        # Adversary = lowest confidence councilor
        adversary_idx = int(np.argmin(confidences))
        adversary_out = np.asarray(outputs[adversary_idx], dtype=np.float32)

        # Challenge: opposition vector
        challenge = -0.5 * adversary_out

        # Final: consensus weighted away from challenge
        return 0.8 * consensus + 0.2 * challenge

    def _hierarchical_consensus(self, outputs: List[np.ndarray], 
                                confidences: List[float]) -> np.ndarray:
        \"\"\"Junior proposes, senior judges.\"\"\"
        if not outputs:
            return np.zeros(self.config['output_dim'])

        n = len(outputs)
        if n == 1:
            return np.asarray(outputs[0], dtype=np.float32)

        # Split: first half junior, second half senior
        mid = n // 2
        junior_outputs = outputs[:mid] if mid > 0 else outputs[:1]
        senior_outputs = outputs[mid:] if mid < n else outputs[-1:]

        # Senior votes for best junior proposal
        senior_mean = np.mean([np.asarray(o, dtype=np.float32) for o in senior_outputs], axis=0)

        # Find junior proposal most similar to senior preference
        best_score = -np.inf
        best_junior = np.asarray(junior_outputs[0], dtype=np.float32)
        for jo in junior_outputs:
            jo_arr = np.asarray(jo, dtype=np.float32)
            score = float(np.dot(senior_mean.flatten(), jo_arr.flatten()))
            if score > best_score:
                best_score = score
                best_junior = jo_arr

        return best_junior

    def _bayesian_consensus(self, outputs: List[np.ndarray], 
                            confidences: List[float]) -> tuple:
        \"\"\"Probabilistic aggregation with uncertainty estimation.\"\"\"
        if not outputs:
            return np.zeros(self.config['output_dim']), 1.0

        outputs_array = np.array([np.asarray(o, dtype=np.float32) for o in outputs])
        conf_array = np.array(confidences, dtype=np.float32)

        # Precision-weighted mean (confidences as precisions)
        precisions = conf_array + 1e-8
        weights = precisions / precisions.sum()

        mean = np.sum(outputs_array * weights[:, np.newaxis], axis=0)

        # Uncertainty from councilor disagreement
        variance = np.sum(weights[:, np.newaxis] * (outputs_array - mean)**2, axis=0)
        uncertainty = float(np.mean(np.sqrt(variance)))

        return mean, uncertainty

    def get_merkle_hash(self) -> str:
        return _QUINE_COUNCIL_HASH

    def replicate(self) -> 'QuineCouncilBrain':
        \"\"\"Create exact copy with same evolved weights.\"\"\"
        return QuineCouncilBrain()

    def mutate(self, rate: float = 0.1, scale: float = 0.1) -> 'QuineCouncilBrain':
        \"\"\"Create mutated council - modifies adapter weights in councilors.\"\"\"
        child = self.replicate()
        for councilor in child.councilors:
            params = councilor.get_params()
            mask = np.random.random(params.shape) < rate
            noise = np.random.normal(0, scale, params.shape).astype(np.float32)
            mutated = params + mask * noise
            # Re-apply mutated params
            in_size = councilor.input_dim * councilor.adapter_dim
            out_size = councilor.adapter_dim * councilor.output_dim
            councilor.adapter_in = mutated[:in_size].reshape(councilor.input_dim, councilor.adapter_dim)
            councilor.adapter_out = mutated[in_size:in_size + out_size].reshape(councilor.adapter_dim, councilor.output_dim)
            councilor.adapter_bias = mutated[in_size + out_size:]
        return child

    # ═══════════════════════════════════════════════════════════════════════
    # UNIVERSAL INVOKE: Run text through ALL councilors with type-aware dispatch
    # ═══════════════════════════════════════════════════════════════════════

    def invoke(self, text: str = None, *, embedding: 'np.ndarray' = None,
