        \"\"\"Universal model invocation across all councilors.

        Invokes each plugged model and aggregates results.

        Args:
            text: Text to process
            embedding: Pre-computed embedding
            prompt: Explicit prompt for generation
            documents: Documents for reranking

        Returns:
            dict with:
                - results: list of individual councilor results
                - consensus: aggregated result (for embeddings)
                - type: dominant model type
        \"\"\"
        inputs = {{}}
        if text is not None:
            inputs['text'] = text
            inputs['prompt'] = text
        if embedding is not None:
            inputs['embedding'] = embedding
        if prompt is not None:
            inputs['prompt'] = prompt
        if documents is not None:
            inputs['documents'] = documents

        if not inputs:
            return {{'error': 'No input provided.', 'results': [], 'type': 'none'}}

        results = []
        embeddings = []
        model_types = []

        # Run through all councilors with models
        for councilor in self.councilors:
            if councilor.model is not None:
                result = _invoke_model(councilor.model, inputs, councilor._model_type)
                result['councilor'] = councilor.name
