            dominant_type = Counter(model_types).most_common(1)[0][0]
        else:
            dominant_type = 'none'

        return {{
            'results': results,
            'consensus': consensus,
            'type': dominant_type,
            'n_invoked': len(results)
        }}

    def embed(self, text: str) -> 'np.ndarray':
        \"\"\"Convenience method for embedding text via council consensus.\"\"\"
        result = self.invoke(text=text)
        return result.get('consensus')

    def generate(self, prompt: str) -> list:
        \"\"\"Convenience method for generation (returns all outputs).\"\"\"
