        idx += size

        size = self.hidden_dim
        self.b1 = params[idx:idx + size]
        idx += size

        size = self.hidden_dim * self.output_dim
        self.w2 = params[idx:idx + size].reshape(self.hidden_dim, self.output_dim)
        idx += size

        self.b2 = params[idx:idx + self.output_dim]

