    def capture_model(self, model, source_path: str = None, max_size_mb: int = 2000) -> dict:
        """Capture an external PyTorch model's weights AND artifacts for embedding in quine.

        Captures:
            - Model weights (state_dict)
            - Model config
            - Tokenizer files (tokenizer.json, tokenizer_config.json, special_tokens_map.json)
            - Generation config
            - README/documentation

        Args:
            model: The PyTorch model to capture
            source_path: Original path/model ID for loading artifacts
            max_size_mb: Maximum size limit
        """
        import io
        import torch
        from pathlib import Path

        # Get state dict
        if hasattr(model, 'state_dict'):
            state_dict = model.state_dict()
        else:
            raise ValueError("Model must have state_dict() method")

        # Serialize to bytes
        buffer = io.BytesIO()
        torch.save(state_dict, buffer)
        weights_bytes = buffer.getvalue()

        size_mb = len(weights_bytes) / (1024*1024)
        if size_mb > max_size_mb:
            raise ValueError(f"Model too large: {{size_mb:.1f}}MB > {{max_size_mb}}MB limit")

        # Encode to base64
        self._captured_model_b64 = base64.b64encode(weights_bytes).decode('ascii')
        self._captured_model_class = type(model).__name__
        self._captured_model_source = source_path or ''

        # Save config if available
        if hasattr(model, 'config'):
            try:
                if hasattr(model.config, 'to_dict'):
                    self._captured_model_config = model.config.to_dict()
                else:
