        # ═══════════════════════════════════════════════════════════════
        # CAPTURE ARTIFACTS (tokenizer, readme, generation config)
        # ═══════════════════════════════════════════════════════════════
        self._captured_artifacts = {{}}
        artifacts_captured = []

        if source_path:
            model_dir = Path(source_path)
            if model_dir.exists() and model_dir.is_dir():
