                                content = tf_path.read_bytes()
                                self._captured_artifacts[tf] = base64.b64encode(content).decode('ascii')
                            else:
                                self._captured_artifacts[tf] = tf_path.read_text(encoding='utf-8')
                            artifacts_captured.append(tf)
                        except Exception as e:
                            print(f"   ⚠️ Could not read {{tf}}: {{e}}")

                for extra in ['generation_config.json', 'README.md', 'readme.md', 'model_card.json']:
