        cfg = _QUINE_MLP_CONFIG
        self.input_size = cfg['input_size']
        self.hidden_size = cfg['hidden_size']
        self.output_size = cfg['output_size']
        self.output_keys = cfg['output_keys']

        # Unpack weights using stored dimensions
        h = self.hidden_size
        o = self.output_size
        idx = 0
        self.w1 = self._params[idx:idx + self.input_size * h].reshape(self.input_size, h)
        idx += self.input_size * h
        self.b1 = self._params[idx:idx + h]
        idx += h
        self.w2 = self._params[idx:idx + h * o].reshape(h, o)
        idx += h * o
        self.b2 = self._params[idx:idx + o]

    def forward_minimal(self, x: np.ndarray) -> dict:
        """Pure numpy forward pass."""
        x = np.asarray(x, dtype=np.float32).flatten()

        # Handle dimension mismatch
        if len(x) < self.input_size:
            x = np.pad(x, (0, self.input_size - len(x)))
        else:
            x = x[:self.input_size]

        h = np.tanh(x @ self.w1 + self.b1)
        out = h @ self.w2 + self.b2
        return {{k: float(out[i]) for i, k in enumerate(self.output_keys)}}

    def forward(self, inputs) -> dict:
        """Standard forward interface (wraps forward_minimal)."""
        if isinstance(inputs, dict):
            x = inputs.get('input', inputs.get('x', inputs.get('observation', inputs.get('vector', None))))
            if x is None:
                # Try to extract numeric values from dict
                x = np.array([v for v in inputs.values() if isinstance(v, (int, float, np.number))], dtype=np.float32)
        else:
            x = np.asarray(inputs, dtype=np.float32)
        result = self.forward_minimal(x)
        result['output'] = np.array([result[k] for k in self.output_keys], dtype=np.float32)
        return result

    def get_params(self) -> np.ndarray:
        return self._params.copy()

    def get_merkle_hash(self) -> str:
