    def _write_arcade_capsule_wrapper(self, inner_dir: Path, capsule_module_name: str):
        """Write capsule wrapper that bridges arcade tools to capsule functions.

        Uses run_mcp_server(register_only=True) to get a FastMCP instance with
        ALL @logged_tool functions registered. Then dispatches tool calls through
        the FastMCP tool registry, bypassing the module-level export problem.
        """
        content = f'''"""
CapsuleWrapper - Bridge between Arcade tools and capsule module.

Uses run_mcp_server(register_only=True) to initialize the capsule's full
MCP tool registry without starting a server. All 126+ tools become available
through the FastMCP _tool_manager, which stores the original callable functions.

Architecture:
    Arcade @tool function → _get_capsule().method() → CapsuleWrapper.__getattr__
    → FastMCP _tool_manager.get_tool(name).fn(**kwargs) → original @logged_tool closure
"""
import sys
import json
from pathlib import Path

# Add parent directory to path so we can import sibling capsule module
_parent = Path(__file__).parent.parent.parent
if str(_parent) not in sys.path:
    sys.path.insert(0, str(_parent))

# Import capsule module
try:
    import {capsule_module_name} as _capsule_module
    _CAPSULE_AVAILABLE = True
except ImportError as e:
    _capsule_module = None
    _CAPSULE_AVAILABLE = False
    print(f"Warning: Could not import capsule module: {{e}}")


class CapsuleWrapper:
    """
    Bridge between Arcade tools and the capsule's MCP tool registry.

    On first use, calls run_mcp_server(register_only=True) to create a FastMCP
    instance with all tools registered. Tool calls are dispatched through the
    FastMCP _tool_manager, which holds the original @logged_tool closures with
    full access to the agent, brain, BAG, and all capsule state.
    """

    def __init__(self):
        if not _CAPSULE_AVAILABLE:
            raise RuntimeError("Capsule module not available")
        self._mcp = None
        self._tool_fns = {{}}  # Cache: tool_name -> callable
        self._initialized = False
        self._mode = None  # 'direct' or 'proxy'
        self._capsule_dir = Path(_capsule_module.__file__).parent
        self._inbox = self._capsule_dir / '.mcp_inbox.json'
        self._outbox = self._capsule_dir / '.mcp_outbox.json'

    def _detect_tui(self):
        """Check if TUI is running (state file exists and is recent)."""
        import time as _time
        state_file = self._capsule_dir / '.capsule_state.json'
        if state_file.exists():
            try:
                if _time.time() - state_file.stat().st_mtime < 60:
                    return True
            except Exception:
                pass
        return False

    def _ensure_init(self):
        """Lazy initialization: detect TUI or register tools standalone."""
        if self._initialized:
            return
        self._initialized = True  # Set early to prevent recursion

        if self._detect_tui():
            # TUI is running - route through inbox/outbox IPC (shared agent)
            self._mode = 'proxy'
            print("[CapsuleWrapper] TUI detected - using proxy mode (shared agent)")
        else:
            # No TUI - standalone mode with own agent
            self._mode = 'direct'
            print("[CapsuleWrapper] Standalone mode - initializing own agent")
            try:
                self._mcp = _capsule_module.run_mcp_server(register_only=True)
                if self._mcp and hasattr(self._mcp, '_tool_manager'):
                    for tool_obj in self._mcp._tool_manager._tools.values():
                        self._tool_fns[tool_obj.name] = tool_obj.fn
            except Exception as e:
                print(f"CapsuleWrapper init error: {{e}}")
                import traceback
                traceback.print_exc()

    def _proxy_call(self, tool_name, kwargs):
        """Route tool call through TUI's inbox/outbox IPC (shared agent)."""
        import time as _time
        import uuid
        import tempfile

        req_id = str(uuid.uuid4())[:8]

        # Clear any stale outbox
        if self._outbox.exists():
            try:
                self._outbox.unlink()
            except Exception:
                pass

        # Atomic write to inbox (temp file + rename)
        request = json.dumps({{
            'id': req_id,
            'tool': tool_name,
            'args': kwargs,
            'ts': _time.time()
        }})
        tmp = Path(tempfile.mktemp(dir=self._capsule_dir, suffix='.tmp'))
        tmp.write_text(request, encoding='utf-8')
        tmp.replace(self._inbox)  # Atomic on POSIX and Windows

        # Fast poll for response (50ms intervals, 120s max)
        for _ in range(2400):
            _time.sleep(0.05)
            if self._outbox.exists():
                try:
                    resp = json.loads(self._outbox.read_text(encoding='utf-8'))
                    if resp.get('id') == req_id:
                        self._outbox.unlink()  # Consume response
                        return json.dumps(resp.get('result', {{}}), indent=2, default=str)
                except Exception:
                    pass

        return json.dumps({{'error': 'timeout waiting for TUI response', 'request_id': req_id}})

    def _call_tool(self, name, **kwargs):
        """Call a tool - routes through TUI proxy if active, else direct."""
        self._ensure_init()

        if self._mode == 'proxy':
            return self._proxy_call(name, kwargs)

        fn = self._tool_fns.get(name)
        if fn:
            try:
                return fn(**kwargs)
            except Exception as e:
                return json.dumps({{"error": str(e), "tool": name}})
        # Fallback: try module-level function
        if _capsule_module and hasattr(_capsule_module, name):
            func = getattr(_capsule_module, name)
            if callable(func):
                try:
                    return func(**kwargs)
                except Exception as e:
                    return json.dumps({{"error": str(e), "tool": name}})
        return json.dumps({{"error": f"Tool '{{name}}' not found in registry"}})

    def __getattr__(self, name):
        """Universal dispatch: routes through TUI proxy or direct tool registry."""
        # Skip private/dunder attributes
        if name.startswith('_'):
            raise AttributeError(name)

        self._ensure_init()

        if self._mode == 'proxy':
            # Return a callable that routes through TUI IPC
            def _proxy_fn(**kwargs):
                return self._proxy_call(name, kwargs)
            return _proxy_fn

        # Direct mode: check tool registry first
        fn = self._tool_fns.get(name)
        if fn:
            return fn

        # Fallback: module-level function
        if _capsule_module and hasattr(_capsule_module, name):
            return getattr(_capsule_module, name)

        raise AttributeError(f"Capsule has no tool or function '{{name}}'")


# Global wrapper instance
_wrapper = None

def init_capsule():
    """Initialize and return the capsule wrapper."""
    global _wrapper
    if _wrapper is None:
        _wrapper = CapsuleWrapper()
    return _wrapper

def get_capsule():
    """Get the capsule wrapper, initializing if needed."""
    global _wrapper
    if _wrapper is None:
        _wrapper = CapsuleWrapper()
    return _wrapper
