class RemoteProviderProxy:
    \"\"\"Wraps an OpenAI-compatible HTTP endpoint as a pluggable slot model.

    Allows inference providers (via Pi CLI or any OpenAI-compatible server)
    to occupy a council slot and be invoked identically to local models.
    \"\"\"

    def __init__(self, base_url: str, model_name: str = None, api_key: str = None):
        _base = str(base_url or '').strip().rstrip('/')
        if _base.endswith('/v1'):
            _base = _base[:-3]
        self.base_url = _base
        self.model_name = model_name
        self.api_key = api_key
        self._is_remote_provider = True
        self._limits = {{'context_window': 128000, 'max_output': 4096, 'supports_chat': True}}
        # Detect model type hint from model name for vision/audio models
        _mn = str(model_name or '').lower()
        if any(k in _mn for k in ('vl', 'vision', 'llava', 'paligemma', 'blip')):
            self._model_type_hint = 'VLM'
        elif any(k in _mn for k in ('whisper', 'asr', 'speech-recognition')):
            self._model_type_hint = 'ASR'
        elif any(k in _mn for k in ('bark', 'tts', 'speecht5', 'text-to-speech')):
            self._model_type_hint = 'TTS'
        else:
            self._model_type_hint = 'LLM'
        self._task_provider_hint = None
        try:
            import urllib.parse as _urlparse
            _parts = [p for p in _urlparse.urlparse(self.base_url).path.split('/') if p]
            if 'hf-router' in _parts:
                _idx = _parts.index('hf-router')
                if _idx + 1 < len(_parts) and _parts[_idx + 1] != 'v1':
                    self._task_provider_hint = _parts[_idx + 1]
                else:
                    self._task_provider_hint = 'hf-inference'
        except Exception:
            self._task_provider_hint = None

        # Auto-detect available models at the endpoint
        if not self.model_name:
            try:
                import urllib.request
                req = urllib.request.Request(self.base_url + '/v1/models')
                if self.api_key:
                    req.add_header('Authorization', 'Bearer ' + self.api_key)
                with urllib.request.urlopen(req, timeout=5) as resp:
                    data = json.loads(resp.read().decode())
                    models = data.get('data', [])
                    if models:
                        self.model_name = models[0].get('id', 'remote')
            except Exception:
                self.model_name = 'remote'

    def _request_headers(self, content_type=None, accept='application/json'):
        headers = {{'Accept': accept}}
        if content_type:
            headers['Content-Type'] = content_type
        if self.api_key:
            headers['Authorization'] = 'Bearer ' + self.api_key
        return headers

    def _detect_audio_format(self, audio_bytes):
        if not audio_bytes:
            return 'bin'
        if audio_bytes[:4] == b'RIFF':
            return 'wav'
        if audio_bytes[:4] == b'fLaC':
            return 'flac'
        if audio_bytes[:4] == b'OggS':
            return 'ogg'
        if audio_bytes[:3] == b'ID3':
            return 'mp3'
        if len(audio_bytes) > 1 and audio_bytes[0] == 0xFF and (audio_bytes[1] & 0xE0) == 0xE0:
            return 'mp3'
        return 'bin'

    def _wrap_audio_bytes(self, audio_bytes):
        import base64
        _fmt = self._detect_audio_format(audio_bytes)
        return {{
            "audio_base64": base64.b64encode(audio_bytes).decode('ascii'),
            "format": _fmt,
            "bytes": len(audio_bytes),
        }}

    def generate(self, prompt=None, text=None, messages=None, max_tokens=256, max_new_tokens=None, temperature=0.7, **kwargs):
        \"\"\"Generate text via the remote endpoint.\"\"\"
        import urllib.request

        if messages is None:
            messages = kwargs.get('messages')

        _prompt = prompt if prompt is not None else text
        if _prompt is None and isinstance(messages, list) and messages:
            _prompt = messages[-1].get('content', '')
        if _prompt is None:
            _prompt = ''

        # Build messages from prompt/messages
        if isinstance(messages, list) and messages:
            _msgs = messages
        elif isinstance(_prompt, list):
            _msgs = _prompt
        else:
            _msgs = [{{"role": "user", "content": str(_prompt)}}]

        _max_tokens = max_new_tokens if max_new_tokens is not None else max_tokens
        if kwargs.get('max_tokens') is not None:
            _max_tokens = kwargs.get('max_tokens')
        if kwargs.get('max_new_tokens') is not None:
            _max_tokens = kwargs.get('max_new_tokens')
        try:
            _max_tokens = int(_max_tokens)
        except Exception:
            _max_tokens = 256

        _temperature = kwargs.get('temperature', temperature)

        payload = json.dumps({{
            "model": self.model_name or "default",
            "messages": _msgs,
            "max_tokens": _max_tokens,
            "temperature": _temperature
        }})

        req = urllib.request.Request(
            self.base_url + '/v1/chat/completions',
            data=payload.encode('utf-8'),
            headers={{
                'Content-Type': 'application/json',
                **({{'Authorization': 'Bearer ' + self.api_key}} if self.api_key else {{}})
            }},
            method='POST'
        )

        try:
            with urllib.request.urlopen(req, timeout=120) as resp:
                data = json.loads(resp.read().decode())
                choices = data.get('choices', [])
                if choices:
                    msg = choices[0].get('message', {{}})
                    return msg.get('content', '')
                return ''
        except Exception as e:
            return f"[Remote provider error: {{e}}]"

    def synthesize(self, text, **kwargs):
        \"\"\"Synthesize audio via remote provider or Hugging Face task fallback.\"\"\"
        import os
