                    _extra_body = {{}}
                _extra_body.setdefault('voice', _voice)
            client = InferenceClient(provider=_provider, api_key=_hf_token)
            audio_bytes = client.text_to_speech(_text, model=self.model_name, extra_body=_extra_body)
            return self._wrap_audio_bytes(audio_bytes)
        except Exception as e:
            if _last_error is not None:
                raise RuntimeError(f"Remote TTS failed via {{self.base_url}}: {{_last_error}}; HF task fallback failed: {{e}}")
            raise RuntimeError(f"Remote TTS failed via {{self.base_url}}: {{e}}")

    def encode(self, text):
        \"\"\"Generate embeddings via the remote endpoint.\"\"\"
        import urllib.request
        import numpy as np

        payload = json.dumps({{
            "model": self.model_name or "default",
            "input": text if isinstance(text, str) else str(text)
        }})

        req = urllib.request.Request(
            self.base_url + '/v1/embeddings',
            data=payload.encode('utf-8'),
            headers={{
                'Content-Type': 'application/json',
                **({{'Authorization': 'Bearer ' + self.api_key}} if self.api_key else {{}})
            }},
            method='POST'
        )

        try:
            with urllib.request.urlopen(req, timeout=30) as resp:
                data = json.loads(resp.read().decode())
                emb_data = data.get('data', [])
                if emb_data:
                    return np.array(emb_data[0].get('embedding', []), dtype=np.float32)
                raise RuntimeError('Remote provider returned no embedding data')
        except Exception as e:
            raise RuntimeError(f"Remote embedding failed: {{e}}")

    def __repr__(self):
        return f"RemoteProviderProxy({{self.base_url}}, model={{self.model_name}})"


# ═══════════════════════════════════════════════════════════════
# SMART MODEL LOADING - Universal HuggingFace Model Loader
# ═══════════════════════════════════════════════════════════════

def _load_model_smart(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"
    Smart model loader that handles all model types.

    FIRST detects model type from HuggingFace Hub config, then routes to correct loader.
    This prevents SentenceTransformer from hanging on LLMs.

    Returns:
        (model, model_type_str, error_msg)
        - model: The loaded model (possibly wrapped for unified interface)
        - model_type_str: 'EMBEDDING', 'LLM', 'SEQ2SEQ', 'VISION', 'HF', or 'ERROR'
        - error_msg: None on success, error string on failure
    \"\"\"
    import os
    import sys

    # ========== REMOTE PROVIDER DETECTION ==========
    # If model_id is a URL, create a RemoteProviderProxy instead of downloading
    if model_id.startswith('http://') or model_id.startswith('https://'):
        if verbose:
            print(f"🌐 Connecting to remote provider: {{model_id}}")
            sys.stdout.flush()

        # Extract optional API key from URL fragment or env
        _api_key = None
        _base_url = model_id
        _model_name = None

        # Support format: http://host:port?model=name&key=sk-xxx
        if '?' in _base_url:
            _url_base, _qs = _base_url.split('?', 1)
            _base_url = _url_base
            try:
                import urllib.parse as _urlparse
                for _pk, _pv in _urlparse.parse_qsl(_qs, keep_blank_values=True):
                    if _pk == 'key':
                        _api_key = _urlparse.unquote_plus(_pv)
                    elif _pk == 'model':
                        _model_name = _urlparse.unquote_plus(_pv)
            except Exception:
                for _param in _qs.split('&'):
                    if '=' in _param:
                        _pk, _pv = _param.split('=', 1)
                        if _pk == 'key':
                            _api_key = _pv
                        elif _pk == 'model':
                            _model_name = _pv

        # Also check env vars
        if not _api_key:
            _api_key = os.environ.get('REMOTE_PROVIDER_KEY', os.environ.get('OPENAI_API_KEY'))

        try:
            proxy = RemoteProviderProxy(_base_url, model_name=_model_name, api_key=_api_key)
            if verbose:
                print(f"   ✅ Connected: {{proxy.model_name}} at {{proxy.base_url}}")
                sys.stdout.flush()
            return proxy, 'LLM', None
        except Exception as e:
            return None, 'ERROR', f"Failed to connect to remote provider: {{e}}"

    # Normalize path if local
    if os.path.exists(model_id):
        # Check for HF cache structure and resolve
        if 'snapshots' in model_id:
            # Already a snapshot path, try to use it
            pass
        elif model_id.endswith('blobs'):
            return None, 'ERROR', "Cannot load from blobs/ directly. Use model ID: plug microsoft/phi-2"

    # Enable HuggingFace download progress bars
    os.environ['HF_HUB_DISABLE_PROGRESS_BARS'] = '0'
    os.environ['TRANSFORMERS_VERBOSITY'] = 'warning'

    if verbose:
        print(f"🔍 Detecting model type for {{model_id}}...")
        sys.stdout.flush()

    # ========== DETECT MODEL TYPE FIRST ==========
    # This prevents SentenceTransformer from hanging on LLMs
    detected_type = None

    try:
        from huggingface_hub import model_info
        info = model_info(model_id)

        # Check pipeline_tag first (most reliable)
        pipeline_tag = getattr(info, 'pipeline_tag', None) or ''
        pipeline_tag = pipeline_tag.lower()

        if pipeline_tag in ('sentence-similarity', 'feature-extraction', 'text-embedding'):
            detected_type = 'EMBEDDING'
        elif pipeline_tag in ('text-generation', 'conversational', 'text2text-generation'):
            if pipeline_tag == 'text2text-generation':
                detected_type = 'SEQ2SEQ'
            else:
                detected_type = 'LLM'
        elif pipeline_tag in ('image-classification', 'object-detection', 'image-segmentation'):
            detected_type = 'VISION'
        elif pipeline_tag in ('zero-shot-classification', 'text-classification'):
            detected_type = 'CLASSIFIER'
        elif pipeline_tag in ('image-text-to-text', 'visual-question-answering', 'image-to-text'):
            detected_type = 'VLM'
        elif pipeline_tag in ('summarization', 'translation'):
            detected_type = 'SEQ2SEQ'
        elif pipeline_tag in ('automatic-speech-recognition',):
            detected_type = 'ASR'
        elif pipeline_tag in ('text-to-speech',):
            detected_type = 'TTS'
        elif pipeline_tag in ('audio-classification',):
            detected_type = 'AUDIO_CLASSIFIER'

        # Fallback: check model architecture from tags
        if detected_type is None and hasattr(info, 'tags') and info.tags:
            tags_lower = [t.lower() for t in info.tags]
            if any('causal' in t or 'gpt' in t or 'llama' in t or 'phi' in t or 'mistral' in t for t in tags_lower):
                detected_type = 'LLM'
            elif any('t5' in t or 'bart' in t or 'seq2seq' in t for t in tags_lower):
                detected_type = 'SEQ2SEQ'
            elif any('sentence' in t or 'embed' in t or 'sbert' in t for t in tags_lower):
                detected_type = 'EMBEDDING'
            elif any('whisper' in t or 'speech' in t or 'asr' in t for t in tags_lower):
                detected_type = 'ASR'

        if verbose and detected_type:
            print(f"   Detected: {{detected_type}} (pipeline: {{pipeline_tag or 'N/A'}})")
            sys.stdout.flush()

    except Exception as e:
        # Can't detect - will try in order but skip SentenceTransformer for safety
        if verbose:
            print(f"   Could not detect type from Hub: {{e}}")
            sys.stdout.flush()

    # ========== REFINE FROM ACTUAL CONFIG.JSON ==========
    # Hub pipeline_tag is a rough approximation. The actual config.json on disk
    # has architectures, label counts, and model_type — ground truth.
    _local_cfg = None
    try:
        _cfg_path = None
        if os.path.isdir(model_id):
            _cfg_path = os.path.join(model_id, 'config.json')
        else:
            try:
                from huggingface_hub import hf_hub_download
                _cfg_path = hf_hub_download(model_id, 'config.json')
            except Exception:
                pass

        if _cfg_path and os.path.isfile(_cfg_path):
            import json
            with open(_cfg_path, 'r') as _f:
                _local_cfg = json.loads(_f.read())
    except Exception:
        pass

    if _local_cfg:
        _archs = _local_cfg.get('architectures', [])
        _arch_str = ' '.join(_archs).lower()
        _id2label = _local_cfg.get('id2label', {{}})
        _model_type_name = str(_local_cfg.get('model_type', '') or '').lower()

        # ForSequenceClassification: label count distinguishes reranker from classifier
        # Rerankers have 1 label (relevance score), classifiers have many (categories)
        if 'forsequenceclassification' in _arch_str:
            if len(_id2label) <= 2:
                detected_type = 'RERANKER'
            else:
                detected_type = 'CLASSIFIER'
        elif _model_type_name == 'whisper' or 'whisper' in _arch_str:
            detected_type = 'ASR'
        elif any(_tag in _model_type_name for _tag in ('bark', 'speecht5', 'vits', 'parler_tts', 'xtts')):
            detected_type = 'TTS'
        # VLM: vision_config + LLM backbone (InternVL, H2OVL, LLaVA, Qwen-VL, etc.)
        # Must check BEFORE forcausallm since many VLMs register as CausalLM
        # Require companion LLM/text config to avoid misclassifying pure vision encoders
        elif (_local_cfg.get('vision_config') and (_local_cfg.get('llm_config') or _local_cfg.get('text_config') or _local_cfg.get('language_config'))) or any(k in _model_type_name for k in ('h2ovl', 'internvl', 'llava', 'qwen2_vl', 'paligemma', 'blip')):
            detected_type = 'VLM'
        # ForCausalLM → LLM (override any Hub confusion)
        elif 'forcausallm' in _arch_str:
            detected_type = 'LLM'
        # Seq2Seq architectures
        elif detected_type not in ('ASR', 'TTS') and ('forseq2seqlm' in _arch_str or 'forconditionalgeneration' in _arch_str):
            detected_type = 'SEQ2SEQ'

        if verbose and detected_type:
            print(f"   Refined from config.json: {{detected_type}} (arch: {{_archs[0] if _archs else 'N/A'}}, labels: {{len(_id2label)}})")
            sys.stdout.flush()

    if verbose:
        print(f"⬇️  Loading {{model_id}}...")
        sys.stdout.flush()

    # ========== ROUTE TO CORRECT LOADER ==========

    # If detected as LLM, skip SentenceTransformer entirely (it hangs on LLMs)
    if detected_type == 'LLM':
        return _load_as_llm(model_id, verbose)
    elif detected_type == 'SEQ2SEQ':
        result = _load_as_seq2seq(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)  # fallback
    elif detected_type == 'VISION':
        return _load_as_vision(model_id, verbose)
    elif detected_type == 'RERANKER':
        result = _load_as_reranker(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)
    elif detected_type == 'EMBEDDING':
        result = _load_as_embedding(model_id, verbose)
        if result[1] != 'ERROR':
            return result
        return _load_as_generic(model_id, verbose)
    elif detected_type == 'CLASSIFIER':
        return _load_as_classifier(model_id, verbose)
    elif detected_type == 'VLM':
        return _load_as_vlm(model_id, verbose)
    elif detected_type == 'ASR':
        return _load_as_asr(model_id, verbose)
    elif detected_type == 'TTS':
        return _load_as_tts(model_id, verbose)
    elif detected_type == 'AUDIO_CLASSIFIER':
        return _load_as_generic(model_id, verbose)

    # Unknown type - try in safe order (LLM first since SentenceTransformer hangs on LLMs)
    if verbose:
        print(f"   Unknown type, trying loaders in order...")
        sys.stdout.flush()

    # Try LLM first (safer, won't hang)
    result = _load_as_llm(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as LLM")
        return result

    # Try Seq2Seq
    result = _load_as_seq2seq(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as SEQ2SEQ")
        return result

    # Try embedding (only after LLM fails - less likely to hang)
    result = _load_as_embedding(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as EMBEDDING")
        return result

    # Try vision
    result = _load_as_vision(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as VISION")
        return result

    # Try VLM
    result = _load_as_vlm(model_id, verbose=False)
    if result[1] != 'ERROR':
        if verbose:
            print(f"✓ Loaded as VLM")
        return result

    # Final fallback: generic
    return _load_as_generic(model_id, verbose)


def _load_as_asr(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as automatic speech recognition (Whisper, etc.).\"\"\"
    try:
        import torch
        from transformers import WhisperForConditionalGeneration, WhisperProcessor
        _device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        _dtype = torch.float16 if _device.type == 'cuda' else torch.float32
        m = WhisperForConditionalGeneration.from_pretrained(model_id, torch_dtype=_dtype, low_cpu_mem_usage=True)
        m.to(_device)
        m.eval()
        p = WhisperProcessor.from_pretrained(model_id)

        class ASRWrapper:
            def __init__(self, model, processor, device, dtype):
                self.model = model
                self.processor = processor
                self.device = device
                self.dtype = dtype
                self._model_type_hint = 'ASR'
                self._is_remote_provider = False
                self._limits = {{'context_length': 448, 'max_gen_tokens': 128}}
            def transcribe(self, audio_path, language=None, **kwargs):
                import os
                import numpy as np
                def _load_audio_file(path):
                    _path = str(path)
                    _ext = os.path.splitext(_path)[1].lower().lstrip('.')
                    if _ext in ('wav', 'wave'):
                        import scipy.io.wavfile as wav
                        return wav.read(_path)
                    try:
                        import av
                    except Exception as _av_import_err:
                        raise RuntimeError("Audio format '%s' requires PyAV for decode" % (_ext or 'unknown')) from _av_import_err
                    _chunks = []
                    _sample_rate = None
                    with av.open(_path) as _container:
                        _stream = next((s for s in _container.streams if s.type == 'audio'), None)
                        if _stream is None:
                            raise RuntimeError("No audio stream found in '%s'" % _path)
                        for _frame in _container.decode(_stream):
                            _sample_rate = int(getattr(_frame, 'sample_rate', 0) or _sample_rate or 16000)
                            _arr = np.asarray(_frame.to_ndarray())
                            if _arr.ndim > 1:
                                _arr = _arr.mean(axis=0)
                            _chunks.append(_arr.astype(np.float32, copy=False))
                    if not _chunks:
                        raise RuntimeError("No decodable audio frames found in '%s'" % _path)
                    return int(_sample_rate or 16000), np.concatenate(_chunks, axis=0)
                sr, audio = _load_audio_file(audio_path)
                if np.issubdtype(audio.dtype, np.integer):
                    _scale = max(abs(np.iinfo(audio.dtype).min), abs(np.iinfo(audio.dtype).max)) or 1
                    audio = audio.astype(np.float32) / float(_scale)
                else:
                    audio = audio.astype(np.float32)
                    _peak = float(np.max(np.abs(audio))) if audio.size else 0.0
                    if _peak > 1.5:
                        audio = audio / _peak
                if len(audio.shape) > 1:
                    audio = audio.mean(axis=1)
                if sr != 16000:
                    from scipy.signal import resample
                    audio = resample(audio, int(len(audio) * 16000 / sr))
                audio = np.asarray(audio, dtype=np.float32)
                inputs = self.processor(audio, sampling_rate=16000, return_tensors="pt")
                input_features = inputs.input_features.to(device=self.device, dtype=self.dtype)
                gen_kwargs = {{'max_new_tokens': min(int(kwargs.get('max_new_tokens', 128) or 128), 128)}}
                if language:
                    try:
                        gen_kwargs['forced_decoder_ids'] = self.processor.get_decoder_prompt_ids(language=language, task=kwargs.get('task', 'transcribe'))
                    except Exception:
                        pass
                with torch.no_grad():
                    predicted_ids = self.model.generate(input_features, **gen_kwargs)
                return self.processor.batch_decode(predicted_ids, skip_special_tokens=True)[0].strip()
            def __call__(self, x):
                return self.transcribe(str(x))

        model = ASRWrapper(m, p, _device, _dtype)
        if verbose:
            print(f"✓ Loaded as WhisperForConditionalGeneration (ASR)")
        return model, 'ASR', None
    except Exception as e:
        return None, 'ERROR', str(e)


def _load_as_tts(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as text-to-speech (Bark, SpeechT5, etc.).\"\"\"
    try:
        import torch
        from transformers import pipeline
        _has_cuda = torch.cuda.is_available()
        _device = 0 if _has_cuda else -1
        _dtype = torch.float16 if _has_cuda else torch.float32
        pipe = pipeline("text-to-speech", model=model_id, device=_device, torch_dtype=_dtype)

        class TTSWrapper:
            def __init__(self, pipe):
                self.pipe = pipe
                self._model_type_hint = 'TTS'
                self._is_remote_provider = False
                self._limits = {{'context_length': 600, 'max_gen_tokens': 0}}
            def synthesize(self, text, **kwargs):
                import base64, io, struct
                result = self.pipe(text)
                audio = result["audio"]
                sr = result["sampling_rate"]
                import numpy as np
                if isinstance(audio, np.ndarray):
                    audio_int16 = (audio * 32767).astype(np.int16) if audio.dtype == np.float32 else audio
                    buf = io.BytesIO()
                    buf.write(b'RIFF')
                    buf.write(struct.pack('<I', 0))
                    buf.write(b'WAVE')
                    buf.write(b'fmt ')
                    buf.write(struct.pack('<IHHIIHH', 16, 1, 1, sr, sr * 2, 2, 16))
                    buf.write(b'data')
                    raw = audio_int16.tobytes()
                    buf.write(struct.pack('<I', len(raw)))
                    buf.write(raw)
                    total = buf.tell() - 8
                    buf.seek(4)
                    buf.write(struct.pack('<I', total))
                    return {{"audio_base64": base64.b64encode(buf.getvalue()).decode(), "sampling_rate": sr, "format": "wav"}}
                return {{"error": "Unexpected audio output type"}}
            def __call__(self, x):
                return self.synthesize(str(x))

        model = TTSWrapper(pipe)
        if verbose:
            print(f"✓ Loaded as TTS pipeline (TTS)")
        return model, 'TTS', None
    except Exception as e:
        return None, 'ERROR', str(e)


