def _load_as_llm(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as CausalLM (GPT, LLaMA, Phi, etc.)\"\"\"
    try:
        import torch
        from transformers import AutoModelForCausalLM, AutoTokenizer
        m = AutoModelForCausalLM.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        t = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)

        # Wrap with .generate() interface
        class LLMWrapper:
            def __init__(self, model, tokenizer):
                self.model = model
                self.tokenizer = tokenizer
                self._model_type_hint = 'LLM'
                self._limits = _read_model_limits(model, tokenizer)
            def generate(self, prompt=None, text=None, max_new_tokens=None, max_length=None, **kwargs):
                # Accept both 'prompt' and 'text' for compatibility
                prompt = prompt or text
                if prompt is None:
                    raise ValueError("Must provide 'prompt' or 'text' argument")
                # Apply chat template for instruct models
                if hasattr(self.tokenizer, 'apply_chat_template') and getattr(self.tokenizer, 'chat_template', None):
                    messages = [{{'role': 'user', 'content': prompt}}]
                    input_text = self.tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
                else:
                    input_text = prompt
                # Use model's actual context window for input sizing
                _ctx = self._limits.get('context_length', 4096)
                inputs = self.tokenizer(input_text, return_tensors='pt', truncation=True, max_length=_ctx)
                if hasattr(self.model, 'device'):
                    inputs = {{k: v.to(self.model.device) for k, v in inputs.items()}}
                # Use model's reported generation limits
                gen_kwargs = {{'pad_token_id': self.tokenizer.eos_token_id, **kwargs}}
                if max_length is not None:
                    gen_kwargs['max_length'] = max_length
                else:
                    _gen = max_new_tokens or self._limits.get('max_gen_tokens', 256)
                    gen_kwargs['max_new_tokens'] = _gen
                input_len = inputs['input_ids'].shape[-1]
                outputs = self.model.generate(**inputs, **gen_kwargs)
                return self.tokenizer.decode(outputs[0][input_len:], skip_special_tokens=True)
            def __call__(self, x):
                return self.generate(prompt=str(x))

        model = LLMWrapper(m, t)
        if verbose:
            print(f"✓ Loaded as AutoModelForCausalLM (LLM)")
        return model, 'LLM', None
    except Exception as e:
        return None, 'ERROR', str(e)


