def _load_as_vision(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as Vision classifier.\"\"\"
    try:
        import torch
        from transformers import AutoModelForImageClassification, AutoFeatureExtractor
        m = AutoModelForImageClassification.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        try:
            fe = AutoFeatureExtractor.from_pretrained(model_id, trust_remote_code=True)
        except Exception:
            fe = None

        class VisionWrapper:
            def __init__(self, model, feature_extractor):
                self.model = model
                self.feature_extractor = feature_extractor
                self._model_type_hint = 'VISION'
            def detect(self, image):
                if self.feature_extractor:
                    inputs = self.feature_extractor(images=image, return_tensors='pt')
                    outputs = self.model(**inputs)
                    return outputs.logits.softmax(dim=-1).tolist()
                return self.model(image)
            def __call__(self, x):
                return self.detect(x)

        model = VisionWrapper(m, fe)
        if verbose:
            print(f"✓ Loaded as AutoModelForImageClassification (VISION)")
        return model, 'VISION', None
    except Exception as e:
        return None, 'ERROR', str(e)


def _load_as_vlm(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as Vision-Language Model (LLaVA, PaliGemma, Qwen-VL, BLIP-2, H2OVL, etc.)\"\"\"
    try:
        import torch
        from transformers import AutoProcessor
        # Try AutoModelForVision2Seq first (standard VLM auto class)
        try:
            from transformers import AutoModelForVision2Seq
            m = AutoModelForVision2Seq.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        except Exception:
            try:
                # Fallback: some VLMs (InternVL, H2OVL) register as AutoModelForCausalLM
                from transformers import AutoModelForCausalLM
                m = AutoModelForCausalLM.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
            except Exception:
                # Final fallback: AutoModel with trust_remote_code for custom architectures
                from transformers import AutoModel
                m = AutoModel.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        try:
            p = AutoProcessor.from_pretrained(model_id, trust_remote_code=True)
        except Exception:
            p = None

        class VLMWrapper:
            def __init__(self, model, processor):
                self.model = model
                self.processor = processor
                self._model_type_hint = 'VLM'
                self._limits = _read_model_limits(model)
            def generate(self, text=None, image=None, max_new_tokens=None, **kwargs):
                if self.processor and image is not None:
                    inputs = self.processor(text=text, images=image, return_tensors='pt')
                elif self.processor and text is not None:
                    inputs = self.processor(text=text, return_tensors='pt')
                else:
                    raise ValueError("Must provide text or image input")
                _gen = max_new_tokens or self._limits.get('max_gen_tokens', 256)
                outputs = self.model.generate(**inputs, max_new_tokens=_gen, **kwargs)
                if self.processor:
                    return self.processor.batch_decode(outputs, skip_special_tokens=True)[0]
                return outputs
            def __call__(self, x):
                return self.generate(text=str(x))

        model = VLMWrapper(m, p)
        if verbose:
            print(f"✓ Loaded as VLM")
        return model, 'VLM', None
    except Exception as e:
        return None, 'ERROR', str(e)


def _load_as_generic(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as generic AutoModel (fallback).\"\"\"
    try:
        import torch
        from transformers import AutoModel, AutoTokenizer
        m = AutoModel.from_pretrained(model_id, trust_remote_code=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        try:
            t = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)
        except Exception:
            t = None

        class GenericWrapper:
            def __init__(self, model, tokenizer):
                self.model = model
                self.tokenizer = tokenizer
                self._model_type_hint = 'GENERIC'
                self._limits = _read_model_limits(model, tokenizer)
            def encode(self, text):
                if self.tokenizer:
                    _ctx = self._limits.get('context_length', 512)
                    inputs = self.tokenizer(text, return_tensors='pt', truncation=True, max_length=_ctx)
                    with __import__('torch').no_grad():
                        out = self.model(**inputs)
                    if hasattr(out, 'pooler_output') and out.pooler_output is not None:
                        return out.pooler_output[0].numpy()
                    return out.last_hidden_state.mean(dim=1)[0].numpy()
                return self.model(text)
            def __call__(self, x):
                return self.encode(str(x))

        model = GenericWrapper(m, t)
        if verbose:
            print(f"✓ Loaded as AutoModel (HF)")
        return model, 'HF', None
    except Exception as e:
        return None, 'ERROR', str(e)


def _load_as_classifier(model_id: str, verbose: bool = True) -> tuple:
    \"\"\"Load model as sequence classifier (distilbert, roberta, bart-mnli, etc.)\"\"\"
    try:
        import torch
        from transformers import AutoModelForSequenceClassification, AutoTokenizer
        m = AutoModelForSequenceClassification.from_pretrained(model_id, trust_remote_code=True, ignore_mismatched_sizes=True, torch_dtype=torch.float16, low_cpu_mem_usage=True)
        t = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)

        class ClassifierWrapper:
            def __init__(self, model, tokenizer):
                self.model = model
                self.tokenizer = tokenizer
                self._model_type_hint = 'CLASSIFIER'
                self._limits = _read_model_limits(model, tokenizer)
            def classify(self, text, **kwargs):
                _ctx = self._limits.get('context_length', 512)
                inputs = self.tokenizer(text, return_tensors='pt', truncation=True, max_length=_ctx)
                import torch
                with torch.no_grad():
                    outputs = self.model(**inputs)
                probs = outputs.logits.softmax(dim=-1).tolist()[0]
                labels = self.model.config.id2label if hasattr(self.model.config, 'id2label') else {{}}
                return [{{'label': labels.get(i, str(i)), 'score': p}} for i, p in enumerate(probs)]
            def __call__(self, x):
                return self.classify(str(x))
            predict = classify

        model = ClassifierWrapper(m, t)
        if verbose:
            print(f"✓ Loaded as AutoModelForSequenceClassification (CLASSIFIER)")
        return model, 'CLASSIFIER', None
    except Exception as e:
        return None, 'ERROR', str(e)


# ═══════════════════════════════════════════════════════════════
# MODEL TYPE DETECTION - For smart routing of heterogeneous models
# ═══════════════════════════════════════════════════════════════

from enum import Enum

class ModelType(Enum):
    \"\"\"Type of model for smart routing.\"\"\"
    GENERIC = "generic"
    LLM = "llm"
    EMBEDDING = "embedding"
    VISION = "vision"
    RL = "rl"
    PLANNER = "planner"
    SLAM = "slam"
    CONTROL = "control"
    SENSOR = "sensor"
    COMMS = "comms"
    STATE_MACHINE = "state_machine"
    ASR = "asr"
    CLASSIFIER = "classifier"
    SEQ2SEQ = "seq2seq"
    # infinity-emb sandbox types
    INFINITY_EMBED = "infinity_embed"
    INFINITY_RERANK = "infinity_rerank"
    INFINITY_CLASSIFY = "infinity_classify"
    INFINITY_CLIP = "infinity_clip"
    INFINITY_CLAP = "infinity_clap"
    # Multimodal understanding
    VLM = "vlm"                     # Vision-Language: .generate(image, prompt) → text
    AUDIO_LLM = "audio_llm"         # Audio understanding: .transcribe(audio) → text
    # Generation
    IMAGE_GEN = "image_gen"         # .generate(prompt) → image
    TTS = "tts"                     # .synthesize(text) → audio
    MUSIC_GEN = "music_gen"         # .generate(prompt) → audio
    VIDEO_GEN = "video_gen"         # .generate(prompt) → video
    # Spatial / 3D
    DEPTH = "depth"                 # .estimate(image) → depth_map
    POINT_CLOUD = "point_cloud"     # .process(points) → features
    NERF = "nerf"                   # .render(pose) → image
    # World models / Embodied
    WORLD_MODEL = "world_model"     # .imagine(state, action) → next_state
    POLICY = "policy"               # .act(obs, goal) → action


def _detect_model_type_runtime(model) -> ModelType:
    \"\"\"
    Unified model type detection.

    Priority order:
    1. _model_type_hint — set by loader from actual config.json / Hub metadata
    2. Class identity — type(model).__name__ from the library that created it
    3. infinity-emb engine detection
    4. hasattr capability probing (last resort for unknown models)
    \"\"\"
    if model is None:
        return ModelType.GENERIC

    # === PRIORITY 1: Loader hint (ground truth from config.json / Hub API) ===
    hint = getattr(model, '_model_type_hint', None)
    if hint:
        _hint_map = {{
            'LLM': ModelType.LLM,
            'EMBEDDING': ModelType.EMBEDDING,
            'RERANKER': ModelType.RERANKER,
            'CLASSIFIER': ModelType.CLASSIFIER,
            'SEQ2SEQ': ModelType.LLM,
            'ASR': ModelType.ASR,
            'TTS': ModelType.TTS,
            'VISION': ModelType.VISION,
            'VLM': ModelType.VLM,
            'AUDIO_LLM': ModelType.AUDIO_LLM,
            'GENERIC': ModelType.GENERIC,
        }}
        mapped = _hint_map.get(hint)
        if mapped is not None:
            return mapped

    # === PRIORITY 2: Class identity ===
    model_class = type(model).__name__
    model_class_lower = model_class.lower()
    if model_class == 'CrossEncoder':
        return ModelType.RERANKER

    # infinity-emb engines
    if 'asyncembeddingengine' in model_class_lower or 'infinityengine' in model_class_lower:
        model_name = getattr(model, '_model_name_or_path',
                    getattr(model, 'model_name_or_path', '')).lower()
        if 'rerank' in model_name:
            return ModelType.INFINITY_RERANK
        elif 'clip' in model_name:
            return ModelType.INFINITY_CLIP
        elif 'clap' in model_name:
            return ModelType.INFINITY_CLAP
        elif any(x in model_name for x in ['emotion', 'sentiment', 'classify']):
            return ModelType.INFINITY_CLASSIFY
        return ModelType.INFINITY_EMBED

    # VLM (check before LLM)
    if hasattr(model, 'generate') and hasattr(model, 'process_images'):
        return ModelType.VLM
    if hasattr(model, 'chat') and ('llava' in model_class_lower or 'qwen' in model_class_lower):
        return ModelType.VLM

    # Audio transcription
    if hasattr(model, 'transcribe') and callable(getattr(model, 'transcribe', None)):
        return ModelType.ASR

    # Image generation
    if 'diffusion' in model_class_lower or 'pipeline' in model_class_lower:
        return ModelType.IMAGE_GEN
    if hasattr(model, 'txt2img'):
        return ModelType.IMAGE_GEN

    # TTS
    if hasattr(model, 'synthesize') or hasattr(model, 'tts'):
        return ModelType.TTS

    # Depth
    if 'depth' in model_class_lower or 'midas' in model_class_lower:
        return ModelType.DEPTH

    # World model
    if hasattr(model, 'imagine') and callable(getattr(model, 'imagine', None)):
        return ModelType.WORLD_MODEL

    # === PRIORITY 3: hasattr capability probing (last resort) ===
    if hasattr(model, 'generate') and callable(getattr(model, 'generate', None)):
        return ModelType.LLM
    if hasattr(model, 'encode') and callable(getattr(model, 'encode', None)):
        return ModelType.EMBEDDING
    if hasattr(model, 'act') and callable(getattr(model, 'act', None)):
        return ModelType.RL
    if hasattr(model, 'step') and callable(getattr(model, 'step', None)):
        return ModelType.RL
    if hasattr(model, 'detect') and callable(getattr(model, 'detect', None)):
        return ModelType.VISION
    if hasattr(model, 'plan') and callable(getattr(model, 'plan', None)):
        return ModelType.PLANNER
    if hasattr(model, 'update') and hasattr(model, 'get_pose'):
        return ModelType.SLAM
    if hasattr(model, 'control') and callable(getattr(model, 'control', None)):
        return ModelType.CONTROL
    if hasattr(model, 'fuse') and callable(getattr(model, 'fuse', None)):
        return ModelType.SENSOR
    if hasattr(model, 'send') or hasattr(model, 'recv'):
        return ModelType.COMMS
    if hasattr(model, 'tick') and callable(getattr(model, 'tick', None)):
        return ModelType.STATE_MACHINE
    return ModelType.GENERIC


def _read_model_limits(model, tokenizer=None):
    \"\"\"Read actual token limits from a plugged model's config.
    Returns only what the model actually reports — no guessing.
    \"\"\"
    limits = {{}}
    raw = getattr(model, 'model', model)

    # Context window from model config (most authoritative sources first)
    if hasattr(raw, 'config'):
        cfg = raw.config
        for attr in ('max_position_embeddings', 'n_positions', 'max_sequence_length'):
            val = getattr(cfg, attr, None)
            if val and isinstance(val, int) and val > 0:
                limits['context_length'] = val
                break
        ml = getattr(cfg, 'max_length', None)
        if ml and isinstance(ml, int) and ml > 0:
            limits.setdefault('context_length', ml)

    # Tokenizer-level limit (skip absurd 2^63 default some tokenizers report)
    if tokenizer:
        tml = getattr(tokenizer, 'model_max_length', None)
        if tml and isinstance(tml, int) and 0 < tml < 1_000_000:
            limits.setdefault('context_length', tml)
            limits['tokenizer_max_length'] = tml

    # Generation config (the model's own shipped defaults)
    if hasattr(raw, 'generation_config'):
        gc = raw.generation_config
        mnt = getattr(gc, 'max_new_tokens', None)
        if mnt and isinstance(mnt, int) and mnt > 0:
            limits['max_gen_tokens'] = mnt
        gml = getattr(gc, 'max_length', None)
        if gml and isinstance(gml, int) and gml > 0:
            limits['gen_max_length'] = gml

    return limits


def _invoke_model(model, inputs, model_type):
    \"\"\"
    Type-aware model invocation with smart output normalization.
    \"\"\"
    if not isinstance(inputs, dict):
        inputs = {{'input': inputs}}

    text = inputs.get('text', inputs.get('prompt', ''))
    obs = inputs.get('observation', inputs.get('obs', inputs.get('input', None)))
    image = inputs.get('image', inputs.get('frame', None))
    state = inputs.get('state', None)
    goal = inputs.get('goal', inputs.get('target', None))
    sensors = inputs.get('sensors', inputs.get('readings', None))
    context = inputs.get('context', inputs)

    try:
        if model_type == ModelType.LLM:
            prompt = text or (str(obs) if obs is not None else "")
            gen_kwargs = {{k: v for k, v in inputs.items() if k in ['max_tokens', 'temperature', 'top_p', 'stop', 'max_length']}}
            result = model.generate(prompt, **gen_kwargs) if gen_kwargs else model.generate(prompt)
            if isinstance(result, str):
                return {{'output': result, 'text': result, 'type': 'llm'}}
            elif isinstance(result, dict):
                result['type'] = 'llm'
                return result
            return {{'output': result, 'text': str(result), 'type': 'llm'}}

        elif model_type == ModelType.EMBEDDING:
            to_encode = text if text else obs
            result = model.encode(to_encode)
            vec = np.asarray(result)
            return {{'output': vec, 'embedding': vec, 'type': 'embedding'}}

        elif model_type == ModelType.RERANKER:
            # Cross-encoder reranker — needs sentence pairs, can't process arbitrary input
            query = text if text else (str(obs) if obs is not None else "")
            docs = inputs.get('documents', inputs.get('docs', []))
            if docs and query and hasattr(model, 'predict'):
                pairs = [[query, d] for d in docs]
                scores = model.predict(pairs)
                if hasattr(scores, 'tolist'):
                    scores = scores.tolist()
                return {{'output': scores, 'scores': scores, 'type': 'reranker'}}
            # No documents provided — hash-based fallback
            import hashlib
            h = hashlib.sha256(query.encode()).digest()
            hash_bytes = np.frombuffer(h, dtype=np.uint8).astype(np.float32)
            vec = (hash_bytes / 255.0) * 2 - 1
            vec = np.tile(vec, 12)[:384]
            return {{'output': vec, 'embedding': vec, 'type': 'reranker_hash'}}

        elif model_type == ModelType.CLASSIFIER:
            # Classifier — needs text input, not numpy arrays
            to_classify = text if text else (str(obs) if obs is not None else "")
            if hasattr(model, 'classify'):
                result = model.classify(to_classify)
            elif hasattr(model, 'predict'):
                result = model.predict([to_classify])
            elif callable(model):
                result = model(to_classify)
            else:
                return {{'output': None, 'error': 'Classifier has no predict/classify method', 'type': 'classifier'}}
            return {{'output': result, 'classification': str(result), 'type': 'classifier'}}

        elif model_type == ModelType.RL:
            if hasattr(model, 'act'):
                action = model.act(obs)
            else:
                action = model.step(obs)
            return {{'output': action, 'action': action, 'type': 'rl'}}

        elif model_type == ModelType.VISION:
            img = image if image is not None else obs
            if hasattr(model, 'detect'):
                detections = model.detect(img)
            else:
                detections = model(img)
            return {{'output': detections, 'detections': detections, 'type': 'vision'}}

        elif model_type == ModelType.PLANNER:
            trajectory = model.plan(state, goal)
            return {{'output': trajectory, 'trajectory': trajectory, 'type': 'planner'}}

        elif model_type == ModelType.SLAM:
            model.update(sensors if sensors is not None else obs)
            pose = model.get_pose()
            return {{'output': pose, 'pose': pose, 'type': 'slam'}}

        elif model_type == ModelType.CONTROL:
            target = goal if goal is not None else inputs.get('setpoint')
            commands = model.control(state, target)
            return {{'output': commands, 'commands': commands, 'type': 'control'}}

        elif model_type == ModelType.SENSOR:
            fused = model.fuse(sensors if sensors is not None else obs)
            return {{'output': fused, 'fused_state': fused, 'type': 'sensor'}}

        elif model_type == ModelType.COMMS:
            if 'message' in inputs and hasattr(model, 'send'):
                result = model.send(inputs['message'])
                return {{'output': result, 'sent': True, 'type': 'comms'}}
            elif hasattr(model, 'recv'):
                message = model.recv()
                return {{'output': message, 'message': message, 'type': 'comms'}}
            return {{'output': None, 'type': 'comms'}}

        elif model_type == ModelType.STATE_MACHINE:
            transition = model.tick(context)
            return {{'output': transition, 'state': transition, 'type': 'state_machine'}}

        elif model_type == ModelType.INFINITY_EMBED:
            to_embed = text if text else (str(obs) if obs is not None else "")
            if isinstance(to_embed, str):
                to_embed = [to_embed]

            async def _do_embed():
                embeddings, usage = await model.embed(sentences=to_embed)
                return np.array(embeddings)

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_embed())
                        vec = future.result(timeout=60)
                else:
                    vec = loop.run_until_complete(_do_embed())
            except RuntimeError:
                vec = asyncio.run(_do_embed())

            return {{'output': vec, 'embedding': vec, 'type': 'infinity_embed'}}

        elif model_type == ModelType.INFINITY_RERANK:
            query = text if text else str(obs)
            docs = inputs.get('documents', inputs.get('docs', []))
            if not docs:
                return {{'output': None, 'error': 'No documents provided for reranking', 'type': 'infinity_rerank'}}

            async def _do_rerank():
                rankings, usage = await model.rerank(query=query, docs=docs)
                return rankings

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_rerank())
                        rankings = future.result(timeout=60)
                else:
                    rankings = loop.run_until_complete(_do_rerank())
            except RuntimeError:
                rankings = asyncio.run(_do_rerank())

            return {{'output': rankings, 'rankings': rankings, 'type': 'infinity_rerank'}}

        elif model_type == ModelType.INFINITY_CLASSIFY:
            to_classify = text if text else (str(obs) if obs is not None else "")
            if isinstance(to_classify, str):
                to_classify = [to_classify]

            async def _do_classify():
                predictions, usage = await model.classify(sentences=to_classify)
                return predictions

            try:
                loop = asyncio.get_event_loop()
                if loop.is_running():
                    import concurrent.futures
                    with concurrent.futures.ThreadPoolExecutor() as pool:
                        future = pool.submit(asyncio.run, _do_classify())
                        predictions = future.result(timeout=60)
                else:
                    predictions = loop.run_until_complete(_do_classify())
            except RuntimeError:
                predictions = asyncio.run(_do_classify())

            return {{'output': predictions, 'predictions': predictions, 'type': 'infinity_classify'}}

        else:
            # Generic fallback
            if hasattr(model, '__call__'):
                result = model(inputs)
                return {{'output': result, 'type': 'generic'}}
            return {{'output': None, 'error': f'Unknown model type: {{model_type}}', 'type': 'unknown'}}

    except Exception as e:
        return {{'output': None, 'error': str(e), 'type': 'error'}}


