# HOLD SYSTEM - Inference-Level Halt (requires cascade-lattice)
# ═══════════════════════════════════════════════════════════════

_HOLD_AVAILABLE = False
_HOLD_SYSTEM = None

try:
    from cascade import sdk_observe, genesis, CausationGraph
    _HAS_CASCADE = True
except ImportError:
    _HAS_CASCADE = False

# HOLD state
class _HoldState:
    def __init__(self):
        self.enabled = True
        self.timeout = 30.0  # Default timeout
        self.current_hold = None
        self.resolution_event = threading.Event()
        self.resolution = None
        self.listeners = []
        self.hold_count = 0
        self.override_count = 0
        self.last_merkle = None
        self._brain_ref = None

    def yield_point(self, action_probs, value, observation, brain_id, blocking=True):
        \"\"\"Yield at decision point for potential human intervention.\"\"\"
        import time

        hold_id = hashlib.sha256(f"{{brain_id}}:{{time.time()}}".encode()).hexdigest()[:16]
        merkle = hashlib.sha256(f"{{hold_id}}:{{action_probs.tobytes().hex()}}".encode()).hexdigest()[:16]

        hold_point = {{
            'id': hold_id,
            'merkle': merkle,
            'action_probs': action_probs,
            'ai_choice': int(np.argmax(action_probs)),
            'ai_confidence': float(np.max(action_probs)),
            'value': value,
            'observation': observation,
            'brain_id': brain_id,
            'timestamp': time.time(),
            'parent_merkle': self.last_merkle,
        }}

        # Observe hold point
        if _HAS_CASCADE:
            sdk_observe(brain_id, observation, {{'event': 'hold_point', **hold_point}})

        self.hold_count += 1

        if not blocking or not self.enabled:
            return {{'action': hold_point['ai_choice'], 'was_override': False, 'hold_id': hold_id}}

        self.current_hold = hold_point
        self.resolution_event.clear()
        self.resolution = None

        # Notify listeners
        for listener in self.listeners:
            try:
                listener(hold_point)
            except Exception:
                pass

        print(f"\\n🛑 HOLD #{{self.hold_count}} | Merkle: {{merkle}}")
        print(f"   AI: action {{hold_point['ai_choice']}} ({{hold_point['ai_confidence']:.1%}})")
        print(f"   Value: {{value:.4f}}")
        print(f"   Waiting... (timeout: {{self.timeout}}s)")

        start = time.time()
        resolved = self.resolution_event.wait(timeout=self.timeout)
        duration = time.time() - start

        if resolved and self.resolution:
            result = self.resolution
        else:
            result = {{'action': hold_point['ai_choice'], 'was_override': False, 'source': 'timeout'}}
            print(f"⏱️ Timeout - accepting AI choice")

        result['hold_id'] = hold_id
        result['duration'] = duration

        # Observe resolution
        if _HAS_CASCADE:
            sdk_observe(brain_id, hold_point, {{'event': 'hold_resolution', **result}})

        # Reward capture for dreamer training
        if self._brain_ref and hasattr(self._brain_ref, '_capture_reward'):
            try:
                was_override = result.get('was_override', False)
                source_key = 'hold_override' if was_override else 'hold_accept'
                self._brain_ref._capture_reward(
                    source_key=source_key,
                    action=self.current_hold.get('ai_choice', 0) if self.current_hold else 0,
                    event_id=f"hold_{{self.hold_count}}",
                    metadata={{
                        'was_override': was_override,
                        'source': result.get('source', 'unknown'),
                    }},
                )
            except Exception:
                pass

        self.last_merkle = hashlib.sha256(f"{{merkle}}:{{result['action']}}".encode()).hexdigest()[:16]
        self.current_hold = None

        return result

    def resolve(self, action, source='human'):
        \"\"\"Resolve current hold with action.\"\"\"
        if not self.current_hold:
            return
        was_override = (action != self.current_hold['ai_choice'])
        if was_override:
            self.override_count += 1
        self.resolution = {{'action': action, 'was_override': was_override, 'source': source}}
        print(f"✓ Resolved: action={{action}}, override={{was_override}}")
        self.resolution_event.set()

    def accept(self):
        \"\"\"Accept AI choice.\"\"\"
        if self.current_hold:
            self.resolve(self.current_hold['ai_choice'], source='accept')

    def override(self, action):
        \"\"\"Override with different action.\"\"\"
        self.resolve(action, source='human')

