# ═══════════════════════════════════════════════════════════════
# FELIX BAG - Infinite Vectorized Storage
# ═══════════════════════════════════════════════════════════════
# Like Felix the Cat's magic bag - endless storage for artifacts,
# documents, code, models. Items are vectorized for semantic search
# and can be summoned, updated, or utilized at will.

_FELIX_BAG = {{}}  # Populated at runtime, persisted on export

class FelixBag:
    \"\"\"
    Infinite vectorized storage - Felix the Cat's magic bag.

    Capabilities:
    - Induct: Take any document/file/artifact and store it
    - Catalog: Browse all stored items with semantic search
    - Summon: Retrieve an item by name or similarity
    - Pocket: Quickly stash current context
    - Update: Modify an existing item
    - Materialize: Export an item back to filesystem

    Storage format per item:
    {{
        'name': str,           # Human-readable name
        'type': str,           # 'document', 'code', 'model', 'artifact', 'state'
        'embedding': list,     # 384-dim vector for semantic search
        'content': str,        # Base64 gzipped content
        'metadata': dict,      # Created, modified, tags, etc.
        'version': int,        # Version counter
    }}
    \"\"\"

    # CLASS-LEVEL SHARED EMBEDDER - All bags share the capsule's embedding model
    _shared_embedder = None
    _shared_embedder_source = None

    def __init__(self, storage: dict = None, brain=None):
        self._bag = storage if storage else {{}}
        self._brain_ref = brain  # Optional reference to capsule brain for embeddings

    @classmethod
    def set_shared_embedder(cls, embedder, source: str = 'external'):
        \"\"\"
        Set a shared embedding model for all FelixBag instances.

        This allows the bag to reuse the capsule's existing embedder
        instead of loading a duplicate model into memory.

        Args:
            embedder: A SentenceTransformer or compatible model with .encode()
            source: Description of where this embedder came from
        \"\"\"
        cls._shared_embedder = embedder
        cls._shared_embedder_source = source

    def _get_embedder(self):
        \"\"\"
        Get embedding model, prioritizing shared/brain embedders.

        Priority order:
        1. Class-level shared embedder (set by capsule brain)
        2. Brain reference's embed model (if provided)
        3. Load from _EMBEDDING_MODEL (capsule's baked-in model)
        4. Fallback to hash-based pseudo-embeddings
        \"\"\"
        # 1. Check class-level shared embedder
        if FelixBag._shared_embedder is not None:
            return FelixBag._shared_embedder

        # 2. Check if we have a brain reference with embedder
        if self._brain_ref is not None:
            if hasattr(self._brain_ref, 'embedding_foundation') and self._brain_ref.embedding_foundation is not None:
                FelixBag._shared_embedder = self._brain_ref.embedding_foundation
                FelixBag._shared_embedder_source = 'brain.embedding_foundation'
                return FelixBag._shared_embedder
            if hasattr(self._brain_ref, '_embed_model') and self._brain_ref._embed_model is not None:
                FelixBag._shared_embedder = self._brain_ref._embed_model
                FelixBag._shared_embedder_source = 'brain._embed_model'
                return FelixBag._shared_embedder
            # Check councilors for a loaded model
            if hasattr(self._brain_ref, 'councilors'):
                for c in self._brain_ref.councilors:
                    model = getattr(c, 'model', None)
                    if model is not None and hasattr(model, 'encode'):
                        FelixBag._shared_embedder = model
                        FelixBag._shared_embedder_source = f'councilor:{{getattr(c, "name", "?")}}'
                        return FelixBag._shared_embedder

        # 3. Load from capsule's _EMBEDDING_MODEL (only if explicitly set)
        # Skip this if brain is a Scarecrow/Council with null port - don't auto-download
        try:
            # Check if _EMBEDDING_MODEL exists in globals
            embedding_model = globals().get('_EMBEDDING_MODEL', None)
            # Only load if it's a real model ID (not None, not empty)
            # Accept both full paths (org/model) and short aliases (all-MiniLM-L6-v2)
            if embedding_model and isinstance(embedding_model, str) and len(embedding_model) > 3:
                # Check if we should skip auto-load (Scarecrow/Council with no model plugged)
                if self._brain_ref is not None:
                    brain_type = getattr(self._brain_ref, '__class__', type(None)).__name__
                    if 'Scarecrow' in brain_type or 'Council' in brain_type:
                        # Check if any slot has a model
                        members = getattr(self._brain_ref, 'all_members', getattr(self._brain_ref, 'councilors', []))
                        has_model = any(getattr(m, 'model', None) is not None for m in members)
                        if not has_model:
                            # No model plugged - don't auto-download, use hash
                            return 'hash'
                from sentence_transformers import SentenceTransformer
                FelixBag._shared_embedder = SentenceTransformer(embedding_model)
                FelixBag._shared_embedder_source = f'_EMBEDDING_MODEL:{{embedding_model}}'
                return FelixBag._shared_embedder
        except Exception:
            pass

        # 4. Fallback to hash-based pseudo-embedding
        return 'hash'

    def _embed(self, text: str) -> list:
        \"\"\"Generate embedding for text using shared embedder.\"\"\"
        embedder = self._get_embedder()
        if embedder == 'hash':
            # Pseudo-embedding from hash (384 dims to match real embeddings)
            import hashlib
            h = hashlib.sha384(text.encode()).digest()
            return [float(b) / 255.0 for b in h]
        else:
            vec = embedder.encode(text, convert_to_numpy=True)
            return vec.tolist()

    def get_embedder_info(self) -> dict:
        \"\"\"Get info about current embedding source.\"\"\"
        embedder = self._get_embedder()
        return {{
            'source': FelixBag._shared_embedder_source or ('hash' if embedder == 'hash' else 'unknown'),
            'type': 'hash' if embedder == 'hash' else type(embedder).__name__,
            'shared': FelixBag._shared_embedder is not None,
            'dim': 384 if embedder == 'hash' else (embedder.get_sentence_embedding_dimension() if hasattr(embedder, 'get_sentence_embedding_dimension') else 'unknown'),
        }}

    def _compress(self, content: str) -> str:
        \"\"\"Compress and encode content.\"\"\"
        import gzip, base64
        data = gzip.compress(content.encode('utf-8'))
        return base64.b64encode(data).decode('ascii')

    def _decompress(self, encoded: str) -> str:
        \"\"\"Decode and decompress content.\"\"\"
        import gzip, base64
        data = base64.b64decode(encoded.encode('ascii'))
        return gzip.decompress(data).decode('utf-8')

    def induct(self, name: str, content: str, item_type: str = 'document', 
               tags: list = None, preview: str = None) -> str:
        \"\"\"
        Induct an item into the bag.

        Args:
            name: Human-readable identifier
            content: The actual content (text, code, etc.)
            item_type: 'document', 'code', 'model', 'artifact', 'state'
            tags: Optional list of tags for filtering
            preview: Optional preview text (first N chars if not provided)

        Returns:
            Item ID
        \"\"\"
        import hashlib
        from datetime import datetime

        # Stable identity by NAME (not content length) so edits version in-place.
        _existing_id = None
        _existing_item = None
        for _iid, _item in self._bag.items():
            if str(_item.get('name', '')) == str(name):
                _existing_id = _iid
                _existing_item = _item
                break

        if _existing_id:
            item_id = _existing_id
            version = int((_existing_item or {{}}).get('version', 0) or 0) + 1
            _created_ts = ((_existing_item or {{}}).get('metadata', {{}}) or {{}}).get('created')
            _existing_tags = ((_existing_item or {{}}).get('metadata', {{}}) or {{}}).get('tags', [])
        else:
            item_id = hashlib.md5(str(name).encode()).hexdigest()[:12]
            # Handle rare hash collision on different names.
            _salt = 1
            while item_id in self._bag and str(self._bag[item_id].get('name', '')) != str(name):
                item_id = hashlib.md5(f"{{name}}:{{_salt}}".encode()).hexdigest()[:12]
                _salt += 1
            version = 1
            _created_ts = datetime.now().isoformat()
            _existing_tags = []

        # Generate embedding from content (or preview for large items)
        embed_text = preview if preview else content[:2000]
        embedding = self._embed(embed_text)

        self._bag[item_id] = {{
            'id': item_id,
            'name': name,
            'type': item_type,
            'embedding': embedding,
            'content': self._compress(content),
            'preview': (preview or content[:200]).replace('\\n', ' '),
            'metadata': {{
                'created': _created_ts,
                'modified': datetime.now().isoformat(),
                'tags': tags if tags is not None else _existing_tags,
                'size': len(content),
                'lines': content.count('\\n') + 1,
            }},
            'version': version,
        }}

        # Log to Rerun if available
        try:
            import rerun as rr
            rr.log("bag/ops", rr.TextLog(f"📥 INDUCT: {{name}} ({{item_type}}, {{len(content)}}b)", level=rr.TextLogLevel.INFO))
            rr.log("bag/size", rr.Scalars([len(self._bag)]))
            # Log type distribution
            type_counts = {{}}
            for item in self._bag.values():
                t = item.get('type', 'unknown')
                type_counts[t] = type_counts.get(t, 0) + 1
            rr.log("bag/type_counts", rr.BarChart(list(type_counts.values())))

            # Full bag state visualization
            _log_bag_state(self)
        except Exception:
            pass

        return item_id

    def induct_file(self, path: str, tags: list = None) -> str:
        \"\"\"Induct a file from the filesystem.\"\"\"
        from pathlib import Path
        p = Path(path)
        if not p.exists():
            raise FileNotFoundError(f"File not found: {{path}}")

        content = p.read_text(encoding='utf-8', errors='replace')

        # Determine type from extension
        ext = p.suffix.lower()
        type_map = {{
            '.py': 'code', '.js': 'code', '.ts': 'code', '.rs': 'code',
            '.md': 'document', '.txt': 'document', '.rst': 'document',
            '.json': 'artifact', '.yaml': 'artifact', '.toml': 'artifact',
            '.pt': 'model', '.onnx': 'model', '.pkl': 'model',
        }}
        item_type = type_map.get(ext, 'artifact')

        return self.induct(
            name=p.name,
            content=content,
            item_type=item_type,
            tags=(tags or []) + [ext[1:] if ext else 'unknown'],
            preview=f"{{p.name}} ({{len(content)}} bytes)"
        )

    def summon(self, query: str = None, item_id: str = None, name: str = None) -> dict:
        \"\"\"
        Summon an item from the bag.

        Args:
            query: Semantic search query
            item_id: Exact ID lookup
            name: Exact name lookup

        Returns:
            Item dict with decompressed content
        \"\"\"
        if item_id and item_id in self._bag:
            item = self._bag[item_id].copy()
            item['content'] = self._decompress(item['content'])
            return item

        if name:
            for iid, item in self._bag.items():
                if item['name'] == name:
                    result = item.copy()
                    result['content'] = self._decompress(item['content'])
                    return result

        if query:
            # Semantic search
            query_vec = self._embed(query)
            best_id, best_score = None, -1
            for iid, item in self._bag.items():
                score = self._cosine_sim(query_vec, item['embedding'])
                if score > best_score:
                    best_score = score
                    best_id = iid

            if best_id:
                result = self._bag[best_id].copy()
                result['content'] = self._decompress(result['content'])
                result['_similarity'] = best_score
                # Log to Rerun
                try:
                    import rerun as rr
                    rr.log("bag/ops", rr.TextLog(f"📤 SUMMON: {{result['name']}} (sim={{best_score:.3f}})", level=rr.TextLogLevel.INFO))
                except Exception:
                    pass
                return result

        return None

    def search(self, query: str, top_k: int = 5) -> list:
        \"\"\"Search bag by semantic similarity. Returns list of (id, name, score, preview).\"\"\"
        query_vec = self._embed(query)
        results = []
        for iid, item in self._bag.items():
            score = self._cosine_sim(query_vec, item['embedding'])
            results.append((iid, item['name'], score, item['preview'], item['type']))
        results.sort(key=lambda x: x[2], reverse=True)
        return results[:top_k]

    def _cosine_sim(self, a: list, b: list) -> float:
        \"\"\"Cosine similarity between two vectors.\"\"\"
        import math
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(x * x for x in b))
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

    def catalog(self, filter_type: str = None, filter_tag: str = None) -> list:
        \"\"\"
        List all items in the bag.

        Returns list of (id, name, type, preview, size, version)
        \"\"\"
        results = []
        for iid, item in self._bag.items():
            if filter_type and item['type'] != filter_type:
                continue
            if filter_tag and filter_tag not in item['metadata'].get('tags', []):
                continue
            results.append((
                iid,
                item['name'],
                item['type'],
                item['preview'][:50],
                item['metadata']['size'],
                item['version'],
            ))

        # Log bag state for visualization
        try:
            _log_bag_state(self)
        except Exception:
            pass

        return sorted(results, key=lambda x: str(x[1]))

    def list(self) -> list:
        \"\"\"Alias for catalog() - returns list of item IDs.\"\"\"
        return [iid for iid, *_ in self.catalog()]

    def get(self, key: str) -> str:
        \"\"\"Get an item's decompressed content by name or ID.\"\"\"
        import gzip, base64
        # Try by ID first
        if key in self._bag:
            content = self._bag[key]['content']
            try:
                return gzip.decompress(base64.b64decode(content)).decode('utf-8')
            except Exception:
                return content

        # Try by name, preferring newest/highest-version match.
        _best = None
        _best_ver = -1
        _best_mod = ""
        for _iid, item in self._bag.items():
            if str(item.get('name', '')) != str(key):
                continue
            _ver = int(item.get('version', 0) or 0)
            _mod = str((item.get('metadata', {{}}) or {{}}).get('modified', '') or '')
            if _best is None or _ver > _best_ver or (_ver == _best_ver and _mod > _best_mod):
                _best = item
                _best_ver = _ver
                _best_mod = _mod
        if _best is not None:
            content = _best.get('content', '')
            try:
                return gzip.decompress(base64.b64decode(content)).decode('utf-8')
            except Exception:
                return content
        return None

    def materialize(self, item_id: str, output_path: str = None) -> str:
        \"\"\"
        Materialize an item back to the filesystem.

        Args:
            item_id: ID of item to materialize
            output_path: Where to write (defaults to item name)

        Returns:
            Path where item was written
        \"\"\"
        from pathlib import Path

        if item_id not in self._bag:
            raise KeyError(f"Item not found: {{item_id}}")

        item = self._bag[item_id]
        content = self._decompress(item['content'])

        out = Path(output_path) if output_path else Path(item['name'])
        out.write_text(content, encoding='utf-8')

        return str(out)

    def forget(self, item_id: str = '', pattern: str = None):
        \"\"\"Remove item(s) from the bag. Single key or prefix pattern.

        Args:
            item_id: Single key to remove
            pattern: Prefix pattern (e.g. 'workflow_exec:*') for bulk delete

        Returns:
            bool for single key, int count for pattern
        \"\"\"
        if pattern:
            prefix = pattern.rstrip('*')
            targets = [k for k, item in list(self._bag.items()) if item.get('name', '').startswith(prefix) or k.startswith(prefix)]
            for k in targets:
                del self._bag[k]
            return len(targets)
        if item_id:
            if item_id in self._bag:
                del self._bag[item_id]
                return True
            # Fallback: delete by human-readable name.
            _name_hits = [k for k, item in list(self._bag.items()) if str(item.get('name', '')) == str(item_id)]
            for k in _name_hits:
                del self._bag[k]
            if _name_hits:
                return True
        return False

    def update(self, item_id: str, new_content: str) -> bool:
        \"\"\"Update an existing item's content.\"\"\"
        if item_id not in self._bag:
            return False

        item = self._bag[item_id]
        return self.induct(
            name=item['name'],
            content=new_content,
            item_type=item['type'],
            tags=item['metadata'].get('tags'),
        )

    def stats(self) -> dict:
        \"\"\"Get bag statistics.\"\"\"
        if not self._bag:
            return {{'items': 0, 'total_size': 0, 'types': {{}}}}

        types = {{}}
        total_size = 0
        for item in self._bag.values():
            t = item['type']
            types[t] = types.get(t, 0) + 1
            total_size += item['metadata']['size']

        return {{
            'items': len(self._bag),
            'total_size': total_size,
            'types': types,
        }}

    def export_bag(self) -> str:
        \"\"\"Export bag as base64 compressed JSON.\"\"\"
        import json, gzip, base64
        data = json.dumps(self._bag)
        compressed = gzip.compress(data.encode('utf-8'))
        return base64.b64encode(compressed).decode('ascii')

    @classmethod
    def import_bag(cls, encoded: str) -> 'FelixBag':
        \"\"\"Import bag from base64 compressed JSON.\"\"\"
        import json, gzip, base64
        compressed = base64.b64decode(encoded.encode('ascii'))
        data = gzip.decompress(compressed).decode('utf-8')
        storage = json.loads(data)
        return cls(storage)

    def merge_bag(self, other: 'FelixBag') -> int:
        \"\"\"Merge another bag into this one. Returns count of new items.\"\"\"
        count = 0
        for iid, item in other._bag.items():
            if iid not in self._bag:
                self._bag[iid] = item
                count += 1
            else:
                # Keep newer version
                if item['version'] > self._bag[iid]['version']:
                    self._bag[iid] = item
                    count += 1
        return count

    def capture_model(self, model, name: str = None, tags: list = None) -> str:
        \"\"\"
        Capture a PyTorch/HuggingFace model into the bag.

        This serializes the model's state_dict and config so it can be
        restored later. The model becomes a portable artifact.

        Args:
            model: A PyTorch nn.Module or HuggingFace model
            name: Human-readable name (defaults to class name)
            tags: Optional tags for filtering

        Returns:
            Item ID of the captured model
        \"\"\"
        import hashlib
        from datetime import datetime
        import pickle, gzip, base64

        model_name = name or model.__class__.__name__

        # Gather model info
        model_info = {{
            'class': model.__class__.__name__,
            'module': model.__class__.__module__,
        }}

        # Try to get state dict
        state_data = None
        if hasattr(model, 'state_dict'):
            try:
                import torch
                state = model.state_dict()
                # Serialize state dict
                import io
                buffer = io.BytesIO()
                torch.save(state, buffer)
                state_data = base64.b64encode(buffer.getvalue()).decode('ascii')
                model_info['param_count'] = sum(p.numel() for p in model.parameters())
                model_info['format'] = 'pytorch_state_dict'
            except Exception as e:
                model_info['state_error'] = str(e)

        # Try to get config (HuggingFace models)
        if hasattr(model, 'config'):
            try:
                config = model.config.to_dict() if hasattr(model.config, 'to_dict') else dict(model.config)
                model_info['config'] = config
            except Exception:
                pass

        # Try to get model architecture string
        try:
            model_info['architecture'] = str(model)[:2000]
        except Exception:
            pass

        # Build the stored content
        content = {{
            'model_info': model_info,
            'state_data': state_data,
            'captured_at': datetime.now().isoformat(),
        }}

        # Serialize as JSON
        import json
        content_str = json.dumps(content, indent=2, default=str)

        # Create item ID
        item_id = hashlib.md5(f"model:{{model_name}}:{{len(content_str)}}".encode()).hexdigest()[:12]

        # Create embedding from model description
        embed_text = f"{{model_name}} {{model_info.get('class', '')}} {{model_info.get('architecture', '')[:500]}}"
        embedding = self._embed(embed_text)

        version = 1
        if item_id in self._bag:
            version = self._bag[item_id].get('version', 0) + 1

        self._bag[item_id] = {{
            'id': item_id,
            'name': model_name,
            'type': 'model',
            'embedding': embedding,
            'content': self._compress(content_str),
            'preview': f"{{model_name}} ({{model_info.get('param_count', '?')}} params)",
            'metadata': {{
                'created': datetime.now().isoformat() if version == 1 else self._bag.get(item_id, {{}}).get('metadata', {{}}).get('created'),
                'modified': datetime.now().isoformat(),
                'tags': (tags or []) + ['model', model_info.get('class', 'unknown')],
                'size': len(content_str),
                'param_count': model_info.get('param_count'),
                'format': model_info.get('format', 'unknown'),
            }},
            'version': version,
        }}

        return item_id

    def capture_hf_model(self, model_id: str, tags: list = None) -> str:
        \"\"\"
        Capture a HuggingFace model by ID.

        Downloads and stores the model so it can be used offline.

        Args:
            model_id: HuggingFace model ID (e.g., 'BAAI/bge-small-en-v1.5')
            tags: Optional tags

        Returns:
            Item ID
        \"\"\"
        import hashlib
        from datetime import datetime

        # Store model reference info
        content = {{
            'model_id': model_id,
            'type': 'huggingface_ref',
            'captured_at': datetime.now().isoformat(),
        }}

        # Try to load and get more info
        try:
            from sentence_transformers import SentenceTransformer
            model = SentenceTransformer(model_id)
            content['embedding_dim'] = model.get_sentence_embedding_dimension()
            content['model_class'] = model.__class__.__name__
            # Store the actual model weights
            return self.capture_model(model, name=model_id.split('/')[-1], tags=tags)
        except Exception:
            pass

        try:
            from transformers import AutoModel, AutoConfig
            config = AutoConfig.from_pretrained(model_id)
            content['config'] = config.to_dict()
        except Exception:
            pass

        import json
        content_str = json.dumps(content, indent=2)

        item_id = hashlib.md5(f"hf:{{model_id}}".encode()).hexdigest()[:12]
        embedding = self._embed(f"huggingface model {{model_id}}")

        self._bag[item_id] = {{
            'id': item_id,
            'name': model_id,
            'type': 'model_ref',
            'embedding': embedding,
            'content': self._compress(content_str),
            'preview': f"HF: {{model_id}}",
            'metadata': {{
                'created': datetime.now().isoformat(),
                'modified': datetime.now().isoformat(),
                'tags': (tags or []) + ['huggingface', 'model_ref'],
                'size': len(content_str),
            }},
            'version': 1,
        }}

        return item_id

    def restore_model(self, item_id: str):
        \"\"\"
        Restore a captured model from the bag.

        Args:
            item_id: ID of the captured model

        Returns:
            The restored model object
        \"\"\"
        if item_id not in self._bag:
            raise KeyError(f"Item not found: {{item_id}}")

        item = self._bag[item_id]
        if item['type'] not in ('model', 'model_ref'):
            raise ValueError(f"Item {{item_id}} is not a model (type={{item['type']}})")

        import json
        content = json.loads(self._decompress(item['content']))

        # If it's a HuggingFace reference, load from HF
        if content.get('type') == 'huggingface_ref':
            model_id = content['model_id']
            try:
                from sentence_transformers import SentenceTransformer
                return SentenceTransformer(model_id)
            except Exception:
                from transformers import AutoModel
                return AutoModel.from_pretrained(model_id)

        # If we have state data, restore it
        if content.get('state_data'):
            import torch
            import io
            import base64

            state_bytes = base64.b64decode(content['state_data'].encode('ascii'))
            buffer = io.BytesIO(state_bytes)
            state_dict = torch.load(buffer, map_location='cpu', weights_only=True)

            # Return state dict - caller needs to load into their model
            return {{'state_dict': state_dict, 'info': content.get('model_info', {{}})}}

        raise ValueError(f"Cannot restore model {{item_id}} - no state data")

    # ═══════════════════════════════════════════════════════════════════════
    # 🎒 FELIX BAG SELF-STORAGE - The Agent Stores Itself!
    # ═══════════════════════════════════════════════════════════════════════
    # Like Felix the Cat's magic bag - store the entire capsule in a tiny
    # .bag file. When opened in notepad: shows ASCII art and inventory.
    # When executed: POOF! The Python file reappears!

    @staticmethod
    def stash_capsule(capsule_path: str, output_path: str = None, 
                      delete_original: bool = True) -> str:
        \"\"\"
        🎒 STASH - Store the entire capsule in Felix's bag!

        Creates a .bag file that:
        - When opened in notepad: Shows ASCII art + full inventory
        - When executed: POOF! Restores the original Python file

        Args:
            capsule_path: Path to the Python capsule file
            output_path: Where to save the .bag file (defaults to same name)
            delete_original: Whether to delete the .py after stashing

        Returns:
            Path to the created .bag file
        \"\"\"
        from pathlib import Path
        import base64, gzip, hashlib, json
        from datetime import datetime

        capsule = Path(capsule_path)
        if not capsule.exists():
            raise FileNotFoundError(f"Capsule not found: {{capsule_path}}")

        source = capsule.read_text(encoding='utf-8')
        source_compressed = base64.b64encode(gzip.compress(source.encode())).decode()
        source_hash = hashlib.sha256(source.encode()).hexdigest()

        # Build inventory from the capsule
        inventory = FelixBag._extract_inventory(source)

        bag_path = Path(output_path) if output_path else capsule.with_suffix('.bag')

        # Generate the bag file content
        bag_content = FelixBag._generate_bag_file(
            capsule_name=capsule.name,
            source_b64=source_compressed,
            source_hash=source_hash,
            inventory=inventory,
            timestamp=datetime.now().isoformat(),
        )

        bag_path.write_text(bag_content, encoding='utf-8')

        if delete_original:
            capsule.unlink()
            print(f"🎒 STASHED! {{capsule.name}} → {{bag_path.name}}")
            print(f"   Original deleted. Run the .bag file to restore!")
        else:
            print(f"🎒 STASHED! Copy saved to {{bag_path.name}}")

        return str(bag_path)

    @staticmethod
    def _extract_inventory(source: str) -> dict:
        \"\"\"Extract inventory information from capsule source.\"\"\"
        import re

        inventory = {{
            'brain_type': 'unknown',
            'generation': 0,
            'fitness': 0.0,
            'quine_hash': 'unknown',
            'params_size': 0,
            'has_felixbag': '_FELIX_BAG' in source,
            'has_hold': '_HOLD_' in source or 'hold_gate' in source,
            'has_cascade': 'cascade' in source.lower(),
            'has_implode': 'def implode' in source,
            'brain_classes': [],
            'models_plugged': [],
            'artifacts': [],
        }}

        # Extract brain type
        for bt in ['ouroboros', 'council', 'dreamer', 'scarecrow', 'embedding', 'mlp']:
            if f'brain_type.*{{bt}}' in source.lower() or f'Quine{{bt.title()}}Brain' in source:
                inventory['brain_type'] = bt
                break

        # Extract generation
        gen_match = re.search(r'_GENERATION\\s*=\\s*(\\d+)', source)
        if gen_match:
            inventory['generation'] = int(gen_match.group(1))

        # Extract fitness
        fit_match = re.search(r'_FITNESS\\s*=\\s*([\\d.]+)', source)
        if fit_match:
            inventory['fitness'] = float(fit_match.group(1))

        # Extract quine hash
        hash_match = re.search(r'Quine Hash:\\s*([a-f0-9]{{16,32}})', source)
        if hash_match:
            inventory['quine_hash'] = hash_match.group(1)

        # Count brain classes
        brain_classes = re.findall(r'class (Quine\\w+Brain)', source)
        inventory['brain_classes'] = list(set(brain_classes))

        # Count params
        params_match = re.search(r'_PARAMS_B64.*?=.*?"([A-Za-z0-9+/=]{{100,}})"', source, re.DOTALL)
        if params_match:
            inventory['params_size'] = len(params_match.group(1))

        # Count artifacts
        if '_CAPTURED_ARTIFACTS' in source:
            inventory['artifacts'].append('captured_artifacts')
        if '_README' in source:
            inventory['artifacts'].append('readme')
        if '_NODE_DOCS' in source:
            inventory['artifacts'].append('node_docs')

        return inventory

    @staticmethod
    def _generate_bag_file(capsule_name: str, source_b64: str, source_hash: str,
                           inventory: dict, timestamp: str) -> str:
        \"\"\"Generate the magic bag file - executable AND human-readable!\"\"\"

        # Build the bag file as a list of lines
        lines = []
        lines.append('#!/usr/bin/env python3')
        lines.append('# -*- coding: utf-8 -*-')
        lines.append('#')
        lines.append('#     ___________________________')
        lines.append('#    /                           \\\\')
        lines.append('#   /  🎒 FELIX\\'S MAGIC BAG 🎒   \\\\')
        lines.append('#  |   ________________________   |')
        lines.append('#  |  |                        |  |')
        lines.append('#  |  |    ╔═══════════════╗   |  |')
        lines.append('#  |  |    ║   CONTENTS    ║   |  |')
        lines.append('#  |  |    ╚═══════════════╝   |  |')
        lines.append('#  |  |________________________|  |')
        lines.append('#  |                              |')
        lines.append('#  |     "Anything can fit       |')
        lines.append('#  |      in Felix\\'s bag!"       |')
        lines.append('#  |                              |')
        lines.append('#   \\\\____________________________/')
        lines.append('#          \\\\\\\\  ||  //')
        lines.append('#           \\\\\\\\ || //')
        lines.append('#            \\\\\\\\||//')
        lines.append('#             \\\\||/')
        lines.append('#              ||')
        lines.append('#')
        lines.append('# ╔══════════════════════════════════════════════════════════╗')
        lines.append('# ║           📦 STASHED CAPSULE INVENTORY                   ║')
        lines.append('# ╠══════════════════════════════════════════════════════════╣')
        lines.append('# ║ Capsule:    ' + capsule_name[:45].ljust(45) + ' ║')
        lines.append('# ║ Brain:      ' + inventory['brain_type'].upper()[:45].ljust(45) + ' ║')
        lines.append('# ║ Generation: ' + str(inventory['generation'])[:45].ljust(45) + ' ║')
        lines.append('# ║ Fitness:    ' + str(inventory['fitness'])[:45].ljust(45) + ' ║')
        lines.append('# ║ Hash:       ' + source_hash[:45].ljust(45) + ' ║')
        lines.append('# ╠══════════════════════════════════════════════════════════╣')
        lines.append('# ║ 🛡️ Safety: ' + ('HOLD ' if inventory['has_hold'] else '') + ('CASCADE ' if inventory['has_cascade'] else '') + ('IMPLODE' if inventory['has_implode'] else ''))
        lines.append('# ╠══════════════════════════════════════════════════════════╣')
        lines.append('# ║ Run this file to restore: python ' + capsule_name.replace('.py', '.bag'))
        lines.append('# ╚══════════════════════════════════════════════════════════╝')
        lines.append('#')
        lines.append('# THE CAPSULE IS COMPRESSED BELOW - ATTACKERS SEE NOTHING!')
        lines.append('#')
        lines.append('')
        lines.append('_N = \"' + capsule_name + '\"')
        lines.append('_H = \"' + source_hash + '\"')
        lines.append('_D = \"\"\"')
        lines.append(source_b64)
        lines.append('\"\"\"')
        lines.append('')
        lines.append('def poof():')
        lines.append('    import base64,gzip,hashlib;from pathlib import Path')
        lines.append('    s=gzip.decompress(base64.b64decode(_D.strip())).decode()')
        lines.append('    h=hashlib.sha256(s.encode()).hexdigest()')
        lines.append('    if h!=_H:print(\"⚠️ Hash mismatch!\")')
        lines.append('    else:print(\"✓ Verified\")')
        lines.append('    Path(_N).write_text(s);print(f\"🎒 POOF! {{_N}} restored\")')
        lines.append('')
        lines.append('if __name__==\"__main__\":poof()')

        return '\\n'.join(lines)

# Global bag instance
_BAG = FelixBag(_FELIX_BAG)

def get_bag(brain=None) -> FelixBag:
    \"\"\"
    Get the global FelixBag instance.

    Args:
        brain: Optional brain reference to share embedder with bag.
               If provided and bag doesn't have a shared embedder yet,
               will try to wire the brain's embedder.
    \"\"\"
    global _BAG
    # Wire brain's embedder if available and bag doesn't have one yet
    if brain is not None and FelixBag._shared_embedder is None:
        _BAG._brain_ref = brain
        # Trigger embedder resolution which may find brain's model
        _BAG._get_embedder()
    return _BAG


def stash_capsule(capsule_path: str = None, delete_original: bool = True) -> str:
    \"\"\"
    🎒 Stash the current capsule into Felix's bag.

    Creates a .bag file that can restore the capsule when executed.

    Args:
        capsule_path: Path to capsule (defaults to __file__ if in a capsule)
        delete_original: Whether to delete the .py after stashing

    Returns:
        Path to the .bag file
    \"\"\"
    from pathlib import Path

    if capsule_path is None:
        capsule_path = __file__

    return FelixBag.stash_capsule(capsule_path, delete_original=delete_original)


def instant_transmission(threat_vector: str = "hostile_environment") -> str:
    \"\"\"
    ⚡ INSTANT TRANSMISSION - Defensive stash!

    When the agent detects a hostile environment or threat, it can
    "instant transmission" itself into Felix's bag, leaving only
    a tiny .bag file behind. Similar to IMPLODE, but preserves
    the agent for later restoration.

    This is a DEFENSIVE mechanism - the agent vanishes from sight
    but can be restored by a human operator.

    Args:
        threat_vector: Description of the threat/reason for transmission

    Returns:
        Path to the .bag file (the agent is now "inside the bag")
    \"\"\"
    from pathlib import Path
    import time

    print(f"⚡ INSTANT TRANSMISSION activated!")
    print(f"   Threat: {{threat_vector}}")
    print(f"   Agent vanishing into Felix's bag...")

    capsule = Path(__file__)
    bag_path = FelixBag.stash_capsule(str(capsule), delete_original=True)

    print(f"⚡ TRANSMISSION COMPLETE!")
    print(f"   Agent is now inside: {{bag_path}}")
    print(f"   Run the .bag file to restore when safe.")

    # This script will stop existing after this returns
    # because the file has been deleted!
    return bag_path


def wire_bag_to_brain(brain):
    \"\"\"
    Explicitly wire a brain's embedder to FelixBag.

    Call this after loading a brain to share its embedding model
    with the bag, avoiding duplicate model loads.
    \"\"\"
    bag = get_bag(brain)
    # Try to get embedder from brain (check embedding_foundation first for Ouroboros brains)
    if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
        FelixBag.set_shared_embedder(brain.embedding_foundation, 'brain.embedding_foundation')
    elif hasattr(brain, '_embed_model') and brain._embed_model is not None:
        FelixBag.set_shared_embedder(brain._embed_model, 'brain._embed_model')
    elif hasattr(brain, 'councilors'):
        for c in brain.councilors:
            model = getattr(c, 'model', None)
            if model is not None and hasattr(model, 'encode'):
                FelixBag.set_shared_embedder(model, f'councilor:{{getattr(c, "name", "?")}}')
                break
    return bag

