def populate_bag_with_embedded():
    \"\"\"
    Pre-populate the FelixBag with all embedded artifacts.

    Called on TUI mount to make bag ready from fresh run.
    Items are tagged with 'embedded' for filtering.
    \"\"\"
    import json
    bag = get_bag()
    added = 0

    def _ensure_asset_catalog():
        _asset_added = 0
        _asset_upgraded = 0
        _existing = {{}}
        try:
            for _iid, _item in getattr(bag, '_bag', {{}}).items():
                _name = str(_item.get('name', ''))
                if _name:
                    _existing[_name] = _iid
                    _existing[_iid] = _iid
        except Exception:
            pass
        for _asset_entry in _CC0_ASSET_CATALOG:
            _asset_key = f"asset_pack:{{_asset_entry['source']}}:{{_asset_entry['id'].split('/')[-1]}}"
            if _asset_key in _existing:
                try:
                    _eid = _existing[_asset_key]
                    _eitem = bag._bag.get(_eid, {{}})
                    _econtent = _eitem.get('content', '') if _eitem else ''
                    _etext = ''
                    if _econtent:
                        try:
                            import gzip as _gz, base64 as _b64
                            _etext = _gz.decompress(_b64.b64decode(str(_econtent).encode('ascii'))).decode('utf-8')
                        except Exception:
                            _etext = str(_econtent)
                    if _etext:
                        _eparsed = json.loads(_etext)
                        if 'download_mode' not in _eparsed or 'download_url' not in _eparsed or 'download_ext' not in _eparsed:
                            for _fld in ('download_url', 'download_mode', 'download_ext'):
                                if _fld not in _eparsed:
                                    _eparsed[_fld] = _asset_entry.get(_fld, '')
                            bag.induct(
                                _asset_key,
                                json.dumps(_eparsed),
                                item_type='asset_catalog',
                                tags=['embedded', 'cc0', 'asset', _asset_entry['source'], 'upgraded']
                            )
                            _asset_upgraded += 1
                except Exception:
                    pass
                continue
            try:
                bag.induct(
                    _asset_key,
                    json.dumps(_asset_entry),
                    item_type='asset_catalog',
                    tags=['embedded', 'cc0', 'asset', _asset_entry['source']]
                )
                _asset_added += 1
            except Exception:
                continue
        return _asset_added + _asset_upgraded

    # Skip if bag already has items (don't double-populate core docs/config),
    # but still backfill newly added asset catalog seeds.
    if len(bag._bag) > 0:
        return _ensure_asset_catalog()

    g = globals()

    # === CORE IDENTITY ===
    # 1. Quine hash (identity)
    if g.get('_QUINE_HASH'):
        bag.induct('quine_hash', json.dumps({{'hash': g['_QUINE_HASH'], 'genesis': g.get('_GENESIS_ROOT')}}),
                   item_type='state', tags=['embedded', 'identity', 'core'])
        added += 1

    # 2. Generation and fitness
    bag.induct('evolution_state', json.dumps({{
        'generation': g.get('_GENERATION', 0),
        'fitness': g.get('_FITNESS', 0.0),
        'quine_hash': g.get('_QUINE_HASH'),
        'genesis_root': g.get('_GENESIS_ROOT')
    }}, indent=2), item_type='state', tags=['embedded', 'evolution', 'core'])
    added += 1

    # === BRAIN DATA ===
    # 3. Brain data (compressed weights) - just metadata, actual data too large
    if g.get('_BRAIN_DATA'):
        bag.induct('brain_weights', json.dumps({{
            'description': 'Compressed neural network weights',
            'size_chars': len(g['_BRAIN_DATA']),
            'compressed': g.get('_DATA_COMPRESSED', True)
        }}), item_type='artifact', tags=['embedded', 'weights', 'core'])
        added += 1

    # 4. Brain config
    if '_BRAIN_CONFIG' in g:
        bag.induct('brain_config', json.dumps(g['_BRAIN_CONFIG'], indent=2),
                   item_type='config', tags=['embedded', 'brain', 'core'])
        added += 1

    # 5. VP config
    if '_VP_CONFIG' in g:
        bag.induct('vp_config', json.dumps(g['_VP_CONFIG'], indent=2),
                   item_type='config', tags=['embedded', 'vp', 'core'])
        added += 1

    # 6. Quine config
    if '_QUINE_CONFIG' in g:
        bag.induct('quine_config', json.dumps(g['_QUINE_CONFIG'], indent=2),
                   item_type='config', tags=['embedded', 'quine', 'core'])
        added += 1

    # 7. Evolved traits
    if '_TRAITS' in g:
        bag.induct('evolved_traits', json.dumps(g['_TRAITS'], indent=2), 
                   item_type='state', tags=['embedded', 'evolution', 'traits'])
        added += 1

    # === DOCUMENTATION ===
    # 8. README
    if g.get('_README'):
        bag.induct('readme', g['_README'],
                   item_type='document', tags=['embedded', 'documentation', 'readme'])
        added += 1

    # 9. Node docs
    if g.get('_NODE_DOCS'):
        content = g['_NODE_DOCS'] if isinstance(g['_NODE_DOCS'], str) else json.dumps(g['_NODE_DOCS'], indent=2)
        bag.induct('node_docs', content,
                   item_type='document', tags=['embedded', 'documentation', 'nodes'])
