def verify_quine_integrity() -> bool:
    \"\"\"
    Verify the quine brain's merkle hash matches the compiled hash.

    Returns True if the brain is unchanged from compilation.
    Any modification to weights, traits, or config will cause this to fail.
    \"\"\"
    try:
        qb = QuineOuroborosBrain()
        computed_hash = qb.get_merkle_hash()
        return computed_hash == _QUINE_HASH
    except NameError:
        pass
    try:
        qb = QuineBrain()
        computed_hash = qb.get_merkle_hash()
        return computed_hash == _QUINE_HASH
    except NameError:
        pass
    try:
        qb = QuineBrainMLP()
        computed_hash = qb.get_merkle_hash()
        return computed_hash == _QUINE_HASH
    except NameError:
        pass
    return False

def get_quine_brain():
    \"\"\"
    Get the quine brain - self-contained, non-malicious inference.

    The quine brain can run inference using only numpy, without
    requiring JAX, PyTorch, or the KEY codebase.
    \"\"\"
    # Ouroboros brain (composite - try first as it's most complete)
    try:
        return QuineOuroborosBrain()
    except NameError:
        pass
    # Council brain
    try:
        return QuineCouncilBrain()
    except NameError:
        pass
    # Scarecrow brain
    try:
        return QuineScarecrowBrain()
    except NameError:
        pass
    # Embedding brain
    try:
        return QuineEmbeddingBrain()
    except NameError:
        pass
    # DreamerV3 brain
    try:
        return QuineBrain()
    except NameError:
        pass
    # MLP brain
    try:
        return QuineBrainMLP()
    except NameError:
        pass
    return None

def get_quine_hash() -> str:
    \"\"\"Return the compiled quine hash.\"\"\"
    return _QUINE_HASH

def replicate_quine(output_path: str = None) -> str:
    \"\"\"
    Replicate the quine brain to a standalone Python file.

    The output file is completely self-contained and can run
    without any KEY dependencies.
    \"\"\"
    if output_path is None:
        output_path = f"quine_{{_QUINE_HASH[:8]}}.py"

    # Extract the quine source from this file
    import inspect
    source_lines = []
    in_quine = False

    for line in inspect.getsource(__import__(__name__)).split('\\n'):
        if '# ═══════════════════════════════════════════════════════════════════════' in line and 'QUINE BRAIN' in line:
            in_quine = True
        if in_quine:
            source_lines.append(line)
            if 'def load_quine_brain' in line:
                # Get the rest of that function
                break

    # Write standalone file
    with open(output_path, 'w') as f:
        f.write('#!/usr/bin/env python3\\n')
        f.write('\"\"\"\\n')
        f.write(f'Quine Brain - Standalone Self-Contained AI\\n')
        f.write(f'Hash: {{_QUINE_HASH}}\\n')
        f.write(f'Verified: {{verify_quine_integrity()}}\\n')
        f.write('\"\"\"\\n\\n')
        f.write('import numpy as np\\nimport base64\\nimport json\\nimport hashlib\\n\\n')
        f.write('\\n'.join(source_lines))
        f.write('\\n\\nif __name__ == "__main__":\\n')
        f.write('    brain = load_quine_brain()\\n')
        f.write('    print(f"Quine Brain loaded. Hash: {{brain.get_merkle_hash()}}")\\n')

    return output_path


