# CAPSULE BRAIN
# ═══════════════════════════════════════════════════════════════

class CapsuleBrain:
    """
    Embedded brain - the COMPLETE evolved AI.

    For DreamerBrain: Full RSSM world model + policy + value + LoRA adapter.
    The entire brain object is pickled and restored - no reconstruction needed.
    """

    def __init__(self):
        self.config = _BRAIN_CONFIG
        self.brain_type = self.config.get("brain_type", "mlp")
        self.hidden_size = self.config.get("hidden_size", 64)
        self.input_keys = self.config.get("input_keys", ["traits"])
        self.output_keys = self.config.get("output_keys", ["action"])

        # Load brain
        self._load_brain()

    def _load_brain(self):
        """Load brain from embedded base64 (JSON for DreamerBrain, pickle fallback for others)."""
        if not _BRAIN_DATA:
            self._brain = None
            self._params = np.array([])
            return

        data = base64.b64decode(_BRAIN_DATA)
        if _DATA_COMPRESSED:
            data = gzip.decompress(data)

        if self.brain_type == "ouroboros":
            # Load the QuineOuroborosBrain defined above
            self._brain = QuineOuroborosBrain()
            self._params = np.array([])  # Ouroboros params are in the brain
            print(f"[🐍 Ouroboros] Composite brain loaded: ALL brain faculties active")
        elif self.brain_type == "dreamer":
            # Try JSON first (pickle-free quine format)
            try:
                full_data = json.loads(data.decode('utf-8'))
                self._brain = self._reconstruct_dreamer_brain(full_data)
                print(f"[Brain] DreamerBrain loaded (JSON): latent={{self._brain.latent_dim}}, actions={{self._brain.action_dim}}")
            except (json.JSONDecodeError, UnicodeDecodeError):
                # Fallback to pickle for legacy capsules
                loaded = pickle.loads(data)
                self._brain = loaded
                print(f"[Brain] DreamerBrain loaded (pickle): latent={{self._brain.latent_dim}}")
        elif self.brain_type == "scarecrow":
            # Load the QuineScarecrowBrain defined above
            self._brain = QuineScarecrowBrain()
            self._params = self._brain.get_params()

            # Check if there's a captured model embedded - on instance OR module level
            has_captured = (hasattr(self, '_captured_model_b64') and self._captured_model_b64) or \\
                           '_CAPTURED_MODEL_B64' in globals()

            if has_captured:
                model_class = getattr(self, '_captured_model_class', None) or \\
                              globals().get('_CAPTURED_MODEL_CLASS', 'unknown')
                class_name = model_class.split('.')[-1]
                for suffix in ['ForCausalLM', 'LMHeadModel', 'ForSequenceClassification', 'Model']:
                    if class_name.endswith(suffix):
                        class_name = class_name[:-len(suffix)]
                        break
                print(f"[Brain] {{class_name}}Brain loaded: adapter {{self._brain.input_dim}}>{{self._brain.adapter_dim}}>{{self._brain.output_dim}}")
            else:
                print(f"[Brain] ScarecrowBrain loaded: {{self._brain.input_dim}}>{{self._brain.adapter_dim}}>{{self._brain.output_dim}}")
        elif self.brain_type == "council":
            # Load the QuineCouncilBrain defined above  
            self._brain = QuineCouncilBrain()
            self._params = np.array([])  # Council params are in councilors
            print(f"[Council] CouncilBrain loaded: {{self._brain.n_councilors}} councilor slots, consensus={{self._brain.consensus_method}}")
        elif self.brain_type == "embedding":
            # Load the QuineEmbeddingBrain defined above
            self._brain = QuineEmbeddingBrain()
            self._params = self._brain.get_params()
            print(f"[Embed] EmbeddingBrain loaded: {{self._brain.model_name}} > {{self._brain.hidden_dim}}>{{self._brain.output_dim}}")
        else:
            # For other types - try numpy bytes first, then pickle
            try:
                self._params = np.frombuffer(data, dtype=np.float32)
            except Exception:
                loaded = pickle.loads(data)
                self._params = loaded if isinstance(loaded, np.ndarray) else np.array([])
            self._brain = None
            self._init_mlp_layers()

    def _reconstruct_dreamer_brain(self, data: dict):
        """Reconstruct DreamerBrain from JSON dict with REAL RSSM."""
        # Try to import real DreamerV3 RSSM
        import sys
        from pathlib import Path
        _dreamer_path = Path(__file__).parent / "dreamerv3"
        if str(_dreamer_path) not in sys.path:
            sys.path.insert(0, str(_dreamer_path))

        try:
            import jax.numpy as jnp
            from jax import random as jax_random
            import ninjax as nj
            import embodied
            import elements
            from dreamerv3 import rssm as dreamer_rssm
            HAS_REAL_RSSM = True
        except ImportError as e:
            print(f"⚠ Real RSSM not available: {{e}}")
            HAS_REAL_RSSM = False

        class EmbeddedDreamerBrain:
            \"\"\"Full DreamerBrain with REAL RSSM embedded in capsule.\"\"\"
            def __init__(self, data, has_rssm=False):
                self.config = data['config']
                self.latent_dim = data.get('latent_dim', self.config['deter_dim'] + 
                    self.config['stoch_dim'] * self.config['stoch_classes'])
                self.action_dim = self.config['action_dim']
                self.lora_rank = data.get('lora_rank', self.config.get('lora_rank', 16))
                self.lora_alpha = data.get('lora_alpha', self.config.get('lora_alpha', 1.0))

                # LoRA weights (the evolved part)
                self.lora_A = np.array(data['lora_A'], dtype=np.float32)
                self.lora_B = np.array(data['lora_B'], dtype=np.float32)
                self.lora_bias = np.array(data['lora_bias'], dtype=np.float32)

                # State
                self._deter = np.zeros(self.config['deter_dim'], dtype=np.float32)
                self._stoch = np.zeros((self.config['stoch_dim'], self.config['stoch_classes']), dtype=np.float32)

                if data.get('state'):
                    self._deter = np.array(data['state'].get('deter', self._deter), dtype=np.float32)
                    stoch_data = data['state'].get('stoch', self._stoch)
                    self._stoch = np.array(stoch_data, dtype=np.float32).reshape(
                        self.config['stoch_dim'], self.config['stoch_classes'])

                # RSSM setup
                self._has_real_rssm = has_rssm
                self._rssm = None
                self._rssm_initialized = False
                self._nj_state = {{}}
                self._prev_action = 0

                if has_rssm:
                    self._init_real_rssm()

            def _init_real_rssm(self):
                \"\"\"Initialize REAL DreamerV3 RSSM.\"\"\"
                # Create action space
                self._act_space = {{
                    'action': elements.Space(np.int32, (), 0, self.config['action_dim'])
                }}

                # Create RSSM
                self._rssm = dreamer_rssm.RSSM(
                    self._act_space,
                    deter=self.config['deter_dim'],
                    hidden=self.config['hidden_dim'],
                    stoch=self.config['stoch_dim'],
                    classes=self.config['stoch_classes'],
                    name='rssm'
                )

                # Define observe function
                def _observe_fn(carry, tokens, action, reset_arr):
                    return self._rssm.observe(carry, tokens, action, reset_arr, training=False, single=True)
                self._observe_fn = _observe_fn
                self._pure_observe = nj.pure(_observe_fn)

                # RNG for ninjax
                self._rng = jax_random.PRNGKey(42)
                print(f"[OK] Capsule RSSM: deter={{self._rssm.deter}}, stoch={{self._rssm.stoch}}x{{self._rssm.classes}}")

            def _ensure_rssm_initialized(self, carry, tokens, action, reset_arr):
                \"\"\"Lazily init RSSM params.\"\"\"
                if self._rssm_initialized:
                    return
                self._rng, subkey = jax_random.split(self._rng)
                seed_int = int(subkey[0]) % (2**31)
                init_fn = nj.init(self._observe_fn)
                self._nj_state = init_fn(self._nj_state, carry, tokens, action, reset_arr, seed=seed_int)
                self._rssm_initialized = True
                print(f"[OK] RSSM params: {{len(self._nj_state)}} entries")

            def _update_rssm_state(self, obs):
                \"\"\"Update RSSM state with observation.\"\"\"
                if not self._has_real_rssm or self._rssm is None:
                    return

                # Prepare inputs
                tokens = jnp.array(obs.reshape(1, -1), dtype=jnp.float32)
                action_val = max(0, min(self._prev_action, self.config['action_dim'] - 1))
                action = {{'action': jnp.array([action_val], dtype=jnp.int32)}}
                reset_arr = jnp.array([False], dtype=bool)
                carry = {{
                    'deter': jnp.array(self._deter.reshape(1, -1), dtype=jnp.float32),
                    'stoch': jnp.array(self._stoch.reshape(1, self.config['stoch_dim'], 
                        self.config['stoch_classes']), dtype=jnp.float32),
                }}

                try:
                    self._ensure_rssm_initialized(carry, tokens, action, reset_arr)
                    self._rng, subkey = jax_random.split(self._rng)
                    seed_int = int(subkey[0]) % (2**31)
                    self._nj_state, (new_carry, entry, feat) = self._pure_observe(
                        self._nj_state, carry, tokens, action, reset_arr,
                        seed=seed_int, create=False, modify=True
                    )
                    self._deter = np.array(new_carry['deter'][0], dtype=np.float32)
                    self._stoch = np.array(new_carry['stoch'][0], dtype=np.float32)
                except Exception as e:
                    # Fallback: simple state update
                    obs_proj = np.zeros(len(self._deter), dtype=np.float32)
                    obs_flat = obs.flatten()
                    obs_proj[:min(len(obs_flat), len(obs_proj))] = obs_flat[:min(len(obs_flat), len(obs_proj))]
                    gate = 1.0 / (1.0 + np.exp(-obs_proj * 0.1))
                    self._deter = gate * self._deter + (1 - gate) * obs_proj * 0.01
                    self._stoch = self._stoch * 0.99 + np.random.randn(*self._stoch.shape).astype(np.float32) * 0.01

            def forward(self, inputs):
                \"\"\"Forward with REAL RSSM state update.\"\"\"
                obs = np.array(inputs.get('obs', [0.0] * 10), dtype=np.float32).flatten()

                # Update RSSM state
                self._update_rssm_state(obs)

                # Get latent
                latent = np.concatenate([self._deter.flatten(), self._stoch.flatten()])

                # LoRA adapter
                scaling = self.lora_alpha / self.lora_rank
                logits = (latent @ self.lora_A @ self.lora_B) * scaling + self.lora_bias

                # Softmax
                exp_logits = np.exp(logits - np.max(logits))
                probs = exp_logits / np.sum(exp_logits)
                action = int(np.argmax(probs))
                self._prev_action = action

                value = float(np.max(probs))

                return {{
                    'action': action,
                    'action_probs': probs,
                    'value': value,
                    'latent': latent,
                }}

            def reset(self):
                self._deter = np.zeros(self.config['deter_dim'], dtype=np.float32)
                self._stoch = np.zeros((self.config['stoch_dim'], self.config['stoch_classes']), dtype=np.float32)
                self._prev_action = 0

        return EmbeddedDreamerBrain(data, has_rssm=HAS_REAL_RSSM)

    def _init_mlp_layers(self):
        """Initialize MLP layers."""
        input_size = len(_TRAITS)
        hidden = self.hidden_size
        output_size = len(self.output_keys)

        if len(self._params) > 0:
            w1_size = input_size * hidden
            b1_size = hidden
            w2_size = hidden * output_size

            if len(self._params) >= w1_size + b1_size + w2_size + output_size:
                idx = 0
                self.w1 = self._params[idx:idx+w1_size].reshape(input_size, hidden)
                idx += w1_size
                self.b1 = self._params[idx:idx+b1_size]
                idx += b1_size
                self.w2 = self._params[idx:idx+w2_size].reshape(hidden, output_size)
                idx += w2_size
                self.b2 = self._params[idx:idx+output_size]
                return

        # Random init
        self.w1 = np.random.randn(input_size, hidden) * 0.1
        self.b1 = np.zeros(hidden)
        self.w2 = np.random.randn(hidden, output_size) * 0.1
        self.b2 = np.zeros(output_size)

    def forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        """Process inputs, return outputs."""
        if self.brain_type == "ouroboros" and self._brain is not None:
            # Use the Ouroboros composite brain system!
            return self._brain.forward(inputs)
        elif self.brain_type == "dreamer" and self._brain is not None:
            # Use the REAL DreamerBrain with full world model!
            return self._brain.forward(inputs)
        elif self.brain_type == "scarecrow" and self._brain is not None:
            # Use the ScarecrowBrain adapter
            return self._brain.forward(inputs)
        elif self.brain_type == "council" and self._brain is not None:
            # Use the CouncilBrain - deliberative multi-agent consensus
            return self._brain.forward(inputs)
        elif self.brain_type == "embedding" and self._brain is not None:
            # Use the EmbeddingBrain - sentence-transformer + projection
            return self._brain.forward(inputs)

        # MLP fallback
        if "traits" in inputs:
            x = np.array(list(inputs["traits"].values()) if isinstance(inputs["traits"], dict) 
                        else inputs["traits"])
        else:
            x = np.array(list(_TRAITS.values()))

        h = np.tanh(x @ self.w1 + self.b1)
        out = h @ self.w2 + self.b2
        return {{key: out[i] for i, key in enumerate(self.output_keys)}}

    def imagine(self, horizon: int = 15, num_trajectories: int = 5):
        """
        IMAGINATION - simulate future using the world model.
        Available for DreamerBrain and Ouroboros (which contains Dreamer).
        """
        if self.brain_type == "ouroboros" and self._brain is not None:
            # Ouroboros has dreamer world model built-in
            return [self._brain._dreamer_simulate({{'text': f'trajectory_{{i}}'}}) for i in range(num_trajectories)]
        elif self.brain_type == "dreamer" and self._brain is not None:
            return self._brain.imagine(horizon, num_trajectories)
        return []

    def get_params(self) -> np.ndarray:
        """Return evolved parameters (LoRA for Dreamer, full for MLP)."""
        if self.brain_type == "ouroboros" and self._brain is not None:
            return self._brain.get_params()
        elif self.brain_type == "dreamer" and self._brain is not None:
            return self._brain.get_params()
        return self._params if hasattr(self, '_params') else np.array([])

    def set_params(self, params: np.ndarray):
        """Update evolved parameters."""
        if self.brain_type == "ouroboros" and self._brain is not None:
            self._brain.set_params(params)
        elif self.brain_type == "dreamer" and self._brain is not None:
            self._brain.set_params(params)
        else:
            self._params = params
            self._init_mlp_layers()


