    # HOLD - Inference-Level Halt (requires cascade-lattice)
    # ═══════════════════════════════════════════════════════════

    def forward_hold(self, inputs: Dict[str, Any] = None, blocking: bool = True) -> Dict[str, Any]:
        \"\"\"
        Run inference with HOLD - yields at decision point.

        HOLD halts inference at the decision point, exposing the action
        probabilities for potential human override. Resolution is
        recorded to CASCADE with full provenance.

        Requires: cascade-lattice (pip install cascade-lattice)

        Args:
            inputs: Input dict
            blocking: If True, blocks until resolved (or timeout)

        Returns:
            Output dict including hold resolution data

        Usage:
            agent = CapsuleAgent()

            # In another thread or async:
            hold = get_hold()
            hold.override(3)  # Override AI choice with action 3
            # or: hold.accept()  # Accept AI's choice

            output = agent.forward_hold({{"obs": observation}})
            # output['was_override'] tells you if human overrode
        \"\"\"
        if not _HOLD_AVAILABLE:
            print("⚠️ HOLD requires cascade-lattice: pip install cascade-lattice")
            return self.forward(inputs, observe=True)

        inputs = inputs or {{"traits": self.traits}}
        self._inference_count += 1

        # Get decision matrix from brain
        output = self.brain.forward(inputs)

        action_probs = output.get('action_probs')
        if action_probs is None:
            # Non-dreamer brain - no HOLD support
            return self.forward(inputs, observe=True)

        # YIELD to HOLD system
        node_id = _NODE_DOCS[0]["node_id"] if _NODE_DOCS else "capsule"
        # Safely extract value - may be dict in nested brain outputs
        raw_value = output.get('value', 0.0)
        # Unwrap nested dicts recursively (handles {{'value': {{'value': 0.5}}}})
        while isinstance(raw_value, dict):
            raw_value = raw_value.get('value', raw_value.get('output', 0.0))
        if isinstance(raw_value, (int, float)) and not isinstance(raw_value, bool):
            hold_value = float(raw_value)
        else:
            hold_value = 0.0
        resolution = _HOLD_SYSTEM.yield_point(
            action_probs=np.array(action_probs),
            value=hold_value,
            observation=inputs,
            brain_id=f"key-evolved/{{node_id}}",
            blocking=blocking,
        )

        # Update output with resolution
        output['action'] = resolution['action']
        output['was_override'] = resolution['was_override']
        output['hold_id'] = resolution['hold_id']
        output['hold_duration'] = resolution.get('duration', 0.0)

        return output

