    def export_pt(self, path: str = "model.pt"):
        """Export to PyTorch format as a proper nn.Module."""
        try:
            import torch
            import torch.nn as nn

            # Get the underlying brain (CapsuleBrain wraps _brain)
            brain = getattr(self.brain, '_brain', self.brain)

            if hasattr(brain, 'adapter_in'):
                # ScarecrowBrain adapter architecture
                class ScarecrowModule(nn.Module):
                    def __init__(self):
                        super().__init__()
                        self.fc1 = nn.Linear(brain.input_dim, brain.adapter_dim, bias=False)
                        self.fc2 = nn.Linear(brain.adapter_dim, brain.output_dim)

                        with torch.no_grad():
                            self.fc1.weight.copy_(torch.tensor(brain.adapter_in.T, dtype=torch.float32))
                            self.fc2.weight.copy_(torch.tensor(brain.adapter_out.T, dtype=torch.float32))
                            self.fc2.bias.copy_(torch.tensor(brain.adapter_bias, dtype=torch.float32))

                    def forward(self, x):
                        return self.fc2(torch.tanh(self.fc1(x)))

                model = ScarecrowModule()
            else:
                # MLP brain architecture  
                class MLPModule(nn.Module):
                    def __init__(self):
                        super().__init__()
                        self.fc1 = nn.Linear(brain.w1.shape[0], brain.w1.shape[1])
                        self.fc2 = nn.Linear(brain.w2.shape[0], brain.w2.shape[1])

                        with torch.no_grad():
                            self.fc1.weight.copy_(torch.tensor(brain.w1.T, dtype=torch.float32))
                            self.fc1.bias.copy_(torch.tensor(brain.b1, dtype=torch.float32))
                            self.fc2.weight.copy_(torch.tensor(brain.w2.T, dtype=torch.float32))
                            self.fc2.bias.copy_(torch.tensor(brain.b2, dtype=torch.float32))

                    def forward(self, x):
                        return self.fc2(torch.tanh(self.fc1(x)))

                model = MLPModule()

            # Save as TorchScript for maximum portability
            scripted = torch.jit.script(model)
            scripted.save(path)
            print(f"Exported TorchScript model to {{path}}")
        except Exception as e:
            print(f"PyTorch export failed: {{e}}")

    def export_onnx(self, path: str = "model.onnx"):
        """Export to ONNX format."""
        try:
            import torch
            import torch.nn as nn

            # Get the underlying brain (CapsuleBrain wraps _brain)
            brain = getattr(self.brain, '_brain', self.brain)

            if hasattr(brain, 'adapter_in'):
                # ScarecrowBrain adapter architecture
                class AdapterModule(nn.Module):
                    def __init__(self, brain):
                        super().__init__()
                        self.fc1 = nn.Linear(brain.input_dim, brain.adapter_dim)
                        self.fc2 = nn.Linear(brain.adapter_dim, brain.output_dim)

                        with torch.no_grad():
                            self.fc1.weight.copy_(torch.tensor(brain.adapter_in.T))
                            self.fc1.bias.zero_()
                            self.fc2.weight.copy_(torch.tensor(brain.adapter_out.T))
                            self.fc2.bias.copy_(torch.tensor(brain.adapter_bias))

                    def forward(self, x):
                        return self.fc2(torch.tanh(self.fc1(x)))

                model = AdapterModule(brain)
                dummy = torch.randn(1, brain.input_dim)
                # Export with weights embedded in single file
                torch.onnx.export(model, dummy, path, input_names=["embedding"],
                                output_names=["output"],
                                export_params=True)
            else:
                # MLP brain architecture
                class MLPModule(nn.Module):
                    def __init__(self, brain):
                        super().__init__()
                        self.fc1 = nn.Linear(len(_TRAITS), brain.hidden_size)
                        self.fc2 = nn.Linear(brain.hidden_size, len(brain.output_keys))

                        with torch.no_grad():
                            self.fc1.weight.copy_(torch.tensor(brain.w1.T))
                            self.fc1.bias.copy_(torch.tensor(brain.b1))
                            self.fc2.weight.copy_(torch.tensor(brain.w2.T))
                            self.fc2.bias.copy_(torch.tensor(brain.b2))

                    def forward(self, x):
                        return self.fc2(torch.tanh(self.fc1(x)))

                model = MLPModule(brain)
                dummy = torch.randn(1, len(_TRAITS))
                # Export with weights embedded in single file
                torch.onnx.export(model, dummy, path, input_names=["traits"],
                                output_names=list(brain.output_keys),
                                export_params=True)

            # Ensure single file output (convert external data to internal)
            try:
                import onnx
                from pathlib import Path
                onnx_model = onnx.load(path)
                onnx.save_model(onnx_model, path, save_as_external_data=False)
                # Clean up any .data file
                data_file = Path(path + '.data')
                if data_file.exists():
                    data_file.unlink()
            except Exception:
                pass  # Single file already

            print(f"Exported to {{path}}")
        except Exception as e:
            print(f"ONNX export failed: {{e}}")

