        story = []

        # README
        story.append(Paragraph("📖 README", title_style))
        story.append(Spacer(1, 12))
        if _README:
            # Split into chunks
            for line in _README.split('\\n'):
                story.append(Paragraph(line or "&nbsp;", styles['Normal']))
        else:
            story.append(Paragraph("No README embedded.", styles['Normal']))
        story.append(PageBreak())

        # Config Doc
        story.append(Paragraph("⚙️ CONFIG", title_style))
        story.append(Spacer(1, 12))
        if _CONFIG_DOC:
            config_text = json.dumps(_CONFIG_DOC, indent=2)
            story.append(Preformatted(config_text[:5000], code_style))  # Limit size
        else:
            story.append(Paragraph("No config embedded.", styles['Normal']))
        story.append(PageBreak())

        # Population Doc
        story.append(Paragraph("👥 POPULATION", title_style))
        story.append(Spacer(1, 12))
        if _POPULATION_DOC:
            pop_text = json.dumps(_POPULATION_DOC, indent=2)
            story.append(Preformatted(pop_text[:5000], code_style))
        else:
            story.append(Paragraph("No population doc embedded.", styles['Normal']))
        story.append(PageBreak())

        # Node Docs
        story.append(Paragraph("🧬 NODE DOCUMENTATION", title_style))
        story.append(Spacer(1, 12))
        if _NODE_DOCS:
            for node_doc in _NODE_DOCS[:5]:  # Limit to 5 nodes
                node_text = json.dumps(node_doc, indent=2)
                story.append(Preformatted(node_text[:2000], code_style))
                story.append(Spacer(1, 12))
        else:
            story.append(Paragraph("No node docs embedded.", styles['Normal']))
        story.append(PageBreak())

        # FelixBag Summary
        story.append(Paragraph("🎒 FELIXBAG CONTENTS", title_style))
        story.append(Spacer(1, 12))
        bag_keys = _BAG.list()
