    @classmethod
    def reconstitute_from_pdf(cls, pdf_path: str, output_dir: str = None):
        \"\"\"Reconstitute an agent from an Instant Transmission PDF.\"\"\"
        try:
            from pypdf import PdfReader
        except ImportError:
            print("Reconstitution requires: pip install pypdf")
            return None

        pdf_path = Path(pdf_path)
        output_dir = Path(output_dir) if output_dir else pdf_path.parent
        output_dir.mkdir(parents=True, exist_ok=True)

        print(f"Reconstituting from: {{pdf_path.name}}")

        reader = PdfReader(str(pdf_path))

        if not reader.attachments:
            print("No attachments found - not an Instant Transmission PDF")
            return None

        for name, data_list in reader.attachments.items():
            for data in data_list:
                out_path = output_dir / name
                out_path.write_bytes(data)
                print(f"   Extracted: {{name}}")

        agent_path = output_dir / "agent.py"
        if not agent_path.exists():
            print("agent.py not found in attachments")
            return None

        import importlib.util
        spec = importlib.util.spec_from_file_location("agent", str(agent_path))
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)

        if hasattr(module, 'CapsuleAgent'):
            capsule = module.CapsuleAgent()
            print(f"Agent reconstituted! Gen {{capsule.generation}}, Fitness {{capsule.fitness:.4f}}")
            return capsule
        return module

    def export_capsule(self, path: str = None) -> str:
        """
        Export updated capsule (self-replication with new weights).
        """
        path = path or f"{{Path(__file__).stem}}_v{{self.generation + 1}}.py"

        # Read current file and update embedded data
        current = Path(__file__).read_text(encoding='utf-8')

        # Update brain data
        params = self.brain.get_params()
        data = pickle.dumps(params)
        if _DATA_COMPRESSED:
            data = gzip.compress(data)
        new_brain_data = base64.b64encode(data).decode('ascii')

        # Replace in source
        import re
        updated = re.sub(
            r'_BRAIN_DATA = """.*?"""',
            f'_BRAIN_DATA = """{{new_brain_data}}"""',
            current,
            flags=re.DOTALL
        )
        updated = re.sub(
            r'_GENERATION = \\d+',
            f'_GENERATION = {{self.generation + 1}}',
            updated
        )
        updated = re.sub(
            r'_FITNESS = [\\d.]+',
            f'_FITNESS = {{self.fitness}}',
            updated
        )

        Path(path).write_text(updated, encoding='utf-8')
        print(f"Exported capsule to {{path}}")
        return path

