    def replicate(self) -> 'CapsuleAgent':
        """
        Create exact clone (quine replication).
        The clone has identical weights and traits.
        """
        clone = CapsuleAgent(observe=False, observe_visual=False)
        clone.brain._params = self.brain._params.copy() if hasattr(self.brain, '_params') else None
        clone.traits = self.traits.copy()
        clone.fitness = self.fitness
        clone.generation = self.generation
        return clone

    def fork(self, mutation_rate: float = 0.1) -> 'CapsuleAgent':
        """
        Create mutated child (for swarm evolution).

        Args:
            mutation_rate: Probability of mutating each weight

        Returns:
            New CapsuleAgent with mutated weights
        """
        child = self.replicate()
        if hasattr(child.brain, '_params') and child.brain._params is not None:
            mask = np.random.random(child.brain._params.shape) < mutation_rate
            noise = np.random.randn(*child.brain._params.shape) * 0.1
            child.brain._params = child.brain._params + mask * noise
            child.generation = self.generation + 1
        return child

    def spawn_swarm(self, n: int, mutate: bool = True) -> list:
        """
        Spawn n clones for parallel orchestration.

        Args:
            n: Number of clones to create
            mutate: If True, each clone is mutated

        Returns:
            List of n CapsuleAgent clones
        """
        swarm = []
        for _ in range(n):
            if mutate:
                swarm.append(self.fork())
            else:
                swarm.append(self.replicate())
        return swarm

    def orchestrate(self, models: list) -> list:
        """
        Wrap multiple models with cloned adapters.

        Args:
            models: List of callables to orchestrate

        Returns:
            List of CapsuleAgents, each wrapping a model
        """
        agents = []
        for model in models:
            agent = self.replicate()
            agent._external_model = model
            agents.append(agent)
        return agents

    def broadcast(self, inputs: dict, agents: list = None) -> list:
        """
        Forward through all agents in parallel.

        Args:
            inputs: Input dict to send to all agents
            agents: List of agents (defaults to [self])

        Returns:
            List of outputs from each agent
        """
        targets = agents or [self]
        return [agent.forward(inputs, observe=False) for agent in targets]

    def merge(self, other: 'CapsuleAgent', ratio: float = 0.5) -> 'CapsuleAgent':
        """
        Blend two agents' weights.

        Args:
            other: Another CapsuleAgent to merge with
            ratio: Blend ratio (0.5 = equal blend)

        Returns:
            New CapsuleAgent with blended weights
        """
        merged = self.replicate()
        if hasattr(self.brain, '_params') and hasattr(other.brain, '_params'):
            if self.brain._params is not None and other.brain._params is not None:
                merged.brain._params = (
                    self.brain._params * ratio + 
                    other.brain._params * (1 - ratio)
                )
        return merged

    def get_merkle_hash(self) -> str:
        """
        Compute cryptographic hash of current weights.

        Returns:
            16-character hex hash string
        """
        import hashlib
        if hasattr(self.brain, '_params') and self.brain._params is not None:
            return hashlib.sha256(
                self.brain._params.astype(np.float32).tobytes()
            ).hexdigest()[:16]
        return hashlib.sha256(b"no_params").hexdigest()[:16]

    def join_lattice(self, lattice_url: str = None) -> dict:
        """
        Connect to a hyperlattice swarm for collective navigation.

        Args:
            lattice_url: URL of lattice server (e.g., HuggingFace Space)
                        Defaults to local cascade_hyperlattice

        Returns:
            Connection status and agent position in lattice
        """
        # Try to import cascade_hyperlattice
        try:
            from cascade_hyperlattice.src.swarm import QuineAgent, QuineSwarm
            from cascade_hyperlattice.src.lattice import Hyperlattice

            # Create a QuineAgent wrapper for this CapsuleAgent
            agent_id = f"capsule_{{self.get_merkle_hash()[:8]}}"
            quine_agent = QuineAgent(
                agent_id=agent_id,
                quine_hash=self.get_merkle_hash(),
                parent_hash=None,
                generation=self.generation,
                position="n_0_0_0",  # Start at origin
            )
            # Attach this CapsuleAgent's brain to the QuineAgent
            quine_agent.brain = self

            return {{
                "status": "connected",
                "agent_id": agent_id,
                "quine_hash": quine_agent.quine_hash,
                "lattice": "local",
            }}
        except ImportError:
            return {{
                "status": "not_available",
                "message": "cascade_hyperlattice not installed",
                "install": "Clone from: https://huggingface.co/spaces/tostido/Cascade-Hyperlattice",
            }}


