def _sanitize_for_hash(data: Any) -> Any:
    """
    Sanitize data structure for cascade hash_input.

    Converts unhashable dict keys (like slice objects from JAX/ninjax)
    to strings so sorted(dict.items()) doesn't fail.
    Also converts numpy arrays to lists for JSON compatibility.
    """
    if isinstance(data, dict):
        sanitized = {{}}
        for k, v in data.items():
            # Convert unhashable keys to string representation
            try:
                hash(k)
                safe_key = k
            except TypeError:
                safe_key = str(k)
            sanitized[safe_key] = _sanitize_for_hash(v)
        return sanitized
    elif isinstance(data, (list, tuple)):
        return [_sanitize_for_hash(x) for x in data]
    elif hasattr(data, 'tolist'):  # numpy array
        return data.tolist()
    elif hasattr(data, 'item'):  # numpy scalar
        return data.item()
    else:
        return data


def _observe_inference(model_id: str, input_data: Any, output_data: Any, 
                       internals: Dict = None, metrics: Dict = None) -> Optional[Dict]:
    """
    Observe an inference call with FULL COMPUTATIONAL INTERNALS.

    This is Glass Box observation - not just I/O receipts, but proof
    of the actual computation that occurred. The merkle hash covers
    the internals, making the proof verifiable.

    Returns full observation record (for Rerun visualization).
    """
    if not _HAS_CASCADE or not _CASCADE_MONITOR:
        return None

    # Sanitize data to prevent unhashable key errors (slice objects from JAX/ninjax)
    safe_input = _sanitize_for_hash(input_data)
    safe_output = _sanitize_for_hash(output_data)
    safe_internals = _sanitize_for_hash(internals or {{}})
    safe_metrics = _sanitize_for_hash(metrics or {{}})

    # Build complete observation record
    observation = {{
        "model_id": model_id,
        "timestamp": __import__('datetime').datetime.now().isoformat(),
        "input": safe_input,
        "output": safe_output,
        "internals": safe_internals,
        "metrics": safe_metrics,
    }}

    try:
        # Observe through CASCADE Monitor
        event = _CASCADE_MONITOR.observe(observation)

        # Compute merkle hash of the full event (already sanitized)
        merkle_root = hash_input(event.to_dict())

        observation["event_id"] = event.event_id
        observation["merkle_root"] = merkle_root
        observation["genesis_linked"] = True
        return observation
    except Exception as e:
        observation["error"] = str(e)
        return observation


