def _log_bag_state(bag: 'FelixBag'):
    """Log FelixBag state to Rerun for visualization."""
    if not _HAS_RERUN or not _RERUN_INITIALIZED:
        return

    items = bag._bag if hasattr(bag, '_bag') else {{}}

    # Count items by type
    type_counts = {{}}
    embeddings = []
    item_names = []

    for key, item in items.items():
        item_type = item.get('type', 'unknown') if isinstance(item, dict) else 'unknown'
        type_counts[item_type] = type_counts.get(item_type, 0) + 1

        # Collect embeddings for projection
        if isinstance(item, dict) and 'embedding' in item:
            emb = item['embedding']
            if isinstance(emb, list) and len(emb) > 0:
                embeddings.append(emb)
                item_names.append(key)

    # Log type distribution
    if type_counts:
        rr.log("bag/type_counts", rr.BarChart(list(type_counts.values())))

    # Log total size
    rr.log("bag/size", rr.Scalars([len(items)]))

    # Log embedding space (2D projection via simple PCA-like reduction)
    if embeddings and len(embeddings) >= 2:
        emb_array = np.array(embeddings)
        # Simple 2D projection: first 2 principal components
        mean = emb_array.mean(axis=0)
        centered = emb_array - mean
        # Use first 2 dimensions as simple projection
        if centered.shape[1] >= 2:
            projected = centered[:, :2]
            rr.log("bag/embeddings", rr.Tensor(projected))

    # Log recent item names
    recent = list(items.keys())[-10:]  # Last 10 items
    for name in recent:
        rr.log("bag/items", rr.TextLog(f"📦 {{name}}"))


def _log_capsule_metadata():
    """Log static capsule metadata to Rerun (CASCADE identity)."""
    if not _HAS_RERUN or not _RERUN_INITIALIZED:
        return

    # Skip if we're in compilation context (globals not yet defined)
    if '_GENERATION' not in globals():
        return

    # Safely get globals with defaults
    gen = globals().get('_GENERATION', 0)
    fit = globals().get('_FITNESS', 0.0)
    gen_root = globals().get('_GENESIS_ROOT', 'unknown')

    # This is the capsule's CASCADE identity - static
    rr.log("identity/model_id", rr.TextLog(f"key-evolved/capsule"), static=True)

    # Log welcome
    rr.log("logs", rr.TextLog(
        f"🔮 Glass Box - CASCADE Event Viewer",
        level=rr.TextLogLevel.INFO
    ))
    rr.log("logs", rr.TextLog(
        f"   Gen {{gen}} | Fitness {{fit:.4f}} | Genesis {{gen_root[:12]}}...",
        level=rr.TextLogLevel.INFO
    ))

    # Seed State Space tab (Tab 3) so blueprint dropdowns are connected
    try:
        traits = globals().get('_TRAITS', {{}})

        # state/traits — evolved trait vector as bar chart
        if traits and isinstance(traits, dict):
            rr.log("state/traits", rr.BarChart(list(traits.values())))

        # state/fitness — initial fitness value
        rr.log("state/fitness", rr.Scalars([float(fit)]))

        # state/slots/activity — zero activity for all slots at startup
        council_cfg = globals().get('_QUINE_COUNCIL_CONFIG', {{}})
        num_slots = council_cfg.get('num_councilors', 24) if isinstance(council_cfg, dict) else 24
        rr.log("state/slots/activity", rr.BarChart([0.0] * num_slots))
