# DATASET BRIDGING FACULTIES (CASCADE DATA_UNITY)
# ═══════════════════════════════════════════════════════════════


class BridgeFaculty:
    """
    Dataset bridging capability for evolved agents.

    Implements CASCADE's data_unity pattern:
    - Load datasets into canonical form
    - Find matches across datasets using Kleene fixed-point iteration
    - Produce provenance-linked bridges with merkle roots
    - Link to genesis when cascade-lattice available

    Uses vectorized matching when embeddings present for O(n²) → O(nm) batched ops.
    """

    def __init__(self, agent: 'CapsuleAgent'):
        self.agent = agent
        self._embed_model = None
        self._provenance_chain = []  # Local chain if no cascade

    def load_dataframe(self, df, source_name: str, id_column: str = None):
        """Convert pandas DataFrame to canonical form."""
        import hashlib

        entities = []
        schema_str = json.dumps({{col: str(df[col].dtype) for col in df.columns}}, sort_keys=True)
        schema_hash = hashlib.sha256(schema_str.encode()).hexdigest()[:16]

        for idx, row in df.iterrows():
            entity_id = str(row[id_column]) if id_column and id_column in df.columns else f"row_{{idx}}"
            entities.append({{
                'id': f"{{source_name}}:{{entity_id}}",
                'source': source_name,
                'attributes': {{col: self._serialize(row[col]) for col in df.columns}},
                'embedding': None,
            }})

        return {{'source': source_name, 'entities': entities, 'schema_hash': schema_hash}}

    def embed(self, form: dict):
        """Compute embeddings for all entities with model-level provenance."""
        if self._embed_model is None:
            # Check if embedding model is configured
            if _EMBEDDING_MODEL is None:
                # No embedding model - fail hard
                raise RuntimeError("CASCADE-LATTICE requires an embedding model. Set _EMBEDDING_MODEL or plug an embedding foundation.")

            try:
                from sentence_transformers import SentenceTransformer
                self._embed_model = SentenceTransformer(_EMBEDDING_MODEL)
                # Wire shared embedder to FelixBag - ONE model for all
                FelixBag.set_shared_embedder(self._embed_model, f'CapsuleBrain:{{_EMBEDDING_MODEL}}')
            except ImportError as e:
                # No sentence-transformers - fail hard
                raise RuntimeError(f"CASCADE-LATTICE requires sentence-transformers: {{e}}")

        texts = []
        for entity in form['entities']:
            parts = [f"{{k}}: {{v}}" for k, v in entity['attributes'].items()]
            texts.append(" | ".join(parts))

        embeddings = self._embed_model.encode(texts, show_progress_bar=False)

        # Hash embeddings for provenance
        import hashlib
        for entity, emb in zip(form['entities'], embeddings):
            entity['embedding'] = emb.tolist()
            entity['embedding_hash'] = hashlib.sha256(emb.tobytes()).hexdigest()[:16]

        return form

    def bridge(self, old_form: dict, new_form: dict, min_confidence: float = 0.5) -> dict:
        """
        Find matches between two datasets using Kleene fixed-point iteration.

        Uses agent traits to tune matching:
        - attr_weight, embed_weight: Balance attribute vs embedding similarity
        - min_confidence: Threshold for matches

        Returns provenance-linked bridge with merkle root.
        """
        import hashlib

        # Get weights from agent traits (evolved!)
        attr_weight = self.agent.traits.get('attr_weight', 0.5)
        embed_weight = self.agent.traits.get('embed_weight', 0.5)
        total = attr_weight + embed_weight
        if total > 0:
            attr_weight /= total
            embed_weight /= total

        # Try vectorized matching first
        matches = self._vectorized_match(old_form, new_form, attr_weight, embed_weight, min_confidence)

        if matches is None:
            # Fallback to pairwise Kleene iteration
            matches = self._kleene_match(old_form, new_form, attr_weight, embed_weight, min_confidence)

        # Compute merkle root (use cascade if available)
        merkle_root = self._compute_merkle(matches)

        # Record in provenance chain
        bridge_record = {{
            'type': 'bridge',
            'old_source': old_form['source'],
            'new_source': new_form['source'],
            'match_count': len(matches),
            'merkle_root': merkle_root,
            'parent': self._provenance_chain[-1]['merkle_root'] if self._provenance_chain else _GENESIS_ROOT,
        }}
        self._provenance_chain.append(bridge_record)

        return {{
            'matches': matches,
            'iterations': matches[-1]['iteration'] + 1 if matches else 0,
            'merkle_root': merkle_root,
            'old_source': old_form['source'],
            'new_source': new_form['source'],
            'genesis_linked': _HAS_CASCADE,
        }}

    def _vectorized_match(self, old_form, new_form, attr_w, embed_w, threshold):
        """Vectorized batch matching using matrix ops."""
        old_entities = old_form['entities']
        new_entities = new_form['entities']

        # Check if embeddings available
        old_embs = [e.get('embedding') for e in old_entities]
        new_embs = [e.get('embedding') for e in new_entities]

        if not all(old_embs) or not all(new_embs):
            return None  # Fall back to pairwise

        # Build embedding matrices
        mat_old = np.array(old_embs)
        mat_new = np.array(new_embs)

        # Normalize for cosine similarity
        norm_old = np.linalg.norm(mat_old, axis=1, keepdims=True) + 1e-8
        norm_new = np.linalg.norm(mat_new, axis=1, keepdims=True) + 1e-8
        mat_old_norm = mat_old / norm_old
        mat_new_norm = mat_new / norm_new

        # Compute all similarities at once: (n, m) matrix
        embed_sims = (mat_old_norm @ mat_new_norm.T + 1) / 2  # Scale to [0, 1]

        # Weighted similarity (embed only for vectorized)
        all_sims = embed_sims * embed_w + 0.5 * attr_w  # Assume 50% attr match

        matches = []
        for i, e_old in enumerate(old_entities):
            for j, e_new in enumerate(new_entities):
                if all_sims[i, j] >= threshold:
                    matches.append({{
                        'old_id': e_old['id'],
                        'new_id': e_new['id'],
                        'confidence': float(all_sims[i, j]),
                        'iteration': 0,
                    }})

        return matches if matches else None

    def _kleene_match(self, old_form, new_form, attr_w, embed_w, threshold):
        """Kleene fixed-point iteration for matching."""
        matches = []
        match_keys = set()

        for iteration in range(20):
            new_matches = 0

            for e_old in old_form['entities']:
                for e_new in new_form['entities']:
                    key = tuple(sorted([e_old['id'], e_new['id']]))
                    if key in match_keys:
                        continue

                    sim = self._similarity(e_old, e_new, attr_w, embed_w)

                    if sim >= threshold:
                        matches.append({{
                            'old_id': e_old['id'],
                            'new_id': e_new['id'],
                            'confidence': sim,
                            'iteration': iteration,
                        }})
                        match_keys.add(key)
                        new_matches += 1

            if new_matches == 0:
                break  # Fixed point reached

        return matches

    async def star(self, stream, min_confidence: float = 0.5):
        """
        Kleene star - endless streaming fixed-point iteration.

        The closure grows forever as new entities arrive. Each yield
        is x* for the data seen so far.

        Args:
            stream: Async iterator yielding entities (never ends)
            min_confidence: Match threshold

        Yields:
            Current match closure after each new entity

        Usage:
            async for closure in bridge.star(entity_stream):
                print(f"Matches so far: {{len(closure['matches'])}}")
                if done:
                    bridge.stop()  # Graceful shutdown
        """
        import hashlib

        self._running = True  # Off switch

        # Get weights from evolved traits
        attr_weight = self.agent.traits.get('attr_weight', 0.5)
        embed_weight = self.agent.traits.get('embed_weight', 0.5)
        total = attr_weight + embed_weight
        if total > 0:
            attr_weight /= total
            embed_weight /= total

        # State: all entities seen, all matches found
        entities = []
        matches = []
        match_keys = set()
        iteration = 0

        async for entity in stream:
            if not self._running:
                # Graceful shutdown - yield final state before exit
                merkle = self._compute_merkle(matches)
                yield {{
                    'matches': matches.copy(),
                    'match_count': len(matches),
                    'entity_count': len(entities),
                    'iteration': iteration,
                    'merkle_root': merkle,
                    'new_matches': 0,
                    'final': True,  # Signals clean termination
                    'reason': 'stopped',
                }}
                self._running = False
                return  # Clean exit from generator

            iteration += 1

            # Embed if not already
            if entity.get('embedding') is None and self._embed_model is not None:
                text = " | ".join(f"{{k}}: {{v}}" for k, v in entity.get('attributes', {{}}).items())
                emb = self._embed_model.encode([text], show_progress_bar=False)[0]
                entity['embedding'] = emb.tolist()
                entity['embedding_hash'] = hashlib.sha256(emb.tobytes()).hexdigest()[:16]

            # Match against all existing entities
            new_matches = []
            for existing in entities:
                key = tuple(sorted([entity['id'], existing['id']]))
                if key in match_keys:
                    continue

                sim = self._similarity(entity, existing, attr_weight, embed_weight)

                if sim >= min_confidence:
                    match = {{
                        'source_id': entity['id'],
                        'target_id': existing['id'],
                        'confidence': sim,
                        'iteration': iteration,
                    }}
                    matches.append(match)
                    match_keys.add(key)
                    new_matches.append(match)

            # Transitive closure: propagate through existing matches
            if new_matches:
                matches, match_keys = self._transitive_close(matches, match_keys, min_confidence)

            # Add to entity pool
            entities.append(entity)

            # Yield current x* (the fixed point for data seen so far)
            merkle = self._compute_merkle(matches)
            yield {{
                'matches': matches.copy(),
                'match_count': len(matches),
                'entity_count': len(entities),
                'iteration': iteration,
                'merkle_root': merkle,
                'new_matches': len(new_matches),
                'final': False,
            }}

        # Stream ended naturally - yield final state
        merkle = self._compute_merkle(matches)
        yield {{
            'matches': matches.copy(),
            'match_count': len(matches),
            'entity_count': len(entities),
            'iteration': iteration,
            'merkle_root': merkle,
            'new_matches': 0,
            'final': True,
            'reason': 'stream_ended',
        }}
        self._running = False

    def _transitive_close(self, matches, match_keys, threshold):
        """Compute transitive closure of matches."""
        # Build adjacency: entity -> set of matched entities
        adj = {{}}
        for m in matches:
            a, b = m.get('source_id') or m.get('old_id'), m.get('target_id') or m.get('new_id')
            adj.setdefault(a, set()).add(b)
            adj.setdefault(b, set()).add(a)

        # Propagate: if A~B and B~C, then A~C (inferred)
        changed = True
        while changed:
            changed = False
            for entity, neighbors in list(adj.items()):
                for neighbor in list(neighbors):
                    for transitive in adj.get(neighbor, []):
                        if transitive != entity:
                            key = tuple(sorted([entity, transitive]))
                            if key not in match_keys:
                                # Inferred match
                                matches.append({{
                                    'source_id': entity,
                                    'target_id': transitive,
                                    'confidence': threshold,  # Min confidence for inferred
                                    'iteration': -1,  # Marks as transitive
                                    'inferred': True,
                                }})
                                match_keys.add(key)
                                adj.setdefault(entity, set()).add(transitive)
                                adj.setdefault(transitive, set()).add(entity)
                                changed = True

        return matches, match_keys

    def stop(self):
        """Stop the star() iterator gracefully."""
        self._running = False

    def is_running(self) -> bool:
        """Check if star() is currently running."""
        return getattr(self, '_running', False)

    def _compute_merkle(self, matches):
        """Compute merkle root, using cascade-lattice if available."""
        import hashlib

        if _HAS_CASCADE and matches:
            # Use cascade's proper merkle computation
            match_hashes = [hashlib.sha256(json.dumps(m, sort_keys=True).encode()).hexdigest() for m in matches]
            return compute_merkle_root(match_hashes)

        # Fallback merkle
        if matches:
            hashes = sorted([hashlib.sha256(json.dumps(m, sort_keys=True).encode()).hexdigest()[:16] for m in matches])
            return hashlib.sha256(''.join(hashes).encode()).hexdigest()[:16]
        return hashlib.sha256(b'empty').hexdigest()[:16]

    def _similarity(self, e1: dict, e2: dict, attr_weight: float, embed_weight: float) -> float:
        """Compute hybrid similarity."""
        # Attribute similarity
        attr_sim = 0.0
        common = set(e1['attributes'].keys()) & set(e2['attributes'].keys())
        if common:
            matches = sum(1 for k in common if e1['attributes'][k] == e2['attributes'][k])
            attr_sim = matches / len(common)

        # Embedding similarity
        embed_sim = 0.0
        if e1.get('embedding') and e2.get('embedding'):
            a = np.array(e1['embedding'])
            b = np.array(e2['embedding'])
            norm_a, norm_b = np.linalg.norm(a), np.linalg.norm(b)
            if norm_a > 0 and norm_b > 0:
                embed_sim = (np.dot(a, b) / (norm_a * norm_b) + 1) / 2

        return attr_weight * attr_sim + embed_weight * embed_sim

    def _serialize(self, v):
        """Make value JSON-serializable."""
        try:
            json.dumps(v)
            return v
        except Exception:
            return str(v)

    def get_provenance_chain(self):
        """Get local provenance chain."""
        return self._provenance_chain


