def export_interface(output_dir: str = None) -> str:
    """
    Generate a complete game interface for this model.

    Creates:
    - manifest.json: Model capabilities and metadata
    - server.py: HTTP server bridging game engine to this model
    - launch.bat: Windows launcher
    - launch.sh: Unix launcher

    The server works with any game engine that speaks HTTP/JSON:
    - Panda3D (Python)
    - Pygame
    - Godot
    - Unity
    - Or any custom client

    Returns path to the generated interface directory.
    """
    import os
    import sys

    model_name = Path(__file__).stem
    output_dir = output_dir or f"{{model_name}}_interface"
    interface_path = Path(output_dir)
    interface_path.mkdir(parents=True, exist_ok=True)

    model_file = Path(__file__).resolve()

    # 1. Generate manifest.json
    manifest = {{
