    manifest_path = interface_path / "manifest.json"
    manifest_path.write_text(json.dumps(manifest, indent=2), encoding='utf-8')
    print(f"✓ Generated {{manifest_path}}")

    # 2. Generate server.py
    server_code = """#!/usr/bin/env python3
\\"\\"\\"
Model Interface Server - Bridges game engine to {{model_name}}

Auto-generated. Do not edit directly.
Run this server, then connect from any game engine (Panda3D, Pygame, Godot, etc.).

Usage:
    python server.py              # Start on default port 8765
    python server.py --port 9000  # Custom port
\\"\\"\\"

