    class WorkflowExecutor:
        \"\"\"Python-native workflow execution engine v2.2.0.

        Executes DAG-based workflows with 10 node types:
        - tool       : Universal node - calls ANY MCP tool by name
        - agent      : Agentic node - plugged model operates granted MCP tools in a loop
        - input      : Workflow entry point (passes $input through)
        - output     : Workflow exit point (collects upstream results)
        - fan_out    : Parallel dispatch via ThreadPoolExecutor
        - http       : HTTP requests (GET, POST, etc.)
        - if         : Conditional branching
        - set        : Data transformation
        - merge      : Branch merging
        - web_search : Web search (Brave, SearXNG, Serper providers)
        \"\"\"

        def __init__(self, cascade_monitor=None):
            self.cascade = cascade_monitor
            self.node_handlers = {{
                "http": self._execute_http,
                "if": self._execute_if,
                "set": self._execute_set,
                "merge": self._execute_merge,
                "tool": self._execute_tool,
                "input": self._execute_input,
                "output": self._execute_output,
                "fan_out": self._execute_fan_out,
                "web_search": self._execute_web_search,
                "agent": self._execute_agent,
            }}
            self._execution_state = {{}}
            self._node_outputs = {{}}
            self._tool_registry = {{}}

        def _build_dag(self, workflow: dict) -> tuple:
            \"\"\"Build DAG from workflow and return execution order.

            Returns:
                Tuple of (execution_order, node_map, reverse_connections)
            \"\"\"
            nodes = workflow.get("nodes", [])
            connections = workflow.get("connections", [])

            # Build node map for quick lookup
            node_map = {{n["id"]: n for n in nodes}}

            # Build adjacency list and in-degree count for topological sort
            in_degree = {{n["id"]: 0 for n in nodes}}
            adjacency = {{n["id"]: [] for n in nodes}}

            # Track connections by target (for merge nodes)
            reverse_connections = {{}}  # target_id -> [(source_id, branch)]

            for conn in connections:
                # Validate required connection fields
                from_id = conn.get("from")
                to_id = conn.get("to")
                if not from_id or not to_id:
                    raise ValueError(f"Invalid connection - missing 'from' or 'to': {{conn}}")
                branch = conn.get("branch")
                adjacency[from_id].append(to_id)
                in_degree[to_id] += 1

                if to_id not in reverse_connections:
                    reverse_connections[to_id] = []
                reverse_connections[to_id].append((from_id, branch))

            # Kahn's algorithm for topological sort
            queue = [n for n in in_degree if in_degree[n] == 0]
            execution_order = []

            while queue:
                node = queue.pop(0)
                execution_order.append(node)
                for neighbor in adjacency[node]:
                    in_degree[neighbor] -= 1
                    if in_degree[neighbor] == 0:
                        queue.append(neighbor)

            # Check for cycles
            if len(execution_order) != len(nodes):
                raise ValueError("Workflow contains cycles - must be a DAG")

            return execution_order, node_map, reverse_connections

        def _resolve_ref(self, ref, context):
            \"\"\"Resolve a single $-expression reference.

            Returns resolved value or None if unresolvable.
            \"\"\"
            import uuid as uuid_mod
            from datetime import datetime
            ref = ref.strip()
            if ref == "$now":
                return datetime.utcnow().isoformat() + "Z"
            elif ref == "$uuid":
                return str(uuid_mod.uuid4())
            elif ref == "$random":
                import random
                return str(random.random())
            try:
                if ref.startswith("$input"):
                    path = ref[6:]
                    if path.startswith("."):
                        path = path[1:]
                    obj = context.get("$input", {{}})
                    for part in path.split(".") if path else []:
                        _arr = None
                        if '[' in part and part.endswith(']'):
                            _bkt = part.index('[')
                            _istr = part[_bkt+1:-1]
                            if _istr.isdigit():
                                _arr = (part[:_bkt], int(_istr))
                        if _arr and isinstance(obj, dict):
                            obj = obj.get(_arr[0])
                            if isinstance(obj, (list, tuple)):
                                obj = obj[_arr[1]] if _arr[1] < len(obj) else None
                        elif not _arr and isinstance(obj, dict):
                            obj = obj.get(part)
                        else:
                            return None
                        if obj is None:
                            return None
                    return obj
                elif ref.startswith("$node."):
                    parts = ref[6:].split(".")
                    node_id = parts[0]
                    obj = context.get("$node", {{}}).get(node_id, {{}})
                    for part in parts[1:]:
                        _arr = None
                        if '[' in part and part.endswith(']'):
                            _bkt = part.index('[')
                            _istr = part[_bkt+1:-1]
                            if _istr.isdigit():
                                _arr = (part[:_bkt], int(_istr))
                        if _arr and isinstance(obj, dict):
                            obj = obj.get(_arr[0])
                            if isinstance(obj, (list, tuple)):
                                obj = obj[_arr[1]] if _arr[1] < len(obj) else None
                        elif not _arr and isinstance(obj, dict):
                            obj = obj.get(part)
                        else:
                            return None
                        if obj is None:
                            return None
                    return obj
                elif ref.startswith("$env."):
                    import os
                    return os.environ.get(ref[5:], "")
            except Exception:
                pass
            return None

        def _resolve_expression(self, expr, context: dict):
            \"\"\"Resolve $-expressions in a value.

            Pass 1: Bare $-expression as entire value (preserves type).
            Pass 2: Inline {{{{$expr}}}} wrapped expressions in larger strings.
            \"\"\"
            import re

            if not isinstance(expr, str):
                return expr

            # Pass 1: Entire string is a bare $-expression — resolve directly
            stripped = expr.strip()
            if stripped.startswith("$") and " " not in stripped:
                # Handle ${{expr}} syntax — strip braces
                if stripped.startswith("${{") and stripped.endswith("}}"):
                    stripped = "$" + stripped[2:-1]
                result = self._resolve_ref(stripped, context)
                if result is not None:
                    return result

            # Pass 2: Inline {{{{...}}}} wrapped expressions
            pattern = r"\\{{\\{{(.+?)\\}}\\}}"
            def replace_expr(match):
                inner = match.group(1).strip()
                result = self._resolve_ref(inner, context)
                return str(result) if result is not None else match.group(0)

            resolved = re.sub(pattern, replace_expr, expr)

            # Pass 3: Inline ${{expr}} syntax in larger strings
            pattern2 = r"\\$\\{{(.+?)\\}}"
            def replace_dollar_brace(match):
                inner = "$" + match.group(1).strip()
                result = self._resolve_ref(inner, context)
                return str(result) if result is not None else match.group(0)

            resolved = re.sub(pattern2, replace_dollar_brace, resolved)
            return resolved

        def _resolve_dict(self, d: dict, context: dict) -> dict:
            \"\"\"Recursively resolve expressions in a dict.\"\"\"
            result = {{}}
            for k, v in d.items():
                if isinstance(v, dict):
                    result[k] = self._resolve_dict(v, context)
                elif isinstance(v, list):
                    result[k] = [self._resolve_expression(item, context) if isinstance(item, str) else item for item in v]
                else:
                    result[k] = self._resolve_expression(v, context)
            return result

        def _validate_params(self, params: dict, context: dict = None) -> tuple[bool, list]:
            \"\"\"Validate parameters for missing or invalid values.

            Args:
                params: Parameters to validate
                context: Workflow execution context (for diagnostic info)

            Returns:
                Tuple of (is_valid, errors)
            \"\"\"
            import re as _re
            errors = []
            for key, value in params.items():
                if value is None:
                    errors.append("Parameter '" + str(key) + "' is null")
                elif isinstance(value, str) and value.strip() == "":
                    errors.append("Parameter '" + str(key) + "' is empty")
                elif isinstance(value, str) and "{{{{" in value:
                    # Extract unresolved {{{{...}}}} patterns for diagnostic detail
                    unresolved = _re.findall(r'\\{{\\{{(.+?)\\}}\\}}', value)
                    if unresolved and context:
                        details = []
                        for expr in unresolved:
                            expr = expr.strip()
                            if expr.startswith("$node."):
                                parts = expr[6:].split(".")
                                node_id = parts[0]
                                requested_key = parts[1] if len(parts) > 1 else "?"
                                node_data = context.get("$node", {{}}).get(node_id, {{}})
                                if node_data:
                                    available = sorted(node_data.keys())
                                    details.append("{{{{$node." + node_id + "." + requested_key + "}}}} - node '" + node_id + "' has keys: " + str(available))
                                else:
                                    details.append("{{{{$node." + node_id + "." + requested_key + "}}}} - node '" + node_id + "' has no outputs (failed or not yet executed)")
                            elif expr.startswith("$input."):
                                field = expr[7:]
                                available_inputs = sorted(context.get("$input", {{}}).keys())
                                details.append("{{{{" + expr + "}}}} - available input fields: " + str(available_inputs))
                            else:
                                details.append("{{{{" + expr + "}}}}")
                        errors.append("Parameter '" + str(key) + "' has unresolved: " + "; ".join(details))
                    elif unresolved:
                        errors.append("Parameter '" + str(key) + "' has unresolved expressions: " + ", ".join("{{{{" + e.strip() + "}}}}" for e in unresolved))
                    else:
                        errors.append("Parameter '" + str(key) + "' has unresolved expression")
            return len(errors) == 0, errors

        def execute(self, workflow: dict, input_data: dict = None) -> dict:
            \"\"\"Execute a workflow with input data.

            Args:
                workflow: Workflow definition dict
                input_data: Input data for the workflow

            Returns:
                Execution result dict
            \"\"\"
            import time
            import uuid
            import os
            from datetime import datetime

            exec_id = f"exec_{{uuid.uuid4().hex[:12]}}"
            start_time = time.time()
            started_at = datetime.now().isoformat()
            input_data = input_data or {{}}

            try:
                # Validate workflow structure
                if "nodes" not in workflow or "connections" not in workflow:
                    return {{
                        "execution_id": exec_id,
                        "status": "failed",
                        "error": "Invalid workflow: missing nodes or connections",
                        "started_at": started_at
                    }}

                # Build DAG and get execution order
                execution_order, node_map, reverse_connections = self._build_dag(workflow)

                # Pre-flight: validate that agent nodes reference populated slots
                try:
                    _si_func = self._tool_registry.get("slot_info")
                    if _si_func:
                        for _nid, _nd in node_map.items():
                            if _nd.get("type") == "agent":
                                _np = _nd.get("parameters", _nd.get("params", {{}}))
                                _slot = _np.get("slot")
                                if _slot is not None:
                                    try:
                                        _slot = int(_slot)
                                    except (ValueError, TypeError):
                                        continue
                                    _si_raw = _si_func(slot=_slot)
                                    _si = json.loads(_si_raw) if isinstance(_si_raw, str) else _si_raw
                                    if not _si.get("plugged", False):
                                        return {{
                                            "execution_id": exec_id,
                                            "status": "failed",
                                            "error": f"Slot {{_slot}} ({{_si.get('name', 'unnamed')}}) is empty - plug a model before running this workflow",
                                            "started_at": started_at
                                        }}
                except Exception:
                    pass  # Pre-flight is best-effort

                # Initialize workflow inputs from input-node defaults, then let explicit
                # workflow_execute(input_data) values override them.
                _input_defaults = {{}}
                for _wf_node in workflow.get("nodes", []):
                    if _wf_node.get("type") == "input":
                        _wf_params = _wf_node.get("parameters", _wf_node.get("params", {{}}))
                        if isinstance(_wf_params, dict) and _wf_params:
                            _wf_ctx = {{
                                "$input": input_data,
                                "$node": {{}},
                                "$env": dict(os.environ),
                            }}
                            _input_defaults.update(self._resolve_dict(_wf_params, _wf_ctx))
                _workflow_input = dict(_input_defaults)
                if isinstance(input_data, dict) and input_data:
                    _workflow_input.update(input_data)

                context = {{
                    "$input": _workflow_input,
                    "$node": {{}},
                    "$env": dict(os.environ),
                }}

                # Track node states
                node_states = {{}}
                final_output = None

                # Execute nodes in topological order
                for node_id in execution_order:
                    node = node_map[node_id]
                    node_type = node.get("type")
                    node_start = time.time()

                    # Get handler
                    handler = self.node_handlers.get(node_type)
                    if not handler:
                        return {{
                            "execution_id": exec_id,
                            "status": "failed",
                            "error": f"Unknown node type: {{node_type}}"
                        }}

                    # Get inputs from connected nodes
                    inputs = {{}}
                    incoming = reverse_connections.get(node_id, [])
                    skip_node = False
                    for source_id, branch in incoming:
                        if source_id in context["$node"]:
                            inputs[source_id] = context["$node"][source_id]
                            # Branch gating: if source is an if-node, check branch
                            source_output = context["$node"].get(source_id, {{}})
                            if isinstance(source_output, dict) and "_branch" in source_output:
                                taken = source_output["_branch"]  # "true" or "false"
                                source_node = node_map.get(source_id, {{}})
                                src_params = source_node.get("parameters", {{}})
                                then_target = src_params.get("then")
                                else_target = src_params.get("else")
                                if then_target or else_target:
                                    if taken == "true" and else_target == node_id:
                                        skip_node = True
                                    elif taken == "false" and then_target == node_id:
                                        skip_node = True

                    if skip_node:
                        node_states[node_id] = {{"status": "skipped", "elapsed_ms": 0}}
                        continue

                    # Execute node with retry logic
                    retry_count = 0
                    max_retries = 3
                    on_error = node.get("on_error", "fail")
                    output = None

                    node_timeout = node.get("timeout", node.get("parameters", {{}}).get("timeout", 300))
                    try:
                        node_timeout = int(node_timeout)
                    except (ValueError, TypeError):
                        node_timeout = 300

                    while retry_count <= max_retries:
                        try:
                            try:
                                _ws_params = node.get("parameters", node.get("params", {{}}))
                                _ws_kind = str(_ws_params.get("workstation_kind", "") or "")
                                _ws_id = str(_ws_params.get("workstation_id", "") or "")
                                if _ws_kind and _ws_id:
                                    _ws_key = "env_scene:" + _ws_kind + ":" + _ws_id
                                    _ws_obj = _env_bag_json(_ws_key, None)
                                    if isinstance(_ws_obj, dict):
                                        _ws_obj["state"] = "running"
                                        _BAG.induct(_ws_key, json.dumps(_ws_obj, default=str), item_type='scene_object')
                            except Exception:
                                pass
                            from concurrent.futures import ThreadPoolExecutor, TimeoutError as FuturesTimeoutError
                            with ThreadPoolExecutor(max_workers=1) as _tex:
                                _future = _tex.submit(handler, node, inputs, context)
                                output = _future.result(timeout=node_timeout)

                            # Handle IF node branching
                            if node_type == "if":
                                branch_result = output.get("branch", "true")
                                output["_branch"] = branch_result

                            # Store output
                            context["$node"][node_id] = output
                            final_output = output

                            # Check if output contains error
                            has_error = False
                            if isinstance(output, dict):
                                has_error = bool(output.get("error"))

                            if has_error:
                                node_states[node_id] = {{
                                    "status": "failed",
                                    "elapsed_ms": int((time.time() - node_start) * 1000),
                                    "error": output.get("error", "Unknown error"),
                                    "output_keys": list(output.keys()) if isinstance(output, dict) else None
                                }}
                            else:
                                try:
                                    _os_params = node.get("parameters", node.get("params", {{}}))
                                    _os_ws_kind = str(_os_params.get("workstation_kind", "") or "")
                                    _os_ws_id = str(_os_params.get("workstation_id", "") or "")
                                    if _os_ws_kind and _os_ws_id:
                                        _os_ws_key = "env_scene:" + _os_ws_kind + ":" + _os_ws_id
                                        _os_ws_obj = _env_bag_json(_os_ws_key, None)
                                        if isinstance(_os_ws_obj, dict):
                                            _os_ws_obj["state"] = "done"
                                            _BAG.induct(_os_ws_key, json.dumps(_os_ws_obj, default=str), item_type='scene_object')
                                    _os_kind = str(_os_params.get("output_shelf_kind", "") or "")
                                    _os_id = str(_os_params.get("output_shelf_id", "") or "")
                                    if _os_kind and _os_id and isinstance(output, dict):
                                        import time as _ost
                                        _art_id = "artifact_" + node_id + "_" + str(int(_ost.time() * 1000))
                                        _art_obj = {{
                                            "kind": "artifact",
                                            "id": _art_id,
                                            "label": str(node.get("id", node_id)) + " output",
                                            "state": "done",
                                            "x": 50,
                                            "y": 50,
                                            "scale": 0.6,
                                            "data": {{
                                                "source_node": node_id,
                                                "source_workstation": _os_kind + ":" + _os_id,
                                            }},
                                        }}
                                        _art_key = "env_scene:artifact:" + _art_id
                                        _BAG.induct(_art_key, json.dumps(_art_obj, default=str), item_type='scene_object')
                                except Exception:
                                    pass
                                node_states[node_id] = {{
                                    "status": "completed",
                                    "elapsed_ms": int((time.time() - node_start) * 1000),
                                    "output_keys": list(output.keys()) if isinstance(output, dict) else None
                                }}
                            break

                        except FuturesTimeoutError:
                            _timeout_msg = f"Node {{node_id}} timed out after {{node_timeout}}s"
                            if on_error == "skip":
                                output = {{"error": _timeout_msg, "skipped": True, "timeout": True}}
                                context["$node"][node_id] = output
                                node_states[node_id] = {{"status": "timeout", "elapsed_ms": node_timeout * 1000}}
                                break
                            else:
                                return {{
                                    "execution_id": exec_id,
                                    "status": "failed",
                                    "error": _timeout_msg,
                                    "failed_node": node_id,
                                    "node_states": node_states,
                                    "started_at": started_at,
                                    "elapsed_ms": int((time.time() - start_time) * 1000)
                                }}
                        except Exception as e:
                            retry_count += 1
                            if on_error == "retry" and retry_count <= max_retries:
                                import time
                                time.sleep(0.5 * retry_count)  # Exponential backoff
                                continue
                            elif on_error == "skip":
                                output = {{"error": str(e), "skipped": True}}
                                context["$node"][node_id] = output
                                node_states[node_id] = {{"status": "skipped", "error": str(e)}}
                                break
                            else:
                                return {{
                                    "execution_id": exec_id,
                                    "status": "failed",
                                    "error": f"Node {{node_id}} failed: {{str(e)}}",
                                    "failed_node": node_id,
                                    "started_at": started_at,
                                    "elapsed_ms": int((time.time() - start_time) * 1000)
                                }}

                _any_failed = any(
                    ns.get("status") == "failed"
                    for ns in node_states.values()
                    if isinstance(ns, dict)
                )
                result = {{
                    "execution_id": exec_id,
                    "status": "partial_failure" if _any_failed else "completed",
                    "workflow_id": workflow.get("id", "unknown"),
                    "nodes_executed": len(execution_order),
                    "output": final_output,
                    "node_states": node_states,
                    "started_at": started_at,
                    "elapsed_ms": int((time.time() - start_time) * 1000)
                }}
                # Save execution history to FelixBag
                try:
                    bag = get_bag()
                    import json as _json
                    bag.induct(
                        name=f"workflow_exec:{{workflow.get('id', 'unknown')}}:{{exec_id}}",
                        content=_json.dumps(result, default=str),
                        item_type="workflow_execution",
                        preview=f"Exec {{exec_id}}: {{result.get('status', 'unknown')}} ({{result.get('elapsed_ms', 0)}}ms)"
                    )
                except Exception:
                    pass  # Don't fail execution if history save fails
                # Reward capture for successful workflow execution
                try:
                    _ragent = get_agent()
                    _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                    _rbrain = getattr(_router, '_brain', _router)
                    if _rbrain and hasattr(_rbrain, '_capture_reward'):
                        _rbrain._capture_reward(source_key='workflow_success', event_id=exec_id, metadata={{'workflow_id': workflow.get('id', 'unknown')}})
                except Exception:
