        def _execute_http(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute HTTP request node.\"\"\"
            import requests
            import time

            params = node.get("parameters", {{}})
            method = params.get("method", "GET").upper()
            url = self._resolve_expression(params.get("url", ""), context)
            headers = self._resolve_dict(params.get("headers", {{}}), context)
            timeout = params.get("timeout", 10)
            response_format = params.get("response_format", "json")

            # Resolve body
            body = params.get("body")
            if body:
                if isinstance(body, dict):
                    body = self._resolve_dict(body, context)
                else:
                    body = self._resolve_expression(body, context)

            start = time.time()

            try:
                if method == "GET":
                    resp = requests.get(url, headers=headers, timeout=timeout)
                elif method == "POST":
                    resp = requests.post(url, json=body, headers=headers, timeout=timeout)
                elif method == "PUT":
                    resp = requests.put(url, json=body, headers=headers, timeout=timeout)
                elif method == "DELETE":
                    resp = requests.delete(url, headers=headers, timeout=timeout)
                elif method == "PATCH":
                    resp = requests.patch(url, json=body, headers=headers, timeout=timeout)
                else:
                    return {{"error": f"Unsupported method: {{method}}"}}

                result = {{
                    "status_code": resp.status_code,
                    "headers": dict(resp.headers),
                    "elapsed_ms": int((time.time() - start) * 1000)
                }}

                if response_format == "json":
                    try:
                        result["json"] = resp.json()
                    except:
                        result["text"] = resp.text
                elif response_format == "text":
                    result["text"] = resp.text
                else:
                    import base64
                    result["binary"] = base64.b64encode(resp.content).decode()

                return result

            except requests.exceptions.Timeout:
                return {{"error": "Request timeout", "elapsed_ms": int((time.time() - start) * 1000)}}
            except Exception as e:
                return {{"error": str(e), "elapsed_ms": int((time.time() - start) * 1000)}}

        def _execute_if(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute conditional branching node.\"\"\"
            params = node.get("parameters", {{}})
            conditions = params.get("conditions", [])
            combine = params.get("combine", "and")

            evaluated = []
            results = []

            for cond in conditions:
                left = self._resolve_expression(cond.get("left"), context)
                right = self._resolve_expression(cond.get("right"), context)
                operator = cond.get("operator", "==")

                # Type coercion
                try:
                    if isinstance(right, (int, float)) and isinstance(left, str):
                        left = float(left) if "." in left else int(left)
                    elif isinstance(left, (int, float)) and isinstance(right, str):
                        right = float(right) if "." in right else int(right)
                except:
                    pass

                # Evaluate condition
                result = False
                if operator == "==":
                    result = left == right
                elif operator == "!=":
                    result = left != right
                elif operator == ">":
                    result = left > right
                elif operator == ">=":
                    result = left >= right
                elif operator == "<":
                    result = left < right
                elif operator == "<=":
                    result = left <= right
                elif operator == "contains":
                    result = str(right) in str(left)
                elif operator == "not_contains":
                    result = str(right) not in str(left)
                elif operator == "starts_with":
                    result = str(left).startswith(str(right))
                elif operator == "ends_with":
                    result = str(left).endswith(str(right))
                elif operator == "is_empty":
                    result = left is None or left == "" or left == []
                elif operator == "is_not_empty":
                    result = left is not None and left != "" and left != []
                elif operator == "regex":
                    import re
                    result = bool(re.search(str(right), str(left)))

                results.append(result)
                evaluated.append({{"left": left, "operator": operator, "right": right, "result": result}})

            # Combine results
            if combine == "and":
                final_result = all(results) if results else True
            else:  # or
                final_result = any(results) if results else False

            return {{
                "result": final_result,
                "branch": "true" if final_result else "false",
                "evaluated_conditions": evaluated
            }}

        def _execute_set(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute data transformation node.\"\"\"
            params = node.get("parameters", {{}})
            values = params.get("values", {{}})
            mode = params.get("mode", "set")

            # Support key/value shorthand alongside values dict
            if not values and "key" in params and "value" in params:
                values = {{params["key"]: params["value"]}}

            # Resolve all expressions in values
            resolved = self._resolve_dict(values, context)

            if mode == "set":
                return resolved
            elif mode == "append":
                # Merge with first input
                result = {{}}
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        result.update(source_data)
                    break
                result.update(resolved)
                return result
            elif mode == "merge":
                # Deep merge
                import copy
                result = {{}}
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        result = copy.deepcopy(source_data)
                    break
                for k, v in resolved.items():
                    if k in result and isinstance(result[k], dict) and isinstance(v, dict):
                        result[k].update(v)
                    else:
                        result[k] = v
                return result

            return resolved

        def _execute_merge(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute branch merge node.\"\"\"
            params = node.get("parameters", {{}})
            mode = params.get("mode", "wait_all")

            branches = []
            for source_id, source_data in inputs.items():
                branches.append({{"branch": source_id, "data": source_data}})

            if mode == "first":
                # Return first non-error branch
                for b in branches:
                    if not (isinstance(b["data"], dict) and b["data"].get("skipped")):
                        return {{
                            "mode": "first",
                            "selected": b["branch"],
                            "data": b["data"]
                        }}
                return {{"mode": "first", "data": branches[0]["data"] if branches else None}}

            elif mode == "wait_all":
                return {{
                    "mode": "wait_all",
                    "branches": branches,
                    "completed_count": len(branches)
                }}

            elif mode == "append":
                all_data = []
                for b in branches:
                    if isinstance(b["data"], list):
                        all_data.extend(b["data"])
                    else:
                        all_data.append(b["data"])
                return {{"mode": "append", "data": all_data}}

            elif mode == "combine":
                combined = {{}}
                for b in branches:
                    if isinstance(b["data"], dict):
                        for k, v in b["data"].items():
                            if k in combined:
                                existing = combined[k]
                                if isinstance(existing, list):
                                    existing.append(v)
                                else:
                                    combined[k] = [existing, v]
                            else:
                                combined[k] = v
                return {{"mode": "combine", "data": combined}}

            return {{"branches": branches}}

        def _execute_web_search(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute web search node - first-class search across multiple providers.

            Supported providers: brave, searxng, serper
            Parameters:
                provider: Search provider (default: brave)
                query: Search query (supports expression interpolation)
                api_key: API key (or use $env.BRAVE_API_KEY / $env.SERPER_API_KEY)
                count: Number of results (default: 10)
                freshness: Time filter - day, week, month, year (brave/serper only)
                language: Language code e.g. en, es, de (default: en)
            \"\"\"
            import requests
            import time
            import os

            params = node.get("parameters", {{}})
            provider = params.get("provider", "brave").lower()
            query = self._resolve_expression(params.get("query", ""), context)
            count = int(params.get("count", 10))
            freshness = params.get("freshness", "")
            language = params.get("language", "en")

            if not query:
                # Auto-wire from upstream if no explicit query
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        query = source_data.get("query", source_data.get("text", source_data.get("output", "")))
                        if query:
                            break
                    elif isinstance(source_data, str):
                        query = source_data
                        break
            if not query:
                return {{"error": "No search query provided", "provider": provider}}

            # Resolve API key: explicit param > env var
            api_key = self._resolve_expression(params.get("api_key", ""), context)
            if not api_key:
                env_keys = {{
                    "brave": "BRAVE_API_KEY",
                    "serper": "SERPER_API_KEY",
                    "searxng": "",
                }}
                env_var = env_keys.get(provider, "")
                if env_var:
                    api_key = os.environ.get(env_var, "")

            start = time.time()

            try:
                if provider == "brave":
                    if not api_key:
                        return {{"error": "Brave API key required. Set BRAVE_API_KEY env var or pass api_key parameter."}}
                    url = "https://api.search.brave.com/res/v1/web/search"
                    req_params = {{"q": query, "count": min(count, 20)}}
                    if freshness:
                        req_params["freshness"] = freshness
                    if language:
                        req_params["search_lang"] = language
                    resp = requests.get(url, params=req_params,
                                        headers={{"Accept": "application/json", "X-Subscription-Token": api_key}},
                                        timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    web_results = data.get("web", {{}}).get("results", [])
                    results = [{{
                        "title": r.get("title", ""),
                        "url": r.get("url", ""),
                        "snippet": r.get("description", ""),
                        "age": r.get("age", ""),
                    }} for r in web_results[:count]]

                elif provider == "searxng":
                    base_url = self._resolve_expression(
                        params.get("base_url", "http://localhost:8888"), context)
                    resp = requests.get(f"{{base_url}}/search",
                                        params={{"q": query, "format": "json", "language": language,
                                                "pageno": 1, "categories": "general"}},
                                        timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    results = [{{
                        "title": r.get("title", ""),
                        "url": r.get("url", ""),
                        "snippet": r.get("content", ""),
                        "engine": r.get("engine", ""),
                    }} for r in data.get("results", [])[:count]]

                elif provider == "serper":
                    if not api_key:
                        return {{"error": "Serper API key required. Set SERPER_API_KEY env var or pass api_key parameter."}}
                    resp = requests.post("https://google.serper.dev/search",
                                         json={{"q": query, "num": min(count, 100), "hl": language}},
                                         headers={{"X-API-KEY": api_key, "Content-Type": "application/json"}},
                                         timeout=15)
                    resp.raise_for_status()
                    data = resp.json()
                    results = [{{
                        "title": r.get("title", ""),
                        "url": r.get("link", ""),
                        "snippet": r.get("snippet", ""),
                        "position": r.get("position", 0),
                    }} for r in data.get("organic", [])[:count]]

                else:
                    return {{"error": f"Unknown provider: {{provider}}. Use brave, searxng, or serper."}}

                elapsed = int((time.time() - start) * 1000)
                return {{
                    "provider": provider,
                    "query": query,
                    "count": len(results),
                    "results": results,
                    "elapsed_ms": elapsed,
                }}

            except requests.exceptions.Timeout:
                return {{"error": "Search request timeout", "provider": provider, "elapsed_ms": int((time.time() - start) * 1000)}}
            except requests.exceptions.HTTPError as e:
                return {{"error": f"HTTP {{e.response.status_code}}: {{e.response.text[:200]}}", "provider": provider}}
            except Exception as e:
                return {{"error": str(e), "provider": provider, "elapsed_ms": int((time.time() - start) * 1000)}}

        def _execute_tool(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute universal tool node - calls any MCP tool by name.

            This is the key primitive: any of the capsule's 140+ MCP tools
            becomes a usable workflow node through this single handler.

            Node definition:
                {{"type": "tool", "tool_name": "embed_text", "parameters": {{"text": "..."}}}}
            \"\"\"
            import json
            tool_name = node.get("tool_name", "")
            if not tool_name:
                raise ValueError(f"Tool node '{{node['id']}}' missing 'tool_name'")

            # Resolve parameters from node definition
            params = node.get("parameters", node.get("params", {{}}))
            resolved_params = self._resolve_dict(params, context) if params else {{}}

            # Validate resolved parameters
            if resolved_params:
                _valid, _errs = self._validate_params(resolved_params, context)
                if not _valid:
                    return {{"error": "Invalid parameters: " + ", ".join(_errs)}}

            # Auto-wire: if no explicit params, merge upstream outputs as parameters
            if inputs and not params:
                for source_id, source_data in inputs.items():
                    if isinstance(source_data, dict):
                        for k, v in source_data.items():
                            if k not in resolved_params:
                                resolved_params[k] = v

            # Look up tool function: registry first, then globals fallback
            tool_func = self._tool_registry.get(tool_name) or globals().get(tool_name)
            if tool_func is None:
                raise ValueError(f"Tool not found: {{tool_name}}")

            # Bypass logged_tool decorator to avoid caching interference
            # Workflow execution itself is the observable unit
            while hasattr(tool_func, '__wrapped__'):
                tool_func = tool_func.__wrapped__

            # Filter params to match tool signature (prevents auto-wired
            # upstream data from crashing zero-arg or few-arg tools)
            import inspect
            try:
                sig = inspect.signature(tool_func)
                has_var_keyword = any(
                    p.kind == inspect.Parameter.VAR_KEYWORD
                    for p in sig.parameters.values()
                )
                if not has_var_keyword and resolved_params:
                    accepted = set(sig.parameters.keys())
                    resolved_params = {{k: v for k, v in resolved_params.items() if k in accepted}}
            except (ValueError, TypeError):
                pass  # Can't inspect — pass params as-is

            # Call tool with filtered parameters
            try:
                result_str = tool_func(**resolved_params)
            except TypeError:
                if resolved_params:
                    result_str = tool_func(*resolved_params.values())
                else:
                    raise

            # Parse JSON result - handle LLM responses with markdown + JSON
            if isinstance(result_str, dict):
                return result_str
            if isinstance(result_str, str):
                try:
                    return json.loads(result_str)
                except (json.JSONDecodeError, ValueError):
                    pass
                # Find first valid JSON object in response
                _decoder = json.JSONDecoder()
                _idx = 0
                while _idx < len(result_str):
                    _idx = result_str.find(chr(123), _idx)
                    if _idx == -1:
                        break
                    try:
                        obj, _ = _decoder.raw_decode(result_str, _idx)
                        if isinstance(obj, dict):
                            return obj
                    except (json.JSONDecodeError, ValueError):
                        pass
                    _idx += 1
                return {{"result": result_str}}
            return {{"result": result_str}}

        def _execute_agent(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute agent node - plugged model operates granted MCP tools in a loop.

            A plugged model is given a task and a whitelist of MCP tools it can call.
            The model reasons, calls tools, receives results, and loops until it
            produces a final answer or hits max_iterations.

            Node definition:
                {{"type": "agent", "parameters": {{
                    "slot": 1,
                    "task": "Search memory for X and summarize",
                    "granted_tools": ["bag_search", "embed_text", "get_status"],
                    "max_iterations": 5,
                    "max_tokens": 512
                }}}}

            Output keys: .final_answer, .iterations, .tool_calls, .slot, .name
            \"\"\"
            import json

            params = node.get("parameters", node.get("params", {{}}))
            resolved_params = self._resolve_dict(params, context) if params else {{}}

            slot_idx = resolved_params.get("slot", 0)
            if isinstance(slot_idx, str):
                try:
                    slot_idx = int(slot_idx)
                except ValueError:
                    slot_idx = 0
            task = resolved_params.get("task", "")
            if not task:
                return {{"error": "Agent node requires 'task' parameter"}}
            granted_tools = resolved_params.get("granted_tools", [])
            if isinstance(granted_tools, str):
                try:
                    granted_tools = json.loads(granted_tools)
                except (json.JSONDecodeError, ValueError):
                    granted_tools = [t.strip() for t in granted_tools.split(",") if t.strip()]
            if not granted_tools:
                granted_tools = [
                    "get_status", "list_slots", "slot_info", "get_capabilities", "embed_text",
                    "invoke_slot", "call",
                    "bag_get", "bag_put", "bag_search", "bag_catalog", "bag_induct",
                    "bag_read_doc", "bag_list_docs", "bag_search_docs", "bag_tree",
                    "bag_versions", "bag_diff", "bag_checkpoint", "bag_restore",
                    "file_read", "file_write", "file_edit", "file_append", "file_prepend",
                    "file_delete", "file_rename", "file_copy", "file_list", "file_tree",
                    "file_search", "file_info", "file_checkpoint", "file_versions", "file_diff", "file_restore",
                    "workflow_list", "workflow_get", "workflow_status",
                    "cascade_graph", "cascade_chain", "cascade_data", "cascade_system",
                    "cascade_record", "cascade_instrument", "cascade_proxy",
                    "diagnose_file", "diagnose_directory", "symbiotic_interpret",
                    "trace_root_causes", "forensics_analyze", "metrics_analyze",
                ]
            max_iterations = int(resolved_params.get("max_iterations", 5))
            agent_max_tokens = int(resolved_params.get("max_tokens", 0))

            # Validate granted tools (ignore unknown entries instead of hard-failing).
            available_tools = {{}}
            _unknown_granted_tools = []
            for tool_name in granted_tools:
                tool_func = self._tool_registry.get(tool_name) or globals().get(tool_name)
                if tool_func is None:
                    _unknown_granted_tools.append(tool_name)
                    continue
                while hasattr(tool_func, '__wrapped__'):
                    tool_func = tool_func.__wrapped__
                available_tools[tool_name] = tool_func

            granted_tools = list(available_tools.keys())
            if not granted_tools:
                return {{
                    "error": "No valid granted tools available",
                    "unknown_tools": _unknown_granted_tools,
                }}

            # Get invoke_slot for model communication
            invoke_func = self._tool_registry.get("invoke_slot") or globals().get("invoke_slot")
            if invoke_func is None:
                return {{"error": "invoke_slot not found in tool registry"}}
            while hasattr(invoke_func, '__wrapped__'):
                invoke_func = invoke_func.__wrapped__

            # Build tool descriptions for the model prompt
            import inspect
            tool_descriptions = []
            for tname, tfunc in available_tools.items():
                try:
                    sig = inspect.signature(tfunc)
                    sig_parts = []
                    for p in sig.parameters.values():
                        ann = p.annotation.__name__ if p.annotation != inspect.Parameter.empty else "any"
                        part = f"{{p.name}}: {{ann}}"
                        if p.default != inspect.Parameter.empty:
                            part += f" = {{p.default}}"
                        sig_parts.append(part)
                    params_str = ", ".join(sig_parts)
                    doc = (tfunc.__doc__ or "").strip().split("\\n")[0]
                    tool_descriptions.append(f"- {{tname}}({{params_str}}): {{doc}}")
                except Exception:
                    tool_descriptions.append(f"- {{tname}}(): (no signature available)")
            tools_block = "\\n".join(tool_descriptions)

            # ── Dynamic context blocks scoped to granted_tools (B13) ──
            context_blocks = []
            _granted_set = set(granted_tools)
            _has_prefix = lambda pfx: any(t.startswith(pfx) for t in _granted_set)
            _has_any = lambda *names: bool(_granted_set & set(names))

            # Identity — always included
            try:
                _id_name = f"slot_{{slot_idx}}"
                _id_total = 0
                _id_consensus = "bayesian"
                _get_agent_fn = self._tool_registry.get("get_status")
                if _get_agent_fn:
                    import json as _j
                    _st = _j.loads(_get_agent_fn())
                    _id_total = _st.get("slots_filled", 0)
                    _id_consensus = "bayesian"
                try:
                    _brain_ref = None
                    _ga = self._tool_registry.get("get_agent") or globals().get("get_agent")
                    if callable(_ga):
                        _a = _ga()
                        _ob = getattr(_a, '_brain', getattr(_a, 'brain', None))
                        _brain_ref = getattr(_ob, '_brain', _ob)
                    if _brain_ref and hasattr(_brain_ref, 'councilors'):
                        _c = _brain_ref.councilors[slot_idx]
                        _id_name = getattr(_c, 'name', _id_name)
                        _id_total = sum(1 for c in _brain_ref.councilors if getattr(c, 'model', None))
                        _id_consensus = getattr(_brain_ref, 'consensus_method', _id_consensus)
                except Exception:
                    pass
                context_blocks.append(
                    f"IDENTITY: You are {{_id_name}}, council slot {{slot_idx}} "
                    f"in an Ouroboros capsule. {{_id_total}} models active, "
                    f"consensus: {{_id_consensus}}. Your outputs are provenance-tracked."
                )
            except Exception:
                context_blocks.append(f"IDENTITY: You are an agent in council slot {{slot_idx}}.")

            # FelixBag
            if _has_prefix("bag_") or _has_prefix("file_"):
                context_blocks.append(
                    "FELIXBAG: Persistent semantic memory and virtual workspace. "
                    "bag_search(query) uses BGE embeddings for semantic search (not keyword). "
                    "bag_put(key, value) stores, bag_get(key) retrieves. "
                    "bag_catalog() lists all items (filterable by type). "
                    "bag_induct(key, content, item_type) adds typed items (text, json, code, workflow). "
                    "bag_read_doc(key) returns full document content and metadata. "
                    "bag_list_docs(prefix/filter_type) lists workspace documents. "
                    "bag_tree(prefix) gives a drillable workspace tree. "
                    "bag_checkpoint(key)/bag_versions(key)/bag_diff(key)/bag_restore(key, checkpoint_key) "
                    "provide document history, differential tracking, and recovery. "
                    "file_read(path)/file_write(path, content)/file_edit(path, old_text, new_text) "
                    "provide file-style workspace operations with deterministic single-edit semantics. "
                    "file_append/file_prepend/file_delete/file_rename/file_copy manage lifecycle. "
                    "file_checkpoint/file_versions/file_diff/file_restore mirror version workflows. "
                    "All file_* operations are FelixBag-scoped (no raw host filesystem access). "
                    "Items persist across sessions."
                )

            # CASCADE
            if _has_prefix("cascade_"):
                context_blocks.append(
                    "CASCADE: Provenance and observability lattice. "
                    "cascade_graph: causal reasoning (add_event, add_link, get_causes, get_effects). "
                    "cascade_chain: merkle-linked provenance (create_chain, add_record, verify). "
                    "cascade_data: PII scanning (pii_scan), schema inference, license analysis. "
                    "cascade_system: log ingestion and format classification. "
                    "cascade_record: tape recording (tape_write, tape_read) and structured logging."
                )

            # Inference
            if _has_any("embed_text", "classify", "rerank", "forward", "infer", "generate"):
                context_blocks.append(
                    "INFERENCE: embed_text(text) returns 384-dim BGE embeddings. "
                    "classify(text) returns labels with confidence (output key: 'output'). "
                    "rerank(query, documents) re-orders by relevance. "
                    "generate(prompt) produces text from a plugged LLM. "
                    "forward(text) runs through the quine brain. "
                    "infer(text) runs full council consensus across all slots."
                )

            # Council
            if _has_any("invoke_slot", "list_slots", "council_status", "slot_info",
                        "broadcast", "compare", "debate", "chain", "all_slots"):
                context_blocks.append(
                    "COUNCIL: Multi-model system, 32 slots. "
                    "invoke_slot(slot, text, mode) calls a model (modes: generate, embed, classify). "
                    "list_slots() shows all slots. compare(input_text) runs through all slots. "
                    "debate(text, rounds) runs multi-round deliberation. "
                    "chain(slot_sequence, text) pipes output sequentially through slots."
                )

            # Workflows
            if _has_prefix("workflow_"):
                context_blocks.append(
                    "WORKFLOWS: DAG automation engine. "
                    "workflow_create(definition) from JSON. "
                    "workflow_execute(workflow_id, input_data) may be restricted by operator policy. "
                    "10 node types: tool (top-level tool_name), agent, input, output, "
                    "fan_out (targets array), http, if (conditions array + then/else), "
                    "set, merge, web_search. "
                    "Data wiring: $input.field, $node.nodeId.key, $env.VAR."
                )

            # HuggingFace
            if _has_prefix("hub_"):
                context_blocks.append(
                    "HUGGINGFACE: hub_search(query) finds models, hub_search_datasets(query) datasets. "
                    "hub_info(model_id) gets details. hub_top(task) gets trending. "
                    "hub_download(model_id) downloads locally. "
                    "hub_plug(model_id) downloads AND plugs into a council slot. "
                    "Use short keywords (1-2 words) for best search results."
                )

            # Diagnostics
            if _has_prefix("diagnose_") or _has_any("symbiotic_interpret", "trace_root_causes",
                                                     "forensics_analyze", "metrics_analyze"):
                context_blocks.append(
                    "DIAGNOSTICS: diagnose_file(path) runs full analysis on Python files. "
                    "symbiotic_interpret(signal) normalizes raw or structured signals into event-like diagnostics. "
                    "trace_root_causes(description) traces against observed history and persisted causation state. "
                    "forensics_analyze(data) auto-selects dataset or anomaly forensics based on input shape, including structured failure bursts and small debug payloads. "
                    "metrics_analyze(name, values) detects anomalies and trends."
                )

            # Status
            if _has_any("get_status", "verify_integrity", "verify_hash", "get_capabilities",
                        "get_identity", "get_genesis", "heartbeat"):
                context_blocks.append(
                    "STATUS: get_status() returns generation, fitness, brain type, slot count. "
                    "verify_integrity() checks merkle hash. heartbeat() lightweight alive check. "
                    "get_capabilities() lists all capsule capabilities."
                )

            context_section = "\\n\\n".join(context_blocks) + "\\n\\n" if context_blocks else ""

            # ── Ecosystem awareness: other agents + recent activity ──
            try:
                _eco_lines = []
                if _brain_ref and hasattr(_brain_ref, 'councilors'):
                    for _ei, _ec in enumerate(_brain_ref.councilors):
                        if _ei == slot_idx:
                            continue
                        _em = getattr(_ec, 'model', None)
                        if _em is not None:
                            _ename = getattr(_ec, 'name', f'slot_{{_ei}}')
                            _esrc = getattr(_ec, '_model_source', 'unknown')
                            _etype = getattr(_ec, '_model_type', 'generic')
                            _eco_lines.append(f"  Slot {{_ei}}: {{_ename}} ({{_etype}}, {{_esrc}})")
                if _eco_lines:
                    context_blocks.append(
                        "ECOSYSTEM: Other active agents in the council:\\n"
                        + "\\n".join(_eco_lines)
                        + "\\nUse bag_search to find their recent work. "
                        "Use invoke_slot(slot, text) to delegate to them."
                    )
            except Exception:
                pass

            # ── Operational envelope: denied tools + constraints ──
            try:
                _all_registered = set(self._tool_registry.keys())
                _denied = sorted(_all_registered - _granted_set - {{"get_agent"}})
                if len(_denied) > 0 and len(_denied) <= 30:
                    context_blocks.append(
                        f"BOUNDARIES: You have {{len(granted_tools)}} granted tools. "
                        f"You do NOT have access to: {{', '.join(_denied[:15])}}."
                        + (" (and more)" if len(_denied) > 15 else "")
                        + f" Max iterations: {{max_iterations}}."
                    )
                elif len(_denied) > 30:
                    context_blocks.append(
                        f"BOUNDARIES: You have {{len(granted_tools)}} granted tools out of {{len(_all_registered)}} total. "
                        f"Only use tools listed in AVAILABLE TOOLS above. "
                        f"Max iterations: {{max_iterations}}."
                    )
            except Exception:
                pass

            # ── Recent FelixBag activity for cross-agent coordination ──
            try:
                _bag_fn = self._tool_registry.get("bag_catalog")
                if _bag_fn and _has_prefix("bag_"):
                    _cat_raw = _bag_fn()
                    _cat = json.loads(_cat_raw) if isinstance(_cat_raw, str) else _cat_raw
                    _items = _cat.get("items", [])
                    _recent_sessions = [
                        it for it in _items
                        if isinstance(it, (list, tuple)) and len(it) >= 2
                        and (str(it[1]).startswith("agent_session:") or str(it[1]).startswith("workflow_exec:"))
                    ][-5:]
                    if _recent_sessions:
                        _sess_lines = [f"  {{it[1]}}" for it in _recent_sessions]
                        context_blocks.append(
                            "RECENT ACTIVITY:\\n" + "\\n".join(_sess_lines)
                            + "\\nUse bag_get(key) to inspect any of these."
                        )
            except Exception:
                pass

            context_section = "\\n\\n".join(context_blocks) + "\\n\\n" if context_blocks else ""
            upstream_context = ""
            for source_id, source_data in inputs.items():
                if isinstance(source_data, dict):
                    for k, v in source_data.items():
                        if k not in ("error", "skipped", "_branch"):
                            val_str = str(v)[:500] if not isinstance(v, str) else v[:500]
                            upstream_context += f"\\n{{k}}: {{val_str}}"

            system_prompt = (
                f"{{context_section}}"
                "You are an AI agent operating inside an Ouroboros workflow node. "
                "You have access to ONLY the tools listed below. "
                "Respond with EXACTLY ONE JSON object per turn.\\n\\n"
                f"AVAILABLE TOOLS:\\n{{tools_block}}\\n\\n"
                "To call a tool, respond with:\\n"
                '{{"tool": "tool_name", "args": {{"param": "value"}}}}\\n\\n'
                "When you have completed the task, respond with:\\n"
                '{{"final_answer": "your complete answer here"}}\\n\\n'
                "Rules:\\n"
                "- Call ONE tool at a time\\n"
                "- Wait for the result before calling another\\n"
                "- Use ONLY the tools listed above\\n"
                "- Never invoke your own slot; delegate only to other slots\\n"
                "- Always end with a final_answer"
            )

            full_task = f"TASK: {{task}}"
            if upstream_context:
                full_task += f"\\n\\nCONTEXT FROM PREVIOUS NODES:{{upstream_context}}"

            # Agent loop - structured message list
            chat_messages = [
                {{"role": "system", "content": system_prompt}},
                {{"role": "user", "content": full_task}},
            ]
            tool_calls_log = []
            final_answer = None
            slot_name = f"slot_{{slot_idx}}"
            iterations_used = 0
            _last_iteration_nudge = "This is your LAST iteration. You MUST respond with {{\\\"final_answer\\\": \\\"your answer\\\"}} now."

            def _coerce_dict_payload(value):
                if isinstance(value, dict):
                    return dict(value)
                if isinstance(value, str):
                    try:
                        parsed_value = json.loads(value)
                        if isinstance(parsed_value, dict):
                            return parsed_value
                    except Exception:
                        pass
                return {{}}

            def _slot_as_int(value):
                if value is None:
                    return None
                try:
                    return int(value)
                except Exception:
                    return None

            def _self_call_guard(tool_name, tool_args):
                tname = str(tool_name or "").strip()
                targs = tool_args if isinstance(tool_args, dict) else {{}}

                if tname == "invoke_slot":
                    tgt = _slot_as_int(targs.get("slot"))
                    if tgt is not None and tgt == slot_idx:
                        return f"Self-invocation blocked: invoke_slot(slot={{slot_idx}}). Choose a different slot."
                    return ""

                if tname == "agent_chat":
                    tgt = _slot_as_int(targs.get("slot", 0))
                    if tgt is not None and tgt == slot_idx:
                        return f"Self-invocation blocked: agent_chat(slot={{slot_idx}}). Choose a different slot."
                    return ""

                if tname == "chat":
                    if "slot" not in targs or targs.get("slot") is None:
                        return "chat requires an explicit non-self slot."
                    tgt = _slot_as_int(targs.get("slot"))
                    if tgt is not None and tgt == slot_idx:
                        return f"Self-invocation blocked: chat(slot={{slot_idx}}). Choose a different slot."
                    return ""

                if tname == "call":
                    relay_tool = str(targs.get("tool_name", "") or "").strip()
                    if not relay_tool:
                        return "call requires tool_name."
                    if relay_tool == "call":
                        return "Recursive call->call is blocked."
                    if relay_tool not in available_tools:
                        return f"call denied: '{{relay_tool}}' is not in granted_tools."
                    relay_args = _coerce_dict_payload(targs.get("args", {{}}))
                    nested = _self_call_guard(relay_tool, relay_args)
                    if nested:
                        return f"call blocked: {{nested}}"
                    return ""

                return ""

            for iteration in range(max_iterations):
                iterations_used = iteration + 1
                # Nudge on penultimate iteration
                if iteration == max_iterations - 1:
                    if chat_messages and chat_messages[-1].get("role") == "user":
                        chat_messages[-1]["content"] = str(chat_messages[-1].get("content", "")) + "\\n\\n" + _last_iteration_nudge
                    else:
                        chat_messages.append({{
                            "role": "user",
                            "content": _last_iteration_nudge
                        }})

                try:
                    _invoke_kwargs = {{"slot": slot_idx, "text": full_task, "mode": "generate", "messages": chat_messages}}
                    if agent_max_tokens > 0:
                        _invoke_kwargs["max_tokens"] = agent_max_tokens
                    result_str = invoke_func(**_invoke_kwargs)
                    result = json.loads(result_str) if isinstance(result_str, str) else result_str
                except Exception as e:
                    return {{
                        "error": f"Model invocation failed: {{str(e)}}",
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                    }}

                if not isinstance(result, dict):
                    return {{
                        "error": f"Model invocation returned non-dict response: {{type(result).__name__}}",
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                    }}
                if result.get("status") == "error" or result.get("error"):
                    return {{
                        "error": "Model invocation failed: " + str(result.get("error", "unknown error")),
                        "slot": slot_idx,
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                        "name": result.get("name", slot_name),
                    }}

                model_output = result.get("output", "")
                slot_name = result.get("name", slot_name)

                # Append model response as assistant message
                chat_messages.append({{"role": "assistant", "content": model_output}})

                # Parse model output as JSON
                parsed = None
                if isinstance(model_output, str):
                    try:
                        parsed = json.loads(model_output.strip())
                    except (json.JSONDecodeError, ValueError):
                        pass
                    if parsed is None:
                        _decoder = json.JSONDecoder()
                        _scan = 0
                        while _scan < len(model_output):
                            _scan = model_output.find(chr(123), _scan)
                            if _scan == -1:
                                break
                            try:
                                obj, _ = _decoder.raw_decode(model_output, _scan)
                                if isinstance(obj, dict) and ("tool" in obj or "final_answer" in obj):
                                    parsed = obj
                                    break
                            except (json.JSONDecodeError, ValueError):
                                pass
                            _scan += 1

                if parsed is None:
                    final_answer = model_output if isinstance(model_output, str) and model_output.strip() else "Model returned an empty response."
                    break

                if "final_answer" in parsed:
                    final_answer = parsed["final_answer"]
                    break

                if "tool" in parsed:
                    called_tool = parsed["tool"]
                    called_args = parsed.get("args", {{}})
                    if not isinstance(called_args, dict):
                        called_args = _coerce_dict_payload(called_args)

                    if called_tool not in available_tools:
                        chat_messages.append({{
                            "role": "user",
                            "content": f"Tool '{{called_tool}}' is NOT in your granted tools. Available: {{', '.join(granted_tools)}}. Try again."
                        }})
                        tool_calls_log.append({{
                            "tool": called_tool, "args": called_args,
                            "result": "DENIED - not in granted_tools",
                            "iteration": iteration,
                        }})
                        continue

                    _guard_msg = _self_call_guard(called_tool, called_args)
                    if _guard_msg:
                        chat_messages.append({{
                            "role": "user",
                            "content": _guard_msg + " Choose a different tool/slot and continue."
                        }})
                        tool_calls_log.append({{
                            "tool": called_tool, "args": called_args,
                            "result": "DENIED - " + _guard_msg,
                            "iteration": iteration,
                        }})
                        continue

                    if called_tool == "call":
                        if isinstance(called_args.get("args"), dict):
                            called_args["args"] = json.dumps(called_args.get("args", {{}}), default=str)
                        elif "args" not in called_args or called_args.get("args") is None:
                            called_args["args"] = "{{}}"

                    tool_func = available_tools[called_tool]
                    try:
                        try:
                            sig = inspect.signature(tool_func)
                            has_var_kw = any(
                                p.kind == inspect.Parameter.VAR_KEYWORD
                                for p in sig.parameters.values()
                            )
                            if not has_var_kw and called_args:
                                accepted = set(sig.parameters.keys())
                                called_args = {{k: v for k, v in called_args.items() if k in accepted}}
                        except (ValueError, TypeError):
                            pass

                        tool_result = tool_func(**called_args)
                        if isinstance(tool_result, str):
                            try:
                                tool_result_parsed = json.loads(tool_result)
                                tool_result_str = json.dumps(tool_result_parsed, indent=2, default=str)
                            except (json.JSONDecodeError, ValueError):
                                tool_result_str = tool_result
                        else:
                            tool_result_str = json.dumps(tool_result, indent=2, default=str)
                    except Exception as e:
                        tool_result_str = f"ERROR: {{str(e)}}"

                    tool_calls_log.append({{
                        "tool": called_tool, "args": called_args,
                        "result": tool_result_str[:500],
                        "iteration": iteration,
                    }})

                    # Append tool result as user message (proper role separation)
                    chat_messages.append({{
                        "role": "user",
                        "content": f"Tool result for {{called_tool}}({{json.dumps(called_args, default=str)}}):\\n{{tool_result_str}}\\n\\nContinue with your next tool call or provide your final_answer."
                    }})
                else:
                    final_answer = json.dumps(parsed, default=str)
                    break

            if final_answer is None:
                final_answer = f"Agent reached max iterations ({{max_iterations}}) without final answer."

            _agent_result = {{
                "final_answer": final_answer,
                "iterations": iterations_used,
                "tool_calls": tool_calls_log,
                "slot": slot_idx,
                "name": slot_name,
            }}

            # ── Persist session trace to FelixBag ──
            try:
                import time as _sess_time
                _bag_fn = self._tool_registry.get("bag_induct")
                if _bag_fn:
                    _ts = int(_sess_time.time())
                    _sess_key = f"agent_session:{{slot_idx}}:{{_ts}}"
                    _sess_data = json.dumps({{
                        "slot": slot_idx,
                        "name": slot_name,
                        "task": task,
                        "final_answer": final_answer[:1000] if isinstance(final_answer, str) else str(final_answer)[:1000],
                        "iterations": iterations_used,
                        "tool_calls": tool_calls_log,
                        "granted_tools": granted_tools,
                        "timestamp": _ts,
                    }}, default=str)
                    _bag_fn(key=_sess_key, content=_sess_data, item_type="agent_session")
            except Exception:
                pass

            return _agent_result

        def _execute_input(self, node: dict, inputs: dict, context: dict) -> dict:
            \"\"\"Execute input node - workflow entry point.

            Passes merged workflow input defaults and explicit input_data through to
