            return json.dumps({{"error": f"Invalid JSON: {{str(e)}}"}})

        if "id" not in workflow:
            return json.dumps({{"error": "Workflow must have an 'id' field"}})
        if "nodes" not in workflow:
            return json.dumps({{"error": "Workflow must have a 'nodes' array"}})
        if "connections" not in workflow:
            return json.dumps({{"error": "Workflow must have a 'connections' array"}})

        bag = get_bag()
        workflow_key = f"workflow:{{workflow['id']}}"
        workflow_json = json.dumps(workflow)

        # Use induct for proper FelixBag storage with catalog support
        bag.induct(
            name=workflow_key,
            content=workflow_json,
            item_type="workflow",
            preview=f"Workflow: {{workflow.get('name', workflow['id'])}} ({{len(workflow.get('nodes', []))}} nodes)"
        )

        return json.dumps({{
            "status": "created",
            "id": workflow["id"],
            "name": workflow.get("name", "Unnamed"),
            "node_count": len(workflow.get("nodes", []))
        }})

