    def workflow_delete(workflow_id: str) -> str:
        \"\"\"Delete a workflow by ID.\"\"\"
        import json
        bag = get_bag()
        workflow_key = f"workflow:{{workflow_id}}"

        if bag.get(workflow_key) is None:
            return json.dumps({{"error": f"Workflow not found: {{workflow_id}}"}})

        # Find item by name and delete by its internal item_id
        deleted = False
        for iid, item in list(bag._bag.items()):
            if item.get('name') == workflow_key:
                bag.forget(iid)
                deleted = True
                break
        if not deleted:
            bag.forget(workflow_key)

        return json.dumps({{
            "status": "deleted",
            "id": workflow_id
        }})

    def workflow_history(workflow_id: str, limit: int = 10) -> str:
        \"\"\"Get execution history for a workflow.\"\"\"
        import json
        bag = get_bag()
        executions = []

        try:
            # catalog() returns list of tuples: (id, name, type, preview, size, version)
            catalog_items = bag.catalog() if hasattr(bag, "catalog") else []
            for item in catalog_items:
                if len(item) >= 2:
                    item_name = item[1]  # name is second element
                    if item_name.startswith("workflow_exec:") and workflow_id in item_name:
                        try:
                            exec_data = bag.get(item_name)
                            if exec_data:
                                if isinstance(exec_data, str):
                                    exec_data = json.loads(exec_data)
                                if exec_data.get("workflow_id") == workflow_id:
                                    executions.append(exec_data)
                        except:
                            pass
        except:
            pass

        executions.sort(key=lambda x: x.get("started_at", ""), reverse=True)
        executions = executions[:limit]

        return json.dumps({{
            "workflow_id": workflow_id,
            "executions": executions,
            "count": len(executions)
        }})

    def workflow_status(execution_id: str) -> str:
        \"\"\"Get status of a workflow execution.\"\"\"
        import json
        bag = get_bag()
        # Search by execution_id in item names (name format: workflow_exec:wf_id:exec_id)
        exec_data = None
        try:
            for iid, item in bag._bag.items():
