            return json.dumps(exec_data)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    def _cleanup_old_capsule_processes():
        \"\"\"Kill old Python processes that may be holding MCP port or stale capsule instances.\"\"\"
        import os
        import subprocess
        import sys
        current_pid = os.getpid()

        try:
            # Find processes listening on MCP port 8765
            if sys.platform == 'win32':
                result = subprocess.run(
                    ['netstat', '-ano'], capture_output=True, text=True, timeout=5
                )
                for line in result.stdout.split('\\n'):
                    if ':8765' in line and 'LISTENING' in line:
                        parts = line.split()
                        if parts:
                            try:
                                pid = int(parts[-1])
                                if pid != current_pid:
                                    subprocess.run(['taskkill', '/F', '/PID', str(pid)], 
                                                   capture_output=True, timeout=5)
                            except (ValueError, subprocess.TimeoutExpired):
                                pass
            else:
                # Unix: use lsof
                result = subprocess.run(
                    ['lsof', '-ti', ':8765'], capture_output=True, text=True, timeout=5
                )
                for pid_str in result.stdout.strip().split('\\n'):
                    if pid_str:
                        try:
                            pid = int(pid_str)
                            if pid != current_pid:
                                os.kill(pid, 9)
                        except (ValueError, ProcessLookupError):
                            pass
        except Exception:
            pass  # Silently ignore cleanup failures

    # Run cleanup on module load
    _cleanup_old_capsule_processes()

