        def on_worker_state_changed(self, event):
            \"\"\"Handle worker completion - call stored callback with result.\"\"\"
            if event.state == WorkerState.SUCCESS:
                worker_name = event.worker.name
                if worker_name in self._worker_callbacks:
                    callback = self._worker_callbacks.pop(worker_name)
                    self._hide_loading()  # Hide spinner on completion
                    try:
                        callback(event.worker.result)
                    except Exception as e:
                        self._log(f"⚠️ Worker callback error: {{e}}")
            elif event.state == WorkerState.ERROR:
                worker_name = event.worker.name
                if worker_name in self._worker_callbacks:
                    self._worker_callbacks.pop(worker_name)
                    self._hide_loading()  # Hide spinner on error
                    self._log(f"❌ Worker {{worker_name}} failed: {{event.worker.error}}")

