        async def _watch_mcp_log(self):
            """Watch MCP log file and display in MCP tab."""
            import asyncio
            mcp_log_path = Path(__file__).parent / '.mcp_server.log'
            last_size = 0

            while True:
                try:
                    if mcp_log_path.exists():
                        current_size = mcp_log_path.stat().st_size
                        if current_size > last_size:
                            # Read new content
                            with open(mcp_log_path, 'r', encoding='utf-8', errors='replace') as f:
                                f.seek(last_size)
                                new_content = f.read()
                            last_size = current_size
                            # Display in MCP tab
                            for line in new_content.strip().split('\\n'):
                                if line.strip():
                                    self._mcp_log(line)
                except Exception:
                    pass
                await asyncio.sleep(0.3)

        async def _watch_relay_center(self):
            \"\"\"
            🎛️ RELAY CENTER WATCHER

            Agent writes commands to .relay_center.cmd
            TUI picks them up and executes them live.
            You watch your TUI, agent drives from its terminal.

            ROBUST PARSING:
            - Handles commands appended without leading newlines
            - Detects known command prefixes even when concatenated
            - Tracks processed commands by hash to allow repeats
            - Normalizes Windows/Unix line endings
            \"\"\"
            import asyncio
            import re
            import hashlib

            last_mtime = 0
            processed_hashes = set()  # Track processed commands by hash+timestamp

            # Known command prefixes that can appear concatenated
            COMMAND_PREFIXES = [
                'vast ', 'hub ', 'plug ', 'unplug', 'status', 'help', 'slots',
                'embed ', 'imagine', 'deliberate ', 'council ', 'bag ',
                'to ', 'pipe ', 'broadcast ', 'who',
                'infer', 'cascade', 'observe', 'save', 'implode', 'defrost',
                'quickstart', 'about', 'provenance', 'lineage', 'heartbeat',
                'hash', 'capabilities', 'caps', 'compare', 'verify', 'pocket',
                'catalog', 'workflow '
            ]

            def extract_commands(text):
                \"\"\"Extract commands even if concatenated without newlines.\"\"\"
                # Normalize line endings
                text = text.replace('\\r\\n', '\\n').replace('\\r', '\\n')

                # Split by newlines first
                lines = text.split('\\n')
                commands = []

                for line in lines:
                    line = line.strip()
                    if not line or line.startswith('#'):
                        continue

                    # Check if line contains concatenated commands
                    # e.g. "vast search x>=1vast search y>=2vast search z>=3"
                    remaining = line
                    while remaining:
                        found_cmd = False
                        for prefix in COMMAND_PREFIXES:
                            # Find second occurrence of prefix (first could be at start)
                            first_pos = remaining.lower().find(prefix.lower())
                            if first_pos == 0:
                                # Command at start, look for next command
                                second_pos = -1
                                for p in COMMAND_PREFIXES:
                                    pos = remaining.lower().find(p.lower(), len(prefix))
                                    if pos > 0 and (second_pos == -1 or pos < second_pos):
                                        second_pos = pos

                                if second_pos > 0:
                                    # Found concatenated commands
                                    cmd = remaining[:second_pos].strip()
                                    if len(cmd) > 2:
                                        commands.append(cmd)
                                    remaining = remaining[second_pos:]
                                    found_cmd = True
                                    break
                                else:
                                    # Single command on this line
                                    if len(remaining) > 2:
                                        commands.append(remaining)
                                    remaining = ''
                                    found_cmd = True
                                    break

                        if not found_cmd:
                            # No known prefix at start - treat whole thing as command
                            if len(remaining) > 2:
                                commands.append(remaining)
                            remaining = ''

                return commands

            while self._relay_listening:
                try:
                    if self._relay_center.exists():
                        # Check if file was modified
                        current_mtime = self._relay_center.stat().st_mtime
                        if current_mtime != last_mtime:
                            # File changed - wait for write to complete (debounce)
                            await asyncio.sleep(0.3)
                            last_mtime = self._relay_center.stat().st_mtime

                            content = self._relay_center.read_text(encoding='utf-8')

                            # Extract commands (handles concatenation)
                            commands = extract_commands(content)

                            # Process each command (only if not already processed)
                            for cmd in commands:
                                # Hash includes timestamp bucket to allow re-runs
                                time_bucket = int(current_mtime * 10)  # 100ms granularity
                                cmd_hash = hashlib.md5(f"{{cmd}}:{{time_bucket}}".encode()).hexdigest()[:12]

                                if cmd_hash not in processed_hashes:
                                    processed_hashes.add(cmd_hash)
                                    # Keep hash set bounded
                                    if len(processed_hashes) > 1000:
                                        processed_hashes.clear()

                                    self._log(f"🤖 RELAY: {{cmd}}")
                                    await self.on_input_submitted(
                                        type('E', (), {{'value': cmd, 'input': type('I', (), {{'value': ''}})}})()
                                    )

                            # After processing, keep only comments (instructions)
                            # and ensure file ends with newline for clean appends
                            lines = content.replace('\\r\\n', '\\n').replace('\\r', '\\n').split('\\n')
                            comment_lines = [line for line in lines if not line.strip() or line.strip().startswith('#')]

                            # Ensure trailing newline for clean appends
                            clean_content = '\\n'.join(comment_lines)
                            if clean_content and not clean_content.endswith('\\n'):
                                clean_content += '\\n'

                            self._relay_center.write_text(clean_content, encoding='utf-8')

                    # UNIVERSAL SIGNAL PORT - check for external signals
                    await self._check_signal_port()

                    # ═══════════════════════════════════════════════════════════
                    # MCP REQUEST BUS - Handle pending requests from MCP proxy
                    # Fast path: check inbox existence (no JSON parse if empty)
                    # ═══════════════════════════════════════════════════════════
                    await self._handle_mcp_request()

                    # HEARTBEAT - Update state file every 10 seconds so proxy mode knows we're alive
                    if not hasattr(self, '_last_heartbeat'):
                        self._last_heartbeat = 0
                    import time as _hb_time
                    if _hb_time.time() - self._last_heartbeat > 10:
                        self._write_capsule_state()
                        self._last_heartbeat = _hb_time.time()

                except Exception as e:
                    self._log(f"❌ RELAY ERROR: {{e}}")
                await asyncio.sleep(0.1)  # 100ms loop - responsive to MCP

