                lines.append("")
                lines.append(f"  [bold white]{{len(instances)}} INSTANCE(S) ACTIVE[/]")
                lines.append("  " + "━" * 55)

                # Iterate through all instances
                for idx, (iid, inst) in enumerate(instances.items()):
                    color = GPU_COLORS[idx % len(GPU_COLORS)]
                    status = inst.get('status', 'unknown')
                    gpu_name = inst.get('gpu', 'GPU')
                    connected = inst.get('connected', False)
                    models = inst.get('models', [])
                    ssh_host = inst.get('ssh_host', '')
                    ssh_port = inst.get('ssh_port', '')
                    cost_hr = inst.get('cost_per_hr', 0.0)
                    total_cost += cost_hr

                    # Status indicators
                    status_icon = '🟢' if status == 'running' else '🟡' if 'loading' in status else '🔴'
                    conn_icon = '⚡' if connected else '○'
                    current_marker = ' ◀ CURRENT' if iid == current_id else ''

                    lines.append("")
                    lines.append(f"  [{{color}}]━━━ INSTANCE {{iid}} ━━━[/{{color}}]{{current_marker}}")
                    lines.append(f"  {{status_icon}} [bold {{color}}]{{gpu_name}}[/] - {{status.upper()}}")
                    lines.append(f"  {{conn_icon}} Connected: {{'[green]YES[/]' if connected else '[dim]NO[/]'}}  │  ${{cost_hr:.3f}}/hr")

                    # ─── GPU UTILIZATION BAR ───
                    gpu_util = inst.get('gpu_util', 0)
                    vram_used = inst.get('vram_used', 0)
                    vram_total = inst.get('vram_total', 1)
                    vram_pct = (vram_used / vram_total * 100) if vram_total > 0 else 0

                    # Create visual bar (20 chars wide)
                    bar_width = 20
                    gpu_filled = int(bar_width * gpu_util / 100)
                    gpu_bar = "█" * gpu_filled + "░" * (bar_width - gpu_filled)
                    vram_filled = int(bar_width * vram_pct / 100)
                    vram_bar = "█" * vram_filled + "░" * (bar_width - vram_filled)

                    util_color = 'green' if gpu_util < 50 else 'yellow' if gpu_util < 80 else 'red'
                    lines.append(f"  [dim]GPU:[/] [{{util_color}}]{{gpu_bar}}[/] {{gpu_util}}%")
                    lines.append(f"  [dim]VRAM:[/] [cyan]{{vram_bar}}[/] {{vram_used:.1f}}/{{vram_total:.1f}}GB")

                    # SSH info
                    if ssh_host and ssh_port:
                        lines.append(f"  [dim]SSH: {{ssh_host}}:{{ssh_port}}[/]")

                    # Models loaded on this instance (color-coded)
                    if models:
                        lines.append(f"  [bold {{color}}]📦 Models ({{len(models)}}):[/]")
                        for model_name in models[:5]:  # Show max 5
                            lines.append(f"     [{{color}}]●[/{{color}}] {{model_name}}")
                        if len(models) > 5:
                            lines.append(f"     [dim]... and {{len(models) - 5}} more[/]")
                    else:
                        lines.append(f"  [dim]No models loaded - use 'plug MODEL'[/]")

                # Total cost summary with LIVE accumulator
                lines.append("")
                lines.append("  " + "━" * 55)
                # Calculate accumulated cost based on runtime
                total_accumulated = 0.0
                for iid, inst in instances.items():
                    cost_hr = inst.get('cost_per_hr', 0.0)
                    start_time = inst.get('start_time', 0)
                    if start_time:
                        runtime_hours = (__import__('time').time() - start_time) / 3600
                        total_accumulated += cost_hr * runtime_hours
                lines.append(f"  [bold white]💰 RATE: ${{total_cost:.3f}}/hr[/] │ [bold yellow]📊 SPENT: ~${{total_accumulated:.2f}}[/]")

                # ─── TOOL ACTIVITY STREAM ───
                activity = getattr(self, '_vast_activity_log', [])
                if activity:
                    lines.append("")
                    lines.append("  [bold cyan]┌─ RECENT ACTIVITY ─────────────────────────────────────────┐[/]")
                    # Show last 5 activity entries (most recent first)
                    for entry in activity[-5:]:
                        ts = entry.get('time', '--:--:--')
                        tool = entry.get('tool', 'unknown')
                        status = entry.get('status', '??')
                        icon = '✓' if status == 'ok' else '✗' if status == 'error' else '⟳'
                        color = 'green' if status == 'ok' else 'red' if status == 'error' else 'yellow'
                        lines.append(f"  [{{color}}]{{icon}} {{ts}} │ {{tool}}[/]")
                    lines.append("  [bold cyan]└───────────────────────────────────────────────────────────┘[/]")

                # Commands
                lines.append("")
                lines.append("  [bold white]Commands:[/]")
                lines.append("    vast connect <id>     Switch to instance")
                lines.append("    vast stop <id>        Stop specific instance")
                lines.append("    vast broadcast <cmd>  Send to ALL GPUs")
                lines.append("    vast distribute ...   Send different cmds to each")
                lines.append("")
                lines.append("[bold cyan]└───────────────────────────────────────────────────────────┘[/bold cyan]")

            return "\\n".join(lines)

        def _update_vast_tab(self):
            \"\"\"Refresh the VAST tab display.\"\"\"
            try:
                vast_view = self.query_one("#vast-view", Static)
                vast_view.update(self._render_vast_tab())
            except Exception:
                pass

        def _start_vast_polling(self):
            \"\"\"Start background thread to poll vast instance status.\"\"\"
            import threading
            import subprocess
            import json
            import time

            def poll_loop():
                while self._vast_state.get('id') and self._vast_poll_thread:
                    try:
                        # Get instance status
                        result = subprocess.run(
                            ['vastai', 'show', 'instance', str(self._vast_state['id']), '--raw'],
                            capture_output=True, text=True, timeout=30
                        )
                        if result.returncode == 0:
                            data = json.loads(result.stdout)
                            self._vast_state['status'] = data.get('actual_status', 'unknown')
                            self._vast_state['gpu'] = data.get('gpu_name', 'GPU')
                            self._vast_state['public_ip'] = data.get('public_ipaddr', '')
                            self._vast_state['cost_per_hr'] = data.get('dph_total', 0)
                            self._vast_state['vram_total'] = data.get('gpu_ram', 0) / 1024  # MB to GB
                            self._vast_state['ssh_host'] = data.get('ssh_host', '')
                            self._vast_state['ssh_port'] = data.get('ssh_port', '')

                            # Parse ports for MCP URL
                            ports = data.get('ports', {{}})
                            if '8765/tcp' in ports and ports['8765/tcp']:
                                host_port = ports['8765/tcp'][0].get('HostPort', '8765')
                                self._vast_state['mcp_url'] = f"http://{{self._vast_state['public_ip']}}:{{host_port}}/sse"

                            # Get GPU stats via SSH if possible
                            if self._vast_ssh_key and self._vast_state['status'] == 'running':
                                ssh_port = None
                                if '22/tcp' in ports and ports['22/tcp']:
                                    ssh_port = ports['22/tcp'][0].get('HostPort')
                                if ssh_port:
                                    try:
                                        gpu_result = subprocess.run([
                                            'ssh', '-i', self._vast_ssh_key,
                                            '-o', 'StrictHostKeyChecking=no',
                                            '-o', 'ConnectTimeout=5',
                                            '-p', ssh_port,
                                            f"root@{{self._vast_state['public_ip']}}",
                                            "nvidia-smi --query-gpu=utilization.gpu,memory.used,memory.total --format=csv,noheader,nounits 2>/dev/null | head -1"
                                        ], capture_output=True, text=True, timeout=10)
                                        if gpu_result.returncode == 0 and gpu_result.stdout.strip():
                                            parts = gpu_result.stdout.strip().split(',')
                                            if len(parts) >= 3:
                                                self._vast_state['gpu_util'] = int(parts[0].strip())
                                                self._vast_state['vram_used'] = float(parts[1].strip()) / 1024
                                                self._vast_state['vram_total'] = float(parts[2].strip()) / 1024

                                        # Also get MCP logs
                                        log_result = subprocess.run([
                                            'ssh', '-i', self._vast_ssh_key,
                                            '-o', 'StrictHostKeyChecking=no',
                                            '-o', 'ConnectTimeout=5',
                                            '-p', ssh_port,
                                            f"root@{{self._vast_state['public_ip']}}",
                                            "tail -20 /workspace/mcp.log 2>/dev/null || echo 'No logs yet'"
                                        ], capture_output=True, text=True, timeout=10)
                                        if log_result.returncode == 0:
                                            self._vast_state['logs'] = log_result.stdout.strip().split('\\n')[-20:]
                                    except Exception:
                                        pass

                            # Sync to _vast_instances so _render_vast_tab sees fresh data
                            iid = str(self._vast_state['id'])
                            if iid in self._vast_instances:
                                self._vast_instances[iid]['status'] = self._vast_state['status']
                                self._vast_instances[iid]['gpu'] = self._vast_state['gpu']
                                self._vast_instances[iid]['cost_per_hr'] = self._vast_state['cost_per_hr']
                                self._vast_instances[iid]['ssh_host'] = self._vast_state['ssh_host']
                                self._vast_instances[iid]['ssh_port'] = self._vast_state['ssh_port']
                                self._vast_instances[iid]['gpu_util'] = self._vast_state.get('gpu_util', 0)
                                self._vast_instances[iid]['vram_used'] = self._vast_state.get('vram_used', 0)
                                self._vast_instances[iid]['vram_total'] = self._vast_state.get('vram_total', 0)

                            # Update display (thread-safe)
                            try:
                                self.call_from_thread(self._update_vast_tab)
                            except AttributeError:
                                pass
                    except Exception as e:
                        pass

                    time.sleep(10)  # Poll every 10 seconds

            self._vast_poll_thread = threading.Thread(target=poll_loop, daemon=True)
            self._vast_poll_thread.start()

        def _stop_vast_polling(self):
            \"\"\"Stop the vast polling thread.\"\"\"
            self._vast_poll_thread = None

        def action_quit(self):
            \"\"\"Override quit to stop polling threads first.\"\"\"
            self._stop_vast_polling()
            self.exit()

        def _render_tree(self):
            \"\"\"
            🌐 AGENT TREE - Infinite Nested Tree View

            Features:
            - Infinite nesting depth for agent hierarchies
            - Empty ports collapsed by default (shown as summary)
            - Active models shown prominently with full details
            - Scales to thousands of nested agents
            - Tree structure: parent → children → grandchildren → ...
            \"\"\"
            import json
            import time
            lines = []

            # Toggle state for showing empty slots (default: hidden)
            show_empty = getattr(self, '_show_empty_slots', False)

            # ═══════════════════════════════════════════════════════════════
            # HEADER
            # ═══════════════════════════════════════════════════════════════
            lines.append(f"[bold cyan]┌─ AGENT TREE ──────────────────────────────────────────────┐[/bold cyan]")
            lines.append("")

            # ═══════════════════════════════════════════════════════════════
            # SLOTS - Recursive infinite nesting
            # ═══════════════════════════════════════════════════════════════
            lines.append("[bold white]│ ┌─ SLOTS ───────────────────────────────────────────┐ │[/bold white]")

            # Parse CASCADE feed for latency data
            cascade_stats = self._parse_cascade_for_stats()

            # Count active vs empty
            members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))

            def count_tree_nodes(node, depth=0):
                \"\"\"Recursively count all nodes in tree.\"\"\"
                count = 1
                children = getattr(node, '_clones', []) + getattr(node, '_children', []) + getattr(node, 'councilors', [])
                for child in children:
                    count += count_tree_nodes(child, depth + 1)
                return count

            def render_node(node, depth=0, prefix="", is_last=True, slot_idx=None):
                \"\"\"Recursively render a node and its children.\"\"\"
                node_lines = []

                name = getattr(node, 'name', f'agent_{{slot_idx or 0}}')
                model = getattr(node, 'model', None)
                mid = getattr(node, '_model_source', None) or ''

                # Tree branch characters
                if depth == 0:
                    branch = ""
                    next_prefix = "    "
                else:
                    branch = prefix + ("└── " if is_last else "├── ")
                    next_prefix = prefix + ("    " if is_last else "│   ")

                # Only show if active OR show_empty is True
                is_active = model is not None

                if is_active or show_empty or depth == 0:
                    # Status icon
                    if is_active:
                        status = "[green]●[/green]"
                    else:
                        status = "[dim]○[/dim]"

                    # Model type detection (handles both local and remote models)
                    # GPU color palette for remote models
                    GPU_COLORS = ['magenta', 'cyan', 'yellow', 'green', 'white', 'blue', 'red', 'bright_magenta']

                    if model is not None:
                        is_remote = getattr(node, '_is_remote', False) or (isinstance(model, str) and model.startswith('REMOTE:'))

                        if is_remote:
                            # REMOTE MODEL - color by GPU instance
                            instance_id = str(getattr(node, '_vast_instance_id', '') or getattr(self, '_vast_instance_id', '') or '')
                            # Find instance index for color
                            instance_keys = list(self._vast_instances.keys()) if hasattr(self, '_vast_instances') else []
                            gpu_idx = instance_keys.index(instance_id) if instance_id in instance_keys else 0
                            gpu_color = GPU_COLORS[gpu_idx % len(GPU_COLORS)]
                            mtype = f"[bold {{gpu_color}}]🖥️ GPU{{instance_id[-4:] if len(instance_id) > 4 else instance_id}}[/]"
                        elif hasattr(model, 'encode'):
                            mtype = "[blue]EMBED[/blue]"
                        elif hasattr(model, 'generate'):
                            mtype = "[magenta]LLM[/magenta]"
                        elif hasattr(model, 'detect'):
                            mtype = "[yellow]VISION[/yellow]"
                        elif hasattr(model, 'classify'):
                            mtype = "[cyan]CLASS[/cyan]"
                        elif hasattr(model, 'rerank'):
                            mtype = "[green]RERANK[/green]"
                        else:
                            mtype = "[dim]GEN[/dim]"
                    else:
                        mtype = "[dim]--[/dim]"

                    # Dimensions (skip for remote models which are string references)
                    dims = ""
                    if model is not None and not isinstance(model, str):
                        try:
                            if hasattr(model, 'get_sentence_embedding_dimension'):
                                dims = f"{{model.get_sentence_embedding_dimension()}}d"
                            elif hasattr(model, 'config') and hasattr(model.config, 'hidden_size'):
                                dims = f"{{model.config.hidden_size}}d"
                        except Exception:
                            pass

                    # Latency
                    slot_key = str(slot_idx) if slot_idx is not None else "0"
                    latency = cascade_stats.get('slot_latencies', {{}}).get(slot_key, None)
                    lat_str = ""
                    if latency:
                        if latency > 100:
                            lat_str = f" [yellow]⚡{{latency:.0f}}ms[/yellow]"
                        elif latency < 30:
                            lat_str = f" [green]⚡{{latency:.0f}}ms[/green]"
                        else:
                            lat_str = f" ⚡{{latency:.0f}}ms"

                    # Short model ID or name
                    short_mid = mid[:20] if mid else name[:20]

                    # Count children for summary
                    children = getattr(node, '_clones', []) + getattr(node, '_children', [])
                    child_count = len(children)
                    child_summary = f" [dim]({{child_count}} nested)[/dim]" if child_count > 0 else ""

                    if is_active:
                        node_lines.append(f"│ │  {{branch}}{{status}} {{short_mid}} {{mtype}} {{dims}}{{lat_str}}{{child_summary}}")
                    else:
                        node_lines.append(f"│ │  {{branch}}{{status}} [dim]{{short_mid}}[/dim]{{child_summary}}")

                # Recurse into children (clones, children, sub-councilors)
                children = getattr(node, '_clones', []) + getattr(node, '_children', [])

                # Count active children for collapse summary
                active_children = [c for c in children if getattr(c, 'model', None) is not None]
                empty_children = [c for c in children if getattr(c, 'model', None) is None]

                # Limit depth display to prevent overwhelming output
                max_display_depth = 5
                if depth < max_display_depth:
                    # Show active children always
                    for idx, child in enumerate(active_children):
                        is_child_last = (idx == len(active_children) - 1) and len(empty_children) == 0
                        node_lines.extend(render_node(child, depth + 1, next_prefix, is_child_last, slot_idx=idx))

                    # Show empty children only if toggled
                    if show_empty:
                        for idx, child in enumerate(empty_children):
                            is_child_last = (idx == len(empty_children) - 1)
                            node_lines.extend(render_node(child, depth + 1, next_prefix, is_child_last, slot_idx=len(active_children) + idx))
                    elif len(empty_children) > 0:
                        # Show collapsed summary for empty
                        node_lines.append(f"│ │  {{next_prefix}}[dim]└── ({{len(empty_children)}} empty ports collapsed)[/dim]")

                elif len(children) > 0:
                    # At max depth, show summary
                    total_below = count_tree_nodes(node) - 1
                    active_below = len([c for c in children if getattr(c, 'model', None)])
                    node_lines.append(f"│ │  {{next_prefix}}[dim]└── ... ({{total_below}} more: {{active_below}} active)[/dim]")

                return node_lines

            # Render root brain/council
            if members:
                total_active = sum(1 for c in members if getattr(c, 'model', None) is not None)
                total_empty = len(members) - total_active

                # Show summary header
                lines.append(f"│ │  [bold]🧠 {{self.brain_type.upper()}}[/bold] [dim]({{total_active}} active, {{total_empty}} empty)[/dim]")
                lines.append("│ │")

                for i, c in enumerate(members):
                    is_last = (i == len(members) - 1)
                    # Only render if active or show_empty
                    if getattr(c, 'model', None) is not None or show_empty:
                        lines.extend(render_node(c, depth=1, prefix="", is_last=is_last, slot_idx=i))

                # If hiding empty and there are empty slots, show summary
                if not show_empty and total_empty > 0 and total_active < len(members):
                    lines.append(f"│ │  [dim]    └── ({{total_empty}} empty ports - press E to expand)[/dim]")
            else:
                lines.append("│ │  [dim]No agents - use 'plug <model_id>'[/dim]")

            lines.append("│ │")
            lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
            lines.append("")

            # ═══════════════════════════════════════════════════════════════
            # IMAGINATION TRAJECTORIES - Dreamer's Projected Futures
            # Each trajectory is a POTENTIAL WORK TREE that can be allocated
            # to adapters for differential interpretation
            # ═══════════════════════════════════════════════════════════════
            show_imagination = getattr(self, '_show_imagination', True)
            if self.is_ouroboros or self.brain_type == 'dreamer':
                lines.append("[bold magenta]│ ┌─ IMAGINATION (Dreamer Trajectories) ─────────────────┐ │[/bold magenta]")

                # Get last imagination from dreamer
                dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None)
                last_imagination = getattr(dreamer, '_last_imagination', []) if dreamer else []

                # Get adapter topology if available
                adapter_topo = None
                if hasattr(self.brain, 'get_adapter_topology'):
                    adapter_topo = self.brain.get_adapter_topology()

                if last_imagination and show_imagination:
                    n_branches = len(last_imagination)
                    horizon = len(last_imagination[0]) if last_imagination and last_imagination[0] else 0
                    real_rssm = last_imagination[0][0].get('real_rssm', False) if last_imagination and last_imagination[0] else False

                    rssm_badge = "[green]●RSSM[/green]" if real_rssm else "[dim]○sim[/dim]"

                    # Show adapter count if multi-adapter
                    if adapter_topo and adapter_topo['count'] > 1:
                        adapter_badge = f"[cyan]×{{adapter_topo['count']}}adapt[/cyan]"
                        lines.append(f"│ │  {{rssm_badge}} {{adapter_badge}} [bold]{{n_branches}} branches × {{horizon}} steps[/bold]")
                    else:
                        lines.append(f"│ │  {{rssm_badge}} [bold]{{n_branches}} branches × {{horizon}} steps[/bold]")
                    lines.append("│ │")

                    # Get trajectory interpretation if brain supports it
                    trajectory_interps = []
                    if hasattr(self.brain, 'interpret_trajectory'):
                        for traj in last_imagination[:8]:
                            if traj:
                                # Extract latent vectors from trajectory
                                latents = [step.get('latent', step.get('stoch', None)) for step in traj]
                                latents = [l for l in latents if l is not None]
                                if latents:
                                    try:
                                        interp = self.brain.interpret_trajectory(latents)
                                        trajectory_interps.append(interp)
                                    except Exception:
                                        trajectory_interps.append(None)
                                else:
                                    trajectory_interps.append(None)
                            else:
                                trajectory_interps.append(None)

                    # Render each branch as collapsible tree
                    for branch_idx, trajectory in enumerate(last_imagination[:8]):  # Max 8 branches
                        if not trajectory:
                            continue

                        first_step = trajectory[0]
                        branch_action = first_step.get('branch_action', branch_idx)
                        total_value = first_step.get('trajectory_total_value', sum(s.get('value', 0) for s in trajectory))

                        # Get trajectory interpretation confidence
                        traj_conf = None
                        hotspots = []
                        if branch_idx < len(trajectory_interps) and trajectory_interps[branch_idx]:
                            traj_conf = trajectory_interps[branch_idx].get('trajectory_confidence', None)
                            hotspots = trajectory_interps[branch_idx].get('divergence_hotspots', [])

                        # Branch header with value bar
                        value_bar = "█" * min(10, int(abs(total_value) * 2))
                        if total_value > 0:
                            value_color = "green" if total_value > 2 else "yellow"
                        else:
                            value_color = "red"

                        is_best = branch_idx == 0  # Assuming sorted by value
                        star = "[bold yellow]★[/bold yellow]" if is_best else " "

                        # Confidence badge from multi-adapter interpretation
                        conf_badge = ""
                        if traj_conf is not None:
                            if traj_conf > 0.8:
                                conf_badge = "[green]⬤[/green]"  # High confidence
                            elif traj_conf > 0.5:
                                conf_badge = "[yellow]◐[/yellow]"  # Medium
                            else:
                                conf_badge = "[red]○[/red]"  # Low - adapters disagreed

                        lines.append(f"│ │  {{star}} {{conf_badge}} [bold cyan]Action {{branch_action}}[/bold cyan] → [{{value_color}}]{{value_bar}} {{total_value:.2f}}[/{{value_color}}]")

                        # Show trajectory steps (collapsed by default, show first 3)
                        show_steps = getattr(self, '_expand_trajectories', False)
                        steps_to_show = trajectory if show_steps else trajectory[:3]

                        for step_idx, step in enumerate(steps_to_show):
                            is_last_step = step_idx == len(steps_to_show) - 1
                            branch_char = "└──" if is_last_step else "├──"

                            step_val = step.get('value', 0)
                            step_action = step.get('action', '?')
                            latent_norm = step.get('latent_norm', 0)

                            # Mini value indicator
                            val_char = "↑" if step_val > 0.5 else "↓" if step_val < -0.5 else "→"

                            # Mark divergence hotspots
                            hotspot_mark = "[bold red]![/bold red]" if step_idx in hotspots else ""

                            lines.append(f"│ │      {{branch_char}} t={{step_idx}}: a={{step_action}} {{val_char}}{{step_val:.2f}} [dim]‖{{latent_norm:.0f}}[/dim] {{hotspot_mark}}")

                        if not show_steps and len(trajectory) > 3:
                            lines.append(f"│ │      [dim]└── ... ({{len(trajectory) - 3}} more steps)[/dim]")

                    lines.append("│ │")
                    expand_hint = "[T]=collapse" if getattr(self, '_expand_trajectories', False) else "[T]=expand steps"
                    lines.append(f"│ │  [dim]{{expand_hint}} | [I]=imagine now[/dim]")

                    # Show adapter divergence legend if applicable
                    if adapter_topo and adapter_topo['count'] > 1:
                        lines.append(f"│ │  [dim]Confidence: [green]⬤[/green]=agree [yellow]◐[/yellow]=partial [red]○[/red]=divergent  [bold red]![/bold red]=hotspot[/dim]")
                else:
                    lines.append("│ │  [dim]No imagination yet - type 'imagine' to project futures[/dim]")

                lines.append("[dim]│ └─────────────────────────────────────────────────────┘ │[/dim]")
                lines.append("")

            # ═══════════════════════════════════════════════════════════════
            # DECISION MATRIX - Best Actions from Imagination
            # ═══════════════════════════════════════════════════════════════
            if self.is_ouroboros or self.brain_type == 'dreamer':
                dreamer = getattr(self.brain, '_dreamer', None) or getattr(self.brain, 'dreamer_world_model', None)
                last_imagination = getattr(dreamer, '_last_imagination', []) if dreamer else []

                if last_imagination:
