        def _parse_cascade_for_stats(self) -> dict:
            \"\"\"Parse CASCADE feed for real-time stats.\"\"\"
            import json
            stats = {{
                'total_inferences': 0,
                'avg_latency': 0,
                'slot_latencies': {{}},
                'recent_events': []
            }}

            try:
                feed_file = _CASCADE_FEED_DIR / 'feed.jsonl' if _CASCADE_FEED_DIR else None
                if feed_file and feed_file.exists():
                    lines = feed_file.read_text(encoding='utf-8').strip().split('\\n')
                    events = []
                    latencies = []

                    for line in lines[-100:]:  # Last 100 events
                        try:
                            evt = json.loads(line)
                            events.append(evt)

                            etype = evt.get('event_type', '')
                            data = evt.get('data', {{}})

                            if etype in ('inference', 'embed'):
                                stats['total_inferences'] += 1
                                if 'elapsed_ms' in data:
                                    latencies.append(data['elapsed_ms'])
                                    slot = str(data.get('slot', 0))
                                    stats['slot_latencies'][slot] = data['elapsed_ms']
                        except Exception:
                            pass

                    stats['recent_events'] = events[-10:]
                    if latencies:
                        stats['avg_latency'] = sum(latencies) / len(latencies)
            except Exception:
                pass

            return stats

        def _format_uptime(self) -> str:
            \"\"\"Format uptime as human-readable string.\"\"\"
            import time
            elapsed = time.time() - self._start_time
            if elapsed < 60:
                return f"{{int(elapsed)}}s"
            elif elapsed < 3600:
                return f"{{int(elapsed // 60)}}m {{int(elapsed % 60)}}s"
            else:
                hours = int(elapsed // 3600)
                mins = int((elapsed % 3600) // 60)
                return f"{{hours}}h {{mins}}m"

        def _render_provenance(self):
            \"\"\"
            Render CASCADE CAUSATION GRAPH - live event topology + merkle chain.

            Shows: graph stats, component breakdown, causation chains,
            root/leaf events, merkle root history, and feed.jsonl backup.
            \"\"\"
            import json
            lines = ["[bold blue]🔗 CASCADE CAUSATION GRAPH[/bold blue]", ""]

            if not _CASCADE_AVAILABLE:
