            if self._causation_graph is not None:
                try:
                    stats = self._causation_graph.get_stats()
                    evt_count = stats.get('event_count', 0)
                    link_count = stats.get('link_count', 0)
                    components = stats.get('components', [])
                    event_types = stats.get('event_types', [])

                    lines.append("")
                    lines.append("[bold cyan]┌─ GRAPH TOPOLOGY ─────────────────────────┐[/]")
