                    if components:
                        lines.append(f"  [bold]Components:[/] [dim]{{', '.join(str(c) for c in components[:5])}}[/]")
                    if event_types:
                        lines.append(f"  [bold]Event Types:[/] [dim]{{', '.join(str(t) for t in event_types[:8])}}[/]")
                    lines.append("[bold cyan]└──────────────────────────────────────────┘[/]")
                except Exception as e:
                    lines.append(f"[dim]Graph stats error: {{e}}[/]")
            else:
                lines.append("[dim]CausationGraph not initialized[/]")

            # ─── MERKLE ROOT HISTORY ───
            if self._merkle_roots:
                lines.append("")
                lines.append("[bold green]┌─ MERKLE CHAIN ───────────────────────────┐[/]")
                lines.append(f"  [bold]Current Root:[/] [bold green]⟐ {{self._merkle_roots[-1][:16]}}[/]")
                lines.append(f"  [bold]Chain Length:[/] [cyan]{{len(self._merkle_roots)}}[/] roots")
                # Show last few roots
                for i, root in enumerate(self._merkle_roots[-5:]):
                    idx = len(self._merkle_roots) - 5 + i
                    if idx < 0:
                        continue
                    lines.append(f"  [dim]#{{idx+1}}[/] [green]{{root[:16]}}[/]")
                lines.append("[bold green]└──────────────────────────────────────────┘[/]")

            # ─── RECENT EVENTS (from graph) ───
            if self._causation_graph is not None:
                try:
                    recent = self._causation_graph.get_recent_events(8)
                    if recent:
                        lines.append("")
                        lines.append("[bold white]┌─ RECENT EVENTS ──────────────────────────┐[/]")
                        for evt in recent:
                            etype = evt.event_type if hasattr(evt, 'event_type') else str(evt)
                            comp = evt.component if hasattr(evt, 'component') else '?'
                            eid = evt.event_id[:8] if hasattr(evt, 'event_id') else '?'
                            # Color by type
                            color = MerkleWidget._EVENT_COLORS.get(etype, 'dim white')
                            lines.append(f"  [{{color}}]▸ {{eid}}[/] {{etype}} [dim]({{comp}})[/]")
                        lines.append("[bold white]└──────────────────────────────────────────┘[/]")
                except Exception:
                    pass

                # ─── ROOT & LEAF EVENTS ───
                try:
                    roots = self._causation_graph.get_root_events()
                    leaves = self._causation_graph.get_leaf_events()
                    if roots or leaves:
                        lines.append("")
                        lines.append("[bold magenta]┌─ CAUSATION ENDPOINTS ────────────────────┐[/]")
                        if roots:
                            root_types = [r.event_type for r in roots[:3]] if hasattr(roots[0], 'event_type') else ['?']
                            lines.append(f"  [bold]Entry Points:[/] [dim]{{', '.join(root_types)}}[/] ({{len(roots)}} total)")
                        if leaves:
                            leaf_types = [l.event_type for l in leaves[:3]] if hasattr(leaves[0], 'event_type') else ['?']
                            lines.append(f"  [bold]Current State:[/] [dim]{{', '.join(leaf_types)}}[/] ({{len(leaves)}} total)")
                        lines.append("[bold magenta]└──────────────────────────────────────────┘[/]")
                except Exception:
                    pass

            # ─── FEED.JSONL BACKUP ───
            try:
                feed_file = _CASCADE_FEED_DIR / 'feed.jsonl' if _CASCADE_FEED_DIR else None
                if feed_file and feed_file.exists():
                    feed_lines = feed_file.read_text(encoding="utf-8").strip().split('\\n')
                    lines.append("")
                    lines.append(f"[dim]📁 feed.jsonl: {{len(feed_lines)}} persisted events[/]")
            except Exception:
                pass

            # ─── IN-MEMORY EVENT LOG ───
            if self._cascade_events:
                lines.append("")
                lines.append("[bold]In-Memory Log (last 5):[/bold]")
                for evt in self._cascade_events[-5:]:
                    lines.append(f"  {{evt}}")

            return "\\n".join(lines)

