        async def action_vast(self, subcmd: str = None, args: list = None):
            \"\"\"Control Vast.ai GPU rental for remote model hosting.

            Usage:
                vast                    - Show status and help
                vast search <query>     - Search GPU offers (e.g. 'gpu_ram>=48')
                vast rent <offer_id>    - Rent a GPU and deploy vLLM
                vast instances          - List your active instances
                vast connect <id>       - Route model inference to instance
                vast stop               - Destroy current instance
            \"\"\"
            args = args or []

            # ═══════════════════════════════════════════════════════════════
            # AUTO SSH KEY SETUP - No user intervention required!
            # ═══════════════════════════════════════════════════════════════
            def ensure_ssh_key():
                \"\"\"Auto-generate and register SSH key with Vast.ai if needed.\"\"\"
                import subprocess
                from pathlib import Path as P
                ssh_dir = P.home() / '.ssh'
                key_path = ssh_dir / 'vastai_key'
                pub_path = ssh_dir / 'vastai_key.pub'

                # Create .ssh dir if needed
                ssh_dir.mkdir(parents=True, exist_ok=True)

                # Generate key if not exists (no passphrase)
                if not key_path.exists():
                    self._log("🔑 Generating SSH key for Vast.ai (no passphrase)...")
                    try:
                        result = subprocess.run([
                            'ssh-keygen', '-t', 'ed25519',
                            '-f', str(key_path),
                            '-N', '',  # Empty passphrase
                            '-C', 'vastai-auto'
                        ], capture_output=True, text=True, timeout=30)
                        if result.returncode != 0:
                            self._log(f"❌ SSH keygen failed: {{result.stderr}}")
                            return False
                        self._log(f"✅ SSH key generated: {{key_path}}")
                    except FileNotFoundError:
                        # ssh-keygen not available, try Python crypto
                        try:
                            from cryptography.hazmat.primitives import serialization
                            from cryptography.hazmat.primitives.asymmetric.ed25519 import Ed25519PrivateKey

                            private_key = Ed25519PrivateKey.generate()

                            # Save private key (no encryption)
                            private_bytes = private_key.private_bytes(
                                encoding=serialization.Encoding.PEM,
                                format=serialization.PrivateFormat.OpenSSH,
                                encryption_algorithm=serialization.NoEncryption()
                            )
                            key_path.write_bytes(private_bytes)

                            # Save public key
                            public_key = private_key.public_key()
                            public_bytes = public_key.public_bytes(
                                encoding=serialization.Encoding.OpenSSH,
                                format=serialization.PublicFormat.OpenSSH
                            )
                            pub_path.write_bytes(public_bytes + b' vastai-auto\\n')

                            self._log(f"✅ SSH key generated (Python crypto): {{key_path}}")
                        except ImportError:
                            self._log("❌ Need ssh-keygen or: pip install cryptography")
                            return False
                        except Exception as e:
                            self._log(f"❌ Key generation failed: {{e}}")
                            return False

                # Read public key
                if not pub_path.exists():
                    self._log(f"❌ Public key not found: {{pub_path}}")
                    return False

                pubkey = pub_path.read_text().strip()

                # Register with Vast.ai (use 'create ssh-key' - 'set ssh-key' is deprecated)
                self._log("🔑 Registering SSH key with Vast.ai...")
                try:
                    result = subprocess.run(
                        ['vastai', 'create', 'ssh-key', pubkey],
                        capture_output=True, text=True, timeout=30
                    )
                    if result.returncode == 0:
                        self._log("✅ SSH key registered with Vast.ai")
                        return True
                    elif 'already' in result.stdout.lower() or 'already' in result.stderr.lower():
                        self._log("✅ SSH key already registered")
                        return True
                    else:
                        # Key might already be set, try anyway
                        self._log(f"⚠️ Key registration: {{result.stdout or result.stderr}}")
                        return True  # Proceed anyway
                except Exception as e:
                    self._log(f"⚠️ Could not register key: {{e}}")
                    return True  # Proceed anyway - key might already be set

            # Vast SDK initialization (uses module-level _vast_sdk globals)
            def _init_vast_sdk():
                \"\"\"Initialize Vast.ai SDK with API key from environment.\"\"\"
                global _vast_sdk, _vast_sdk_available
                if _vast_sdk is not None:
                    return _vast_sdk_available
                try:
                    from vastai import VastAI
                    api_key = os.environ.get('VAST_API_KEY', '')
                    if api_key:
                        _vast_sdk = VastAI(api_key=api_key)
                        _vast_sdk_available = True
                        return True
                    else:
                        # Try to read from vastai config file
                        config_path = Path.home() / '.vast_api_key'
                        if config_path.exists():
                            api_key = config_path.read_text().strip()
                            _vast_sdk = VastAI(api_key=api_key)
                            _vast_sdk_available = True
                            return True
                except ImportError:
                    pass
                except Exception:
                    pass
                return False

            def vast_available():
                \"\"\"Check if Vast.ai SDK or CLI is available.\"\"\"
                # Try SDK first
                if _init_vast_sdk():
                    return True
                # Fall back to CLI
                import subprocess
                try:
                    result = subprocess.run(['vastai', '--version'], capture_output=True, text=True, timeout=5)
                    return result.returncode == 0
                except Exception:
                    return False

            def run_vast(cmd_args, raw=True):
                \"\"\"Run vastai command via SDK (preferred) or CLI fallback.\"\"\"
                import subprocess
                import json

                # Try SDK first (no external CLI needed)
                if _init_vast_sdk() and _vast_sdk:
                    try:
                        # Map CLI commands to SDK methods
                        if len(cmd_args) >= 2:
                            action = cmd_args[0]
                            target = cmd_args[1]

                            if action == 'search' and target == 'offers':
                                query = ' '.join(cmd_args[2:]) if len(cmd_args) > 2 else ''
                                return _vast_sdk.search_offers(query=query)

                            elif action == 'show' and target == 'instances':
                                return _vast_sdk.show_instances()

                            elif action == 'show' and target == 'instance':
                                instance_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                return _vast_sdk.show_instance(id=instance_id)

                            elif action == 'create' and target == 'instance':
                                offer_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                # Parse additional args
                                image = 'vastai/pytorch:latest'
                                disk = 50
                                for arg in cmd_args[3:]:
                                    if arg.startswith('--image'):
                                        image = arg.split('=')[1] if '=' in arg else cmd_args[cmd_args.index(arg)+1]
                                    elif arg.startswith('--disk'):
                                        disk = int(arg.split('=')[1] if '=' in arg else cmd_args[cmd_args.index(arg)+1])
                                result = _vast_sdk.launch_instance(
                                    num_gpus=1,
                                    gpu_name=None,  # Use offer_id instead
                                    image=image,
                                    disk=disk,
                                )
                                return result

                            elif action == 'destroy' and target == 'instance':
                                instance_id = int(cmd_args[2]) if len(cmd_args) > 2 else 0
                                return _vast_sdk.destroy_instance(id=instance_id)

                            elif action == 'ssh-keys' and target == 'list':
                                return _vast_sdk.show_ssh_keys()

                            elif action == 'create' and target == 'ssh-key':
                                ssh_key = cmd_args[2] if len(cmd_args) > 2 else ''
                                return _vast_sdk.create_ssh_key(ssh_key=ssh_key)
                    except Exception as sdk_err:
                        # SDK failed, fall through to CLI
                        pass

                # Fall back to CLI
                try:
                    full_cmd = ['vastai'] + cmd_args
                    if raw:
                        full_cmd.append('--raw')
                    result = subprocess.run(full_cmd, capture_output=True, text=True, timeout=60)
                    if result.returncode != 0:
                        return {{'error': result.stderr or 'Command failed'}}
                    if raw:
                        try:
                            return json.loads(result.stdout)
                        except Exception:
                            return {{'output': result.stdout}}
                    return {{'output': result.stdout}}
                except subprocess.TimeoutExpired:
                    return {{'error': 'Command timed out'}}
                except FileNotFoundError:
                    return {{'error': 'vastai CLI not found. Set VAST_API_KEY env var or: pip install vastai'}}
                except Exception as e:
                    return {{'error': str(e)}}

            if subcmd == 'search' and args:
                # Search for GPU offers - show ALL with pagination
                # Parse page number if present
                page = 1
                page_size = 20
                query_parts = []
                for arg in args:
                    if arg.startswith('page=') or arg.startswith('p='):
                        try:
                            page = int(arg.split('=')[1])
                        except Exception:
                            pass
                    elif arg.startswith('size='):
                        try:
                            page_size = int(arg.split('=')[1])
                        except Exception:
                            pass
                    else:
                        query_parts.append(arg)

                query = ' '.join(query_parts) if query_parts else 'rentable=true'
                self._log(f"🔍 Searching Vast.ai: {{query}}")
                result = run_vast(['search', 'offers', query])

                if 'error' in result:
                    self._log(f"❌ {{result['error']}}")
                    return

                offers = result if isinstance(result, list) else []
                self._vast_offers_cache = offers  # Cache ALL results

                if not offers:
                    self._log("📭 No offers found")
                    return

                # Pagination
                total = len(offers)
                total_pages = (total + page_size - 1) // page_size
                start_idx = (page - 1) * page_size
                end_idx = min(start_idx + page_size, total)
                page_offers = offers[start_idx:end_idx]

                self._log(f"━━━━━━ GPU OFFERS (Page {{page}}/{{total_pages}}, {{total}} total) ━━━━━━")
                self._log("")
                self._log("  #   | ID       | GPU              | VRAM  | $/hr   | Rel%  | GPUs")
                self._log("  ----+----------+------------------+-------+--------+-------+-----")

                for i, offer in enumerate(page_offers):
                    idx = start_idx + i + 1
                    gpu = offer.get('gpu_name', '?').replace('_', ' ')[:16]
                    vram = offer.get('gpu_ram', 0)
                    price = offer.get('dph_total', 0)
                    reliability = offer.get('reliability', 0) * 100
                    oid = str(offer.get('id', '?'))[:8]
                    num_gpus = offer.get('num_gpus', 1)
                    self._log(f"  {{idx:3}} | {{oid:8}} | {{gpu:16}} | {{vram:5.0f}}GB | ${{price:5.2f}} | {{reliability:5.1f}}% | {{num_gpus}}x")

                self._log("")
                self._log(f"📊 Showing {{start_idx+1}}-{{end_idx}} of {{total}} offers")
