                    self._vast_state['status'] = 'created'
                    self._vast_state['start_time'] = instance_state['start_time']
                    self._vast_state['cost_per_hr'] = instance_state['cost_per_hr']
                    self._vast_state['gpu'] = instance_state['gpu']

