                def send_to_gpu(instance_id, executor):
                    try:
                        # Write command to remote relay file
                        relay_cmd = f'echo "{{cmd_to_broadcast}}" >> /workspace/.relay_center.cmd'
                        result = executor.execute(relay_cmd)

