                # Syntax: vast distribute <id>:<cmd> <id>:<cmd> ...
                if not args:
                    self._log("❌ Usage: vast distribute <instance_id>:<command> ...")
                    self._log("   Example: vast distribute 30736390:plug codellama 30736411:plug mistral")
                    return

                # Parse id:command pairs
                tasks = {{}}
                current_id = None
                current_cmd_parts = []

                for arg in args:
                    if ':' in arg and arg.split(':')[0].isdigit():
                        # Save previous task if exists
                        if current_id and current_cmd_parts:
                            tasks[current_id] = ' '.join(current_cmd_parts)
                        # Start new task
                        parts = arg.split(':', 1)
                        current_id = parts[0]
                        current_cmd_parts = [parts[1]] if len(parts) > 1 and parts[1] else []
                    else:
                        # Continue current command
                        if current_id:
                            current_cmd_parts.append(arg)

                # Save last task
                if current_id and current_cmd_parts:
