                    self._log(f"   [{{iid}}] {{gpu_name}} ← {{cmd}}")
                self._log("━" * 50)

                import threading
                results = {{}}

                def send_task(instance_id, command):
                    executor = self._remote_gpus.get(instance_id)
                    if not executor:
                        results[instance_id] = {{'status': 'error', 'error': 'No executor'}}
                        return
                    try:
                        # Write command to remote relay file
