        def _refresh_slots(self):
            # Refresh slots for ANY brain with all_members (Scarecrow or Council)
            members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
            if not members:
                return
            slots = self.query_one("#slots")
            # Remove existing children synchronously to avoid ID conflicts
            for child in list(slots.children):
                child.remove()
            # Show filled slots first, then collapsed empty count
            filled = []
            empty_count = 0
            for i, c in enumerate(members):
                has = getattr(c, 'model', None) is not None
                if has:
                    name = getattr(c, 'name', f'slot_{{i}}')
                    mid = getattr(c, '_model_source', None)
                    clones = len(getattr(c, '_clones', []))
                    filled.append((i, name, mid, clones))
                else:
                    empty_count += 1
            # Mount filled slots (no ID to avoid conflicts on refresh)
            for i, name, mid, clones in filled:
                slots.mount(SlotWidget(i, name, 'plugged', mid, clones))
            # Show empty slots - different for Scarecrow vs Council
            if empty_count > 0:
                if self.brain_type == 'scarecrow':
                    # Scarecrow: prominent NULL PORT indicator
                    slots.mount(Static("[bold yellow]⚫ NULL PORT[/bold yellow]\\n[dim]plug <model> to activate[/]"))
                else:
                    # Council: collapsed empty count (no ID to avoid conflicts)
                    slots.mount(Static(f"[dim]⚫ {{empty_count}} empty slots[/] [dim](plug <model>)[/]"))
            self.query_one("#info", Static).update(self._render_info())
            # Update tree view
            try:
                self.query_one("#tree-view", Static).update(self._render_tree())
            except Exception:
                pass
            # Write live state for external tools
            self._write_capsule_state()

        def _write_capsule_state(self):
            \"\"\"
            Write live capsule state to .capsule_state.json for external tools.

            This is a PROGRAMMER'S GUIDE - external AI agents and tools can read
            this file to understand the current state of the capsule.

            External tools can poll this file or use inotify/watchdog to react
            to state changes.
            \"\"\"
            import json
            import time

            state_file = Path(__file__).parent / '.capsule_state.json'

            # Collect slot info
            members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
            slots = []
            for i, c in enumerate(members):
                model = getattr(c, 'model', None)
                model_type = getattr(c, '_model_type', None)

                # Determine invocation capabilities based on model type
                invocation_caps = []
                if model is not None:
                    invocation_caps.append('invoke')  # All models support invoke
                    if model_type:
                        mt_name = model_type.name if hasattr(model_type, 'name') else str(model_type)
                        if 'EMBED' in mt_name or 'SENTENCE' in mt_name or 'CLIP' in mt_name or 'CLAP' in mt_name:
                            invocation_caps.append('embed')
                        if 'LLM' in mt_name or mt_name == 'HUGGINGFACE':
                            invocation_caps.extend(['generate', 'embed'])  # Many HF models support both
                        if 'RERANK' in mt_name:
                            invocation_caps.append('rerank')
                        if 'CLASSIFY' in mt_name:
                            invocation_caps.append('classify')
                    # Check for specific methods on the model
                    if hasattr(model, 'encode'):
                        if 'embed' not in invocation_caps:
                            invocation_caps.append('embed')
                    if hasattr(model, 'generate'):
                        if 'generate' not in invocation_caps:
                            invocation_caps.append('generate')
                    if hasattr(model, 'classify'):
                        if 'classify' not in invocation_caps:
                            invocation_caps.append('classify')
                    if hasattr(model, 'rerank'):
                        if 'rerank' not in invocation_caps:
                            invocation_caps.append('rerank')

                slots.append({{
                    'index': i,
                    'name': getattr(c, 'name', f'slot_{{i}}'),
                    'has_model': model is not None,
                    'model_source': getattr(c, '_model_source', None),
                    'model_type': str(getattr(c, '_model_type', 'unknown')),
                    'clones': len(getattr(c, '_clones', [])),
                    'invocation_capabilities': invocation_caps,
                }})

            state = {{
                # Identity
                'brain_type': self.brain_type,
                'generation': self.agent.generation,
                'fitness': self.agent.fitness,
                'quine_hash': getattr(self.brain, '_quine_hash', None),

                # Slot status
                'slots': slots,
                'total_slots': len(slots),
                'filled_slots': sum(1 for s in slots if s['has_model']),

                # Runtime status
                'relay_listening': self._relay_listening,
                'cascade_active': _CASCADE_AVAILABLE,
                'theme': self.AVAILABLE_THEMES[self._theme_index],

                # Sandbox/Invocation system status
                'sandbox': {{
                    'infinity_emb_available': INFINITY_AVAILABLE,
                    'model_types_supported': [mt.name for mt in ModelType],
                    'invocation_methods': ['invoke', 'embed', 'generate', 'classify', 'rerank'],
                    'async_capable': True,
                }},

                # Timestamps
                'last_updated': time.strftime('%Y-%m-%dT%H:%M:%S'),
                'uptime_seconds': time.time() - getattr(self, '_start_time', time.time()),

                # External interface paths
                'interfaces': {{
                    'relay_center': str(self._relay_center) if hasattr(self, '_relay_center') else None,
                    'cascade_feed': str(_CASCADE_FEED_DIR / 'feed.jsonl') if _CASCADE_FEED_DIR else None,
                    'slot_manifest': str(Path(__file__).parent / '.slot_manifest.json'),
                    'signal_intake': str(self._signal_port_file()),
                    'state_file': str(state_file)
                }},

                # Help for external tools
                '_help': {{
                    'relay_center': 'Write commands to this file to control the TUI',
                    'cascade_feed': 'Read this JSONL for merkle-hashed event stream',
                    'slot_manifest': 'Read/write slot configuration persistence',
                    'signal_intake': 'Write ANY JSON/data here for universal signal observation (returns CID)',
                    'commands': ['plug <model>', 'unplug <slot>', 'infer', 'invoke <text>', 'embed <text>', 
                                 'generate <prompt>', 'classify <text>', 'rerank <query> :: <docs>',
                                 'status', 'slots', 'observe', 'help']
                }}
            }}

            # Add bag catalog
            try:
                bag = get_bag()
                catalog = bag.catalog()
                state['bag'] = {{
                    'items': len(catalog),
                    'catalog': [{{
                        'id': item[0],
                        'name': item[1],
                        'type': item[2],
                        'preview': item[3],
                        'size': item[4],
                        'version': item[5]
                    }} for item in catalog]
                }}
            except Exception:
                state['bag'] = {{'items': 0, 'catalog': []}}

            try:
                state_file.write_text(json.dumps(state, indent=2), encoding='utf-8')
            except Exception:
                pass  # Non-critical, don't crash TUI

        def _export_item_as_pdf(self, item: dict, output_path: str):
            \"\"\"
            Export a FelixBag item as a formatted PDF document.

            For code items (especially quine_source):
            - Full source with line numbers
            - Monospace font, small size for density
            - Page breaks every ~100 lines
            - 1:1 exact replica of the source
            - EMBEDDED ATTACHMENT for lossless reconstitution

            For documents:
            - Readable paragraph formatting
            - Also embedded as attachment

            The PDF contains a visual "RECONSTITUTE" button and instructions
            for extracting the original file from the PDF attachment.
            \"\"\"
            from reportlab.lib.pagesizes import letter
            from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Preformatted, PageBreak, Table, TableStyle
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.lib.units import inch
            from reportlab.lib.colors import black, white, HexColor
            from reportlab.lib.enums import TA_CENTER
            from pypdf import PdfWriter, PdfReader
            from pathlib import Path
            import time
            import html
            import io
            import gzip
            import base64

            pdf_path = Path(output_path)
            temp_pdf = str(pdf_path) + ".tmp"

            # Content is stored as base64 gzipped - decompress it
            raw_content = item.get('content', '')
            try:
                content = gzip.decompress(base64.b64decode(raw_content)).decode('utf-8')
            except Exception:
                content = raw_content  # Already plain text

            # For code items, use full source export style
            if item['type'] == 'code' or item['name'] == 'quine_source':
                doc = SimpleDocTemplate(temp_pdf, pagesize=letter,
                                        leftMargin=0.5*inch, rightMargin=0.5*inch,
                                        topMargin=0.5*inch, bottomMargin=0.5*inch)

                styles = getSampleStyleSheet()
                story = []

                # Code style - monospace, very small for full source
                code_style = ParagraphStyle(
                    'Code',
                    parent=styles['Normal'],
                    fontName='Courier',
                    fontSize=7,
                    leading=8.5,
                    leftIndent=0,
                    textColor=black,
                )

                # Title
                title_style = ParagraphStyle(
                    'Title',
                    parent=styles['Heading1'],
                    fontSize=16,
                    textColor=HexColor('#1a1a2e'),
                    spaceAfter=8,
                )

                header_style = ParagraphStyle(
                    'Header',
                    parent=styles['Normal'],
                    fontSize=9,
                    textColor=HexColor('#666666'),
                )

                # Title page with RECONSTITUTE button
                story.append(Paragraph(f"{{item['name']}}", title_style))
                story.append(Paragraph(f"FelixBag Export - Full Source Code", styles['Heading3']))
                story.append(Spacer(1, 8))

                lines = content.splitlines()
                meta_lines = [
                    f"Type: {{item['type']}} | Version: {{item['version']}}",
                    f"Lines: {{len(lines)}} | Size: {{len(content):,}} bytes",
                    f"Exported: {{time.strftime('%Y-%m-%d %H:%M:%S')}}",
                ]
                if item['metadata'].get('tags'):
                    meta_lines.append(f"Tags: {{', '.join(item['metadata']['tags'])}}")
                for line in meta_lines:
                    story.append(Paragraph(line, header_style))

                story.append(Spacer(1, 12))

                # Determine attachment filename (needed for header)
                ext = '.py' if item['type'] == 'code' else '.txt'
                if item['name'] == 'quine_source':
                    attach_name = 'agent.py'
                else:
                    attach_name = item['name'].replace(' ', '_') + ext

                story.append(Paragraph(f"Original attached as: <b>{{attach_name}}</b>", header_style))
                story.append(Spacer(1, 8))
                story.append(PageBreak())

                # Source code with line numbers - chunked for memory
                chunk_size = 120  # Lines per page
                newline = chr(10)  # Use chr() to avoid quine escaping issues

                for i in range(0, len(lines), chunk_size):
                    chunk = lines[i:i+chunk_size]
                    numbered = []
                    for j, line in enumerate(chunk, start=i+1):
                        # Escape but also replace problematic chars for Preformatted
                        safe_line = line.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
                        # Truncate very long lines to avoid overflow
                        if len(safe_line) > 200:
