        def on_cascade_bridge_message(self, message: CascadeBridgeMessage):
            """Handle MCP tool events bridged from the MCP server thread."""
            tool = message.event_type
            data = message.data
            duration = data.get('duration_ms', 0)

            # Log to main log tab
            self._log(f"🔌 MCP: {{tool}} ({{duration:.0f}}ms)")

            # Log to MCP tab
            self._mcp_log(f"🔧 {{tool}} ({{duration:.0f}}ms) step#{{data.get('step', '?')}}")

            # Auto-switch to relevant tab based on tool category
            try:
                tabs = self.query_one("#tabs", TabbedContent)
                if tool.startswith('vast_'):
                    tabs.active = "tab-vast"
                elif tool in ('workflow_execute', 'workflow_status', 'workflow_history'):
                    exec_result = data.get('execution_result')
                    self._update_execution_tab(exec_result)
                    tabs.active = "tab-exec"
                elif tool.startswith('workflow_'):
                    self._update_workflows_tab()
                    tabs.active = "tab-workflows"
                else:
                    tabs.active = "tab-mcp"
            except Exception:
                pass

            # Record to CASCADE lattice
            self._record_cascade(tool, data)

        def _record_cascade(self, event_type: str, data: dict):
            \"\"\"
            Record event to CASCADE-LATTICE with full CausationGraph tracking.

            Every event:
            1. cascade.store.observe() → merkle-hashed CID receipt
            2. CascadeEvent → added to live CausationGraph
            3. CausationLink → temporal chain from previous event
            4. Incremental merkle root → computed from all event hashes
            5. Rerun → temporal sequence + graph visualization
            6. MerkleWidget → live sidebar display
            \"\"\"
            import time
            import json
            import hashlib
            ts = time.strftime("%H:%M:%S")
            receipt_info = None
            cid = None
            chain_depth = 0

            if _CASCADE_AVAILABLE:
                try:
                    # 1. CASCADE store observation → CID receipt
                    parent_cid = self._last_cascade_cid if hasattr(self, '_last_cascade_cid') else None
                    receipt = _cascade_store_observe(
                        model_id=f"council_{{self.agent.generation}}",
                        data={{**data, 'event_type': event_type, 'timestamp': time.time()}},
                        parent_cid=parent_cid,
                        sync=False
                    )
                    if receipt:
                        cid = receipt.cid
                        self._last_cascade_cid = cid
                        self._seen_cids.add(cid)  # Mark seen so poller skips
                        receipt_info = f"{{cid[:16]}}..."

                    # 2. Create CausationGraph Event
                    self._event_count += 1
                    event = CascadeEvent(
                        timestamp=time.time(),
                        component=f"capsule_gen{{self.agent.generation}}",
                        event_type=event_type,
                        data={{**data, 'cid': cid or 'none', 'seq': self._event_count}}
                    )

                    if self._causation_graph is not None:
                        self._causation_graph.add_event(event)

                        # 3. Temporal causation link from previous event
                        if self._last_event_id is not None:
                            link = CausationLink(
                                from_event=self._last_event_id,
                                to_event=event.event_id,
                                causation_type="temporal",
                                strength=1.0,
                                explanation=f"{{event_type}} follows previous"
                            )
                            self._causation_graph.add_link(link)
                            # Calculate chain depth
                            try:
                                causes = self._causation_graph.get_causes(event.event_id, max_depth=20)
                                chain_depth = len(causes) if causes else 0
                            except Exception:
                                chain_depth = self._event_count - 1

                        self._last_event_id = event.event_id

                    # 4. Incremental merkle root from all event hashes
                    event_hash = hashlib.sha256(
                        f"{{event.event_id}}:{{event_type}}:{{cid or ''}}".encode()
                    ).hexdigest()[:16]
                    self._event_hashes.append(event_hash)

                    merkle_root = cascade_merkle_root(self._event_hashes)
                    self._merkle_roots.append(merkle_root)
                    if len(self._merkle_roots) > 100:
                        self._merkle_roots = self._merkle_roots[-100:]

                    # 5. Rerun temporal sequence + graph
                    if _HAS_RERUN and _RERUN_INITIALIZED:
                        try:
                            rr.set_time("cascade_event", sequence=self._event_count)
                            rr.log("cascade/cid", rr.TextLog(f"📦 {{cid or 'no-cid'}}", level=rr.TextLogLevel.INFO))
                            rr.log("cascade/event_type", rr.TextLog(event_type))
                            rr.log("cascade/merkle_root", rr.TextLog(f"⟐ {{merkle_root}}"))
                            rr.log("provenance/depth", rr.Scalars([float(chain_depth)]))
                            rr.log("provenance/event_count", rr.Scalars([float(self._event_count)]))

                            # CASCADE Events tab (Tab 1)
                            rr.log("event", rr.TextLog(f"{{event_type}}: {{str(data)[:80]}}", level=rr.TextLogLevel.INFO))
                            rr.log("provenance", rr.TextLog(f"🔗 {{merkle_root}}", level=rr.TextLogLevel.INFO))
                            rr.log("logs", rr.TextLog(f"CASCADE Event #{{self._event_count}}: {{event_type}} {{merkle_root[:12]}}...", level=rr.TextLogLevel.INFO))

                            # MCP Tools tab (Tab 2) — log when source is mcp
                            if data.get('source') == 'mcp':
                                mcp_step = data.get('step', self._event_count)
                                rr.set_time("mcp_tool", sequence=mcp_step)
                                rr.log("mcp/duration_ms", rr.Scalars([float(data.get('duration_ms', 0))]))
                                rr.log("mcp/result_size", rr.Scalars([float(data.get('result_size', 0))]))
                                rr.log("mcp/tool", rr.TextLog(data.get('tool', event_type), level=rr.TextLogLevel.INFO))
                                rr.log("mcp/args", rr.TextLog(str(data)[:200]))
                                # Aggregate numeric metrics
                                metric_vals = [v for k, v in data.items() if isinstance(v, (int, float)) and k not in ('step', 'duration_ms', 'result_size')]
                                if metric_vals:
                                    rr.log("mcp/metrics", rr.Scalars([sum(metric_vals) / len(metric_vals)]))

                            # State Space tab (Tab 3) — update on every event
                            if hasattr(self, 'agent') and self.agent:
                                brain = self.agent.brain
                                if hasattr(brain, '_slot_counts'):
                                    rr.log("state/slots/activity", rr.BarChart(brain._slot_counts))
                                    rr.log("state/slots/count", rr.Scalars([float(sum(brain._slot_counts))]))
                                else:
                                    # Fallback: count plugged councilors
                                    members = getattr(brain, 'councilors', [])
                                    activity = [1.0 if getattr(c, 'model', None) is not None else 0.0 for c in members]
                                    if activity:
                                        rr.log("state/slots/activity", rr.BarChart(activity))
                                        rr.log("state/slots/count", rr.Scalars([float(sum(activity))]))
                                if hasattr(self.agent, 'fitness'):
                                    rr.log("state/fitness", rr.Scalars([self.agent.fitness]))
                                if hasattr(self.agent, 'traits') and self.agent.traits:
                                    t = self.agent.traits
                                    vals = list(t.values()) if isinstance(t, dict) else list(t)
                                    if vals:
                                        rr.log("state/traits", rr.BarChart(vals))
                        except Exception:
                            pass

                    # Write to .cascade_feed for agent observation
                    if _CASCADE_FEED_DIR:
                        feed_file = _CASCADE_FEED_DIR / 'feed.jsonl'
                        with open(feed_file, 'a') as f:
                            f.write(json.dumps({{
                                'cid': cid,
                                'event_type': event_type,
                                'event_id': event.event_id,
                                'data': data,
                                'timestamp': time.time(),
                                'parent_cid': parent_cid,
                                'merkle_root': merkle_root,
                                'chain_depth': chain_depth,
                                'seq': self._event_count
                            }}) + '\\n')
                except Exception as e:
                    receipt_info = f"ERR: {{e}}"

            # Local log for TUI display
            display = f"[{{ts}}] {{event_type}}: {{str(data)[:30]}}"
            if cid:
                display += f" [blue]{{cid[:12]}}[/]"
            self._cascade_events.append(display)
            if len(self._cascade_events) > 50:
                self._cascade_events.pop(0)

            # 6. Update merkle widget with depth + running root
            try:
                merkle = self.query_one("#merkle", MerkleWidget)
                root_display = cid or (self._merkle_roots[-1] if self._merkle_roots else None)
                if root_display:
                    merkle.add_receipt(root_display, event_type, chain_depth)
                if self._merkle_roots:
                    merkle.set_merkle_root(self._merkle_roots[-1])
            except Exception:
                pass

            # Update provenance view
            try:
                self.query_one("#provenance", Static).update(self._render_provenance())
            except Exception:
                pass

            return cid

        def _observe_signal(self, signal: any) -> dict:
            \"\"\"
            UNIVERSAL SIGNAL PORT - Accepts ANY modulation format.

            Uses cascade-lattice SymbioticAdapter which self-adapts to:
            - JSON strings
            - Python dicts
            - Raw bytes
            - Tensor outputs
            - Model predictions
            - Unknown/novel formats

            Returns standardized receipt with CID for provenance tracking.

            This is the "unisex port, agnostic to modulation" - any external
            tool can call this with any data format and get merkle-hashed
            proof of observation.
            \"\"\"
            import time
            import json

            result = {{
                'success': False,
                'interpreted': None,
                'cid': None,
                'error': None,
                'timestamp': time.time()
            }}

            # Try SymbioticAdapter first (learns signal patterns)
            if _SYMBIOTIC_ADAPTER is not None:
                try:
                    interpreted = _SYMBIOTIC_ADAPTER.interpret(signal)
                    result['interpreted'] = interpreted
                    result['success'] = True

                    # Record to cascade for merkle receipt
                    cid = None
                    result['cid'] = cid
                    self._log(f"📡 Signal observed: {{type(signal).__name__}} → CID: {{cid[:12] if cid else 'none'}}...")
                    return result
                except Exception as e:
                    result['error'] = f"SymbioticAdapter: {{e}}"

            # Fallback: Manual interpretation
            try:
                if isinstance(signal, bytes):
                    interpreted = {{'type': 'bytes', 'length': len(signal), 'hex_preview': signal[:32].hex()}}
                elif isinstance(signal, str):
                    # Try JSON parse
                    try:
                        interpreted = {{'type': 'json', 'data': json.loads(signal)}}
                    except Exception:
                        interpreted = {{'type': 'string', 'length': len(signal), 'preview': signal[:100]}}
                elif isinstance(signal, dict):
                    interpreted = {{'type': 'dict', 'keys': list(signal.keys())[:10], 'data': signal}}
                elif isinstance(signal, (list, tuple)):
                    interpreted = {{'type': 'sequence', 'length': len(signal), 'preview': str(signal[:5])}}
                else:
                    interpreted = {{'type': type(signal).__name__, 'str': str(signal)[:200]}}

                result['interpreted'] = interpreted
                result['success'] = True
                cid = None
                result['cid'] = cid
                self._log(f"📡 Signal observed (fallback): {{type(signal).__name__}}")
            except Exception as e:
                result['error'] = str(e)
                self._log(f"⚠️ Signal observation failed: {{e}}")

            return result

        def _signal_port_file(self) -> Path:
            \"\"\"Path to the signal intake file that external tools can write to.\"\"\"
            return Path(__file__).parent / '.signal_intake.json'

        async def _check_signal_port(self):
            \"\"\"Check for external signals written to .signal_intake.json\"\"\"
            port_file = self._signal_port_file()
            if port_file.exists():
                try:
                    import json
                    content = port_file.read_text(encoding='utf-8')
                    port_file.unlink()  # Consume the signal

                    try:
                        signal = json.loads(content)
                    except Exception:
                        signal = content  # Raw string if not JSON

                    result = self._observe_signal(signal)
                    self._log(f"📥 External signal consumed: CID={{result.get('cid', 'none')[:12] if result.get('cid') else 'none'}}...")
                except Exception as e:
                    self._log(f"⚠️ Signal port error: {{e}}")

        def _summarize_for_mcp(self, obj, max_array_len=5, max_dict_items=10, max_str_len=200):
            \"\"\"
            Summarize complex objects for MCP responses.
            Truncates numpy arrays, limits dict items, shortens strings.
            Returns JSON-serializable summary.
            \"\"\"
            if obj is None:
                return None
            elif isinstance(obj, (int, float, bool)):
                return obj
            elif isinstance(obj, str):
                return obj[:max_str_len] + '...' if len(obj) > max_str_len else obj
            elif hasattr(obj, 'tolist'):
                # Numpy array
                arr = obj.flatten() if hasattr(obj, 'flatten') else obj
                arr_list = arr.tolist() if hasattr(arr, 'tolist') else list(arr)
                if len(arr_list) > max_array_len:
                    return {{
                        '_type': 'array',
                        'shape': list(obj.shape) if hasattr(obj, 'shape') else [len(arr_list)],
                        'dtype': str(obj.dtype) if hasattr(obj, 'dtype') else 'unknown',
                        'sample': arr_list[:max_array_len],
                        'truncated': True
                    }}
                return arr_list
            elif isinstance(obj, dict):
                items = list(obj.items())[:max_dict_items]
                result = {{k: self._summarize_for_mcp(v, max_array_len, max_dict_items, max_str_len) for k, v in items}}
                if len(obj) > max_dict_items:
                    result['_truncated'] = True
                    result['_total_keys'] = len(obj)
                return result
            elif isinstance(obj, (list, tuple)):
                if len(obj) > max_array_len:
                    return {{
                        '_type': 'list',
                        'length': len(obj),
                        'sample': [self._summarize_for_mcp(x, max_array_len, max_dict_items, max_str_len) for x in obj[:max_array_len]],
                        'truncated': True
                    }}
                return [self._summarize_for_mcp(x, max_array_len, max_dict_items, max_str_len) for x in obj]
            else:
                # Fallback: convert to string and truncate
                s = str(obj)
                return s[:max_str_len] + '...' if len(s) > max_str_len else s

        async def _handle_mcp_request(self):
            \"\"\"
            Handle MCP requests via inbox/outbox pattern.

            Inbox: .mcp_inbox.json (MCP writes, TUI consumes)
            Outbox: .mcp_outbox.json (TUI writes, MCP consumes)
            \"\"\"
            import json
            import tempfile
            from pathlib import Path

            capsule_dir = Path(__file__).parent
            inbox = capsule_dir / '.mcp_inbox.json'
            outbox = capsule_dir / '.mcp_outbox.json'

            # No inbox = no pending request
            if not inbox.exists():
                return

            try:
                req = json.loads(inbox.read_text(encoding='utf-8'))
                inbox.unlink()  # Consume immediately
            except Exception:
                return

            req_id = req.get('id', 'unknown')
            tool = req.get('tool', '')
            args = req.get('args', {{}})

            # Local key-normalization helpers for proxy-mode parity with normal MCP tools.
            _DOC_KEY_PREFIX = "__docv2__"
            _DOC_KEY_SUFFIX = "__k"

            def _doc_escape_key(value: str) -> str:
                return str(value).replace("~", "~~").replace("/", "~s")

            def _doc_unescape_key(value: str) -> str:
                _s = str(value)
                _out = []
                _i = 0
                _n = len(_s)
                while _i < _n:
                    _ch = _s[_i]
                    if _ch == "~" and _i + 1 < _n:
                        _nx = _s[_i + 1]
                        if _nx == "~":
                            _out.append("~")
                            _i += 2
                            continue
                        if _nx == "s":
                            _out.append("/")
                            _i += 2
                            continue
                    _out.append(_ch)
                    _i += 1
                return "".join(_out)

            def _doc_is_encoded_key(key: str) -> bool:
                return isinstance(key, str) and key.startswith(_DOC_KEY_PREFIX)

            def _doc_decode_key(key: str) -> str:
                if not _doc_is_encoded_key(key):
                    return str(key)
                _body = str(key)[len(_DOC_KEY_PREFIX):]
                if _body.endswith(_DOC_KEY_SUFFIX):
                    _body = _body[:-len(_DOC_KEY_SUFFIX)]
                return _doc_unescape_key(_body)

            def _doc_should_virtualize_key(key: str) -> bool:
                if not isinstance(key, str) or not key:
                    return False
                if key.startswith('bag_checkpoint:'):
                    return False
                if _doc_is_encoded_key(key):
                    return True
                return '/' in key

            def _doc_encode_exact_key(key: str) -> str:
                if _doc_is_encoded_key(key):
                    return key
                return f"{{_DOC_KEY_PREFIX}}{{_doc_escape_key(key)}}{{_DOC_KEY_SUFFIX}}"

            def _doc_encode_prefix(prefix: str) -> str:
                if _doc_is_encoded_key(prefix):
                    return prefix
                return f"{{_DOC_KEY_PREFIX}}{{_doc_escape_key(prefix)}}"

            def _doc_key_variants(key: str, as_prefix: bool = False) -> list:
                _vals = []
                def _add(v):
                    if not isinstance(v, str):
                        return
                    if not v:
                        return
                    if v not in _vals:
                        _vals.append(v)

                _raw = str(key or '')
                if not _raw:
                    return _vals
                _add(_raw)
                _dec = _doc_decode_key(_raw)
                _add(_dec)
                if _doc_should_virtualize_key(_dec):
                    _enc = _doc_encode_prefix(_dec) if as_prefix else _doc_encode_exact_key(_dec)
                    _add(_enc)
                return _vals

            def _doc_checkpoint_variants(checkpoint_key: str) -> list:
                _vals = []
                _raw = str(checkpoint_key or '')
                if not _raw:
                    return _vals
                _vals.append(_raw)
                if not _raw.startswith('bag_checkpoint:'):
                    return _vals
                try:
                    _left, _ts = _raw.rsplit(':', 1)
                    _src = _left[len('bag_checkpoint:'):]
                    _src_dec = _doc_decode_key(_src)
                    _src_enc = _doc_encode_exact_key(_src_dec) if _doc_should_virtualize_key(_src_dec) else _src_dec
                    for _cand in (
                        f"bag_checkpoint:{{_src}}:{{_ts}}",
                        f"bag_checkpoint:{{_src_dec}}:{{_ts}}",
                        f"bag_checkpoint:{{_src_enc}}:{{_ts}}",
                    ):
                        if _cand not in _vals:
                            _vals.append(_cand)
                except Exception:
                    pass
                return _vals

            def _doc_decode_checkpoint_key(checkpoint_key: str) -> str:
                _raw = str(checkpoint_key or '')
                if not _raw.startswith('bag_checkpoint:'):
                    return _doc_decode_key(_raw)
                try:
                    _left, _ts = _raw.rsplit(':', 1)
                    _src = _left[len('bag_checkpoint:'):]
                    return f"bag_checkpoint:{{_doc_decode_key(_src)}}:{{_ts}}"
                except Exception:
                    return _raw

            # Rich MCP request logging
            import time
            start_time = time.time()
            args_preview = {{k: (str(v)[:40] + '...' if len(str(v)) > 40 else v) for k, v in args.items()}}
            self._log(f"🔌 MCP REQUEST: {{tool}}")
            self._log(f"   📋 ID: {{req_id[:12]}}")
            if args_preview:
                for k, v in args_preview.items():
                    self._log(f"   ├─ {{k}}: {{v}}")

            # Also log to MCP tab specifically
            self._mcp_log(f"━━━ {{tool}} ━━━")
            self._mcp_log(f"⏱️  {{time.strftime('%H:%M:%S')}}")
            self._mcp_log(f"🆔 {{req_id[:12]}}")
            if args:
                self._mcp_log("📥 Args:")
                for k, v in args_preview.items():
                    self._mcp_log(f"   {{k}}: {{v}}")

            # Auto-switch to relevant tab based on tool
            try:
                if tool.startswith('vast_'):
                    # Switch to VAST tab for vast.ai operations
                    self.query_one("#tabs", TabbedContent).active = "tab-vast"
                    # Force refresh VAST tab
                    self._update_vast_tab()
                else:
                    # Switch to MCP tab for other operations
                    self.query_one("#tabs", TabbedContent).active = "tab-mcp"
                # Force refresh log display
                self.refresh()
            except Exception:
                pass  # Tab switching is optional

            result = {{'error': 'unknown tool'}}

            try:
                # ═══════════════════════════════════════════════════════════
                # CORE TOOLS - Copied from real standalone MCP implementations
                # ═══════════════════════════════════════════════════════════

                if tool == 'forward':
                    text = args.get('text', '')
                    embedding = args.get('embedding')
                    brain_type = _BRAIN_CONFIG.get('brain_type', 'unknown')

                    # Parse embedding if it's a string representation
                    if isinstance(embedding, str):
                        try:
                            # Try to parse numpy array string format '[...]'
                            embedding = np.fromstring(embedding.strip('[]'), sep=' ', dtype=np.float32)
                        except Exception:
                            try:
                                import json
                                embedding = np.array(json.loads(embedding), dtype=np.float32)
                            except Exception:
                                embedding = None
                    elif isinstance(embedding, list):
                        embedding = np.array(embedding, dtype=np.float32)

                    if brain_type == 'ouroboros':
                        obs = {{'text': text or 'Hello', 'input': embedding if embedding is not None else np.random.rand(384).astype(np.float32)}}
                    else:
                        obs = {{'text': text, 'input': embedding if embedding is not None else np.random.rand(384).astype(np.float32)}}

                    try:
                        out = self.brain.forward(obs)
                    except Exception as e:
                        import traceback
                        result = {{'error': str(e), 'traceback': traceback.format_exc()[:500]}}
                    else:
                        # Create a SUMMARY instead of dumping everything
                        def summarize_value(v, max_len=10):
                            if hasattr(v, 'tolist'):
                                arr = v.tolist() if hasattr(v, 'tolist') else list(v)
                                if len(arr) > max_len:
                                    return {{'type': 'array', 'shape': list(getattr(v, 'shape', [len(arr)])), 'sample': arr[:5], 'truncated': True}}
                                return arr
                            elif isinstance(v, dict):
                                return {{kk: summarize_value(vv, max_len) for kk, vv in list(v.items())[:10]}}
                            elif isinstance(v, (list, tuple)) and len(v) > max_len:
                                return {{'type': 'list', 'length': len(v), 'sample': [summarize_value(x) for x in v[:3]], 'truncated': True}}
                            else:
                                return v

                        summary = {{k: summarize_value(v) for k, v in list(out.items())[:15]}}
                        summary['_note'] = 'Output summarized. Use specific tools (embed_text, deliberate) for detailed results.'
                        result = summary

                elif tool == 'plug_model':
                    model_id = args.get('model_id', '')
                    slot_name = args.get('slot_name')

                    if not model_id:
                        result = {{'error': 'no model_id provided'}}
                    else:
                        model, mtype, error = _load_model_smart(model_id, verbose=True)
                        if error:
                            result = {{'error': error}}
                        else:
                            outer_brain = self.brain
                            brain = getattr(outer_brain, '_brain', outer_brain)

                            if not hasattr(brain, 'councilors'):
                                result = {{'error': 'Brain has no council slots', 'brain_type': type(brain).__name__}}
                            else:
                                plugged = False
                                for i, c in enumerate(brain.councilors):
                                    if getattr(c, 'model', None) is None:
                                        c.model = model
                                        c._model_source = model_id
                                        c._model_type = mtype
                                        c._limits = getattr(model, '_limits', _read_model_limits(model, getattr(model, 'tokenizer', None)))
                                        c.name = slot_name or model_id.split('/')[-1]
                                        plugged = True
                                        result = {{'status': 'ok', 'slot': i, 'model': model_id, 'type': str(mtype)}}
                                        self._write_capsule_state()
                                        break

                                if not plugged:
                                    result = {{'error': 'no empty slots'}}

                elif tool == 'unplug_slot':
                    slot = int(args.get('slot', 0))

                    outer_brain = self.brain
                    brain = getattr(outer_brain, '_brain', outer_brain)

                    if not hasattr(brain, 'councilors'):
                        result = {{'error': 'Brain has no council slots', 'brain_type': type(brain).__name__}}
                    elif 0 <= slot < len(brain.councilors):
                        c = brain.councilors[slot]
                        c.model = None
                        c._model_source = None
                        c._model_type = None
                        result = {{'status': 'ok', 'unplugged': slot}}
                        self._write_capsule_state()
                    else:
                        result = {{'error': f'invalid slot {{slot}}'}}

                elif tool == 'list_slots':
                    outer_brain = self.brain
                    brain = getattr(outer_brain, '_brain', outer_brain)

                    if hasattr(brain, 'councilors'):
                        councilors = brain.councilors
                        slots = []
                        for i, c in enumerate(councilors):
                            if hasattr(c, 'model'):
                                has = c.model is not None
                                name = getattr(c, 'name', f'slot_{{i}}')
                                model_source = getattr(c, '_model_source', None)
                                mt = getattr(c, '_model_type', None)
                                model_type = (mt.name if hasattr(mt, 'name') else str(mt)) if mt is not None else None
                            elif isinstance(c, dict):
                                has = c.get('model') is not None
                                name = c.get('name', f'slot_{{i}}')
                                model_source = c.get('model_source')
                                model_type = c.get('_model_type') or c.get('model_type')
                            else:
                                has = False
                                name = f'slot_{{i}}'
                                model_source = None
                                model_type = None
                            slot_info = {{'index': i, 'name': name, 'plugged': has, 'model_source': model_source}}
                            if has and model_type:
                                slot_info['model_type'] = str(model_type)
                            slots.append(slot_info)
                        result = {{'slots': slots, 'total': len(slots), 'brain_type': type(brain).__name__}}
                    else:
                        result = {{'error': 'Brain has no council slots', 'brain_type': type(brain).__name__}}

                elif tool == 'deliberate':
                    question = args.get('question', '')
                    context = args.get('context', '')

                    outer_brain = self.brain
                    brain = getattr(outer_brain, '_brain', outer_brain)

                    def serialize(v):
                        if hasattr(v, 'tolist'):
                            return v.tolist()
                        elif isinstance(v, dict):
                            return {{k: serialize(vv) for k, vv in v.items()}}
                        elif isinstance(v, list):
                            return [serialize(x) for x in v]
                        return v

                    def format_deliberation(raw):
                        data = serialize(raw)
                        if not isinstance(data, dict):
                            return {{
                                "result": str(data),
                                "reasoning_trace": [],
                                "metrics": {{
                                    "consensus_method": "unknown",
                                    "councilor_votes": 0,
                                    "plugged_councilors": 0,
                                    "consensus_vector_dim": 0
                                }}
                            }}

                        deliberation = data.get('deliberation', {{}})
                        reasoning_trace = []
                        if isinstance(deliberation, dict):
                            for name, vote in deliberation.items():
                                if not isinstance(vote, dict):
                                    reasoning_trace.append({{
                                        "councilor": str(name),
                                        "confidence": 0.0,
                                        "plugged": False
                                    }})
                                    continue
                                conf_val = vote.get('confidence', 0.0)
                                try:
                                    conf = float(conf_val)
                                except Exception:
                                    conf = 0.0
                                reasoning_trace.append({{
                                    "councilor": str(name),
                                    "confidence": conf,
                                    "plugged": bool(vote.get('plugged', False))
                                }})

                        reasoning_trace.sort(key=lambda x: x.get('confidence', 0.0), reverse=True)

                        votes = data.get('councilor_votes', len(reasoning_trace))
                        try:
                            votes = int(votes)
                        except Exception:
                            votes = len(reasoning_trace)

                        derived_plugged = sum(1 for r in reasoning_trace if r.get('plugged'))
                        if reasoning_trace:
                            plugged = derived_plugged
                        else:
                            plugged = data.get('plugged_councilors', derived_plugged)
                        try:
                            plugged = int(plugged)
                        except Exception:
                            plugged = derived_plugged

                        consensus_vec = data.get('consensus_output', [])
                        vec_dim = len(consensus_vec) if isinstance(consensus_vec, list) else 0
                        method = str(data.get('consensus_method', 'unknown'))

                        if reasoning_trace:
                            top = reasoning_trace[0]
                            result_text = (
                                "Deliberation complete. Method=%s; plugged=%d; voters=%d; "
                                "lead=%s (confidence=%.2f)." % (
                                    method,
                                    plugged,
                                    votes,
                                    top.get('councilor', 'unknown'),
                                    float(top.get('confidence', 0.0))
                                )
                            )
                        else:
                            result_text = "Deliberation complete. Method=%s; plugged=%d; voters=%d." % (
                                method, plugged, votes
                            )

                        return {{
                            "result": result_text,
                            "reasoning_trace": reasoning_trace,
                            "metrics": {{
                                "consensus_method": method,
                                "councilor_votes": votes,
                                "plugged_councilors": plugged,
                                "consensus_vector_dim": vec_dim
                            }}
                        }}

                    if hasattr(brain, 'deliberate'):
                        try:
                            out = brain.deliberate(question, context=context)
                            result = format_deliberation(out)
                        except Exception as e:
                            result = {{'error': f'Deliberation failed: {{e}}', 'brain_type': type(brain).__name__}}
                    elif hasattr(brain, '_council_deliberate'):
                        try:
                            embedding = None
                            if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
                                embedding = brain.embedding_foundation.encode(f'{{question}} {{context}}', convert_to_numpy=True)
                            elif hasattr(brain, 'embed'):
                                embedding = brain.embed(f'{{question}} {{context}}')
                            else:
                                # Use deterministic zero embedding instead of random (avoids NaN propagation)
                                embedding = np.zeros(384, dtype=np.float32)

                            # Validate embedding - sanitize any NaN/Inf
                            embedding = np.asarray(embedding, dtype=np.float32).flatten()
                            if len(embedding) < 384:
                                embedding = np.pad(embedding, (0, 384 - len(embedding)))
                            embedding = embedding[:384]
                            embedding = np.nan_to_num(embedding, nan=0.0, posinf=0.0, neginf=0.0)

                            adapted = {{
                                'text': question,
                                'context': context,
                                'adapted_output': embedding,
                                'adapter_applied': True
                            }}
                            out = brain._council_deliberate(adapted)
                            result = format_deliberation(out)
                        except Exception as e:
                            result = {{'error': f'Deliberation failed: {{e}}', 'details': 'council_deliberate exception'}}
                    else:
                        result = {{'error': 'Brain does not support deliberation', 'brain_type': type(brain).__name__}}

                elif tool == 'imagine':
                    scenario = args.get('scenario', '')
                    steps = int(args.get('steps', 5))

                    outer_brain = self.brain
                    brain = getattr(outer_brain, '_brain', outer_brain)

                    if hasattr(brain, 'imagine'):
                        # Embed scenario text if possible
                        obs = None
                        if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
                            try:
                                obs = brain.embedding_foundation.encode(scenario, convert_to_numpy=True)
                            except Exception:
                                pass
                        elif hasattr(brain, 'embed'):
                            try:
                                obs = brain.embed(scenario)
                            except Exception:
                                pass
