                            try:
                                obs = brain._embed_inputs({{'text': scenario}})
                            except Exception:
                                pass

                        if obs is None:
                            obs = np.zeros(384, dtype=np.float32)

                        # Detect signature to call correctly
                        import inspect
                        sig = inspect.signature(brain.imagine)
                        params = list(sig.parameters.keys())
                        first_param = params[0] if params else None

                        try:
                            # Check if first param expects obs/start_state or horizon
                            if first_param in ('obs', 'start_state', 'observation'):
                                # Signature: imagine(obs, steps/horizon)
                                if 'horizon' in sig.parameters:
                                    out = brain.imagine(obs, horizon=steps)
                                elif 'steps' in sig.parameters:
                                    out = brain.imagine(obs, steps=steps)
                                else:
                                    out = brain.imagine(obs)
                            elif first_param == 'horizon' or first_param == 'steps':
                                # Signature: imagine(horizon, ...) - no obs param
                                out = brain.imagine(horizon=steps)
                            elif 'horizon' in sig.parameters:
                                # Has horizon as keyword param
                                out = brain.imagine(horizon=steps)
                            elif 'steps' in sig.parameters:
                                out = brain.imagine(steps=steps)
                            else:
                                # Fallback - try with obs
                                out = brain.imagine(obs)
                        except Exception as e:
                            err_text = str(e)
                            if 'No RSSM available' in err_text or 'Real RSSM unavailable' in err_text:
                                dreamer_model = getattr(brain, 'dreamer_world_model', None)
                                has_real_rssm = bool(
                                    dreamer_model is not None and
                                    getattr(dreamer_model, '_has_real_rssm', False) and
                                    getattr(dreamer_model, '_rssm', None) is not None
                                )
                                result = {{
                                    'error': 'Real RSSM unavailable - imagination cannot run',
                                    'scenario': scenario,
                                    'brain_type': type(brain).__name__,
                                    'has_real_rssm': has_real_rssm,
                                    'rssm_import_error': globals().get('_RSSM_IMPORT_ERROR'),
                                    'rssm_init_error': getattr(dreamer_model, '_rssm_init_error', None) if dreamer_model is not None else None,
                                    'required_dependencies': ['jax', 'jaxlib', 'ninjax', 'embodied', 'elements', 'einops', 'optax', 'portal', 'chex', 'cloudpickle'],
                                }}
                            else:
                                result = {{'error': f'Imagination failed: {{e}}', 'scenario': scenario, 'brain_type': type(brain).__name__}}
                        else:
                            def serialize(v):
                                if hasattr(v, 'tolist'):
                                    return v.tolist()
                                elif isinstance(v, dict):
                                    return {{k: serialize(vv) for k, vv in v.items()}}
                                elif isinstance(v, list):
                                    return [serialize(x) for x in v]
                                return v
                            result = {{'scenario': scenario, 'steps': steps, 'trajectory': serialize(out)}}
                    else:
                        result = {{
                            'error': 'Brain does not support imagination',
                            'brain_type': type(brain).__name__,
                            'hint': 'Imagination requires a world model (dreamer/ouroboros brain). Use forward() for basic inference or deliberate() for reasoning.'
                        }}

                # ═══════════════════════════════════════════════════════════
                # EMBEDDING/GENERATION TOOLS
                # ═══════════════════════════════════════════════════════════
                elif tool == 'embed_text':
                    text = args.get('text', '')

