                                        _in_len = inputs['input_ids'].shape[-1]
                                        outputs = model.generate(**inputs, max_new_tokens=max_tokens, do_sample=True, temperature=temperature)
                                        text = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                                    else:
