                    embedding_foundation = getattr(brain, 'embedding_foundation', None)

                    def _to_numpy_embedding(value):
                        if hasattr(value, 'detach'):
                            value = value.detach()
                        if hasattr(value, 'cpu'):
                            value = value.cpu()
                        return np.asarray(value, dtype=np.float32)

                    reranker = None
                    reranker_slot = None
                    available_slots = []
                    skipped_encode_only_slots = []
                    for i, c in enumerate(councilors):
                        model = getattr(c, 'model', None)
                        if not model:
                            continue
                        hint = getattr(model, '_model_type_hint', None)
                        available_slots.append({{'slot': i, 'hint': hint or 'unknown', 'has_predict': bool(hasattr(model, 'predict')), 'has_encode': bool(hasattr(model, 'encode'))}})
                        if reranker is None and hint == 'RERANKER' and hasattr(model, 'predict'):
                            reranker = model
                            reranker_slot = i

                    if reranker:
                        try:
                            pairs = [[query, doc] for doc in documents]
                            scores_raw = reranker.predict(pairs)
                            if hasattr(scores_raw, 'tolist'):
                                scores_raw = scores_raw.tolist()
                            indexed = list(zip(range(len(documents)), scores_raw, documents))
                            ranked = sorted(indexed, key=lambda x: x[1], reverse=True)
                            result = {{'query': query, 'method': 'cross-encoder', 'source': f'slot_{{reranker_slot}}', 'ranked': [{{'rank': r+1, 'doc_idx': i, 'score': float(s), 'text': t[:100]}} for r, (i, s, t) in enumerate(ranked)]}}
                        except Exception as e:
                            result = {{'error': f'Cross-encoder rerank failed: {{e}}', 'source': f'slot_{{reranker_slot}}'}}
                    else:
                        embed_fn = None
                        embedder_source = ''
                        if embedding_foundation and hasattr(embedding_foundation, 'encode'):
                            embed_fn = lambda t: embedding_foundation.encode(t, convert_to_numpy=True)
                            embedder_source = 'embedding_foundation'

                        if not embed_fn:
                            for i, c in enumerate(councilors):
                                model = getattr(c, 'model', None)
                                if not model:
                                    continue
                                hint = getattr(model, '_model_type_hint', None)
                                if hint == 'EMBEDDING' and hasattr(model, 'encode'):
                                    embed_fn = model.encode
                                    embedder_source = f'slot_{{i}}'
                                    break
                                if hint not in ('EMBEDDING', 'RERANKER') and hasattr(model, 'encode'):
                                    skipped_encode_only_slots.append({{'slot': i, 'hint': hint or 'unknown'}})

                        if not embed_fn:
                            result = {{
                                'error': 'No capable reranker or embedder is available',
                                'hint': 'Plug a true reranker or an explicit embedding model. Remote LLM providers with encode() are ignored for rerank fallback.',
                                'available_slots': available_slots,
                                'skipped_encode_only_slots': skipped_encode_only_slots,
                                'has_embedding_foundation': bool(embedding_foundation and hasattr(embedding_foundation, 'encode'))
                            }}
                        else:
                            try:
                                q_emb = _to_numpy_embedding(embed_fn(query))
                                doc_embs = [_to_numpy_embedding(embed_fn(d)) for d in documents]

                                scores = []
                                q_norm = np.linalg.norm(q_emb)
                                for i, d_emb in enumerate(doc_embs):
                                    sim = np.dot(q_emb, d_emb) / (q_norm * np.linalg.norm(d_emb) + 1e-8)
                                    scores.append((i, float(sim), documents[i]))

                                ranked = sorted(scores, key=lambda x: x[1], reverse=True)
                                result = {{'query': query, 'method': 'cosine-similarity', 'source': embedder_source, 'ranked': [{{'rank': r+1, 'doc_idx': i, 'score': s, 'text': t[:100]}} for r, (i, s, t) in enumerate(ranked)]}}
                            except Exception as e:
                                result = {{'error': f'Embedding rerank failed: {{e}}', 'source': embedder_source or 'unknown'}}

                # ═══════════════════════════════════════════════════════════
                # BAG TOOLS
