                                self._send_json(200, {{'object': 'list', 'data': models}})
                            elif self.path == '/health':
                                self._send_json(200, {{'status': 'ok'}})
                            else:
                                self._send_json(200, {{'status': 'ok', 'endpoints': ['/v1/chat/completions', '/v1/models', '/health']}})
                        def do_POST(self):
                            cl = int(self.headers.get('Content-Length', 0))
                            body = self.rfile.read(cl)
                            try:
                                data = json.loads(body) if body else {{}}
                            except Exception:
                                self._send_json(400, {{'error': 'Invalid JSON'}})
                                return
                            if self.path == '/v1/chat/completions':
                                messages = data.get('messages', [])
                                model = data.get('model', 'slot-0')
                                max_tokens = data.get('max_tokens', 512)
                                slot_idx = 0
                                if isinstance(model, str) and model.startswith('slot-'):
                                    try: slot_idx = int(model.split('-')[1])
                                    except: pass
                                try:
                                    r = self.server._invoke_fn(slot=slot_idx, text=messages[-1].get('content', '') if messages else '', mode='generate', max_tokens=max_tokens, messages=messages)
                                    rd = json.loads(r) if isinstance(r, str) else r
                                    import time as _t
                                    self._send_json(200, {{
                                        'id': f'chatcmpl-tui-{{int(_t.time())}}',
                                        'object': 'chat.completion',
                                        'created': int(_t.time()),
                                        'model': f'slot-{{slot_idx}}',
                                        'choices': [{{'index': 0, 'message': {{'role': 'assistant', 'content': rd.get('output', '')}}, 'finish_reason': 'stop'}}],
                                    }})
                                except Exception as e:
                                    self._send_json(500, {{'error': str(e)}})
                            else:
                                self._send_json(404, {{'error': f'Unknown: {{self.path}}'}})

                    _srv = _api_http.HTTPServer(('0.0.0.0', port), _TUIAPIHandler)
