                # Show FULL result values for all tools
                def format_value(v, indent=3):
                    prefix = " " * indent
                    if v is None:
                        return "null"
                    elif isinstance(v, bool):
                        return str(v).lower()
                    elif isinstance(v, (int, float)):
                        return str(v)
                    elif isinstance(v, str):
                        if len(v) > 200:
                            return v[:200] + f"... ({{len(v)}} chars)"
                        return v
                    elif isinstance(v, list):
                        if len(v) == 0:
                            return "[]"
                        elif len(v) > 10:
                            # Show first 5 items
                            items = [format_value(x, indent+2) for x in v[:5]]
                            return "[" + ", ".join(items) + f", ... +{{len(v)-5}} more]"
                        else:
                            items = [format_value(x, indent+2) for x in v]
                            return "[" + ", ".join(items) + "]"
                    elif isinstance(v, dict):
                        if len(v) == 0:
                            return "{{}}"
                        elif len(v) > 8:
                            keys = list(v.keys())[:5]
                            return "{{" + ", ".join(keys) + f", ... +{{len(v)-5}} more}}}}"
                        else:
                            return "{{" + ", ".join(v.keys()) + "}}"
                    else:
                        s = str(v)
                        if len(s) > 100:
                            return s[:100] + "..."
                        return s

                for k, v in result.items():
