                        mt = _detect_model_type_runtime(m)
                        if mt == ModelType.INFINITY_RERANK or hasattr(m, 'rerank'):
                            model = m
                            model_source = getattr(c, '_model_source', 'unknown')
                            model_type = mt
                            break

                if model is None:
                    self._log("❌ No reranker plugged. Try: plug mixedbread-ai/mxbai-rerank-xsmall-v1")
                    return

                self._log(f"⏳ Reranking {{len(docs)}} docs for: {{query[:40]}}...")
                self._log("   (Running in background)")

                def _rerank_worker(model=model, query=query, docs=docs, model_type=model_type, model_source=model_source):
                    import time as t
                    t0 = t.perf_counter()
                    try:
                        result = _invoke_model(model, {{'text': query, 'documents': docs}}, model_type)
                        elapsed = (t.perf_counter() - t0) * 1000
                        return result, elapsed, model_source, len(docs), None
                    except Exception as e:
                        return None, 0, model_source, len(docs), str(e)

                def _on_rerank_complete(result):
                    res, elapsed, src, n_docs, error = result
                    if error:
                        self._log(f"❌ Rerank error: {{error}}")
                        return
                    if 'rankings' in res:
                        self._log(f"✅ Rankings:")
                        for rank in res['rankings'][:5]:
                            self._log(f"   {{rank}}")
                    else:
                        self._log(f"✅ Result: {{res}}")
                    self._log(f"⏱️ {{elapsed:.1f}}ms")

                self._worker_callbacks['rerank'] = _on_rerank_complete
                self.run_worker(_rerank_worker, name='rerank', thread=True, exit_on_error=False)

            elif action == 'rerank' and not args:
