                # Spawn clones via replicate if available
                for _ in range(n_clones):
                    if hasattr(councilor, 'replicate'):
                        clone = councilor.replicate()
                    else:
                        # Manual clone - share model reference
                        clone = type(councilor).__new__(type(councilor))
