                if fmt == 'pt' or fmt == 'pytorch' or fmt == 'torch':
                    # PyTorch TorchScript export
                    path = path or 'council_model.pt'
                    if not path.endswith('.pt'):
                        path += '.pt'
                    export_path = Path(__file__).parent / path
                    try:
                        import torch
                        import torch.nn as nn

                        # Build combined council module
                        class CouncilModule(nn.Module):
                            def __init__(self, councilors):
                                super().__init__()
                                self.modules_list = nn.ModuleList()
                                for c in councilors:
                                    if hasattr(c, 'model') and hasattr(c.model, 'parameters'):
                                        self.modules_list.append(c.model)

                            def forward(self, x):
                                if len(self.modules_list) == 0:
                                    return x
                                outputs = [m(x) for m in self.modules_list]
                                return torch.stack(outputs).mean(dim=0)

                        export_members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
                        model = CouncilModule(export_members)
                        scripted = torch.jit.script(model)
                        scripted.save(str(export_path))
                        self._log(f"📤 Exported PyTorch: {{export_path.name}}")
                        self._log(f"   Load with: torch.jit.load('{{path}}')")
