                    try:
                        # Read current file
                        current = Path(__file__).read_text(encoding='utf-8')

                        # Update generation
                        import re
                        new_gen = self.agent.generation + 1
                        updated = re.sub(
                            r'_GENERATION = \\d+',
                            f'_GENERATION = {{new_gen}}',
