                            new_data = base64.b64encode(data).decode('ascii')
                            # Wrap at 80 chars
                            wrapped = '\\n'.join(new_data[i:i+80] for i in range(0, len(new_data), 80))
                            updated = re.sub(
                                r'_BRAIN_DATA = \"\"\".*?\"\"\"',
