                    has_embedder = getattr(self.brain, 'embedding_foundation', None) or getattr(self.brain, '_embedding_model', None)
                    self._log(f"  Dreamer: {{'✓' if has_dreamer else '○'}}")
                    self._log(f"  Embedder: {{'✓' if has_embedder else '○'}}")

                # Show vote breakdown
                if isinstance(result, dict) and 'deliberation' in result:
                    self._log(f"  ── VOTES ──")
                    for name, vote in result['deliberation'].items():
                        conf = vote.get('confidence', 0.5)
                        plugged = '✓' if vote.get('plugged', False) else '○'
                        out = vote.get('output', None)
                        if out is not None and hasattr(out, 'mean'):
                            out_str = f"mean={{out.mean():.4f}}"
                        else:
                            out_str = str(out)[:20] if out is not None else 'N/A'
                        self._log(f"    [{{plugged}}] {{name}}: {{out_str}} (conf={{conf:.2f}})")

                if isinstance(result, dict):
                    self._log(f"  Provenance: {{result.get('provenance', result.get('_merkle_root', 'N/A'))}}")
                self._log(f"⏱️ {{elapsed:.1f}}ms")

            elif action == 'broadcast':
                # Broadcast a message to all councilors
                is_council = self.brain_type == 'council' or self.is_ouroboros
                if not is_council:
                    self._log("❌ broadcast only available for council/ouroboros brains")
                    return

                if not args:
                    self._log("Usage: broadcast <message>")
                    self._log("  Sends message to all councilors for processing")
                    return

                msg = ' '.join(args)
                councilors = getattr(self.brain, 'councilors', getattr(self.brain, 'all_members', []))
                self._log(f"📡 Broadcasting to {{len(councilors)}} councilors: '{{msg[:40]}}'")

                results = []
                for i, c in enumerate(councilors):
                    if hasattr(c, 'forward') and getattr(c, 'model', None):
                        obs = {{'text': msg, 'input': np.random.rand(384).astype(np.float32)}}
                        r = c.forward(obs)
                        results.append((i, r))
                        self._log(f"  [{{i}}] ✓ responded")

                self._log(f"✅ {{len(results)}} responses received")

            elif action == 'to':
                # Route command to specific councilor slot
                is_council = self.brain_type == 'council' or self.is_ouroboros
                if not is_council:
                    self._log("❌ 'to' only available for council/ouroboros brains")
                    return

                if not args or len(args) < 2:
                    self._log("Usage: to <slot> <command> [args...]")
                    self._log("  Routes command to specific councilor slot")
                    self._log("  Example: to 4 generate 'Hello world'")
                    return

                try:
                    slot_idx = int(args[0])
                except ValueError:
                    self._log(f"❌ Slot must be a number, got: {{args[0]}}")
                    return

                members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
                if slot_idx < 0 or slot_idx >= len(members):
                    self._log(f"❌ Invalid slot: {{slot_idx}} (have {{len(members)}} slots)")
                    return

                c = members[slot_idx]
                model = getattr(c, 'model', None)
                if model is None:
                    self._log(f"❌ Slot {{slot_idx}} is empty")
                    return

                # Execute command on specific slot
                cmd = args[1]
                cmd_args = ' '.join(args[2:]) if len(args) > 2 else ''

                self._log(f"🎯 Routing to slot {{slot_idx}}: {{cmd}} {{cmd_args[:30]}}")

                import time
                t0 = time.perf_counter()

                if cmd == 'embed':
                    if hasattr(model, 'encode'):
                        result = model.encode(cmd_args)
                        self._log(f"  ✓ Embedding: shape={{result.shape if hasattr(result, 'shape') else len(result)}}")
                    else:
                        self._log(f"  ❌ Model doesn't support embedding")
                        return
                elif cmd == 'generate':
                    if hasattr(model, 'generate'):
                        _lim = getattr(c, '_limits', getattr(model, '_limits', {{}}))
                        _gen = _lim.get('max_gen_tokens', 256)
                        result = model.generate(cmd_args, max_new_tokens=_gen)
                        self._log(f"  ✓ Generated: {{str(result)[:100]}}")
                    else:
                        self._log(f"  ❌ Model doesn't support generation")
                        return
                elif cmd == 'forward' or cmd == 'invoke':
                    if hasattr(c, 'forward'):
                        obs = {{'text': cmd_args, 'input': np.random.rand(384).astype(np.float32)}}
                        result = c.forward(obs)
                        self._log(f"  ✓ Forward result: {{str(result)[:100]}}")
                    else:
                        self._log(f"  ❌ Slot doesn't support forward")
                        return
                else:
                    self._log(f"  ❌ Unknown command: {{cmd}}")
                    self._log(f"     Supported: embed, generate, forward, invoke")
                    return

                elapsed = (time.perf_counter() - t0) * 1000
                self._log(f"⏱️ {{elapsed:.1f}}ms")

            elif action == 'pipe':
                # Pipe data through the brain's processing pipeline
                if not args:
                    self._log("Usage: pipe <data>")
                    self._log("  Pipes data through the brain's forward() method")
                    return

                data = ' '.join(args)
                obs = {{'text': data, 'input': np.random.rand(384).astype(np.float32)}}

                import time
                t0 = time.perf_counter()
                result = self.brain.forward(obs)
                elapsed = (time.perf_counter() - t0) * 1000

                self._log(f"🔀 PIPE: '{{data[:40]}}'")
                if isinstance(result, dict):
                    for k, v in list(result.items())[:5]:
                        if hasattr(v, 'shape'):
                            self._log(f"  {{k}}: {{v.shape}}")
                        elif isinstance(v, (int, float, str, bool)):
                            self._log(f"  {{k}}: {{v}}")
                self._log(f"⏱️ {{elapsed:.1f}}ms")

            # 🔢 NUMBER SELECTION - select from last hub search results
            elif action.isdigit():
                idx = int(action) - 1  # 1-indexed to 0-indexed
                if hasattr(self, '_last_hub_results') and self._last_hub_results:
                    if 0 <= idx < len(self._last_hub_results):
                        model_id = self._last_hub_results[idx]
                        self._log(f"📦 Selected: {{model_id}}")
                        # Trigger hub plug command
                        await self.on_input_submitted(type('E', (), {{'value': f'hub plug {{model_id}}', 'input': type('I', (), {{'value': ''}})}})())
                    else:
                        self._log(f"❌ No result #{{action}} (only {{len(self._last_hub_results)}} results)")
                else:
                    self._log(f"❌ No hub search results to select from")
                    self._log("   Run 'hub search <query>' first, then type a number")

            # ═══════════════════════════════════════════════════════════════════════
            # SLOT-TARGETED INVOCATION: invoke@N, embed@N, generate@N
            # ═══════════════════════════════════════════════════════════════════════
            elif '@' in action and action.split('@')[0] in ('invoke', 'embed', 'generate', 'classify'):
                base_cmd, slot_str = action.split('@', 1)
                try:
                    slot_idx = int(slot_str)
                except ValueError:
                    self._log(f"❌ Invalid slot: {{slot_str}} (use number)")
                    return

                members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
                if slot_idx >= len(members):
                    self._log(f"❌ Slot {{slot_idx}} doesn't exist (max: {{len(members)-1}})")
                    return

                c = members[slot_idx]
                model = getattr(c, 'model', None)
                if model is None:
                    self._log(f"❌ Slot {{slot_idx}} is empty. Use 'plug MODEL' first.")
                    return

                text_input = ' '.join(args) if args else 'test'
                model_source = getattr(c, '_model_source', f'slot_{{slot_idx}}')
                model_type = _detect_model_type_runtime(model)

                self._log(f"⏳ {{base_cmd}}@{{slot_idx}}: {{text_input[:40]}}...")

                import time
                t0 = time.perf_counter()
                try:
                    if base_cmd == 'embed' and hasattr(model, 'encode'):
                        result = {{'embedding': np.asarray(model.encode(text_input)), 'type': 'embedding'}}
                    elif base_cmd == 'generate' and hasattr(model, 'generate'):
                        result = {{'text': model.generate(text_input), 'type': 'llm'}}
                    else:
                        result = _invoke_model(model, {{'text': text_input, 'prompt': text_input}}, model_type)
                    elapsed = (time.perf_counter() - t0) * 1000

                    if 'embedding' in result:
                        emb = result['embedding']
                        self._log(f"✅ [@{{slot_idx}}] Embedding: shape={{emb.shape}}, norm={{np.linalg.norm(emb):.4f}}")
                    elif 'text' in result:
                        self._log(f"✅ [@{{slot_idx}}] Generated: {{result['text'][:150]}}...")
                    else:
                        self._log(f"✅ [@{{slot_idx}}] Output: {{str(result.get('output', result))[:100]}}")
                    self._log(f"⏱️ {{elapsed:.1f}}ms")
                except Exception as e:
                    self._log(f"❌ {{base_cmd}}@{{slot_idx}} error: {{e}}")

            # ═══════════════════════════════════════════════════════════════════════
            # ALL/BROADCAST: Run on all plugged models
            # ═══════════════════════════════════════════════════════════════════════
            elif action == 'all' and args:
                subcmd = args[0].lower()
                text_input = ' '.join(args[1:]) if len(args) > 1 else 'test'

                if subcmd not in ('invoke', 'embed', 'generate', 'classify'):
                    self._log(f"Usage: all <invoke|embed|generate|classify> <text>")
                    return

                members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))
                plugged = [(i, c) for i, c in enumerate(members) if getattr(c, 'model', None)]

                if not plugged:
                    self._log("❌ No models plugged. Use 'plug MODEL' first.")
                    return

                self._log(f"🔊 BROADCAST {{subcmd.upper()}}: '{{text_input[:40]}}' → {{len(plugged)}} models")
                self._log("")

                import time
                results = []
                for slot_idx, c in plugged:
                    model = c.model
                    name = getattr(c, 'name', f'slot_{{slot_idx}}')
                    model_type = _detect_model_type_runtime(model)

                    t0 = time.perf_counter()
                    try:
                        if subcmd == 'embed' and hasattr(model, 'encode'):
                            result = {{'embedding': np.asarray(model.encode(text_input)), 'type': 'embedding'}}
                        elif subcmd == 'generate' and hasattr(model, 'generate'):
                            result = {{'text': model.generate(text_input), 'type': 'llm'}}
                        else:
                            result = _invoke_model(model, {{'text': text_input}}, model_type)
                        elapsed = (time.perf_counter() - t0) * 1000
                        results.append((slot_idx, name, result, elapsed))

                        # Show result
                        if 'embedding' in result:
                            emb = result['embedding']
                            self._log(f"  [{{slot_idx}}] {{name}}: dim={{emb.shape[-1]}}, norm={{np.linalg.norm(emb):.3f}} ({{elapsed:.0f}}ms)")
                        elif 'text' in result:
                            self._log(f"  [{{slot_idx}}] {{name}}: {{result['text'][:60]}}... ({{elapsed:.0f}}ms)")
                        else:
                            self._log(f"  [{{slot_idx}}] {{name}}: {{str(result.get('output', '?'))[:50]}} ({{elapsed:.0f}}ms)")
                    except Exception as e:
                        self._log(f"  [{{slot_idx}}] {{name}}: ❌ {{e}}")

                # Show embedding similarity matrix if all embeddings
                if subcmd == 'embed' and len(results) > 1:
                    embeddings = [r[2].get('embedding') for r in results if 'embedding' in r[2]]
                    if len(embeddings) > 1:
                        self._log("")
                        self._log("  📊 SIMILARITY MATRIX:")
                        for i, (si, ni, _, _) in enumerate(results):
                            if i >= len(embeddings):
                                break
                            sims = []
                            for j, (sj, nj, _, _) in enumerate(results):
                                if j >= len(embeddings):
                                    break
                                sim = np.dot(embeddings[i].flatten(), embeddings[j].flatten()) / (np.linalg.norm(embeddings[i]) * np.linalg.norm(embeddings[j]) + 1e-8)
                                sims.append(f"{{sim:.2f}}")
                            self._log(f"    {{ni[:8]:8s}}: {{' '.join(sims)}}")

                self._log("")
                self._log(f"✅ {{len(results)}}/{{len(plugged)}} completed")

            # ═══════════════════════════════════════════════════════════════════════
            # CHAT: Multi-turn conversation mode
            # ═══════════════════════════════════════════════════════════════════════
            elif action == 'chat' and args:
                subcmd = args[0].lower() if args else None

                # Initialize chat history if needed
                if not hasattr(self, '_chat_history'):
                    self._chat_history = []

                if subcmd == 'clear':
                    self._chat_history = []
                    self._log("💬 Chat history cleared")
                    return
                elif subcmd == 'history':
                    if not self._chat_history:
                        self._log("💬 No chat history")
                    else:
                        self._log("💬 CHAT HISTORY:")
                        for msg in self._chat_history[-20:]:  # Last 20
                            role = msg.get('role', '?')
                            content = msg.get('content', '')[:100]
                            icon = '👤' if role == 'user' else '🤖'
                            self._log(f"  {{icon}} {{content}}")
                    return

                # Normal chat message
                user_msg = ' '.join(args)
                self._chat_history.append({{'role': 'user', 'content': user_msg}})

                # Find LLM-capable model
                members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', [self.brain]))
                model = None
                model_source = None
                for c in members:
                    m = getattr(c, 'model', None)
                    if m is not None and hasattr(m, 'generate'):
                        model = m
                        model_source = getattr(c, '_model_source', 'unknown')
                        break

                if model is None:
                    self._log("❌ No LLM plugged. Try: plug microsoft/phi-2")
                    return

                self._log(f"💬 {{user_msg}}")
                self._log("   ...")

                # Build prompt with history
                prompt_parts = []
                for msg in self._chat_history[-10:]:  # Last 10 turns
                    role = msg.get('role', 'user')
                    content = msg.get('content', '')
                    prompt_parts.append(f"{{role.upper()}}: {{content}}")
                prompt = '\\n'.join(prompt_parts) + '\\nASSISTANT:'

                def _chat_worker(model=model, prompt=prompt):
                    import time as t
                    t0 = t.perf_counter()
                    try:
                        response = model.generate(prompt)
                        elapsed = (t.perf_counter() - t0) * 1000
                        return response, elapsed, None
                    except Exception as e:
                        return None, 0, str(e)

                def _on_chat_complete(result):
                    response, elapsed, error = result
                    if error:
                        self._log(f"❌ Chat error: {{error}}")
                        return
                    # Store response
                    self._chat_history.append({{'role': 'assistant', 'content': response}})
                    # Display
                    self._log(f"🤖 {{response[:500]}}")
                    self._log(f"⏱️ {{elapsed:.0f}}ms")

                self._worker_callbacks['chat'] = _on_chat_complete
                self.run_worker(_chat_worker, name='chat', thread=True, exit_on_error=False)

            elif action == 'chat' and not args:
                self._log("💬 CHAT MODE")
                self._log("   chat <message>     → Send message to LLM")
                self._log("   chat clear         → Clear history")
                self._log("   chat history       → Show conversation")
                self._log("")
                self._log("Examples:")
                self._log("   chat Hello, who are you?")
                self._log("   chat What did I just ask?")

            # ═══════════════════════════════════════════════════════════════════════
            # CHAIN/PIPE: Sequential model processing
            # ═══════════════════════════════════════════════════════════════════════
            elif action == 'chain' and args:
                # Parse chain: chain 0→1→2 "input" or chain 0,1,2 input
                chain_spec = args[0]
                text_input = ' '.join(args[1:]) if len(args) > 1 else 'test'

                # Parse slot sequence
                if '→' in chain_spec or '->' in chain_spec:
                    slots = [int(s.strip()) for s in chain_spec.replace('->', '→').split('→')]
                elif ',' in chain_spec:
                    slots = [int(s.strip()) for s in chain_spec.split(',')]
                else:
                    self._log("Usage: chain 0→1→2 <input>  or  chain 0,1,2 <input>")
                    return

                members = getattr(self.brain, 'all_members', getattr(self.brain, 'councilors', []))

                self._log(f"🔗 CHAIN: {{' → '.join(str(s) for s in slots)}}")
                self._log(f"   Input: {{text_input[:50]}}...")
                self._log("")

                current_data = text_input
                import time
                total_t0 = time.perf_counter()

                for step, slot_idx in enumerate(slots):
                    if slot_idx >= len(members):
                        self._log(f"  [{{step}}] ❌ Slot {{slot_idx}} doesn't exist")
                        break

                    c = members[slot_idx]
                    model = getattr(c, 'model', None)
                    name = getattr(c, 'name', f'slot_{{slot_idx}}')

                    if model is None:
                        self._log(f"  [{{step}}] ❌ Slot {{slot_idx}} empty")
                        break

                    t0 = time.perf_counter()
                    try:
                        model_type = _detect_model_type_runtime(model)

                        # Invoke with current data
                        if hasattr(model, 'encode'):
                            result = model.encode(str(current_data) if not isinstance(current_data, str) else current_data)
                            current_data = result
                            result_str = f"embedding dim={{len(result) if hasattr(result, '__len__') else '?'}}"
                        elif hasattr(model, 'generate'):
                            result = model.generate(str(current_data) if not isinstance(current_data, str) else current_data)
                            current_data = result
                            result_str = f"text: {{str(result)[:40]}}..."
                        else:
                            result = _invoke_model(model, {{'text': str(current_data), 'input': current_data}}, model_type)
                            current_data = result.get('output', result.get('embedding', result.get('text', current_data)))
                            result_str = f"output: {{str(current_data)[:40]}}..."

                        elapsed = (time.perf_counter() - t0) * 1000
                        self._log(f"  [{{step}}] {{name}}: {{result_str}} ({{elapsed:.0f}}ms)")
                    except Exception as e:
                        self._log(f"  [{{step}}] {{name}}: ❌ {{e}}")
                        break

                total_elapsed = (time.perf_counter() - total_t0) * 1000
                self._log("")
                self._log(f"✅ Chain complete: {{total_elapsed:.0f}}ms total")

            elif action == 'chain' and not args:
                self._log("🔗 CHAIN MODE - Sequential model processing")
                self._log("   chain 0→1→2 <input>   → Process through slots in sequence")
                self._log("   chain 0,1,2 <input>   → Same, comma-separated")
                self._log("")
                self._log("Each step's output becomes the next step's input.")
                self._log("Works with: embedders, LLMs, any model")
                self._log("")
                self._log("Example:")
                self._log("   chain 0→1 Hello world")
                self._log("   # Slot 0 embeds, slot 1 processes embedding")

            # ═══════════════════════════════════════════════════════════════════════
            # SERVE: Start API server mode
            # ═══════════════════════════════════════════════════════════════════════
            elif action == 'serve':
                port = int(args[0]) if args else 8420
                self._log(f"🌐 Starting API server on port {{port}}...")
                self._log("")
                self._log("API Endpoints (OpenAI-compatible):")
                self._log(f"   POST http://localhost:{{port}}/v1/embeddings")
                self._log(f"   POST http://localhost:{{port}}/v1/completions")
                self._log(f"   POST http://localhost:{{port}}/v1/chat/completions")
                self._log(f"   GET  http://localhost:{{port}}/v1/models")
                self._log("")
                self._log("Ouroboros-specific:")
                self._log(f"   POST http://localhost:{{port}}/invoke")
                self._log(f"   POST http://localhost:{{port}}/deliberate")
                self._log(f"   POST http://localhost:{{port}}/imagine")
                self._log(f"   GET  http://localhost:{{port}}/slots")
                self._log("")
                self._log("⚠️ Server runs in background. Stop with 'serve stop'")

                # Store server reference
                if hasattr(self, '_api_server') and self._api_server:
                    self._log("❌ Server already running. Use 'serve stop' first.")
                    return

                # Start server in background thread
                def _run_api_server(brain=self.brain, port=port):
                    import http.server
                    import json

                    brain_ref = brain

                    class OuroborosAPIHandler(http.server.BaseHTTPRequestHandler):
                        def log_message(self, format, *args):
                            pass  # Suppress request logging

                        def _send_json(self, data, status=200):
                            self.send_response(status)
                            self.send_header('Content-Type', 'application/json')
                            self.send_header('Access-Control-Allow-Origin', '*')
                            self.end_headers()
                            self.wfile.write(json.dumps(data).encode())

                        def do_OPTIONS(self):
                            self.send_response(200)
                            self.send_header('Access-Control-Allow-Origin', '*')
                            self.send_header('Access-Control-Allow-Methods', 'GET, POST, OPTIONS')
                            self.send_header('Access-Control-Allow-Headers', 'Content-Type, Authorization')
                            self.end_headers()

                        def do_GET(self):
                            if self.path == '/v1/models':
                                members = getattr(brain_ref, 'all_members', getattr(brain_ref, 'councilors', []))
                                models = []
                                for i, c in enumerate(members):
                                    if getattr(c, 'model', None):
                                        models.append({{
                                            'id': getattr(c, 'name', f'slot_{{i}}'),
                                            'object': 'model',
                                            'owned_by': 'ouroboros'
                                        }})
                                self._send_json({{'object': 'list', 'data': models}})
                            elif self.path == '/slots':
                                members = getattr(brain_ref, 'all_members', getattr(brain_ref, 'councilors', []))
                                slots = []
                                for i, c in enumerate(members):
                                    slots.append({{
                                        'index': i,
                                        'name': getattr(c, 'name', f'slot_{{i}}'),
                                        'plugged': getattr(c, 'model', None) is not None,
                                        'source': getattr(c, '_model_source', None)
                                    }})
                                self._send_json({{'slots': slots}})
                            else:
                                self._send_json({{'error': 'Not found'}}, 404)

                        def do_POST(self):
                            content_length = int(self.headers.get('Content-Length', 0))
                            body = self.rfile.read(content_length).decode() if content_length else '{{}}'
                            try:
                                data = json.loads(body)
                            except Exception:
                                data = {{}}

                            if self.path == '/v1/embeddings':
                                text = data.get('input', '')
                                # Find embedding model
                                members = getattr(brain_ref, 'all_members', getattr(brain_ref, 'councilors', []))
                                for c in members:
                                    model = getattr(c, 'model', None)
                                    if model and hasattr(model, 'encode'):
                                        emb = model.encode(text)
                                        self._send_json({{
                                            'object': 'list',
                                            'data': [{{'object': 'embedding', 'embedding': list(np.asarray(emb).flatten().tolist())}}]
                                        }})
                                        return
                                self._send_json({{'error': 'No embedding model'}}, 400)

                            elif self.path in ('/v1/completions', '/v1/chat/completions'):
                                prompt = data.get('prompt', '')
                                messages = data.get('messages', [])
                                if messages:
                                    prompt = '\\n'.join(m.get('content', '') for m in messages)

                                # Find LLM
                                members = getattr(brain_ref, 'all_members', getattr(brain_ref, 'councilors', []))
                                for c in members:
                                    model = getattr(c, 'model', None)
                                    if model and hasattr(model, 'generate'):
                                        text = model.generate(prompt)
                                        self._send_json({{
                                            'id': 'ouro-' + str(hash(prompt))[:8],
                                            'object': 'chat.completion',
                                            'choices': [{{'message': {{'role': 'assistant', 'content': text}}, 'finish_reason': 'stop'}}]
                                        }})
                                        return
                                self._send_json({{'error': 'No LLM model'}}, 400)

                            elif self.path == '/invoke':
                                text = data.get('text', data.get('input', ''))
                                slot = data.get('slot', None)

                                members = getattr(brain_ref, 'all_members', getattr(brain_ref, 'councilors', []))
                                if slot is not None and slot < len(members):
                                    c = members[slot]
                                    model = getattr(c, 'model', None)
                                    if model:
                                        mt = _detect_model_type_runtime(model)
                                        result = _invoke_model(model, {{'text': text}}, mt)
                                        self._send_json(result)
                                        return

                                # Broadcast to all
                                results = []
                                for i, c in enumerate(members):
                                    model = getattr(c, 'model', None)
                                    if model:
                                        mt = _detect_model_type_runtime(model)
                                        result = _invoke_model(model, {{'text': text}}, mt)
                                        results.append({{'slot': i, 'result': result}})
                                self._send_json({{'results': results}})

                            elif self.path == '/deliberate':
                                text = data.get('text', data.get('query', 'deliberate'))
                                obs = {{'text': text, 'input': np.random.rand(384).astype(np.float32)}}
                                result = brain_ref.forward(obs)
                                # Convert numpy to lists for JSON
                                json_safe = {{}}
                                for k, v in result.items():
                                    if hasattr(v, 'tolist'):
                                        json_safe[k] = v.tolist()
                                    elif isinstance(v, dict):
                                        json_safe[k] = {{kk: vv.tolist() if hasattr(vv, 'tolist') else vv for kk, vv in v.items()}}
                                    else:
                                        json_safe[k] = v
                                self._send_json(json_safe)

                            elif self.path == '/imagine':
                                horizon = data.get('horizon', data.get('steps', 15))
                                text = data.get('text', 'imagine')
                                obs = {{'text': text, 'input': np.random.rand(384).astype(np.float32)}}

                                dreamer = getattr(brain_ref, 'dreamer_world_model', None)
                                if dreamer and hasattr(dreamer, 'imagine'):
                                    result = dreamer.imagine(obs, horizon=horizon)
                                elif hasattr(brain_ref, 'imagine'):
                                    result = brain_ref.imagine(obs, horizon=horizon)
                                else:
                                    result = brain_ref.forward(obs)

                                # Convert numpy to lists
                                json_safe = {{}}
                                for k, v in result.items():
                                    if hasattr(v, 'tolist'):
                                        json_safe[k] = v.tolist()
                                    else:
                                        json_safe[k] = v
                                self._send_json(json_safe)

                            else:
                                self._send_json({{'error': 'Not found'}}, 404)

                    server = http.server.HTTPServer(('0.0.0.0', port), OuroborosAPIHandler)
                    server.serve_forever()

                import threading
                self._api_server = threading.Thread(target=_run_api_server, daemon=True)
                self._api_server.start()
                self._log(f"✅ API server started on port {{port}}")

