def _mcp_vast_list_instances_raw():
    import subprocess as _subprocess
    result = _subprocess.run(['vastai', 'show', 'instances', '--raw'],
                             capture_output=True, text=True, timeout=30)
    if result.returncode != 0:
        raise RuntimeError(result.stderr or 'Cannot get instance list')
    stdout = str(result.stdout or '').strip()
    if not stdout:
        return []
    data = json.loads(stdout)
    return data if isinstance(data, list) else []

def _mcp_vast_get_instance(instance_id):
    instances = _mcp_vast_list_instances_raw()
    for inst in instances:
        if str(inst.get('id')) == str(instance_id):
            return inst, instances
    return None, instances

def _mcp_vast_network_info(inst):
    public_ip = str((inst or {{}}).get('public_ipaddr', '') or '')
    ports = (inst or {{}}).get('ports', {{}}) or {{}}
    http_urls = []
    port_mappings = []
    api_server_url = ''
    api_host_port = None
    for port_key, mappings in ports.items():
        container_port = str(port_key).split('/')[0]
        for mapping in (mappings or []):
            host_port = str(mapping.get('HostPort') or container_port)
            host_ip = str(mapping.get('HostIp') or public_ip)
            url = f"http://{{public_ip}}:{{host_port}}" if public_ip and host_port else ''
            if url:
                http_urls.append(url)
            port_mappings.append({{
                "container_port": container_port,
                "host_port": host_port,
                "host_ip": host_ip,
                "url": url,
            }})
            if container_port == str(_MCP_VAST_API_PORT) and public_ip and host_port:
                api_host_port = host_port
                api_server_url = f"http://{{public_ip}}:{{host_port}}/v1"
    return {{
        "public_ip": public_ip,
        "http_urls": http_urls,
        "port_mappings": port_mappings,
        "api_host_port": api_host_port,
        "api_server_url": api_server_url,
    }}

