def _summarize_response(result: str, tool_name: str) -> dict:
    \"\"\"Generate COMPLETE spec sheet from any JSON response.

    Uses cascade-lattice classify_metric to categorize metrics.
    Aggregates ALL items - no truncation. Goal: make full fetch unnecessary.
    \"\"\"
    try:
        from cascade_lattice.analysis import classify_metric, MetricCategory
        has_cascade = True
    except ImportError:
        has_cascade = False
        MetricCategory = None

    spec = {{"tool": tool_name}}

    try:
        data = json.loads(result) if isinstance(result, str) else result
    except Exception:
        spec["raw_preview"] = result[:500] if isinstance(result, str) else str(result)[:500]
        return spec

    if isinstance(data, dict):
        # Extract errors/hints first
        if "error" in data:
            spec["error"] = data["error"]
        if "hint" in data:
            spec["hint"] = data["hint"]

        # Extract list items - COMPLETE aggregation
        for key in ("models", "slots", "results", "items", "children", "entries", "members"):
            if key in data and isinstance(data[key], list):
                items = data[key]
                spec["total"] = len(items)

                # Aggregate ALL items - collect unique values per field
                all_ids = []
                field_values = {{}}  # field_name -> list of values
                numeric_stats = {{}}  # field_name -> (sum, count, min, max)

                for item in items:
                    if isinstance(item, dict):
                        for k, v in item.items():
                            if k in ("id", "name", "key"):
                                all_ids.append(v)
                            elif isinstance(v, (int, float)):
                                if k not in numeric_stats:
                                    numeric_stats[k] = [v, 1, v, v]
                                else:
                                    s = numeric_stats[k]
                                    s[0] += v  # sum
                                    s[1] += 1  # count
                                    s[2] = min(s[2], v)  # min
                                    s[3] = max(s[3], v)  # max
                            elif isinstance(v, str) and len(v) < 50:
                                if k not in field_values:
                                    field_values[k] = set()
                                field_values[k].add(v)
                    else:
                        all_ids.append(str(item))

                # ALL ids - complete list
                if all_ids:
                    spec["all_ids"] = all_ids

                # Unique values per field (for task, status, type, etc.)
                for k, vals in field_values.items():
                    if len(vals) <= 20:  # reasonable number of unique values
                        spec[f"unique_{{k}}s"] = list(vals)
                    else:
                        spec[f"unique_{{k}}_count"] = len(vals)

                # Numeric field statistics
                if numeric_stats:
                    spec["stats"] = {{}}
                    for k, (total, cnt, mn, mx) in numeric_stats.items():
                        if has_cascade:
                            cat = classify_metric(k)
                            cat_name = cat.name if cat != MetricCategory.UNKNOWN else None
                        else:
                            cat_name = None
                        stat = {{"sum": total, "avg": round(total/cnt, 2), "min": mn, "max": mx}}
                        if cat_name:
                            stat["category"] = cat_name
                        spec["stats"][k] = stat
                break

        # Extract all top-level metrics
        metrics = {{}}
        for key, val in data.items():
            if isinstance(val, (int, float)):
                if has_cascade:
                    cat = classify_metric(key)
                    cat_name = cat.name if cat != MetricCategory.UNKNOWN else "other"
                else:
                    cat_name = "other"
                if cat_name not in metrics:
                    metrics[cat_name] = {{}}
                metrics[cat_name][key] = val
            elif isinstance(val, str) and len(val) < 200:
                spec[key] = val
        if metrics:
            spec["metrics"] = metrics

    elif isinstance(data, list):
        spec["total"] = len(data)
        all_ids = []
        for item in data:
            if isinstance(item, dict):
                for k in ("id", "name", "key"):
                    if k in item:
                        all_ids.append(item[k])
                        break
            else:
                all_ids.append(str(item))
        if all_ids:
            spec["all_ids"] = all_ids

    return spec

# Module-level CASCADE monitor for MCP tools (initialized in run_mcp_server)
_CASCADE_MCP_MONITOR = None
_CASCADE_MCP_AVAILABLE = False
_MCP_TOOL_STEP = 0

def run_mcp_server(host: str = None, port: int = 8765, shared_agent=None, quiet: bool = False, register_only: bool = False):
    \"\"\"Run capsule as MCP server for VS Code / Copilot / Kiro integration.

    Args:
        host: If provided, run HTTP server on this host (e.g. '0.0.0.0' for remote)
              If None, run stdio transport (local only)
        port: Port for HTTP server (default 8765)
        shared_agent: If provided, use this agent instead of creating a new one.
                      This allows the TUI's agent to be shared with MCP.
        quiet: If True, suppress all console output (for TUI embedding)
        register_only: If True, register all tools but don't start serving.
                       Returns the FastMCP instance for Arcade bridge access.
    \"\"\"
    if not _MCP_AVAILABLE:
        raise RuntimeError("MCP not installed. Run: pip install 'mcp[cli]'")

    # ═══════════════════════════════════════════════════════════════
    # STDIO MODE: Redirect print() to stderr to keep stdout clean for JSON-RPC
    # MCP uses real stdout for protocol, but Python print() pollutes it
    # Solution: Monkey-patch print to go to stderr
    # ═══════════════════════════════════════════════════════════════
    if host is None:
        import sys
        import builtins
        _real_stdout = sys.stdout
        _real_stderr = sys.stderr
        _original_print = builtins.print
        def _stderr_print(*args, **kwargs):
            kwargs['file'] = _real_stderr
            _original_print(*args, **kwargs)
        builtins.print = _stderr_print

    capsule_name = Path(__file__).stem

    # ═══════════════════════════════════════════════════════════════
    # PROXY MODE DETECTION - Route through TUI if it's running
    # ═══════════════════════════════════════════════════════════════
    capsule_dir = Path(__file__).parent
    state_file = capsule_dir / '.capsule_state.json'
    relay_center = capsule_dir / '.relay_center.cmd'
    tui_log = capsule_dir / 'tui.log'

    # Check if TUI is running (state file exists and is recent)
    # register_only mode always uses normal (non-proxy) path
    _proxy_mode = False
    if not register_only and state_file.exists() and shared_agent is None:
        try:
            import time
            state_mtime = state_file.stat().st_mtime
            # TUI is running if state was updated in last 60 seconds
            if time.time() - state_mtime < 60:
                _proxy_mode = True
        except Exception:
            pass

    # MCP log file for TUI display
    _mcp_log_path = Path(__file__).parent / '.mcp_server.log'

    def _mcp_log(msg: str):
        """Log MCP activity to file for TUI display."""
        import datetime
        ts = datetime.datetime.now().strftime('%H:%M:%S')
        try:
            with open(_mcp_log_path, 'a', encoding='utf-8') as f:
                f.write("[" + ts + "] " + msg + "\\n")
        except Exception:
            pass

    # Try to import Arcade TDK for optional integration
    try:
        from arcade_tdk import tool as arcade_tool
        _ARCADE_AVAILABLE = True
    except ImportError:
        arcade_tool = None
        _ARCADE_AVAILABLE = False

    # CASCADE observation for MCP tools
    global _CASCADE_MCP_AVAILABLE, _CASCADE_MCP_MONITOR, _MCP_TOOL_STEP, _RERUN_INITIALIZED
    try:
        from cascade_lattice import observe as cascade_observe, init as cascade_init
        from cascade_lattice.analysis import classify_metric
        _CASCADE_MCP_AVAILABLE = True
    except ImportError:
        _CASCADE_MCP_AVAILABLE = False
        cascade_observe = None

    # ═══════════════════════════════════════════════════════════════
    # AUTO-INIT RERUN ON MCP STARTUP (THE EYES)
    # Three modes:
    #   1. shared_agent set → TUI thread → rerun already initialized, skip
    #   2. host set → subprocess (mcp-remote) → init WITHOUT spawn,
    #      then connect_grpc to TUI's viewer (same recording, no new window)
    #   3. standalone stdio → spawn our own viewer
    # ═══════════════════════════════════════════════════════════════
    # RERUN: Do NOT init here. MCP runs as subprocess with separate memory.
    # Calling rr.init(spawn=True) creates a SECOND recording/viewer.
    # Instead, _observe_mcp_tool calls _ACTIVE_TUI._record_cascade directly
    # (same process), which handles Rerun, MerkleWidget, CausationGraph. Zero duplication.
    if not quiet:
        if _RERUN_INITIALIZED:
            print("[MCP] Rerun shared with TUI (same process)")
        else:
            print("[MCP] Rerun delegated to TUI process via cascade.store")

    def _get_cascade_monitor():
        \"\"\"Get or create CASCADE monitor for MCP observation.\"\"\"
        global _CASCADE_MCP_MONITOR
        if not _CASCADE_MCP_AVAILABLE:
            return None
        if _CASCADE_MCP_MONITOR is None:
            try:
                cascade_init()
                _CASCADE_MCP_MONITOR = cascade_observe()
            except Exception:
                pass
        return _CASCADE_MCP_MONITOR

    def _observe_mcp_tool(tool_name: str, args: dict, result: str, duration_ms: float):
        \"\"\"Observe MCP tool call - direct bridge to TUI via _ACTIVE_TUI._record_cascade.

        Since mcp remote runs in-process with the TUI, we skip SQLite entirely
        and call _record_cascade directly. One system, zero polling.
        \"\"\"
        global _MCP_TOOL_STEP
        _MCP_TOOL_STEP += 1

        # Parse result for metrics
        metrics = {{}}
        try:
            data = json.loads(result) if isinstance(result, str) else result
            if isinstance(data, dict):
                for k, v in data.items():
                    if isinstance(v, (int, float)):
                        metrics[k] = v
        except Exception:
            pass

        # Thread-safe bridge: post_message() is safe to call from any thread.
        # CascadeBridgeMessage is handled by CapsuleTUI.on_cascade_bridge_message
        # which runs on Textual's main event loop.
        tui = _ACTIVE_TUI
        if tui is not None:
            cascade_data = {{
                'event_type': tool_name,
                'tool': tool_name,
                'source': 'mcp',
                'duration_ms': duration_ms,
                'step': _MCP_TOOL_STEP,
                'result_size': len(result) if isinstance(result, str) else 0,
                **metrics
            }}
            # For workflow_execute, pass the full execution result to the TUI
            # so the Execution tab can render it live
            if tool_name == 'workflow_execute':
                try:
                    parsed = json.loads(result) if isinstance(result, str) else result
                    cascade_data['execution_result'] = parsed
                except Exception:
                    pass
            tui.post_message(CascadeBridgeMessage(tool_name, cascade_data))

            # ─── VAST ACTIVITY BRIDGE ───
            # MCP vast tools run in-process but bypass TUI handle_tool(),
            # so the VAST tab never sees activity. Bridge it here.
            if tool_name.startswith('vast_'):
                import time as _vt
                activity_entry = {{
                    'time': _vt.strftime('%H:%M:%S'),
                    'tool': tool_name,
                    'status': 'error' if 'error' in str(result) else 'ok',
                    'exec_time': duration_ms / 1000.0
                }}
                if not hasattr(tui, '_vast_activity_log'):
                    tui._vast_activity_log = []
                tui._vast_activity_log.append(activity_entry)
                if len(tui._vast_activity_log) > 20:
                    tui._vast_activity_log = tui._vast_activity_log[-20:]
                # Bridge instance data so VAST tab shows fleet view
                try:
                    parsed = json.loads(result) if isinstance(result, str) else result
                    if isinstance(parsed, dict) and 'error' not in parsed:
                        if tool_name == 'vast_instances':
                            # Sync instance list to TUI tracking dict
                            for inst in parsed.get('instances', []):
                                iid = str(inst.get('id', ''))
                                if iid and iid not in tui._vast_instances:
                                    tui._vast_instances[iid] = {{
                                        'id': iid,
                                        'gpu': inst.get('gpu', '?'),
                                        'status': inst.get('status', 'unknown'),
                                        'ssh_host': inst.get('ssh_host', ''),
                                        'ssh_port': inst.get('ssh_port', 0),
                                        'cost_per_hr': 0.0,
                                        'start_time': __import__('time').time(),
                                    }}
                        elif tool_name == 'vast_rent' and parsed.get('status') == 'rented':
                            rental = parsed.get('rental', {{}})
                            iid = str(rental.get('new_contract', ''))
                            if iid:
                                tui._vast_instances[iid] = {{
                                    'id': iid,
                                    'gpu': '?',
                                    'status': 'loading',
                                    'ssh_host': '',
                                    'ssh_port': 0,
                                    'cost_per_hr': 0.0,
                                    'start_time': __import__('time').time(),
                                }}
                        elif tool_name == 'vast_stop':
                            # Remove destroyed instance from tracking
                            destroyed_id = str(parsed.get('destroyed', ''))
                            tui._vast_instances.pop(destroyed_id, None)
                except Exception:
                    pass
                # Thread-safe refresh: call_from_thread schedules on Textual event loop
                try:
                    tui.call_from_thread(tui._update_vast_tab)
                except Exception:
                    pass

        return {{"step": _MCP_TOOL_STEP}}

    def logged_tool():
        """Decorator that wraps @mcp.tool() with automatic logging to TUI.

        Also wraps with Arcade's @tool if arcade_tdk is available,
        enabling distribution through Arcade marketplace.

        CACHING: Large responses (>2KB) are cached and a compact summary
        is returned to prevent IDE context overflow. Use get_cached(id)
        to retrieve full response when needed.

        CASCADE: Every tool call is observed through cascade-lattice for
        provenance tracking and Rerun visualization.
        """
        def decorator(func):
            import functools
            import inspect
            import time
            sig = inspect.signature(func)

            @functools.wraps(func)
            def wrapper(*args, **kwargs):
                global _MCP_CACHE_COUNTER
                start_time = time.perf_counter()
                try:
                    bound = sig.bind(*args, **kwargs)
                    bound.apply_defaults()
                    arg_summary = ", ".join(f"{{k}}={{str(v)[:50]}}" for k, v in bound.arguments.items())
                    args_dict = dict(bound.arguments)
                except Exception:
                    arg_summary = "..."
                    args_dict = {{}}
                _mcp_log(f"🔧 {{func.__name__}}({{arg_summary}})")
                try:
                    result = func(*args, **kwargs)

                    # Observe through CASCADE lattice
                    duration_ms = (time.perf_counter() - start_time) * 1000
                    cascade_event = _observe_mcp_tool(func.__name__, args_dict, result, duration_ms)
                    if cascade_event:
                        _mcp_log(f"  🔗 CASCADE event #{{cascade_event['step']}}")

                    # Reward capture for dreamer training
                    try:
                        _ragent = get_agent()
                        _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                        _rbrain = getattr(_router, '_brain', _router)
                        if _rbrain and hasattr(_rbrain, '_capture_reward'):
                            _rbrain._capture_reward(
                                source_key='tool_success',
                                event_id=str(_MCP_TOOL_STEP),
                                metadata={{'tool': func.__name__, 'status': 'success'}},
                            )
                    except Exception:
                        pass

                    # Cache large responses to prevent IDE context overflow
                    # SKIP caching for VAST tools and call() proxy - they need full raw responses
                    result_size = len(result) if isinstance(result, str) else len(str(result))
                    skip_tools = ('vast_', 'call')
                    should_cache = result_size > _MCP_RESPONSE_SIZE_THRESHOLD and not any(func.__name__.startswith(s) for s in skip_tools)
                    if should_cache:
                        _MCP_CACHE_COUNTER += 1
                        cache_id = f"r{{_MCP_CACHE_COUNTER}}"
                        _MCP_RESPONSE_CACHE[cache_id] = result
                        # Rolling window: keep last 50 cached responses
                        if len(_MCP_RESPONSE_CACHE) > 50:
                            oldest = min(_MCP_RESPONSE_CACHE.keys(), key=lambda k: int(k[1:]))
                            del _MCP_RESPONSE_CACHE[oldest]
                        # Generate hyper-informative spec sheet
                        spec = _summarize_response(result, func.__name__)
                        spec["_cached"] = cache_id
                        spec["_size"] = result_size
                        compact = json.dumps(spec)
                        _mcp_log(f"  📦 Cached ({{result_size}}b) as {{cache_id}}")
                        result = compact

                    _mcp_log(f"  ✅ {{func.__name__}} complete")
                    # Structured activity line for VS Code extension log poller
                    try:
                        _activity_json = json.dumps({{
                            "tool": func.__name__,
                            "args": {{k: (str(v)[:80] if len(str(v)) > 80 else v) for k, v in args_dict.items()}},
                            "result": (result[:200] + "...") if isinstance(result, str) and len(result) > 200 else result,
                            "duration_ms": round(duration_ms, 1),
                            "status": "ok"
                        }}, default=str)
                        _mcp_log(f"\U0001F4CA {{_activity_json}}")
                    except Exception:
                        pass
                    return result
                except Exception as e:
                    _mcp_log(f"  ❌ {{func.__name__}} failed: {{e}}")
                    # Structured error line for VS Code extension log poller
                    try:
                        _err_duration = (time.perf_counter() - start_time) * 1000
                        _err_json = json.dumps({{
                            "tool": func.__name__,
                            "args": {{k: (str(v)[:80] if len(str(v)) > 80 else v) for k, v in args_dict.items()}},
                            "error": str(e)[:300],
                            "duration_ms": round(_err_duration, 1),
                            "status": "error"
                        }}, default=str)
                        _mcp_log(f"\U0001F4CA {{_err_json}}")
                    except Exception:
                        pass
                    try:
                        _ragent = get_agent()
                        _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
                        _rbrain = getattr(_router, '_brain', _router)
                        if _rbrain and hasattr(_rbrain, '_capture_reward'):
                            _rbrain._capture_reward(
                                source_key='tool_error',
                                event_id=str(_MCP_TOOL_STEP),
                                metadata={{'tool': func.__name__, 'status': 'error', 'error': str(e)[:200]}},
                            )
                    except Exception:
                        pass
                    raise

            wrapper.__signature__ = sig
            wrapper.__annotations__ = getattr(func, '__annotations__', {{}})

            # Wrap with MCP tool
            wrapped = mcp.tool()(wrapper)

            # Also wrap with Arcade tool if available (for marketplace distribution)
            if _ARCADE_AVAILABLE and arcade_tool is not None:
                try:
                    wrapped = arcade_tool(wrapped)
                except Exception:
                    pass  # Arcade wrapping failed, MCP still works

            return wrapped
        return decorator

