    if _proxy_mode:
        # ═══════════════════════════════════════════════════════════
        # PROXY MODE - Inbox/Outbox pattern for zero-latency IPC
        # MCP writes to inbox, TUI reads inbox → writes outbox
        # Atomic writes via temp file + rename
        # ═══════════════════════════════════════════════════════════
        mcp = FastMCP(capsule_name + "-bus", instructions=_build_mcp_instructions(), host=host or '127.0.0.1', port=port)

        inbox = capsule_dir / '.mcp_inbox.json'
        outbox = capsule_dir / '.mcp_outbox.json'

        def _atomic_write(path: Path, data: dict):
            \"\"\"Atomic write: temp file → rename (prevents partial reads).\"\"\"
            import tempfile
            tmp = Path(tempfile.mktemp(dir=path.parent, suffix='.tmp'))
            tmp.write_text(json.dumps(data), encoding='utf-8')
            tmp.replace(path)  # Atomic on POSIX and Windows

        def _bus_call(tool_name: str, args: dict) -> str:
            \"\"\"Write request to inbox, poll outbox for response.\"\"\"
            import time as t
            import uuid

            req_id = str(uuid.uuid4())[:8]

            # Clear any stale outbox
            if outbox.exists():
                try:
                    outbox.unlink()
                except Exception:
                    pass

            # Atomic write to inbox
            _atomic_write(inbox, {{
                'id': req_id,
                'tool': tool_name,
                'args': args,
                'ts': t.time()
            }})

            # Fast poll for response (50ms intervals, 120s max)
            for _ in range(2400):
                t.sleep(0.05)  # 50ms
                if outbox.exists():
                    try:
                        resp = json.loads(outbox.read_text(encoding='utf-8'))
                        if resp.get('id') == req_id:
                            outbox.unlink()  # Consume response
                            return json.dumps(resp.get('result', {{}}), indent=2, default=str)
                    except Exception:
                        pass

            return json.dumps({{'error': 'timeout', 'request_id': req_id}})

