        # ── FelixBag auto-persistence (proxy mode) ──
        _bag_state_path = Path(__file__).parent / '.bag_state.json'
        if _bag_state_path.exists():
            try:
                _bag_data = json.loads(_bag_state_path.read_text(encoding='utf-8'))
                for _bk, _bv in _bag_data.items():
                    if _bk not in _BAG._bag:
                        _BAG._bag[_bk] = _bv
            except Exception:
                pass

        import atexit as _atexit_mod
        def _auto_save_bag():
            try:
                _p = Path(__file__).parent / '.bag_state.json'
                _p.write_text(json.dumps(_BAG._bag, indent=2, default=str), encoding='utf-8')
            except Exception:
                pass
        _atexit_mod.register(_auto_save_bag)

        import threading as _thr_mod
        def _bag_autosave_loop():
            import time as _t
            while True:
                _t.sleep(300)
                _auto_save_bag()
        _thr_mod.Thread(target=_bag_autosave_loop, daemon=True).start()

        if host:
            # HTTP/SSE transport
            mcp.run(transport="sse")
        else:
            # STDIO transport for Claude Desktop
            mcp.run(transport="stdio")
        return

