    def _env_bag_names(filter_type: str = None) -> list:
        \"\"\"Return FelixBag item names, preferring catalog() over list() IDs.\"\"\"
        names = []
        seen = set()
        try:
            rows = _BAG.catalog(filter_type=filter_type) if filter_type else _BAG.catalog()
        except Exception:
            rows = []
        for row in rows or []:
            name = None
            if isinstance(row, (list, tuple)):
                if len(row) >= 2:
                    name = row[1]
                elif len(row) == 1:
                    name = row[0]
            elif isinstance(row, dict):
                name = row.get('name') or row.get('key') or row.get('id')
            else:
                name = row
            if name is None:
                continue
            text = str(name)
            if text and text not in seen:
                names.append(text)
                seen.add(text)
        if names:
            return names
        try:
            fallback = _BAG.list()
        except Exception:
            fallback = []
        for item in fallback or []:
            if item is None:
                continue
            text = str(item)
            if text and text not in seen:
                names.append(text)
                seen.add(text)
        return names

    def _env_prefixed_names(prefix: str, filter_type: str = None) -> list:
        return [name for name in _env_bag_names(filter_type=filter_type) if str(name).startswith(prefix)]

    def _env_json_value(value, default=None):
        if value is None:
            return default
        if isinstance(value, (dict, list)):
            return value
        try:
            return json.loads(value)
        except Exception:
            return default

    def _env_bag_json(key: str, default=None):
        try:
            raw = _BAG.get(key)
        except Exception:
            raw = None
        if raw is None:
            return default
        parsed = _env_json_value(raw, None)
        return parsed if parsed is not None else raw

    def _env_scene_items() -> dict:
        scene = {{}}
        for key in _env_prefixed_names('env_scene:', 'scene_object'):
            obj = _env_bag_json(key, None)
            if obj is None:
                continue
            scene[str(key)] = obj
        return scene

    def _env_snapshot_names() -> list:
        return _env_prefixed_names('env_snapshot:', 'scene_snapshot')

    def _env_snapshot_records(include_empty: bool = True) -> list:
        records = []
        for key in _env_snapshot_names():
            snap = _env_bag_json(key, None)
            if not isinstance(snap, dict):
                continue
            objects = snap.get('objects') if isinstance(snap.get('objects'), dict) else {{}}
            count = int(snap.get('count') or len(objects))
            live_excerpt = snap.get('live_excerpt') if isinstance(snap.get('live_excerpt'), dict) else {{}}
            record = {{
                "key": str(key),
                "name": str(snap.get('name') or key),
                "timestamp": snap.get('timestamp'),
                "count": count,
                "empty": count <= 0,
                "has_live_excerpt": bool(live_excerpt),
            }}
            if include_empty or not record["empty"]:
                records.append(record)
        return sorted(records, key=lambda item: float(item.get('timestamp') or 0), reverse=True)

    def _env_live_state():
        live = _env_bag_json('env_live_state:latest', None)
        return live if isinstance(live, dict) else None

    def _env_update_live_bootstrap_hint(preserve_empty=None, snapshot_name=None, hydrated_ts=None, pending=None, object_count=None):
        live = _env_live_state()
        if not isinstance(live, dict):
            live = {{}}
        shared = live.get('shared_state')
        if not isinstance(shared, dict):
            shared = {{}}
            live['shared_state'] = shared
        scene = shared.get('scene')
        if not isinstance(scene, dict):
            scene = {{}}
            shared['scene'] = scene
        bootstrap = scene.get('bootstrap')
        if not isinstance(bootstrap, dict):
            bootstrap = {{}}
            scene['bootstrap'] = bootstrap
        if preserve_empty is not None:
            bootstrap['preserve_empty'] = bool(preserve_empty)
        if snapshot_name is not None:
            resolved_snapshot = str(snapshot_name or '')
            bootstrap['snapshot_name'] = resolved_snapshot
            scene['current_snapshot'] = resolved_snapshot
        if hydrated_ts is not None:
            try:
                bootstrap['hydrated_ts'] = int(hydrated_ts)
            except Exception:
                pass
        if pending is not None:
            bootstrap['pending'] = bool(pending)
        if object_count is not None:
            try:
                scene['object_count'] = max(0, int(object_count))
            except Exception:
                pass
        _BAG.induct('env_live_state:latest', json.dumps(live, default=str), item_type='scene_live')
        return live

    def _env_live_ids(live_state=None) -> dict:
        live = live_state if isinstance(live_state, dict) else _env_live_state()
        ids = {{}}
        if not isinstance(live, dict):
            return ids
        shared = live.get('shared_state') if isinstance(live.get('shared_state'), dict) else {{}}
        scene = shared.get('scene') if isinstance(shared.get('scene'), dict) else {{}}
        focus = shared.get('focus') if isinstance(shared.get('focus'), dict) else {{}}
        current_exec = live.get('current_execution') if isinstance(live.get('current_execution'), dict) else {{}}
        selected = live.get('selected_workflow') if isinstance(live.get('selected_workflow'), dict) else {{}}
        workflow_id = current_exec.get('workflow_id') or scene.get('workflow_id') or selected.get('id')
        execution_id = current_exec.get('execution_id') or scene.get('execution_id')
        if workflow_id:
            ids['workflow_id'] = str(workflow_id)
        if execution_id:
            ids['execution_id'] = str(execution_id)
        if focus.get('kind'):
            ids['focus_kind'] = str(focus.get('kind'))
        if focus.get('id'):
            ids['focus_id'] = str(focus.get('id'))
        return ids

    def _env_apply_live_hint(excerpt: dict, live_hint=None) -> dict:
        if not isinstance(excerpt, dict) or not isinstance(live_hint, dict):
            return excerpt
        live = excerpt.get('live')
        if not isinstance(live, dict):
            live = {{}}
            excerpt['live'] = live
        if live_hint.get('available') is not None:
            live['available'] = bool(live_hint.get('available'))
        for key in ('workflow_id', 'execution_id', 'synced_at'):
            if live_hint.get(key) is not None:
                live[key] = live_hint.get(key)
        for section in ('focus', 'scene', 'docs', 'health'):
            hint_section = live_hint.get(section)
            if not isinstance(hint_section, dict):
                continue
            current_section = live.get(section)
            if not isinstance(current_section, dict):
                current_section = {{}}
                live[section] = current_section
            for key, value in hint_section.items():
                if value is not None:
                    current_section[key] = value
        return excerpt

    def _env_state_excerpt(scene_items=None, live_state=None, live_hint=None) -> dict:
        scene_map = scene_items if isinstance(scene_items, dict) else _env_scene_items()
        live = live_state if isinstance(live_state, dict) else _env_live_state()
        snapshot_records = _env_snapshot_records(include_empty=True)
        kinds = sorted(set(
            str((obj or {{}}).get('kind') or '')
            for obj in scene_map.values()
            if isinstance(obj, dict) and (obj or {{}}).get('kind')
        ))
        excerpt = {{
            "persisted": {{
                "object_count": len(scene_map),
                "kinds": kinds[:16],
                "snapshot_count": len(snapshot_records),
                "nonempty_snapshot_count": len([item for item in snapshot_records if not item.get('empty')]),
                "empty_snapshot_count": len([item for item in snapshot_records if item.get('empty')]),
            }},
            "live": {{"available": bool(live)}},
        }}
        if isinstance(live, dict):
            shared = live.get('shared_state') if isinstance(live.get('shared_state'), dict) else {{}}
            scene = shared.get('scene') if isinstance(shared.get('scene'), dict) else {{}}
            bootstrap = scene.get('bootstrap') if isinstance(scene.get('bootstrap'), dict) else {{}}
            focus = shared.get('focus') if isinstance(shared.get('focus'), dict) else {{}}
            docs = shared.get('docs') if isinstance(shared.get('docs'), dict) else {{}}
            health = shared.get('health') if isinstance(shared.get('health'), dict) else {{}}
            current_exec = live.get('current_execution') if isinstance(live.get('current_execution'), dict) else {{}}
            selected = live.get('selected_workflow') if isinstance(live.get('selected_workflow'), dict) else {{}}
            habitat_objects = live.get('habitat_objects') if isinstance(live.get('habitat_objects'), list) else []
            excerpt['live'] = {{
                "available": True,
                "synced_at": live.get('synced_at'),
                "workflow_id": current_exec.get('workflow_id') or scene.get('workflow_id') or selected.get('id') or '',
                "execution_id": current_exec.get('execution_id') or scene.get('execution_id') or '',
                "focus": {{
                    "kind": str(focus.get('kind') or ''),
                    "id": str(focus.get('id') or ''),
                }},
                "scene": {{
                    "object_count": int(scene.get('object_count') or 0),
                    "route_count": int(scene.get('route_count') or 0),
                    "trajectory_count": int(scene.get('trajectory_count') or 0),
                    "camera_mode": str(scene.get('cameraMode') or ''),
                    "habitat_object_count": len(habitat_objects),
                }},
                "bootstrap": {{
                    "pending": bool(bootstrap.get('pending')),
                    "snapshot_name": str(bootstrap.get('snapshot_name') or ''),
                    "preserve_empty": bool(bootstrap.get('preserve_empty')),
                    "hydrated_ts": int(bootstrap.get('hydrated_ts') or 0),
                }},
                "docs": {{
                    "result_count": int(docs.get('result_count') or 0),
                    "active_doc": str(docs.get('active_doc') or ''),
                }},
                "health": {{
                    "tone": str(health.get('tone') or ''),
                    "summary": str(health.get('summary') or ''),
                }},
            }}
        return _env_apply_live_hint(excerpt, live_hint)

    def _env_response(status: str, summary: str, normalized_args=None, delta=None, environment_effects=None, state_excerpt=None, extra=None, error: str = "") -> str:
        payload = {{
