    @logged_tool()
    def forward(text: str = "", embedding: list = None) -> str:
        \"\"\"Run inference through the quine brain.

        Args:
            text: Text input for multi-modal brains
            embedding: Optional pre-computed embedding (384-dim)

        Returns:
            JSON with inference result summary (truncated for readability)
        \"\"\"
        agent = get_agent()
        brain_type = _BRAIN_CONFIG.get('brain_type', 'unknown')

        if brain_type == 'ouroboros':
            obs = {{'text': text or 'Hello', 'input': np.array(embedding) if embedding else np.random.rand(384).astype(np.float32)}}
        else:
            obs = {{'text': text, 'input': np.random.rand(384).astype(np.float32)}}

        try:
            result = agent.forward(obs)
        except Exception as e:
            import traceback
            return json.dumps({{"error": str(e), "traceback": traceback.format_exc()[:500]}})

        # Create a SUMMARY instead of dumping everything
        def summarize_value(v, max_len=10):
            if hasattr(v, 'tolist'):
                arr = v.tolist() if hasattr(v, 'tolist') else list(v)
                if len(arr) > max_len:
                    return {{"type": "array", "shape": list(getattr(v, 'shape', [len(arr)])), "sample": arr[:5], "truncated": True}}
                return arr
            elif isinstance(v, dict):
                return {{kk: summarize_value(vv, max_len) for kk, vv in list(v.items())[:10]}}
            elif isinstance(v, (list, tuple)) and len(v) > max_len:
                return {{"type": "list", "length": len(v), "sample": [summarize_value(x) for x in v[:3]], "truncated": True}}
            else:
                return v

        summary = {{k: summarize_value(v) for k, v in list(result.items())[:15]}}
        summary['_note'] = 'Output summarized. Use specific tools (embed_text, deliberate) for detailed results.'
        return json.dumps(summary, indent=2, default=str)

    @logged_tool()
    def deliberate(question: str, context: str = "") -> str:
        \"\"\"Use slow-thinking deliberation for complex reasoning.

        Args:
            question: The question to deliberate on
            context: Optional context to consider

        Returns:
            JSON with deliberation result and reasoning trace
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain

        # Serialize numpy arrays helper
        def serialize(v):
            if hasattr(v, 'tolist'):
                return v.tolist()
            elif isinstance(v, dict):
                return {{k: serialize(vv) for k, vv in v.items()}}
            elif isinstance(v, list):
                return [serialize(x) for x in v]
            return v

        def format_deliberation(raw):
            data = serialize(raw)
            if not isinstance(data, dict):
                return {{
                    "result": str(data),
                    "reasoning_trace": [],
                    "metrics": {{
                        "consensus_method": "unknown",
                        "councilor_votes": 0,
                        "plugged_councilors": 0,
                        "consensus_vector_dim": 0
                    }}
                }}

            deliberation = data.get('deliberation', {{}})
            reasoning_trace = []
            if isinstance(deliberation, dict):
                for name, vote in deliberation.items():
                    if not isinstance(vote, dict):
                        reasoning_trace.append({{
                            "councilor": str(name),
                            "confidence": 0.0,
                            "plugged": False
                        }})
                        continue
                    conf_val = vote.get('confidence', 0.0)
                    try:
                        conf = float(conf_val)
                    except Exception:
                        conf = 0.0
                    reasoning_trace.append({{
                        "councilor": str(name),
                        "confidence": conf,
                        "plugged": bool(vote.get('plugged', False))
                    }})

            reasoning_trace.sort(key=lambda x: x.get('confidence', 0.0), reverse=True)

            votes = data.get('councilor_votes', len(reasoning_trace))
            try:
                votes = int(votes)
            except Exception:
                votes = len(reasoning_trace)

            derived_plugged = sum(1 for r in reasoning_trace if r.get('plugged'))
            if reasoning_trace:
                plugged = derived_plugged
            else:
                plugged = data.get('plugged_councilors', derived_plugged)
            try:
                plugged = int(plugged)
            except Exception:
                plugged = derived_plugged

            consensus_vec = data.get('consensus_output', [])
            vec_dim = len(consensus_vec) if isinstance(consensus_vec, list) else 0
            method = str(data.get('consensus_method', 'unknown'))

            if reasoning_trace:
                top = reasoning_trace[0]
                result_text = (
                    "Deliberation complete. Method=%s; plugged=%d; voters=%d; "
                    "lead=%s (confidence=%.2f)." % (
                        method,
                        plugged,
                        votes,
                        top.get('councilor', 'unknown'),
                        float(top.get('confidence', 0.0))
                    )
                )
            else:
                result_text = "Deliberation complete. Method=%s; plugged=%d; voters=%d." % (
                    method, plugged, votes
                )

            return {{
                "result": result_text,
                "reasoning_trace": reasoning_trace,
                "metrics": {{
                    "consensus_method": method,
                    "councilor_votes": votes,
                    "plugged_councilors": plugged,
                    "consensus_vector_dim": vec_dim
                }}
            }}

        # Check for deliberate method on inner brain
        if hasattr(brain, 'deliberate'):
            try:
                result = brain.deliberate(question, context=context)
                return json.dumps(format_deliberation(result), indent=2, default=str)
            except Exception as e:
                return json.dumps({{"error": f"Deliberation failed: {{e}}", "brain_type": type(brain).__name__}})
        # Fallback: use _council_deliberate if available
        elif hasattr(brain, '_council_deliberate'):
            try:
                # First create an embedding for the question
                embedding = None
                if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
                    embedding = brain.embedding_foundation.encode(f"{{question}} {{context}}", convert_to_numpy=True)
                elif hasattr(brain, 'embed'):
                    embedding = brain.embed(f"{{question}} {{context}}")
                else:
                    # Use deterministic zero embedding instead of random (avoids NaN propagation)
                    embedding = np.zeros(384, dtype=np.float32)

                # Validate embedding - sanitize any NaN/Inf
                embedding = np.asarray(embedding, dtype=np.float32).flatten()
                if len(embedding) < 384:
                    embedding = np.pad(embedding, (0, 384 - len(embedding)))
                embedding = embedding[:384]
                embedding = np.nan_to_num(embedding, nan=0.0, posinf=0.0, neginf=0.0)

                # Build the adapted dict that _council_deliberate expects
                adapted = {{
                    'text': question,
                    'context': context,
                    'adapted_output': embedding,
                    'adapter_applied': True
                }}
                result = brain._council_deliberate(adapted)
                return json.dumps(format_deliberation(result), indent=2, default=str)
            except Exception as e:
                return json.dumps({{"error": f"Deliberation failed: {{e}}", "details": "council_deliberate exception"}})
        else:
            return json.dumps({{"error": "Brain does not support deliberation", "brain_type": type(brain).__name__}})

    @logged_tool()
    def imagine(scenario: str, steps: int = 5) -> str:
        \"\"\"Use imagination/world model to simulate future states.

        Args:
            scenario: Starting scenario description
            steps: Number of imagination steps

        Returns:
            JSON with imagined trajectory
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain

        if hasattr(brain, 'imagine'):
            # First, convert scenario text to embedding if needed
            obs = None

            # Try to get embedding from brain
            if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
                try:
                    obs = brain.embedding_foundation.encode(scenario, convert_to_numpy=True)
                except Exception:
                    pass
            elif hasattr(brain, 'embed'):
                try:
                    obs = brain.embed(scenario)
                except Exception:
                    pass
            elif hasattr(brain, '_embed_inputs'):
                try:
                    obs = brain._embed_inputs({{'text': scenario}})
                except Exception:
                    pass

            # If no embedding available, use zeros as placeholder
            if obs is None:
                import numpy as np
                obs = np.zeros(384, dtype=np.float32)

            # Detect signature to call correctly
            import inspect
            sig = inspect.signature(brain.imagine)
            params = list(sig.parameters.keys())
            first_param = params[0] if params else None

            try:
                # Check if first param expects obs/start_state or horizon
                if first_param in ('obs', 'start_state', 'observation'):
                    # Signature: imagine(obs, steps/horizon)
                    if 'horizon' in sig.parameters:
                        result = brain.imagine(obs, horizon=steps)
                    elif 'steps' in sig.parameters:
                        result = brain.imagine(obs, steps=steps)
                    else:
                        result = brain.imagine(obs)
                elif first_param == 'horizon' or first_param == 'steps':
                    # Signature: imagine(horizon, ...) - no obs param
                    result = brain.imagine(horizon=steps)
                elif 'horizon' in sig.parameters:
                    # Has horizon as keyword param
                    result = brain.imagine(horizon=steps)
                elif 'steps' in sig.parameters:
                    result = brain.imagine(steps=steps)
                else:
                    # Fallback - try with obs
                    result = brain.imagine(obs)
            except Exception as e:
                err_text = str(e)
                if 'No RSSM available' in err_text or 'Real RSSM unavailable' in err_text:
                    dreamer_model = getattr(brain, 'dreamer_world_model', None)
                    has_real_rssm = bool(
                        dreamer_model is not None and
                        getattr(dreamer_model, '_has_real_rssm', False) and
                        getattr(dreamer_model, '_rssm', None) is not None
                    )
                    return json.dumps({{
                        "error": "Real RSSM unavailable - imagination cannot run",
                        "scenario": scenario,
                        "brain_type": type(brain).__name__,
                        "has_real_rssm": has_real_rssm,
                        "rssm_import_error": globals().get('_RSSM_IMPORT_ERROR'),
                        "rssm_init_error": getattr(dreamer_model, '_rssm_init_error', None) if dreamer_model is not None else None,
                        "required_dependencies": ["jax", "jaxlib", "ninjax", "embodied", "elements", "einops", "optax", "portal", "chex", "cloudpickle"],
                    }}, indent=2, default=str)
                return json.dumps({{"error": f"Imagination failed: {{e}}", "scenario": scenario, "brain_type": type(brain).__name__}})

            # Build summary instead of raw arrays (prevents 614KB context bomb)
            import numpy as np
            summary = []
            flat_result = result if isinstance(result, list) else [result]
            # Handle nested list (branching trajectories)
            all_steps = []
            for item in flat_result:
                if isinstance(item, list):
                    all_steps.extend(item)
                elif isinstance(item, dict):
                    all_steps.append(item)

            for t in all_steps:
                if isinstance(t, dict):
                    stoch_arr = t.get('stoch', None)
                    stoch_std = 0.0
                    if stoch_arr is not None:
                        stoch_std = float(np.std(np.asarray(stoch_arr)))
                    step_data = {{
                        'step': t.get('step', len(summary)),
                        'action': t.get('action', 0),
                        'latent_norm': round(float(t.get('latent_norm', 0)), 4),
                        'stoch_std': round(stoch_std, 4),
                        'real_rssm': t.get('real_rssm', False),
                    }}
                    # Enrich with critic + reward predictions
                    if hasattr(brain, '_critic') or hasattr(brain, '_reward_head'):
                        try:
                            lat = np.concatenate([
                                np.array(t.get('deter', np.zeros(4096))).flatten(),
                                np.array(t.get('stoch', np.zeros(1024))).flatten(),
                            ])[:5120]
                            if hasattr(brain, '_critic'):
                                step_data['critic_value'] = round(brain._critic.forward(lat), 4)
                            if hasattr(brain, '_reward_head'):
                                step_data['pred_reward'] = round(brain._reward_head.forward(lat), 4)
                        except Exception:
                            pass
                    summary.append(step_data)

            # Aggregate norm trend
            norms = [s['latent_norm'] for s in summary] if summary else [0.0]
            norm_trend = {{
                'start': norms[0],
                'end': norms[-1],
                'mean': round(sum(norms) / len(norms), 4),
            }}

            n_branches = len(flat_result) if all(isinstance(item, list) for item in flat_result) else 1
            return json.dumps({{
                'tool': 'imagine',
                'scenario': scenario,
                'steps': len(summary),
                'branches': n_branches,
                'trajectory_summary': summary,
                'norm_trend': norm_trend,
                'real_rssm': True,
            }}, indent=2, default=str)
        else:
            return json.dumps({{"error": "Brain does not support imagination", "brain_type": type(brain).__name__}})

    @logged_tool()
    def embed_text(text: str) -> str:
        \"\"\"Generate embedding for text input.

        Args:
            text: Text to embed

        Returns:
            JSON with embedding vector
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain

        # Check multiple possible embedding sources
        embed_fn = None
        if hasattr(brain, 'embedding_foundation') and brain.embedding_foundation is not None:
            # Ouroboros brain with SentenceTransformer (check first - most common)
            embed_fn = lambda t: brain.embedding_foundation.encode(t, convert_to_numpy=True)
        elif hasattr(brain, 'embed'):
            embed_fn = brain.embed
        elif hasattr(brain, 'get_embedding'):
            embed_fn = brain.get_embedding
        elif hasattr(brain, '_embed_inputs'):
            # Ouroboros internal embedding
            embed_fn = lambda t: brain._embed_inputs({{'text': t}})

        if embed_fn:
            try:
                result = embed_fn(text)
                if hasattr(result, 'tolist'):
                    result = result.tolist()
                return json.dumps({{"embedding": result, "dim": len(result) if isinstance(result, list) else 0}})
            except Exception as e:
                return json.dumps({{"error": f"Embedding failed: {{e}}"}})
        else:
            return json.dumps({{"error": "Brain does not support embedding", "brain_type": type(brain).__name__}})

