    @logged_tool()
    def bag_put(key: str, value: str) -> str:
        \"\"\"Store item in FelixBag memory.

        Args:
            key: Key to store under
            value: Value to store (string)

        Returns:
            Confirmation JSON
        \"\"\"
        _target_type = 'text'
        # Auto-checkpoint existing document before overwrite (best-effort)
        try:
            _eid, _eitem = _bag_find_item(key)
            if _eitem and not _bag_is_checkpoint_name(str(_eitem.get('name', ''))):
                _bag_create_checkpoint(key, message="auto-checkpoint before bag_put overwrite", tag="auto")
                _etype = str(_eitem.get('type', '') or '')
                if _etype in ('document', 'code', 'artifact', 'state', 'text'):
                    _target_type = _etype
        except Exception:
            pass

        # FelixBag uses 'induct' not 'put'
        if hasattr(_BAG, 'induct'):
            _BAG.induct(key, value, item_type=_target_type)
        elif hasattr(_BAG, 'put'):
            _BAG.put(key, value)
        else:
            # Fallback: direct dict access
            _BAG._bag[key] = value
        return json.dumps({{"status": "ok", "key": key}})

    @logged_tool()
    def list_slots() -> str:
        \"\"\"List available council slots for model plugging.

        Returns:
            JSON with slot status
        \"\"\"
        agent = get_agent()
        # Navigate to innermost brain: CapsuleAgent.brain._brain (QuineOuroborosBrain)
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain wrapper

        # Check councilors - handle both empty and non-empty lists
        if hasattr(brain, 'councilors'):
            councilors = brain.councilors
            slots = []
            for i, c in enumerate(councilors):
                model = None
                model_type = None
                model_hint = None
                is_remote = False
                # Handle both QuineSlot objects and dict-style councilors
                if hasattr(c, 'model'):
                    model = c.model
                    has = model is not None
                    name = getattr(c, 'name', f'slot_{{i}}')
                    model_source = getattr(c, '_model_source', None)
                    model_type = getattr(c, '_model_type', None)
                    if hasattr(model_type, 'value'):
                        model_type = model_type.value
                    elif model_type is not None:
                        model_type = str(model_type)
                    model_hint = getattr(model, '_model_type_hint', None) if model is not None else None
                    is_remote = bool(getattr(model, '_is_remote_provider', False)) if model is not None else False
                elif isinstance(c, dict):
                    has = c.get('model') is not None
                    name = c.get('name', f'slot_{{i}}')
                    model_source = c.get('model_source')
                    model_type = c.get('model_type')
                    model_hint = c.get('model_type_hint')
                else:
                    has = False
                    name = f'slot_{{i}}'
                    model_source = None
                slots.append({{
                    "index": i,
                    "name": name,
                    "plugged": has,
                    "model_source": model_source,
                    "model_type": model_type,
                    "model_type_hint": model_hint,
                    "is_remote_provider": is_remote,
                    "supports_transcribe": bool(
                        has and model is not None and hasattr(model, 'transcribe') and (
                            not bool(getattr(model, '_is_remote_provider', False))
                            or str(getattr(model, '_model_type_hint', '') or '').upper() == 'ASR'
                        )
                    ),
                    "supports_synthesize": bool(
                        has and model is not None and hasattr(model, 'synthesize') and (
                            not bool(getattr(model, '_is_remote_provider', False))
                            or str(getattr(model, '_model_type_hint', '') or '').upper() == 'TTS'
                        )
                    ),
                    "supports_generate": bool(has and model is not None and hasattr(model, 'generate')),
                    "supports_encode": bool(has and model is not None and hasattr(model, 'encode'))
                }})
            return json.dumps({{"slots": slots, "total": len(slots), "brain_type": type(brain).__name__}}, indent=2)
        return json.dumps({{"error": "Brain has no council slots", "brain_type": type(brain).__name__}})

    @logged_tool()
    def plug_model(model_id: str, slot_name: str = None) -> str:
        \"\"\"Plug an external model into a council slot.

        Args:
            model_id: HuggingFace model ID or path
            slot_name: Optional slot name (uses model name if not provided)

        Returns:
            JSON with plug result
        \"\"\"
        global _PLUG_MODEL_BUSY, _PLUG_MODEL_CURRENT

        # Thread-safe check-and-set to prevent queue buildup
        with _PLUG_MODEL_LOCK:
            if _PLUG_MODEL_BUSY:
                return json.dumps({{"error": "busy", "currently_plugging": _PLUG_MODEL_CURRENT, "hint": "Wait for current plug to complete"}})
            _PLUG_MODEL_BUSY = True
            _PLUG_MODEL_CURRENT = model_id

        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        if not model_id:
            with _PLUG_MODEL_LOCK:
                _PLUG_MODEL_BUSY = False
                _PLUG_MODEL_CURRENT = None
            return json.dumps({{"error": "no model_id provided"}})

        try:
            model, mtype, error = _load_model_smart(model_id, verbose=True)
            if error:
                return json.dumps({{"error": error}})
        finally:
            # Always release lock
            with _PLUG_MODEL_LOCK:
                _PLUG_MODEL_BUSY = False
                _PLUG_MODEL_CURRENT = None

        if not hasattr(brain, 'councilors'):
            return json.dumps({{"error": "Brain has no council slots", "brain_type": type(brain).__name__}})

        _stored_type = getattr(model, '_model_type_hint', None)
        if not _stored_type:
            try:
                _runtime_type = _detect_model_type_runtime(model)
                _stored_type = _runtime_type.value if hasattr(_runtime_type, 'value') else str(_runtime_type)
            except Exception:
                _stored_type = mtype
        _stored_type = str(_stored_type)

        plugged = False
        for i, c in enumerate(brain.councilors):
            if getattr(c, 'model', None) is None:
                c.model = model
                c.tokenizer = getattr(model, 'tokenizer', None)
                c.processor = getattr(model, 'processor', None)
                c._model_source = model_id
                c._model_type = _stored_type
                c._model_type_hint = getattr(model, '_model_type_hint', None)
                c._limits = getattr(model, '_limits', _read_model_limits(model, getattr(model, 'tokenizer', None)))
                c.name = slot_name or model_id.split('/')[-1]
                plugged = True
                return json.dumps({{"status": "ok", "slot": i, "model": model_id, "type": _stored_type, "limits": c._limits}})

        if not plugged:
            return json.dumps({{"error": "no empty slots"}})

    @logged_tool()
    def spawn_swarm(count: int = 3) -> str:
        \"\"\"Spawn a swarm of child agents.

        Args:
