        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)  # Unwrap CapsuleBrain

        if hasattr(brain, 'spawn_swarm'):
