            agent._swarm = swarm
            return json.dumps({{"spawned": len(swarm), "ids": [s.id if hasattr(s, 'id') else str(i) for i, s in enumerate(swarm)]}})
        # Fallback: use replicate to create clones
        elif hasattr(brain, 'replicate'):
            swarm = [brain.replicate() for _ in range(count)]
            agent._swarm = swarm
            return json.dumps({{"spawned": count, "ids": [f"clone_{{i}}" for i in range(count)], "method": "replicate"}})
        return json.dumps({{"error": "Brain does not support swarm spawning", "brain_type": type(brain).__name__}})

