            _rerun_initialized = True
            return json.dumps({{"status": "ok", "recording": "shared_with_tui", "message": "Rerun already active (shared with TUI)"}})

        try:
            import rerun as rr
            import rerun.blueprint as rrb
            name = recording_name or f"{{Path(__file__).stem}}_session"
            rr.init(name, spawn=True)

            # Apply the canonical Glass Box blueprint
