            rr.log("capsule/state", rr.TextDocument(f"Generation: {{gen}}\\nFitness: {{fit:.4f}}\\nBrain: {{_BRAIN_CONFIG.get('brain_type', 'unknown')}}"))

            _rerun_initialized = True
