    @logged_tool()
    def log_to_rerun(entity_path: str, data_type: str, value: str) -> str:
        \"\"\"Log data to Rerun viewer for visualization.

        Args:
            entity_path: Path in rerun hierarchy (e.g., 'brain/inference/step_1')
            data_type: Type of data - 'scalar', 'text', 'tensor', 'point3d', 'log'
            value: The value to log (JSON string for complex types)

        Returns:
            Confirmation JSON
        \"\"\"
        if not _HAS_RERUN:
            return json.dumps({{"error": "Rerun not installed"}})

        try:
            import rerun as rr
            if data_type == 'scalar':
                rr.log(entity_path, rr.Scalars([float(value)]))
            elif data_type == 'text':
                rr.log(entity_path, rr.TextDocument(value))
            elif data_type == 'log':
                rr.log(entity_path, rr.TextLog(value, level=rr.TextLogLevel.INFO))
            elif data_type == 'tensor':
                arr = np.array(json.loads(value))
                rr.log(entity_path, rr.Tensor(arr))
            elif data_type == 'point3d':
                points = np.array(json.loads(value))
                rr.log(entity_path, rr.Points3D(points))
            elif data_type == 'bar':
                vals = json.loads(value) if isinstance(value, str) else value
                rr.log(entity_path, rr.BarChart(vals))
            else:
                rr.log(entity_path, rr.TextDocument(str(value)))
            return json.dumps({{"status": "ok", "path": entity_path}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def rerun_log_inference(text: str = "", step: int = None) -> str:
        \"\"\"Run inference and log full pipeline to Rerun for debugging.

        Args:
            text: Optional text input
            step: Optional step number (auto-increments if not provided)

        Returns:
            JSON with inference result and Rerun log status
        \"\"\"
        nonlocal _rerun_inference_step
        if not _HAS_RERUN or not _rerun_initialized:
            return json.dumps({{"error": "Rerun not initialized. Call start_rerun_viewer first."}})

        try:
            import rerun as rr

            # Auto-increment step
            if step is None:
                _rerun_inference_step += 1
                step = _rerun_inference_step

            rr.set_time("inference", sequence=step)

            agent = get_agent()
            brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)

            # Log input
            rr.log("logs", rr.TextLog(f"📥 Inference #{{step}}: '{{text[:50]}}...'", level=rr.TextLogLevel.DEBUG))

            # Create observation
            obs = {{'text': text or 'test', 'input': np.random.rand(384).astype(np.float32)}}

            # Run forward
            result = agent.forward(obs)

            # Log embedding if available
            if 'embedding' in result:
                emb = result['embedding']
                if hasattr(emb, 'tolist'):
                    emb = emb.tolist()
                rr.log("inference/embedding", rr.Tensor(np.array(emb[:64])))  # First 64 dims
                rr.log("metrics/embedding_norm", rr.Scalars([float(np.linalg.norm(emb))]))

            # Log action if available
            if 'action' in result:
                act = result['action']
                if hasattr(act, 'tolist'):
                    act = act.tolist()
                if isinstance(act, list):
                    rr.log("inference/action", rr.BarChart(act))

            # Log confidence
            if 'confidence' in result:
                rr.log("metrics/confidence", rr.Scalars([float(result['confidence'])]))

            rr.log("logs", rr.TextLog(f"✅ Inference #{{step}} complete", level=rr.TextLogLevel.INFO))

            # Serialize for return (recursive to handle nested numpy arrays)
            serialized = _sanitize_for_hash(result)

            return json.dumps({{"step": step, "logged": True, "result": serialized}}, indent=2)
        except Exception as e:
            import traceback
            return json.dumps({{"error": str(e), "traceback": traceback.format_exc()}})

