    @logged_tool()
    def vast_search(query: str = "rentable=true", page: int = 1, page_size: int = 20) -> str:
        \"\"\"Search Vast.ai for GPU rental offers.

        Args:
            query: Search query (e.g., 'gpu_ram>=48', 'rentable=true')
            page: Page number
            page_size: Results per page

        Returns:
            JSON with GPU offers
        \"\"\"
        import subprocess
        try:
            result = subprocess.run(['vastai', 'search', 'offers', query, '--raw'], 
                                   capture_output=True, text=True, timeout=60)
            if result.returncode != 0:
                return json.dumps({{"error": result.stderr or "Command failed"}})
            offers = json.loads(result.stdout)
            # Cache ALL results so vast_details can use them
            _MCP_VAST_CACHE.clear()
            _MCP_VAST_CACHE.extend(offers)
            total = len(offers)
            start = (page - 1) * page_size
            end = min(start + page_size, total)
            page_offers = offers[start:end]
            results = []
            for i, o in enumerate(page_offers):
                results.append({{
                    "index": start + i + 1,
                    "id": o.get('id'),
                    "gpu": o.get('gpu_name', '?').replace('_', ' '),
                    "vram_gb": o.get('gpu_ram', 0),
                    "price_hr": o.get('dph_total', 0),
                    "reliability": o.get('reliability', 0) * 100,
                    "num_gpus": o.get('num_gpus', 1)
                }})
            return json.dumps({{"page": page, "total": total, "offers": results}}, indent=2)
        except FileNotFoundError:
            return json.dumps({{"error": "vastai CLI not installed (pip install vastai)"}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

