    @logged_tool()
    def vast_ready(instance_id: str) -> str:
        \"\"\"Check if a Vast.ai instance is ready with Ouroboros stack installed.

        Args:
            instance_id: Instance ID to check

        Returns:
            JSON with readiness status, wait guidance, and available capabilities
        \"\"\"
        try:
            import paramiko
            import subprocess

            console_url = "https://cloud.vast.ai/instances/?instance_id=" + str(instance_id)

            def _not_ready(message: str, phase: str, status: str = 'unknown', wait_for: str = '/tmp/ouroboros_ready', **extra) -> str:
                payload = {{
                    "ready": False,
                    "status": status,
                    "phase": phase,
                    "console_url": console_url,
                    "wait_for": wait_for,
                    "message": message,
                    "next_step": "Wait for the instance to finish booting, then call vast_ready again. Ask the user to watch the GPU Fleet tab or open the Vast console link if needed."
                }}
                payload.update(extra)
                return json.dumps(payload, indent=2)

            target, _instances = _mcp_vast_get_instance(instance_id)
            if not target:
                return json.dumps({{"error": f"Instance {{instance_id}} not found"}})

            status = target.get('actual_status', 'unknown')
            if status != 'running':
                return _not_ready(f"Instance not running yet (status: {{status}})", phase='instance_' + str(status), status=status, wait_for='running')

            net = _mcp_vast_network_info(target)
            attachment = _MCP_VAST_ATTACHMENTS.get(str(instance_id)) or {{}}

            ssh_host = target.get('ssh_host', '')
            ssh_port = target.get('ssh_port', 22)

            if not ssh_host:
                return _not_ready('No SSH host available yet', phase='awaiting_ssh_host', status=status, wait_for='ssh_host', api_server_url=net.get('api_server_url', ''), port_exposed=bool(net.get('api_server_url')))

            # Try SSH connection
            client = paramiko.SSHClient()
            client.set_missing_host_key_policy(paramiko.AutoAddPolicy())

            key_path = Path.home() / '.ssh' / 'id_rsa'
            if not key_path.exists():
                return _not_ready('No SSH key at ~/.ssh/id_rsa', phase='missing_ssh_key', status=status, wait_for='local_ssh_key')

            try:
                client.connect(ssh_host, port=int(ssh_port), username='root',
                              key_filename=str(key_path), timeout=20,
                              look_for_keys=False, allow_agent=False)

                # Check if ouroboros packages are ready
                stdin, stdout, stderr = client.exec_command('cat /tmp/ouroboros_ready 2>/dev/null || echo "NOT_READY"')
                ready_check = stdout.read().decode().strip()

                # Check installed packages
                stdin, stdout, stderr = client.exec_command('pip list 2>/dev/null | grep -E "torch|accelerate|transformers|sentence-transformers|vllm|bitsandbytes|optimum|autoawq|awq" | head -30')
                packages = stdout.read().decode().strip()

                # Check GPU
                stdin, stdout, stderr = client.exec_command('nvidia-smi --query-gpu=name,memory.total --format=csv,noheader 2>/dev/null')
                gpu_info = stdout.read().decode().strip()

                client.close()

                is_ready = 'OUROBOROS_READY=1' in ready_check
                package_list = packages.split('\\n') if packages else []
                package_names = []
                for line in package_list:
                    parts = str(line or '').split()
                    if parts:
                        package_names.append(parts[0].strip().lower())
                has_torch = ("torch" in package_names)
                has_transformers = ("transformers" in package_names)
                support_matrix = {{
                    "causal_plain": (has_torch and has_transformers),
                    "causal_bnb": (has_torch and has_transformers and "bitsandbytes" in package_names),
                    "causal_gptq": (has_torch and has_transformers and ("gptqmodel" in package_names or "optimum" in package_names)),
                    "causal_awq": (has_torch and has_transformers and ("gptqmodel" in package_names or "autoawq" in package_names or "awq" in package_names)),
                    "embedding": ("sentence-transformers" in package_names),
                    "vllm": ("vllm" in package_names),
                }}
                usable_families = [name for name, supported in support_matrix.items() if supported]
                ssh_target = f"{{ssh_host}}:{{ssh_port}}"

                if not is_ready:
                    return _not_ready('Packages still installing...', phase='installing', status='running', packages_installed=package_list, support_matrix=support_matrix, usable_now=bool(usable_families), usable_families=usable_families, gpu=gpu_info or 'unknown', ssh=ssh_target, api_server_url=net.get('api_server_url', ''), port_exposed=bool(net.get('api_server_url')), attachment=attachment)

                return json.dumps({{
                    "ready": True,
                    "status": "running",
                    "phase": "ready",
                    "console_url": console_url,
                    "wait_for": "ready=true",
                    "next_step": "Use vast_load_model(instance_id, model_id) to start the remote API server and attach the GPU as a local slot.",
                    "ssh": ssh_target,
                    "gpu": gpu_info or "unknown",
                    "packages_installed": package_list,
                    "support_matrix": support_matrix,
                    "usable_now": True,
                    "usable_families": usable_families,
                    "port_exposed": bool(net.get('api_server_url')),
                    "api_server_url": net.get('api_server_url', ''),
                    "attachment": attachment,
                    "message": "Ouroboros stack ready!"
                }}, indent=2)

            except Exception as ssh_err:
                return _not_ready('SSH connection failed - instance may still be booting', phase='ssh_bootstrap', status=status, ssh_error=str(ssh_err))

        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def vast_run(instance_id: str, code: str) -> str:
        \"\"\"Execute Python code on a remote Vast.ai GPU instance.

        This is the core remote execution facility - run ANY Python on rented GPU.
        Use for model loading, inference, training, or any GPU-accelerated task.

        Args:
            instance_id: Instance ID to run on
            code: Python code to execute (will be run via python -c)

        Returns:
            JSON with stdout, stderr, and return code
        \"\"\"
        try:
            import paramiko
            import subprocess

            # Get instance details
            result = subprocess.run(['vastai', 'show', 'instances', '--raw'],
                                   capture_output=True, text=True, timeout=30)
            if result.returncode != 0:
                return json.dumps({{"error": "Cannot get instance list"}})

            instances = json.loads(result.stdout)
            target = None
            for inst in instances:
                if str(inst.get('id')) == str(instance_id):
                    target = inst
                    break

            if not target:
                return json.dumps({{"error": f"Instance {{instance_id}} not found"}})

            ssh_host = target.get('ssh_host', '')
            ssh_port = target.get('ssh_port', 22)

            if not ssh_host:
                return json.dumps({{"error": "No SSH host available"}})

            # SSH connection
            client = paramiko.SSHClient()
            client.set_missing_host_key_policy(paramiko.AutoAddPolicy())

            key_path = Path.home() / '.ssh' / 'id_rsa'
            if not key_path.exists():
                return json.dumps({{"error": "No SSH key at ~/.ssh/id_rsa"}})

            client.connect(ssh_host, port=int(ssh_port), username='root',
                          key_filename=str(key_path), timeout=30,
                          look_for_keys=False, allow_agent=False)

            # Write code to temp file and execute
            import base64
            code_b64 = base64.b64encode(code.encode()).decode()
            remote_cmd = f'echo {{code_b64}} | base64 -d > /tmp/ouroboros_run.py && python3 /tmp/ouroboros_run.py'

            stdin, stdout, stderr = client.exec_command(remote_cmd, timeout=300)

            out = stdout.read().decode()
            err = stderr.read().decode()
            exit_code = stdout.channel.recv_exit_status()

            client.close()

            return json.dumps({{
                "success": exit_code == 0,
                "stdout": out,
                "stderr": err,
                "exit_code": exit_code
            }}, indent=2)

        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def vast_load_model(instance_id: str, model_id: str, quantization: str = "4bit") -> str:
        \"\"\"Prepare a remote GPU model server and attach it locally as a normal slot.

        This is the preferred remote-GPU inference path:
        1. Vast tools provision and manage the remote GPU
        2. The current champion runtime is deployed to that node
        3. The requested model is loaded on the remote GPU
        4. The built-in OpenAI-compatible API server is started remotely
        5. The exposed endpoint is plugged locally as a normal council slot

        Args:
            instance_id: Instance ID
            model_id: HuggingFace model ID
            quantization: "none", "4bit", or "8bit"

        Returns:
            JSON with local attachment status and remote endpoint metadata
        \"\"\"
        import paramiko
        import time as _time
        import urllib.request

        model_id_l = str(model_id or '').lower()
        if "awq" in model_id_l:
            load_strategy = "native_awq"
            effective_quant = "awq"
        elif "gptq" in model_id_l:
            load_strategy = "native_gptq"
            effective_quant = "gptq"
        elif quantization == "4bit":
            load_strategy = "bnb_4bit"
            effective_quant = quantization
        elif quantization == "8bit":
            load_strategy = "bnb_8bit"
            effective_quant = quantization
        else:
            load_strategy = "native_plain"
            effective_quant = quantization

        if any(tok in model_id_l for tok in ["gguf", ".gguf", "exl2", "mlx"]):
            return json.dumps({{
                "error": "The remote slot bridge currently supports Transformers causal LM checkpoints only.",
                "model_id": model_id,
                "next_step": "Use a Transformers causal LM here, or manage this model manually with vast_run."
            }}, indent=2)

        family_gate = {{
            "native_plain": "causal_plain",
            "bnb_4bit": "causal_bnb",
            "bnb_8bit": "causal_bnb",
            "native_gptq": "causal_gptq",
            "native_awq": "causal_awq",
        }}
        required_family = family_gate.get(load_strategy, "causal_plain")
        ready_payload = {{}}
        try:
            ready_payload = json.loads(vast_ready(instance_id))
        except Exception:
            ready_payload = {{}}
        if isinstance(ready_payload, dict) and ready_payload.get('error'):
            ready_payload.setdefault('blocked_tool', 'vast_load_model')
            return json.dumps(ready_payload, indent=2)
        support_matrix = ready_payload.get('support_matrix') or {{}}
        if not support_matrix.get(required_family):
            return json.dumps({{
                "error": "Remote GPU is not ready for the requested model family yet.",
                "instance_id": instance_id,
                "model_id": model_id,
                "load_strategy": load_strategy,
                "required_family": required_family,
                "support_matrix": support_matrix,
                "next_step": "Wait for vast_ready(instance_id) to report the required family as usable before retrying."
            }}, indent=2)

        target, _instances = _mcp_vast_get_instance(instance_id)
        if not target:
            return json.dumps({{"error": f"Instance {{instance_id}} not found"}})
        net = _mcp_vast_network_info(target)
        endpoint_url = net.get('api_server_url', '')
        if not endpoint_url:
            return json.dumps({{
                "error": "No exposed API server endpoint is available for this instance.",
                "instance_id": instance_id,
                "next_step": "Rent the GPU through the updated vast_rent path so port 8420 is exposed for remote-slot attachment."
            }}, indent=2)

        ssh_host = target.get('ssh_host', '')
        ssh_port = target.get('ssh_port', 22)
        if not ssh_host:
            return json.dumps({{"error": "No SSH host available", "instance_id": instance_id}})

        existing = _MCP_VAST_ATTACHMENTS.get(str(instance_id))
        if existing and existing.get('local_slot') is not None:
            try:
                unplug_slot(int(existing.get('local_slot')))
            except Exception:
                pass

        key_path = Path.home() / '.ssh' / 'id_rsa'
        if not key_path.exists():
            return json.dumps({{"error": "No SSH key at ~/.ssh/id_rsa", "instance_id": instance_id}})

        remote_root = '/tmp/ouroboros_remote_slot'
        remote_capsule = remote_root + '/champion_remote.py'
        remote_boot = remote_root + '/boot_remote_api.py'
        remote_state = remote_root + '/attach_state.json'
        remote_pid = remote_root + '/attach_server.pid'
        remote_log = remote_root + '/attach_server.log'
        slot_label = (model_id.split('/')[-1] if '/' in model_id else model_id) + '@vast-' + str(instance_id)
        q = lambda s: str(s).replace('\\\\', '\\\\\\\\').replace("'", "\\\\'")

        client = paramiko.SSHClient()
        client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        try:
            client.connect(ssh_host, port=int(ssh_port), username='root',
                           key_filename=str(key_path), timeout=20,
                           look_for_keys=False, allow_agent=False)
            client.exec_command("mkdir -p " + remote_root + " && pkill -f boot_remote_api.py >/dev/null 2>&1 || true && rm -f " + remote_state + " " + remote_pid)
            sftp = client.open_sftp()
            sftp.put(str(Path(__file__).resolve()), remote_capsule)
            boot_lines = [
                "import importlib.util",
                "import json",
                "import os",
                "import time",
                "import torch",
                "from transformers import AutoModelForCausalLM, AutoTokenizer",
                "remote_capsule = '" + q(remote_capsule) + "'",
                "remote_state = '" + q(remote_state) + "'",
                "model_id = '" + q(model_id) + "'",
                "slot_label = '" + q(slot_label) + "'",
                "load_strategy = '" + q(load_strategy) + "'",
                "requested_quant = '" + q(quantization) + "'",
                "effective_quant = '" + q(effective_quant) + "'",
                "api_port = " + str(_MCP_VAST_API_PORT),
                "def _write_state(payload):",
                "    os.makedirs(os.path.dirname(remote_state), exist_ok=True)",
                "    with open(remote_state, 'w', encoding='utf-8') as f:",
                "        json.dump(payload, f)",
                "spec = importlib.util.spec_from_file_location('champion_remote', remote_capsule)",
                "mod = importlib.util.module_from_spec(spec)",
                "spec.loader.exec_module(mod)",
                "tokenizer = AutoTokenizer.from_pretrained(model_id, trust_remote_code=True)",
                "if load_strategy == 'bnb_4bit':",
                "    from transformers import BitsAndBytesConfig",
                "    bnb_config = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_quant_type='nf4', bnb_4bit_compute_dtype=torch.float16, bnb_4bit_use_double_quant=True)",
                "    model = AutoModelForCausalLM.from_pretrained(model_id, quantization_config=bnb_config, device_map='auto', trust_remote_code=True)",
                "elif load_strategy == 'bnb_8bit':",
                "    from transformers import BitsAndBytesConfig",
                "    bnb_config = BitsAndBytesConfig(load_in_8bit=True)",
                "    model = AutoModelForCausalLM.from_pretrained(model_id, quantization_config=bnb_config, device_map='auto', trust_remote_code=True)",
                "else:",
                "    model = AutoModelForCausalLM.from_pretrained(model_id, device_map='auto', trust_remote_code=True)",
                "agent = mod.get_agent()",
                "outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)",
                "brain = getattr(outer_brain, '_brain', outer_brain)",
                "slot_idx = None",
                "for i, c in enumerate(brain.councilors):",
                "    if getattr(c, 'model', None) is None:",
                "        c.model = model",
                "        c.tokenizer = tokenizer",
                "        c.processor = getattr(model, 'processor', None)",
                "        c._model_source = model_id",
                "        c._model_type = 'LLM'",
                "        c._limits = getattr(model, '_limits', mod._read_model_limits(model, tokenizer))",
                "        c.name = slot_label",
                "        slot_idx = i",
                "        break",
                "if slot_idx is None:",
                "    raise RuntimeError('No empty remote slots available')",
                "mod.start_api_server(port=api_port)",
                "_write_state(dict(status='ready', remote_slot=slot_idx, slot_name=slot_label, model_id=model_id, load_strategy=load_strategy, requested_quantization=requested_quant, effective_quantization=effective_quant, api_port=api_port))",
                "while True:",
                "    time.sleep(30)",
            ]
            boot_script = "\\n".join(boot_lines)
            with sftp.file(remote_boot, 'w') as boot_f:
                boot_f.write(boot_script)
            sftp.chmod(remote_boot, 0o755)
            sftp.close()
            client.exec_command("nohup python3 " + remote_boot + " > " + remote_log + " 2>&1 & echo $! > " + remote_pid)
            endpoint_root = endpoint_url[:-3] if endpoint_url.endswith('/v1') else endpoint_url.rstrip('/')
            health_url = endpoint_root + '/health'
            state_payload = {{}}
            server_ready = False
            for _ in range(30):
                try:
                    with urllib.request.urlopen(health_url, timeout=5) as resp:
                        if resp.status == 200:
                            server_ready = True
                            break
                except Exception:
                    pass
                _time.sleep(2)
            try:
                stdin, stdout, stderr = client.exec_command('cat ' + remote_state + ' 2>/dev/null || true')
                raw_state = stdout.read().decode().strip()
                if raw_state:
                    state_payload = json.loads(raw_state)
            except Exception:
                state_payload = {{}}
            if not server_ready:
                return json.dumps({{
                    "error": "Remote API server did not become reachable from the Space.",
                    "instance_id": instance_id,
                    "endpoint_url": endpoint_url,
                    "remote_state": state_payload,
                    "next_step": "Inspect the GPU Fleet logs or the remote server log, then retry."
                }}, indent=2)
            remote_slot = state_payload.get('remote_slot', 0)
            plug_url = endpoint_url + '?model=slot-' + str(remote_slot)
            plug_result = json.loads(plug_model(plug_url, slot_name=slot_label))
            if plug_result.get('error'):
                return json.dumps({{
                    "error": "Remote server came up, but local slot attachment failed.",
                    "instance_id": instance_id,
                    "endpoint_url": endpoint_url,
                    "plug_result": plug_result,
                    "remote_state": state_payload
                }}, indent=2)
            local_slot = plug_result.get('slot')
            attachment = {{
                "instance_id": str(instance_id),
                "local_slot": local_slot,
                "slot_name": slot_label,
                "model_id": model_id,
                "load_strategy": load_strategy,
                "requested_quantization": quantization,
                "effective_quantization": effective_quant,
                "endpoint_url": endpoint_url,
                "remote_slot": remote_slot,
            }}
            _MCP_VAST_ATTACHMENTS[str(instance_id)] = attachment
            return json.dumps({{
                "status": "attached",
                "instance_id": instance_id,
                "endpoint_url": endpoint_url,
                "remote_slot": remote_slot,
                "local_slot": local_slot,
                "slot_name": slot_label,
                "model_id": model_id,
                "load_strategy": load_strategy,
                "requested_quantization": quantization,
                "effective_quantization": effective_quant,
                "attachment": attachment,
                "next_step": "Use the attached local slot normally with invoke_slot, agent_chat, compare, workflows, and debug tooling."
            }}, indent=2)
        except Exception as e:
            return json.dumps({{
                "error": str(e),
                "instance_id": instance_id,
                "model_id": model_id,
                "load_strategy": load_strategy
            }}, indent=2)
        finally:
            try:
                client.close()
            except Exception:
                pass

    @logged_tool()
    def vast_generate(instance_id: str, prompt: str, max_tokens: int = 256) -> str:
        \"\"\"Route generation through the locally attached remote-GPU slot.

        Vast direct generation is no longer the preferred path. Once a remote GPU
        has been attached locally, generation should flow through the normal slot
        system so sessions, workflows, compare, and debug all behave consistently.
        \"\"\"
        attachment = _MCP_VAST_ATTACHMENTS.get(str(instance_id))
        if not attachment or attachment.get('local_slot') is None:
            return json.dumps({{
                "error": "No local slot is attached for this Vast instance.",
                "instance_id": instance_id,
                "next_step": "Call vast_load_model(instance_id, model_id) first. That will start the remote API server and attach it locally as a normal slot."
            }}, indent=2)
        slot_idx = int(attachment.get('local_slot'))
        result = json.loads(invoke_slot(slot=slot_idx, text=prompt, mode='generate', max_tokens=max_tokens))
        return json.dumps({{
            "instance_id": instance_id,
            "local_slot": slot_idx,
            "slot_name": attachment.get('slot_name'),
            "endpoint_url": attachment.get('endpoint_url'),
            "result": result
        }}, indent=2)

    @logged_tool()
    def vast_embed(instance_id: str, texts: list, model_id: str = "BAAI/bge-large-en-v1.5") -> str:
        \"\"\"Report the preferred path for embeddings in the remote-slot architecture.

        Remote Vast embeddings should not be treated as a parallel inference world.
        The built-in API bridge is currently focused on LLM slot parity, so direct
        vast_embed is demoted to a manual/legacy path.
