    @logged_tool()
    def bag_diff(key: str, from_checkpoint: str = "", to_checkpoint: str = "current", context_lines: int = 3) -> str:
        """Diff a document against checkpoints (or between checkpoints)."""
        import difflib
        _iid, _item = _bag_find_item(key)
        if not _item:
            return json.dumps(dict(error=f"Document not found: {{key}}"))
        _doc_name = str(_item.get('name', key))
        _checkpoints = _bag_list_checkpoints(_doc_name)
        if not _checkpoints:
            return json.dumps(dict(error="No checkpoints available for diff", key=_doc_decode_key(_doc_name)))

        _from_key = str(from_checkpoint or "").strip()
        if not _from_key:
            _from_key = _checkpoints[0].get('checkpoint_key', '')
        _from_payload = _bag_extract_checkpoint_payload(_from_key)
        if 'error' in _from_payload:
            return json.dumps(_from_payload)
        _from_text = str(_from_payload.get('content', ''))

        _to_checkpoint = str(to_checkpoint or "").strip()
        if not _to_checkpoint:
            _to_checkpoint = "current"

        if _to_checkpoint == "current":
            _to_text = _bag_item_text(_item)
            _to_label = f"current:{{_doc_name}}"
            _to_label_display = f"current:{{_doc_decode_key(_doc_name)}}"
        else:
            _to_payload = _bag_extract_checkpoint_payload(_to_checkpoint)
            if 'error' in _to_payload:
                return json.dumps(_to_payload)
            _to_text = str(_to_payload.get('content', ''))
            _to_label = str(_to_payload.get('_checkpoint_key', _to_checkpoint))
            _to_label_display = str(_to_payload.get('_checkpoint_key_display', _doc_decode_checkpoint_key(_to_label)))

        _from_label = str(_from_payload.get('_checkpoint_key', _from_key))
        _from_label_display = str(_from_payload.get('_checkpoint_key_display', _doc_decode_checkpoint_key(_from_label)))

        _diff = list(
            difflib.unified_diff(
                _from_text.splitlines(),
                _to_text.splitlines(),
                fromfile=_from_label,
                tofile=_to_label,
                lineterm='',
                n=max(0, int(context_lines)),
            )
        )
        _added = sum(1 for _l in _diff if _l.startswith('+') and not _l.startswith('+++'))
        _removed = sum(1 for _l in _diff if _l.startswith('-') and not _l.startswith('---'))
        return json.dumps(
            dict(
                key=_doc_decode_key(_doc_name),
                storage_key=_doc_name,
                from_checkpoint=_from_label_display,
                from_checkpoint_storage=_from_label,
                to_target=_to_label_display,
                to_target_storage=_to_label,
                added_lines=_added,
                removed_lines=_removed,
                diff="\\n".join(_diff),
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def bag_restore(key: str, checkpoint_key: str, create_checkpoint: bool = True) -> str:
        """Restore a FelixBag document from a checkpoint snapshot."""
        _payload = _bag_extract_checkpoint_payload(checkpoint_key)
        if 'error' in _payload:
            return json.dumps(_payload)
        _target_key = key or str(_payload.get('source_key', ''))
        if not _target_key:
            return json.dumps(dict(error="Target key required for restore"))
        _content = str(_payload.get('content', ''))
        _source_type = str(_payload.get('source_type', 'document'))

        _existing_id, _existing_item = _bag_find_item(_target_key)
        _backup = None
        if create_checkpoint and _existing_item and not _bag_is_checkpoint_name(str(_existing_item.get('name', ''))):
            _backup = _bag_create_checkpoint(_target_key, message=f"pre-restore backup from {{checkpoint_key}}", tag="restore_backup")

        _new_id = _BAG.induct(_target_key, _content, item_type=_source_type, tags=['restored'], preview=f"restored from {{checkpoint_key}}")
        _new_item_id, _new_item = _bag_find_item(_target_key)
        _from_ck_storage = str(_payload.get('_checkpoint_key', checkpoint_key))
        _from_ck_display = str(_payload.get('_checkpoint_key_display', _doc_decode_checkpoint_key(_from_ck_storage)))
        _backup_ck_storage = _backup.get('checkpoint_key') if isinstance(_backup, dict) else None
        _backup_ck_display = _doc_decode_checkpoint_key(_backup_ck_storage) if isinstance(_backup_ck_storage, str) and _backup_ck_storage else None
        return json.dumps(
            dict(
                status="ok",
                restored_key=_doc_decode_key(_target_key),
                restored_storage_key=_target_key,
                restored_item_id=_new_id or _new_item_id,
                restored_version=_new_item.get('version', 1) if isinstance(_new_item, dict) else None,
                from_checkpoint=_from_ck_display,
                from_checkpoint_storage=_from_ck_storage,
                backup_checkpoint=_backup_ck_display,
                backup_checkpoint_storage=_backup_ck_storage,
            ),
            indent=2,
            default=str,
        )

    def _tool_unwrapped(_fn):
        return getattr(_fn, '__wrapped__', _fn)

    def _file_item_type(file_type: str, fallback: str = "text") -> str:
        _raw = str(file_type or '').strip().lower()
        if not _raw:
            _raw = str(fallback or 'text').strip().lower()
        _allowed = {{
            'text', 'json', 'code', 'workflow', 'agent_session',
            'config', 'model', 'markdown', 'document', 'artifact', 'state'
        }}
        return _raw if _raw in _allowed else 'text'

    @logged_tool()
    def file_read(path: str) -> str:
        """Read a file/document from FelixBag workspace."""
        if not path:
            return json.dumps(dict(error="path required"))
        _iid, _item = _bag_find_item(path)
        if not _item:
            return json.dumps(dict(error=f"File not found: {{path}}", path=path))
        _name = str(_item.get('name', path))
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Checkpoint artifacts are not regular files", path=_doc_decode_checkpoint_key(_name)))
        _content = _bag_item_text(_item)
        _display_path = _doc_decode_key(_name)
        return json.dumps(
            dict(
                path=_display_path,
                key=_display_path,
                storage_path=_name,
                storage_key=_name,
                id=_iid,
                type=_item.get('type', 'text'),
                version=_item.get('version', 1),
                metadata=_item.get('metadata', {{}}),
                content=_content,
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def file_write(path: str, content: str, file_type: str = "text") -> str:
        """Create or overwrite a file/document in FelixBag workspace."""
        if not path:
            return json.dumps(dict(error="path required"))

        _existing_id, _existing_item = _bag_find_item(path)
        _checkpoint = None
        _itype_fallback = str(_existing_item.get('type', 'text')) if isinstance(_existing_item, dict) else 'text'
        _itype = _file_item_type(file_type, fallback=_itype_fallback)

        if _existing_item and not _bag_is_checkpoint_name(str(_existing_item.get('name', ''))):
            _checkpoint = _bag_create_checkpoint(path, message="auto-checkpoint before file_write overwrite", tag="auto")

        _new_id = _BAG.induct(path, str(content), item_type=_itype)
        _resolved_id, _resolved_item = _bag_find_item(path)
        _storage_path = str(_resolved_item.get('name', path)) if isinstance(_resolved_item, dict) else str(path)
        _display_path = _doc_decode_key(_storage_path)
        return json.dumps(
            dict(
                status="ok",
                path=_display_path,
                key=_display_path,
                storage_path=_storage_path,
                storage_key=_storage_path,
                type=_itype,
                item_id=_new_id or _resolved_id,
                version=_resolved_item.get('version', 1) if isinstance(_resolved_item, dict) else None,
                bytes=len(str(content or '')),
                replaced=bool(_existing_item),
                checkpoint_key=_checkpoint.get('checkpoint_key') if isinstance(_checkpoint, dict) else None,
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def file_edit(path: str, old_text: str, new_text: str) -> str:
        """Surgical single replacement in a FelixBag file/document."""
        if not path:
            return json.dumps(dict(error="path required"))
        if old_text is None or str(old_text) == "":
            return json.dumps(dict(error="old_text required", path=path))

        _iid, _item = _bag_find_item(path)
        if not _item:
            return json.dumps(dict(error=f"File not found: {{path}}", path=path))

        _name = str(_item.get('name', path))
        _display_path = _doc_decode_key(_name)
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Cannot edit checkpoint artifacts", path=_display_path, key=_display_path, storage_path=_name, storage_key=_name))

        _before = _bag_item_text(_item)
        if str(old_text) == str(new_text):
            return json.dumps(
                dict(
                    status="ok",
                    path=_display_path,
                    key=_display_path,
                    storage_path=_name,
                    storage_key=_name,
                    replaced=0,
                    note="No-op edit (old_text equals new_text)",
                    version=_item.get('version', 1),
                ),
                indent=2,
                default=str,
            )

        if str(old_text) not in _before:
            _preview = _before[:200]
            return json.dumps(
                dict(
                    error="old_text not found",
                    path=_display_path,
                    key=_display_path,
                    storage_path=_name,
                    storage_key=_name,
                    contains=False,
                    preview=_preview,
                ),
                indent=2,
                default=str,
            )

        _checkpoint = _bag_create_checkpoint(_name, message="auto-checkpoint before file_edit", tag="auto")
        _after = _before.replace(str(old_text), str(new_text), 1)
        _itype = _file_item_type(_item.get('type', 'text'), fallback='text')

        _new_id = _BAG.induct(_name, _after, item_type=_itype)
        _rid, _ritem = _bag_find_item(_name)
        return json.dumps(
            dict(
                status="ok",
                path=_display_path,
                key=_display_path,
                storage_path=_name,
                storage_key=_name,
                item_id=_new_id or _rid,
                type=_itype,
                replaced=1,
                old_bytes=len(_before),
                new_bytes=len(_after),
                version=_ritem.get('version', 1) if isinstance(_ritem, dict) else None,
                checkpoint_key=_checkpoint.get('checkpoint_key') if isinstance(_checkpoint, dict) else None,
            ),
            indent=2,
            default=str,
        )

    @logged_tool()
    def file_append(path: str, content: str) -> str:
        """Append content to a FelixBag file/document (create if missing)."""
        if not path:
            return json.dumps(dict(error="path required"))
        _iid, _item = _bag_find_item(path)
        if not _item:
            _write_fn = _tool_unwrapped(file_write)
            return _write_fn(path=path, content=str(content or ''), file_type='text')

        _name = str(_item.get('name', path))
        _display_path = _doc_decode_key(_name)
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Cannot append to checkpoint artifacts", path=_display_path, key=_display_path, storage_path=_name, storage_key=_name))

        _before = _bag_item_text(_item)
        _separator = "" if not _before else "\\n"
        _after = _before + _separator + str(content or '')
        _checkpoint = _bag_create_checkpoint(_name, message="auto-checkpoint before file_append", tag="auto")
        _itype = _file_item_type(_item.get('type', 'text'), fallback='text')
        _new_id = _BAG.induct(_name, _after, item_type=_itype)
        _rid, _ritem = _bag_find_item(_name)
