    @logged_tool()
    def file_prepend(path: str, content: str) -> str:
        """Prepend content to a FelixBag file/document (create if missing)."""
        if not path:
            return json.dumps(dict(error="path required"))
        _iid, _item = _bag_find_item(path)
        if not _item:
            _write_fn = _tool_unwrapped(file_write)
            return _write_fn(path=path, content=str(content or ''), file_type='text')

        _name = str(_item.get('name', path))
        _display_path = _doc_decode_key(_name)
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Cannot prepend to checkpoint artifacts", path=_display_path, key=_display_path, storage_path=_name, storage_key=_name))

        _before = _bag_item_text(_item)
        _separator = "" if not _before else "\\n"
        _after = str(content or '') + _separator + _before
        _checkpoint = _bag_create_checkpoint(_name, message="auto-checkpoint before file_prepend", tag="auto")
        _itype = _file_item_type(_item.get('type', 'text'), fallback='text')
        _new_id = _BAG.induct(_name, _after, item_type=_itype)
        _rid, _ritem = _bag_find_item(_name)
        return json.dumps(
            dict(
                status="ok",
                path=_display_path,
                key=_display_path,
                storage_path=_name,
                storage_key=_name,
                item_id=_new_id or _rid,
                type=_itype,
                prepended_bytes=len(str(content or '')),
                version=_ritem.get('version', 1) if isinstance(_ritem, dict) else None,
                checkpoint_key=_checkpoint.get('checkpoint_key') if isinstance(_checkpoint, dict) else None,
