    @logged_tool()
    def file_delete(path: str) -> str:
        """Delete a FelixBag file/document by path."""
        if not path:
            return json.dumps(dict(error="path required"))
        _iid, _item = _bag_find_item(path)
        if not _item:
            return json.dumps(dict(error=f"File not found: {{path}}", path=path))
        _name = str(_item.get('name', path))
        _display_path = _doc_decode_key(_name)
        if _bag_is_checkpoint_name(_name):
            return json.dumps(dict(error="Use bag_forget for checkpoint artifacts", path=_display_path, key=_display_path, storage_path=_name, storage_key=_name))

        try:
