        return json.dumps(dict(status="ok", path=_display_path, key=_display_path, storage_path=_name, storage_key=_name, removed_id=_iid), indent=2, default=str)

    @logged_tool()
    def file_rename(old_path: str, new_path: str) -> str:
        """Rename/move a FelixBag file/document key."""
        if not old_path or not new_path:
            return json.dumps(dict(error="old_path and new_path required"))
        if old_path == new_path:
            return json.dumps(dict(error="old_path and new_path are identical"))

        _src_id, _src_item = _bag_find_item(old_path)
        if not _src_item:
            return json.dumps(dict(error=f"Source not found: {{old_path}}", old_path=old_path, new_path=new_path))
        _src_name = str(_src_item.get('name', old_path))
        if _bag_is_checkpoint_name(_src_name):
            return json.dumps(dict(error="Cannot rename checkpoint artifacts", old_path=_src_name, new_path=new_path))

        _dst_id, _dst_item = _bag_find_item(new_path)
        if _dst_item:
            return json.dumps(dict(error=f"Destination already exists: {{new_path}}", old_path=_src_name, new_path=new_path))

        _content = _bag_item_text(_src_item)
        _itype = _file_item_type(_src_item.get('type', 'text'), fallback='text')
        _checkpoint = _bag_create_checkpoint(_src_name, message=f"auto-checkpoint before file_rename to {{new_path}}", tag="auto")

        _new_id = _BAG.induct(new_path, _content, item_type=_itype)
        if hasattr(_BAG, 'remove'):
            _BAG.remove(_src_id)
        else:
            getattr(_BAG, '_bag', {{}}).pop(_src_id, None)

        _rid, _ritem = _bag_find_item(new_path)
        _new_storage = str(_ritem.get('name', new_path)) if isinstance(_ritem, dict) else str(new_path)
        _old_display = _doc_decode_key(_src_name)
        _new_display = _doc_decode_key(_new_storage)
        return json.dumps(
            dict(
                status="ok",
                old_path=_old_display,
                old_storage_path=_src_name,
                new_path=_new_display,
                new_storage_path=_new_storage,
                key=_new_display,
                storage_key=_new_storage,
                item_id=_new_id or _rid,
                type=_itype,
                version=_ritem.get('version', 1) if isinstance(_ritem, dict) else None,
                checkpoint_key=_checkpoint.get('checkpoint_key') if isinstance(_checkpoint, dict) else None,
            ),
            indent=2,
            default=str,
        )

