    @logged_tool()
    def bag_induct(key: str, content: str, item_type: str = "text") -> str:
        \"\"\"Add content to the FelixBag memory.

        Args:
            key: Unique key for the item
            content: Content to store
            item_type: Type of content ('text', 'json', 'code', etc.)

        Returns:
            JSON with induction result
        \"\"\"
        # Auto-checkpoint existing document before overwrite (best-effort)
        try:
            _eid, _eitem = _bag_find_item(key)
            if _eitem and not _bag_is_checkpoint_name(str(_eitem.get('name', ''))):
                _bag_create_checkpoint(key, message="auto-checkpoint before bag_induct overwrite", tag="auto")
        except Exception:
            pass

        if hasattr(_BAG, 'induct'):
            _BAG.induct(key, content, item_type=item_type)
        elif hasattr(_BAG, 'put'):
            _BAG.put(key, content)
        else:
            _BAG._bag[key] = content
        try:
            _ragent = get_agent()
            _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
            _rbrain = getattr(_router, '_brain', _router)
            if _rbrain and hasattr(_rbrain, '_capture_reward'):
                _rbrain._capture_reward(source_key='bag_induct', event_id=key, metadata={{'key': key, 'type': item_type}})
        except Exception:
            pass
        return json.dumps({{"status": "ok", "key": key, "type": item_type}})

