    @logged_tool()
    def infer(text: str = "") -> str:
        \"\"\"Run full consensus inference through all council members.

        Args:
            text: Optional text input

        Returns:
            JSON with consensus result
        \"\"\"
        agent = get_agent()
        obs = {{'text': text or 'infer', 'input': np.random.rand(384).astype(np.float32)}}

        try:
            result = agent.forward(obs)
        except Exception as e:
            import traceback
            return json.dumps({{"error": str(e), "traceback": traceback.format_exc()}})

        def serialize(v):
            if hasattr(v, 'tolist'):
                return v.tolist()
            elif isinstance(v, dict):
                return {{k: serialize(vv) for k, vv in v.items()}}
            elif isinstance(v, list):
                return [serialize(x) for x in v]
            return v

        def _extract_text(v):
            if isinstance(v, str):
                _s = v.strip()
                if _s:
                    return _s
                return None
            if isinstance(v, dict):
                for _k in ('assistant_text', 'answer', 'output_text', 'text', 'output', 'response', 'summary'):
                    if _k in v:
                        _hit = _extract_text(v.get(_k))
                        if _hit:
                            return _hit
                for _vv in v.values():
                    _hit = _extract_text(_vv)
                    if _hit:
                        return _hit
                return None
            if isinstance(v, list):
                for _vv in v:
                    _hit = _extract_text(_vv)
                    if _hit:
                        return _hit
                return None
            return None

        _serialized = serialize(result)
        _assistant_text = _extract_text(_serialized)

        def _infer_is_unhelpful_text(s):
            if not isinstance(s, str):
                return True
            _t = s.strip()
            if not _t:
                return True
            try:
                import re as _infer_re
                if _infer_re.fullmatch(r"[0-9a-fA-F]{{12,128}}", _t):
                    return True
            except Exception:
                pass
            if isinstance(_serialized, dict):
                if _t == str(_serialized.get('provenance', '') or '').strip():
                    return True
                if _t == str(_serialized.get('_merkle_root', '') or '').strip():
                    return True
            return False

        # C1 fix: infer should surface a natural-language answer as primary text,
        # not provenance/hash identifiers.
        if _infer_is_unhelpful_text(_assistant_text) and isinstance(text, str) and text.strip():
            try:
                _delib_raw = deliberate(question=text.strip(), context="")
                _delib_obj = json.loads(_delib_raw) if isinstance(_delib_raw, str) else _delib_raw
                _candidate = _delib_obj.get('result') if isinstance(_delib_obj, dict) else None
                if isinstance(_candidate, str) and _candidate.strip() and not _infer_is_unhelpful_text(_candidate):
                    _assistant_text = _candidate.strip()
            except Exception:
                pass

        if _infer_is_unhelpful_text(_assistant_text):
            if isinstance(_serialized, dict):
                _assistant_text = "Inference completed. Structured consensus payload returned."
            elif isinstance(_serialized, list):
                _assistant_text = f"Inference completed with {{len(_serialized)}} result items."

        if isinstance(_serialized, dict):
            _out = dict(_serialized)
            if isinstance(_assistant_text, str) and _assistant_text.strip():
                _out['assistant_text'] = _assistant_text[:2000]
                if not isinstance(_out.get('answer'), str) or not str(_out.get('answer', '')).strip():
                    _out['answer'] = _assistant_text[:2000]
            return json.dumps(_out, indent=2, default=str)

        return json.dumps({{
            "result": _serialized,
            "assistant_text": (_assistant_text[:2000] if isinstance(_assistant_text, str) else None),
            "answer": (_assistant_text[:2000] if isinstance(_assistant_text, str) else None)
        }}, indent=2, default=str)

    @logged_tool()
    def generate(prompt: str, max_tokens: int = 256, temperature: float = 0.7) -> str:
        \"\"\"Generate text using an LLM in a council slot.

        Args:
            prompt: Text prompt
            max_tokens: Maximum tokens to generate
            temperature: Sampling temperature

        Returns:
            JSON with generated text
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        if not hasattr(brain, 'councilors'):
            return json.dumps({{"error": "No council slots"}})

        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            if model and hasattr(model, 'generate'):
                tokenizer = getattr(c, 'tokenizer', None)
                _lim = getattr(c, '_limits', getattr(model, '_limits', {{}}))
                _ctx = _lim.get('context_length', 4096)
                _gen = max_tokens or _lim.get('max_gen_tokens', 256)
                try:
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(i, brain)
                            messages = [{{"role": "system", "content": _sys}}, {{"role": "user", "content": prompt}}]
                            input_text = tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(input_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(prompt, return_tensors="pt", truncation=True, max_length=_ctx)
                        input_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, do_sample=True, temperature=temperature, pad_token_id=tokenizer.eos_token_id)
                        text = tokenizer.decode(outputs[0][input_len:], skip_special_tokens=True)
                    else:
                        try:
                            text = model.generate(prompt=prompt, max_tokens=_gen, temperature=temperature)
                        except TypeError:
                            text = model.generate(prompt)
                        text = str(text)
                    return json.dumps({{"slot": i, "prompt": prompt, "output": text, "limits_used": _lim}})
                except Exception as e:
                    return json.dumps({{"error": str(e), "slot": i}})

        return json.dumps({{"error": "No LLM found in slots"}})

