    @logged_tool()
    def rerank(query: str, documents: list) -> str:
        \"\"\"Rerank documents by relevance to a query.

        Args:
            query: Search query
            documents: List of documents to rank

        Returns:
            JSON with ranked documents
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        councilors = list(getattr(brain, 'councilors', []) or [])
        embedding_foundation = getattr(brain, 'embedding_foundation', None)

        def _to_numpy_embedding(value):
            if hasattr(value, 'detach'):
                value = value.detach()
            if hasattr(value, 'cpu'):
                value = value.cpu()
            return np.asarray(value, dtype=np.float32)

        reranker = None
        reranker_slot = None
        available_slots = []
        skipped_encode_only_slots = []
        for i, c in enumerate(councilors):
            model = getattr(c, 'model', None)
            if not model:
                continue
            hint = getattr(model, '_model_type_hint', None)
            available_slots.append({{"slot": i, "hint": hint or "unknown", "has_predict": bool(hasattr(model, 'predict')), "has_encode": bool(hasattr(model, 'encode'))}})
            if reranker is None and hint == 'RERANKER' and hasattr(model, 'predict'):
                reranker = model
                reranker_slot = i

        if reranker:
            try:
                pairs = [[query, doc] for doc in documents]
                scores_raw = reranker.predict(pairs)
                if hasattr(scores_raw, 'tolist'):
                    scores_raw = scores_raw.tolist()
                indexed = list(zip(range(len(documents)), scores_raw, documents))
                ranked = sorted(indexed, key=lambda x: x[1], reverse=True)
                return json.dumps({{"query": query, "method": "cross-encoder", "source": f"slot_{{reranker_slot}}", "ranked": [{{"rank": r+1, "doc_idx": i, "score": float(s), "text": t[:100]}} for r, (i, s, t) in enumerate(ranked)]}}, indent=2)
            except Exception as e:
                return json.dumps({{"error": f"Cross-encoder rerank failed: {{e}}", "source": f"slot_{{reranker_slot}}"}}, indent=2)

        embed_fn = None
        embedder_source = ''
        if embedding_foundation and hasattr(embedding_foundation, 'encode'):
            embed_fn = lambda t: embedding_foundation.encode(t, convert_to_numpy=True)
            embedder_source = 'embedding_foundation'

        if not embed_fn:
            for i, c in enumerate(councilors):
                model = getattr(c, 'model', None)
                if not model:
                    continue
                hint = getattr(model, '_model_type_hint', None)
                if hint == 'EMBEDDING' and hasattr(model, 'encode'):
                    embed_fn = model.encode
                    embedder_source = f'slot_{{i}}'
                    break
                if hint not in ('EMBEDDING', 'RERANKER') and hasattr(model, 'encode'):
                    skipped_encode_only_slots.append({{"slot": i, "hint": hint or "unknown"}})

        if not embed_fn:
            return json.dumps({{
                "error": "No capable reranker or embedder is available",
                "hint": "Plug a true RERANKER or explicit EMBEDDING model. Remote LLM providers with encode() are intentionally skipped for rerank fallback.",
                "available_slots": available_slots,
                "skipped_encode_only_slots": skipped_encode_only_slots,
                "has_embedding_foundation": bool(embedding_foundation and hasattr(embedding_foundation, 'encode'))
            }}, indent=2)

        try:
            q_emb = _to_numpy_embedding(embed_fn(query))
            doc_embs = [_to_numpy_embedding(embed_fn(d)) for d in documents]

            # Compute cosine similarities
            scores = []
            q_norm = np.linalg.norm(q_emb)
            for i, d_emb in enumerate(doc_embs):
                sim = np.dot(q_emb, d_emb) / (q_norm * np.linalg.norm(d_emb) + 1e-8)
                scores.append((i, float(sim), documents[i]))

            ranked = sorted(scores, key=lambda x: x[1], reverse=True)
            return json.dumps({{"query": query, "method": "cosine-similarity", "source": embedder_source, "ranked": [{{"rank": r+1, "doc_idx": i, "score": s, "text": t[:100]}} for r, (i, s, t) in enumerate(ranked)]}}, indent=2)
        except Exception as e:
            return json.dumps({{"error": f"Embedding rerank failed: {{e}}", "source": embedder_source or "unknown"}}, indent=2)

    @logged_tool()
    def broadcast(message: str) -> str:
        \"\"\"Broadcast a message to all council members and collect responses.

        Args:
            message: Message to broadcast

        Returns:
            JSON with all responses
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        if not hasattr(brain, 'councilors'):
            return json.dumps({{"error": "No council slots"}})

        responses = []
        for i, c in enumerate(brain.councilors):
            model = getattr(c, 'model', None)
            name = getattr(c, 'name', f'slot_{{i}}')
            if not model:
                responses.append({{"slot": i, "name": name, "status": "empty"}})
                continue

            _lim = getattr(c, '_limits', getattr(model, '_limits', {{}}))
            _ctx = _lim.get('context_length', 4096)
            _gen = _lim.get('max_gen_tokens', 256)
            try:
                if hasattr(model, 'encode'):
                    emb = model.encode(message)
                    responses.append({{"slot": i, "name": name, "type": "embedding", "dim": len(emb)}})
                elif hasattr(model, 'generate'):
                    tokenizer = getattr(c, 'tokenizer', None)
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(i, brain)
                            _msgs = [{{"role": "system", "content": _sys}}, {{"role": "user", "content": message}}]
                            _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(message, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        text = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            text = model.generate(prompt=message, max_tokens=_gen)
                        except TypeError:
                            text = model.generate(message)
                        text = str(text)
                    responses.append({{"slot": i, "name": name, "type": "generation", "output": text[:200]}})
                elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(message) % 1000 / 1000.0
                    responses.append({{"slot": i, "name": name, "type": "reranker_hash", "output": str(_h)}})
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    result = fn(message)
                    responses.append({{"slot": i, "name": name, "type": "classification", "output": str(result)[:200]}})
                elif callable(model):
                    result = model(message)
                    responses.append({{"slot": i, "name": name, "type": "forward", "output": str(result)[:200]}})
                else:
                    responses.append({{"slot": i, "name": name, "type": "unknown"}})
            except Exception as e:
                responses.append({{"slot": i, "name": name, "error": str(e)}})

        return json.dumps({{"message": message, "responses": responses}}, indent=2)

