    @logged_tool()
    def start_api_server(port: int = 8420) -> str:
        \"\"\"Start an HTTP API server (OpenAI-compatible).

        Args:
            port: Port to listen on

        Returns:
            JSON with server info
        \"\"\"
        import threading
        import http.server

        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        # Capture invoke_slot from the tool registry for routing
        _api_invoke = invoke_slot

        class APIHandler(http.server.BaseHTTPRequestHandler):
            def log_message(self, format, *args): pass

            def _send_json(self, code, data):
                self.send_response(code)
                self.send_header('Content-Type', 'application/json')
                self.send_header('Access-Control-Allow-Origin', '*')
                self.end_headers()
                self.wfile.write(json.dumps(data, default=str).encode())

            def do_OPTIONS(self):
                self.send_response(204)
                self.send_header('Access-Control-Allow-Origin', '*')
                self.send_header('Access-Control-Allow-Methods', 'GET, POST, OPTIONS')
                self.send_header('Access-Control-Allow-Headers', 'Content-Type, Authorization')
                self.end_headers()

            def do_GET(self):
                if self.path == '/v1/models':
                    models = []
                    if hasattr(brain, 'councilors'):
                        for i, c in enumerate(brain.councilors):
                            if getattr(c, 'model', None) is not None:
                                models.append({{
                                    "id": f"slot-{{i}}",
                                    "object": "model",
                                    "owned_by": "ouroboros",
                                    "name": getattr(c, 'name', f'slot_{{i}}'),
                                }})
                    self._send_json(200, {{"object": "list", "data": models}})
                elif self.path == '/slots':
                    slots = []
                    if hasattr(brain, 'councilors'):
                        for i, c in enumerate(brain.councilors):
                            slots.append({{
                                "index": i,
                                "name": getattr(c, 'name', f'slot_{{i}}'),
                                "plugged": getattr(c, 'model', None) is not None,
                            }})
                    self._send_json(200, {{"slots": slots}})
                elif self.path == '/health':
                    self._send_json(200, {{"status": "ok"}})
                else:
                    self._send_json(200, {{
                        "status": "ok",
                        "endpoints": ["/v1/chat/completions", "/v1/models", "/slots", "/health"]
                    }})

            def do_POST(self):
                content_length = int(self.headers.get('Content-Length', 0))
                body = self.rfile.read(content_length)
                try:
                    data = json.loads(body) if body else {{}}
                except (json.JSONDecodeError, ValueError):
                    self._send_json(400, {{"error": {{"message": "Invalid JSON"}}}})
                    return

                if self.path == '/v1/chat/completions':
                    self._handle_chat_completions(data)
                elif self.path == '/v1/embeddings':
                    self._handle_embeddings(data)
                else:
                    self._send_json(404, {{"error": {{"message": f"Unknown endpoint: {{self.path}}"}}}})

            def _handle_chat_completions(self, data):
                import time as _api_time
                import hashlib as _api_hash

                messages = data.get("messages", [])
                model = data.get("model", "slot-0")
                max_tokens = data.get("max_tokens", 512)

                # Extract slot from model name: "slot-N" or just N
                slot_idx = 0
                if isinstance(model, str):
                    if model.startswith("slot-"):
                        try:
                            slot_idx = int(model.split("-")[1])
                        except (ValueError, IndexError):
                            pass
                    elif model.isdigit():
                        slot_idx = int(model)

                # Also check query param: ?slot=N
                from urllib.parse import urlparse, parse_qs
                parsed = urlparse(self.path)
                qs = parse_qs(parsed.query)
                if 'slot' in qs:
                    try:
                        slot_idx = int(qs['slot'][0])
                    except (ValueError, IndexError):
                        pass

                try:
                    result_str = _api_invoke(
                        slot=slot_idx,
                        text=messages[-1].get("content", "") if messages else "",
                        mode="generate",
                        max_tokens=max_tokens,
                        messages=messages,
                    )
                    result = json.loads(result_str) if isinstance(result_str, str) else result_str
                    if not isinstance(result, dict):
                        self._send_json(502, {{"error": {{"message": f"invoke_slot returned non-dict response: {{type(result).__name__}}", "type": "upstream_error"}}}})
                        return
                    if result.get("status") == "error" or result.get("error"):
                        self._send_json(502, {{"error": {{"message": str(result.get("error", "unknown model error")), "type": "model_error"}}}})
                        return

                    output_text = result.get("output", "")
                    if not isinstance(output_text, str):
                        output_text = str(output_text)
                    if not output_text.strip():
                        self._send_json(502, {{"error": {{"message": "Model returned empty output", "type": "model_error"}}}})
                        return
                    _ts = int(_api_time.time())
                    _cid = _api_hash.sha256(f"{{slot_idx}}:{{_ts}}".encode()).hexdigest()[:29]

                    self._send_json(200, {{
                        "id": f"chatcmpl-{{_cid}}",
                        "object": "chat.completion",
                        "created": _ts,
                        "model": f"slot-{{slot_idx}}",
                        "choices": [{{
                            "index": 0,
                            "message": {{
                                "role": "assistant",
                                "content": output_text,
                            }},
                            "finish_reason": "stop",
                        }}],
                        "usage": {{
                            "prompt_tokens": sum(len(m.get("content", "").split()) for m in messages),
                            "completion_tokens": len(output_text.split()),
                            "total_tokens": sum(len(m.get("content", "").split()) for m in messages) + len(output_text.split()),
                        }},
                    }})
                except Exception as e:
                    self._send_json(500, {{"error": {{"message": str(e), "type": "server_error"}}}})

            def _handle_embeddings(self, data):
                _input = data.get("input", "")
                if isinstance(_input, list):
                    _input = _input[0] if _input else ""
                try:
                    result_str = embed_text(text=_input)
                    result = json.loads(result_str) if isinstance(result_str, str) else result_str
                    if not isinstance(result, dict):
                        self._send_json(502, {{"error": {{"message": f"embed_text returned non-dict response: {{type(result).__name__}}", "type": "upstream_error"}}}})
                        return
                    if result.get("status") == "error" or result.get("error"):
                        self._send_json(502, {{"error": {{"message": str(result.get("error", "embedding failed")), "type": "model_error"}}}})
                        return
                    embedding = result.get("embedding", [])
                    self._send_json(200, {{
                        "object": "list",
                        "data": [{{
                            "object": "embedding",
                            "index": 0,
                            "embedding": embedding,
                        }}],
                        "model": "capsule-embedder",
                        "usage": {{"prompt_tokens": len(_input.split()), "total_tokens": len(_input.split())}},
                    }})
                except Exception as e:
                    self._send_json(500, {{"error": {{"message": str(e)}}}})

        def run_server():
            server = http.server.HTTPServer(('0.0.0.0', port), APIHandler)
            server.serve_forever()

        thread = threading.Thread(target=run_server, daemon=True)
        thread.start()

        return json.dumps({{
            "status": "ok",
            "port": port,
            "endpoints": [
                f"http://localhost:{{port}}/v1/chat/completions",
                f"http://localhost:{{port}}/v1/embeddings",
                f"http://localhost:{{port}}/v1/models",
                f"http://localhost:{{port}}/slots",
                f"http://localhost:{{port}}/health"
            ]
        }})

