    @logged_tool()
    def debate(text: str, rounds: int = 3) -> str:
        \"\"\"Run multi-round debate among council members.

        Args:
            text: Topic/input for debate
            rounds: Number of debate rounds

        Returns:
            JSON with debate transcript
        \"\"\"
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        if not hasattr(brain, 'councilors'):
            return json.dumps({{"error": "No council for debate"}})

        transcript = []
        current_input = text

        for round_num in range(rounds):
            round_entries = []
            for i, c in enumerate(brain.councilors):
                model = getattr(c, 'model', None)
                name = getattr(c, 'name', f'slot_{{i}}')
                if not model:
                    continue
                _lim = getattr(c, '_limits', getattr(model, '_limits', {{}}))
                _ctx = _lim.get('context_length', 4096)
                _gen = _lim.get('max_gen_tokens', 256)
                try:
                    if hasattr(model, 'encode'):
                        emb = model.encode(current_input)
                        vote = float(np.mean(emb))
                        round_entries.append({{"councilor": name, "type": "embedding", "vote": vote}})
                    elif hasattr(model, 'generate'):
                        tokenizer = getattr(c, 'tokenizer', None)
                        if tokenizer:
                            _raw = getattr(model, 'model', model)
                            if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                                _sys = _council_system_prompt(i, brain)
                                _msgs = [{{"role": "system", "content": _sys}}, {{"role": "user", "content": current_input}}]
                                _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                                inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                            else:
                                inputs = tokenizer(current_input, return_tensors="pt", truncation=True, max_length=_ctx)
                            _in_len = inputs['input_ids'].shape[-1]
                            outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                            response = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                        else:
                            try:
                                response = model.generate(prompt=current_input, max_tokens=_gen)
                            except TypeError:
                                response = model.generate(current_input)
                            response = str(response)
                        round_entries.append({{"councilor": name, "type": "generation", "response": response[:200]}})
                    elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                        _h = hash(current_input) % 1000 / 1000.0
                        round_entries.append({{"councilor": name, "type": "reranker_hash", "vote": _h}})
                    elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                        fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                        result = fn(current_input)
                        round_entries.append({{"councilor": name, "type": "classification", "response": str(result)[:200]}})
                    elif callable(model):
                        result = model(current_input)
                        round_entries.append({{"councilor": name, "type": "forward", "response": str(result)[:200]}})
                except Exception as e:
                    round_entries.append({{"councilor": name, "error": str(e)}})

            transcript.append({{"round": round_num + 1, "entries": round_entries}})
            # For subsequent rounds, summarize previous round as context
            if round_entries:
                summaries = [e.get('response', str(e.get('vote', '')))[:80] for e in round_entries]
                current_input = f"Round {{round_num+1}} responses: {{'; '.join(summaries)}}. Original topic: {{text}}"

        return json.dumps({{"topic": text, "rounds": rounds, "transcript": transcript}}, indent=2)

