    @logged_tool()
    def chain(text: str, slot_sequence: Optional[list] = None) -> str:
        \"\"\"Chain inference through specific slots in sequence.

        Args:
            text: Initial input text
            slot_sequence: List of slot indices to chain through

        Returns:
            JSON with chain results
        \"\"\"
        if not slot_sequence:
            return json.dumps({{"error": "slot_sequence must contain at least one slot index", "hint": "Example: chain(text='Hello', slot_sequence=[0, 1])"}})
        agent = get_agent()
        outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
        brain = getattr(outer_brain, '_brain', outer_brain)

        if not hasattr(brain, 'councilors'):
            return json.dumps({{"error": "No council for chaining"}})

        current = text
        trace = [{{"slot": "input", "value": current}}]

        for slot_idx in slot_sequence:
            if slot_idx >= len(brain.councilors):
                trace.append({{"slot": slot_idx, "error": "invalid slot"}})
                continue

            c = brain.councilors[slot_idx]
            model = getattr(c, 'model', None)
            name = getattr(c, 'name', f'slot_{{slot_idx}}')

            if not model:
                trace.append({{"slot": slot_idx, "name": name, "status": "empty"}})
                continue
            _lim = getattr(c, '_limits', getattr(model, '_limits', {{}}))
            _ctx = _lim.get('context_length', 4096)
            _gen = _lim.get('max_gen_tokens', 256)
            try:
                if hasattr(model, 'encode'):
                    emb = model.encode(current)
                    current = str(emb[:5].tolist()) if hasattr(emb, 'tolist') else str(emb)[:100]
                    trace.append({{"slot": slot_idx, "name": name, "type": "embed", "preview": current[:50]}})
                elif hasattr(model, 'generate'):
                    tokenizer = getattr(c, 'tokenizer', None)
                    if tokenizer:
                        _raw = getattr(model, 'model', model)
                        if hasattr(tokenizer, 'apply_chat_template') and getattr(tokenizer, 'chat_template', None):
                            _sys = _council_system_prompt(slot_idx, brain)
                            _msgs = [{{"role": "system", "content": _sys}}, {{"role": "user", "content": current}}]
                            _chat_text = tokenizer.apply_chat_template(_msgs, tokenize=False, add_generation_prompt=True)
                            inputs = tokenizer(_chat_text, return_tensors="pt", truncation=True, max_length=_ctx)
                        else:
                            inputs = tokenizer(current, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        result = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            result = model.generate(prompt=current, max_tokens=_gen)
                        except TypeError:
                            result = model.generate(current)
                        result = str(result)
                    current = result
                    trace.append({{"slot": slot_idx, "name": name, "type": "generate", "output": current[:200]}})
                elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(current) % 1000 / 1000.0
                    current = str(_h)
                    trace.append({{"slot": slot_idx, "name": name, "type": "reranker_hash", "output": current}})
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    result = fn(current)
                    current = str(result)
                    trace.append({{"slot": slot_idx, "name": name, "type": "classification", "output": current[:200]}})
                elif callable(model):
                    result = model(current)
                    current = str(result)
                    trace.append({{"slot": slot_idx, "name": name, "type": "forward", "output": current[:200]}})
                else:
                    trace.append({{"slot": slot_idx, "name": name, "status": "unsupported"}})
            except Exception as e:
                trace.append({{"slot": slot_idx, "name": name, "error": str(e)}})

        return json.dumps({{"input": text, "chain": slot_sequence, "trace": trace}}, indent=2)

    @logged_tool()
    def all_slots(text: str) -> str:
        \"\"\"Broadcast text to ALL slots and collect responses.

