                        else:
                            inputs = tokenizer(text, return_tensors="pt", truncation=True, max_length=_ctx)
                        _in_len = inputs['input_ids'].shape[-1]
                        outputs = _raw.generate(**inputs, max_new_tokens=_gen, pad_token_id=tokenizer.eos_token_id)
                        response = tokenizer.decode(outputs[0][_in_len:], skip_special_tokens=True)
                    else:
                        try:
                            response = model.generate(prompt=text, max_tokens=_gen)
                        except TypeError:
                            response = model.generate(text)
                        response = str(response)
                    responses.append({{"slot": i, "name": name, "type": "generation", "output": response[:200]}})
                elif getattr(model, '_model_type_hint', None) == 'RERANKER':
                    _h = hash(text) % 1000 / 1000.0
                    responses.append({{"slot": i, "name": name, "type": "reranker_hash", "output": str(_h)}})
                elif hasattr(model, 'predict') or hasattr(model, 'classify'):
                    fn = getattr(model, 'predict', None) or getattr(model, 'classify', None)
                    result = fn(text)
                    responses.append({{"slot": i, "name": name, "type": "classification", "output": str(result)[:200]}})
                elif callable(model):
                    result = model(text)
                    responses.append({{"slot": i, "name": name, "type": "forward", "output": str(result)[:200]}})
                else:
                    responses.append({{"slot": i, "name": name, "type": "unknown"}})
            except Exception as e:
                responses.append({{"slot": i, "name": name, "error": str(e)}})

        return json.dumps({{"input": text, "responses": responses}}, indent=2)

