    @logged_tool()
    def import_brain(path: str) -> str:
        \"\"\"Import brain state from file.

        Args:
            path: Path to brain file (.pkl or .pt)

        Returns:
            JSON with import status
        \"\"\"
        import torch
        from pathlib import Path as PathLib

        # Resolve relative paths against the script directory
        path_obj = PathLib(path)
        if not path_obj.is_absolute():
            # Try relative to script location first
            script_dir = PathLib(__file__).parent
            resolved = script_dir / path_obj
            if resolved.exists():
                path_obj = resolved
            # Otherwise try current working directory (default behavior)

        if not path_obj.exists():
            return json.dumps({{"error": f"File not found: {{path_obj}}"}})

        try:
            # Try torch.load first (our new save format)
            if path_obj.suffix == '.pt':
                # Use weights_only=False since we're loading our own checkpoints with numpy arrays
                data = torch.load(path_obj, map_location='cpu', weights_only=False)
                agent = get_agent()
                outer_brain = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
                brain = getattr(outer_brain, '_brain', outer_brain)

                # Restore params
                if 'params' in data and hasattr(brain, '_params'):
                    brain._params = np.array(data['params'])
                if 'lora_A' in data and hasattr(brain, 'lora_A'):
                    brain.lora_A = np.array(data['lora_A'])
                if 'lora_B' in data and hasattr(brain, 'lora_B'):
                    brain.lora_B = np.array(data['lora_B'])

                return json.dumps({{"status": "ok", "loaded": str(path_obj), "keys": list(data.keys())}})
            else:
                # Fallback to pickle for .pkl files
                import pickle
                with open(path_obj, 'rb') as f:
                    data = pickle.load(f)

                agent = get_agent()
                if hasattr(data, '_brain'):
                    agent._brain = data._brain
                elif hasattr(data, 'brain'):
                    agent._brain = data.brain

                return json.dumps({{"status": "ok", "loaded": str(path_obj)}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

