    def _asset_matches_filters(entry, src_lower, tag_set, lic_lower, fmt_lower):
        \"\"\"Check if an asset entry matches the given filters.\"\"\"
        if src_lower and str(entry.get('source', '')).lower() != src_lower:
            return False
        if lic_lower and str(entry.get('license', '')).lower() != lic_lower:
            return False
        if fmt_lower and str(entry.get('format', '')).lower() != fmt_lower:
            return False
        if tag_set:
            entry_tags = set(t.strip().lower() for t in str(entry.get('tags', '')).split(',') if t.strip())
            if not tag_set.intersection(entry_tags):
                return False
        return True

    def _asset_entry_from_bag_item(item):
        \"\"\"Decode and parse one asset entry from FelixBag storage.\"\"\"
        if not isinstance(item, dict):
            return None
        try:
            raw = _bag_item_text(item)
        except Exception:
            raw = item.get('content', '')
        if isinstance(raw, dict):
            return raw
        if raw in (None, ''):
            return None
        try:
            return json.loads(raw)
        except Exception:
            return None

    @logged_tool()
    def asset_search(query: str = "", source: str = "", tags: str = "", license: str = "", format: str = "", limit: int = 20) -> str:
        \"\"\"Search the CC0 asset registry by query and filters.

        Args:
            query: Semantic search text (optional - if empty, lists all and applies filters)
            source: Filter by source (kenney, quaternius, polyhaven, ambientcg)
            tags: Comma-separated tag filter (nature, space, buildings, etc.)
            license: License filter (CC0, CC-BY, etc.)
            format: File format filter (glb, gltf, hdr, png, etc.)
            limit: Max results (default 20)

        Returns:
            JSON with matching asset entries
        \"\"\"
        try:
            populate_bag_with_embedded()
        except Exception:
            pass
        results = []
        seen = set()
        tag_set = set(t.strip().lower() for t in tags.split(',') if t.strip()) if tags else set()
        src_lower = source.strip().lower() if source else ""
        lic_lower = license.strip().lower() if license else ""
        fmt_lower = format.strip().lower() if format else ""

        if query and query.strip() and hasattr(_BAG, 'search'):
            raw = _BAG.search(query, top_k=max(limit * 5, limit))
            for row in raw:
                if isinstance(row, (list, tuple)):
                    rname = str(row[1] if len(row) > 1 else (row[0] if len(row) > 0 else ''))
                elif isinstance(row, dict):
                    rname = str(row.get('name', '') or row.get('key', '') or row.get('id', ''))
                else:
                    rname = str(row)
                if not rname.startswith('asset_pack:'):
                    continue
                try:
                    _eid, _eitem = _bag_find_item(rname)
                    if not _eitem:
                        continue
                    entry = _asset_entry_from_bag_item(_eitem)
                    if not entry:
                        continue
                    entry_id = str(entry.get('id', rname))
                    if entry_id in seen:
                        continue
                    if _asset_matches_filters(entry, src_lower, tag_set, lic_lower, fmt_lower):
                        results.append(entry)
                        seen.add(entry_id)
                except Exception:
                    continue
        else:
            query_lower = query.strip().lower() if query else ""
            for _iid, _item in _BAG._bag.items():
                _name = str(_item.get('name', ''))
                if not _name.startswith('asset_pack:'):
                    continue
                try:
                    entry = _asset_entry_from_bag_item(_item)
                    if not entry:
                        continue
                    if not _asset_matches_filters(entry, src_lower, tag_set, lic_lower, fmt_lower):
                        continue
                    entry_id = str(entry.get('id', _name))
                    if entry_id in seen:
                        continue
                    if query_lower:
                        haystack = " ".join([
                            str(entry.get('id', '')),
                            str(entry.get('name', '')),
                            str(entry.get('description', '')),
                            str(entry.get('tags', '')),
                            str(entry.get('source', '')),
                        ]).lower()
                        if query_lower not in haystack:
                            continue
                    results.append(entry)
                    seen.add(entry_id)
                except Exception:
                    continue

        results = results[:limit]
        return json.dumps({{"query": query, "filters": {{"source": source, "tags": tags, "license": license, "format": format}}, "count": len(results), "results": results}}, indent=2)

    @logged_tool()
    def asset_register(name: str, source: str, license: str = "CC0", url: str = "", author: str = "", tags: str = "", format: str = "glb", style: str = "", poly_budget: str = "", preview_url: str = "", download_url: str = "", download_mode: str = "direct_file", download_ext: str = "", description: str = "") -> str:
        \"\"\"Register an asset or pack in the CC0 asset registry.

        Args:
            name: Asset/pack name (required)
            source: Source identifier - kenney, quaternius, polyhaven, ambientcg, or custom (required)
            license: License - CC0, CC-BY, CC-BY-SA, etc. (default CC0)
            url: Download or source URL
            author: Author/creator name
            tags: Comma-separated tags
            format: File format - glb, gltf, obj, hdr, png, etc. (default glb)
            style: Visual style - low-poly, realistic, stylized
            poly_budget: Polygon budget - low, medium, high
            preview_url: Preview image URL
            download_url: Direct download URL (if different from source page url)
            download_mode: How to acquire - direct_file, archive, or catalog_only (default direct_file)
            download_ext: Expected file extension of download (e.g. .zip, .glb)
            description: Human-readable description

        Returns:
            Confirmation JSON
        \"\"\"
        if not name or not source:
            return json.dumps({{"error": "name and source are required"}})

        clean_name = name.strip().lower().replace(' ', '-')
        clean_source = source.strip().lower()
        asset_id = f"{{clean_source}}/{{clean_name}}"
        bag_key = f"asset_pack:{{clean_source}}:{{clean_name}}"

        from datetime import datetime as _dt
        entry = {{
            "id": asset_id,
            "source": clean_source,
            "name": name.strip(),
            "description": description,
            "license": license.strip() or "CC0",
            "author": author.strip(),
            "tags": tags,
            "format": format.strip().lower(),
            "style": style.strip().lower(),
            "poly_budget": poly_budget.strip().lower(),
            "url": url.strip(),
            "preview_url": preview_url.strip(),
            "download_url": download_url.strip(),
            "download_mode": download_mode.strip().lower() or "direct_file",
            "download_ext": download_ext.strip(),
            "registered_at": _dt.now().isoformat()
        }}

        if hasattr(_BAG, 'induct'):
            _BAG.induct(
                bag_key,
                json.dumps(entry),
                item_type='asset_catalog',
                tags=['asset', clean_source, str(entry.get('license', 'CC0')).strip()]
            )
        elif hasattr(_BAG, 'put'):
            _BAG.put(bag_key, json.dumps(entry))
        else:
            _BAG._bag[bag_key] = json.dumps(entry)

        return json.dumps({{"status": "ok", "key": bag_key, "asset_id": asset_id}})

    @logged_tool()
    def asset_download(asset_key: str, destination: str = "") -> str:
        \"\"\"Download an asset file from the registry to local cache.

        Args:
            asset_key: FelixBag key (e.g. 'asset_pack:kenney:nature-kit') or asset ID (e.g. 'kenney/nature-kit')
            destination: Local file path (optional - defaults to .asset_cache/<source>/<filename>)

        Returns:
            JSON with local file path or error
        \"\"\"
        import urllib.request
        import os

        if '/' in asset_key and not asset_key.startswith('asset_pack:'):
            parts = asset_key.split('/', 1)
            asset_key = f"asset_pack:{{parts[0]}}:{{parts[1]}}"

        _eid, _eitem = _bag_find_item(asset_key)
        if not _eitem:
            return json.dumps({{"error": f"Asset not found: {{asset_key}}", "hint": "Use asset_search or asset_list to find available assets"}})

        try:
            meta = _asset_entry_from_bag_item(_eitem)
            if not meta:
                raise ValueError("empty asset metadata")
        except Exception:
            return json.dumps({{"error": "Could not parse asset metadata"}})

        dl_mode = meta.get('download_mode', 'direct_file')
        if dl_mode == 'catalog_only':
            source = meta.get('source', 'unknown')
            return json.dumps({{
                "error": f"This is a catalog source ({{source}}) — individual items must be fetched via its API, not as a single pack download.",
                "source": source,
                "source_url": meta.get('url', ''),
                "hint": f"Use asset_register to add specific items from {{source}} with their direct download URLs."
            }})

        dl_url = meta.get('download_url', '') or meta.get('url', '')
        if not dl_url:
            return json.dumps({{"error": "Asset has no download URL", "asset": asset_key, "hint": "Register a download_url with asset_register."}})

        using_fallback = not meta.get('download_url', '') and dl_url == meta.get('url', '')
        if using_fallback and dl_mode == 'archive':
            return json.dumps({{
                "error": "No direct download URL available for this archive pack.",
                "source_url": dl_url,
                "download_mode": dl_mode,
                "hint": "Download the pack manually from the source page. Then use asset_register with download_url set to the local file path or a direct URL."
            }})

        if not destination:
            cache_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), '.asset_cache', meta.get('source', 'unknown'))
            os.makedirs(cache_dir, exist_ok=True)
            dl_ext = meta.get('download_ext', '')
            asset_name = meta.get('name', 'asset').replace(' ', '_')
            if dl_ext:
                filename = f"{{asset_name}}{{dl_ext}}"
            else:
                url_tail = dl_url.split('/')[-1].split('?')[0]
                if '.' in url_tail and len(url_tail) < 100:
                    filename = url_tail
                else:
                    fmt = meta.get('format', 'glb')
                    filename = f"{{asset_name}}.{{fmt}}"
            destination = os.path.join(cache_dir, filename)
        else:
            parent = os.path.dirname(destination)
            if parent:
                os.makedirs(parent, exist_ok=True)

        if os.path.isfile(dl_url) or dl_url.startswith('file://'):
            import shutil
            _local_src = dl_url.replace('file:///', '').replace('file://', '') if dl_url.startswith('file://') else dl_url
            if not os.path.isfile(_local_src):
                return json.dumps({{"error": f"Local file not found: {{_local_src}}"}})
            shutil.copy2(_local_src, destination)
            return json.dumps({{"status": "ok", "path": destination, "source_path": _local_src, "size": os.path.getsize(destination), "download_mode": dl_mode}})

        try:
            _req = urllib.request.urlopen(dl_url, timeout=30)
            _ct = _req.headers.get('Content-Type', '')
            if 'text/html' in _ct:
                _req.close()
                return json.dumps({{
                    "error": "URL returned Content-Type text/html — this is a landing page, not a binary asset.",
                    "url": dl_url,
                    "content_type": _ct,
                    "hint": "Use asset_register to set a direct download_url."
                }})
            with open(destination, 'wb') as _out:
                _head = _req.read(512)
                if b'<html' in _head.lower() or b'<!doctype' in _head.lower():
                    _req.close()
                    return json.dumps({{
                        "error": "Downloaded content appears to be HTML despite Content-Type.",
                        "url": dl_url,
                        "hint": "The URL may be a landing page. Use asset_register to set a direct download_url."
                    }})
                _out.write(_head)
                while True:
                    _chunk = _req.read(65536)
                    if not _chunk:
                        break
                    _out.write(_chunk)
            _req.close()
            fsize = os.path.getsize(destination)
            return json.dumps({{"status": "ok", "path": destination, "url": dl_url, "size": fsize, "download_mode": dl_mode}})
        except Exception as e:
            if os.path.exists(destination):
                try:
                    os.remove(destination)
                except Exception:
                    pass
            return json.dumps({{"error": str(e), "url": dl_url, "hint": "Check URL accessibility or try manually"}})

    @logged_tool()
    def asset_list(source: str = "", license: str = "", format: str = "", style: str = "", page: int = 1, limit: int = 20) -> str:
        \"\"\"List registered assets with optional filters.

        Args:
            source: Filter by source (kenney, quaternius, polyhaven, ambientcg)
            license: Filter by license (CC0, CC-BY, etc.)
            format: Filter by format (glb, hdr, png, etc.)
            style: Filter by style (low-poly, realistic, etc.)
            page: Page number (default 1)
            limit: Results per page (default 20)

        Returns:
            JSON with paginated asset list
        \"\"\"
        try:
            populate_bag_with_embedded()
        except Exception:
            pass

        all_entries = []
        src_lower = source.strip().lower() if source else ""
        lic_lower = license.strip().lower() if license else ""
        fmt_lower = format.strip().lower() if format else ""
        sty_lower = style.strip().lower() if style else ""

        for _iid, _item in _BAG._bag.items():
            _name = str(_item.get('name', ''))
            if not _name.startswith('asset_pack:'):
                continue
            try:
                entry = _asset_entry_from_bag_item(_item)
                if not entry:
                    continue
                if src_lower and str(entry.get('source', '')).lower() != src_lower:
                    continue
                if lic_lower and str(entry.get('license', '')).lower() != lic_lower:
                    continue
                if fmt_lower and str(entry.get('format', '')).lower() != fmt_lower:
                    continue
                if sty_lower and str(entry.get('style', '')).lower() != sty_lower:
                    continue
                all_entries.append(entry)
            except Exception:
                continue

        all_entries.sort(key=lambda e: (e.get('source', ''), e.get('name', '')))
        start = (page - 1) * limit
        page_entries = all_entries[start:start + limit]

        return json.dumps({{
            "total": len(all_entries),
            "page": page,
            "limit": limit,
            "pages": (len(all_entries) + limit - 1) // limit if all_entries else 0,
            "assets": page_entries
        }}, indent=2)

