    def _cascade_parse_input(raw):
        """Parse JSON-looking signal payloads while preserving plain text."""
        if not isinstance(raw, str):
            return raw
        text = raw.strip()
        if not text:
            return raw
        if text[:1] not in ('{{', '['):
            return raw
        try:
            return json.loads(text)
        except Exception:
            return raw

    def _cascade_json_ready(value, depth: int = 0):
        """Convert cascade objects into JSON-safe structures."""
        if depth > 6:
            return str(value)
        if value is None or isinstance(value, (str, int, float, bool)):
            return value
        if hasattr(value, 'to_dict'):
            try:
                return _cascade_json_ready(value.to_dict(), depth + 1)
            except Exception:
                pass
        if isinstance(value, dict):
            return {{str(k): _cascade_json_ready(v, depth + 1) for k, v in value.items()}}
        if isinstance(value, (list, tuple, set)):
            return [_cascade_json_ready(v, depth + 1) for v in value]
        if hasattr(value, '__dict__'):
            try:
                return {{
                    str(k): _cascade_json_ready(v, depth + 1)
                    for k, v in vars(value).items()
                    if not str(k).startswith('_')
                }}
            except Exception:
                pass
        return str(value)

    def _get_default_cascade_graph():
        """Restore the shared default causation graph and replay observed history."""
        import time
        from cascade.core.graph import CausationGraph
        from cascade.core.event import Event as CEvt, CausationLink as CLink

        g = None
        last_event_id = None

        try:
            if 'cascade_graph' in globals():
                _graphs = getattr(cascade_graph, '_g', None)
                if isinstance(_graphs, dict):
                    g = _graphs.get('default')
        except Exception:
            g = None

        if g is None:
            try:
                _bv = _BAG.get("cascade_graph:default")
                if _bv:
                    _gd = json.loads(_bv) if isinstance(_bv, str) else _bv
                    g = CausationGraph()
                    for ed in _gd.get("events", []):
                        try:
                            g.add_event(CEvt.from_dict(ed))
                        except Exception:
                            pass
                    for ld in _gd.get("links", []):
                        try:
                            g.add_link(CLink.from_dict(ld))
                        except Exception:
                            pass
            except Exception:
                g = None

        if g is None:
            g = CausationGraph()

        try:
            _events = list(getattr(g, '_events', {{}}).values())
            if _events:
                _events.sort(key=lambda e: float(getattr(e, 'timestamp', 0.0) or 0.0))
                last_event_id = _events[-1].event_id
        except Exception:
            last_event_id = None

        agent = get_agent()
        observations = getattr(agent, '_observations', [])
        try:
            known = set(getattr(g, '_events', {{}}).keys())
        except Exception:
            known = set()

        for obs in observations:
            if not isinstance(obs, dict):
                continue
            obs_event_id = str(obs.get('event_id') or obs.get('receipt') or '').strip()
            if obs_event_id and obs_event_id in known:
                last_event_id = obs_event_id
                continue

            payload = _cascade_parse_input(obs.get('data'))
            evt_data = payload if isinstance(payload, dict) else {{"message": str(payload)}}
            evt_component = str(evt_data.get('component') or evt_data.get('tool') or evt_data.get('route') or 'observe')
            evt_type = str(obs.get('type') or evt_data.get('event_type') or evt_data.get('type') or 'observation')
            evt_kwargs = {{
                "timestamp": float(obs.get('timestamp') or time.time()),
                "component": evt_component,
                "event_type": evt_type,
                "data": evt_data,
            }}
            if obs_event_id:
                evt_kwargs["event_id"] = obs_event_id

            try:
                evt = CEvt(**evt_kwargs)
                g.add_event(evt)
            except Exception:
                continue

            if last_event_id and last_event_id != evt.event_id:
                try:
                    g.add_link(CLink(
                        from_event=last_event_id,
                        to_event=evt.event_id,
                        causation_type="temporal",
                        strength=1.0,
                        explanation="Observed after prior event"
                    ))
                except Exception:
                    pass

            last_event_id = evt.event_id
            known.add(evt.event_id)

        return g, last_event_id

    def _persist_default_cascade_graph(g):
        """Persist the shared default graph to in-memory and FelixBag mirrors."""
        try:
            if 'cascade_graph' in globals():
                if not hasattr(cascade_graph, '_g') or not isinstance(cascade_graph._g, dict):
                    cascade_graph._g = {{}}
                cascade_graph._g['default'] = g
        except Exception:
            pass
        try:
            _gd = {{
                "events": [e.to_dict() for e in getattr(g, '_events', {{}}).values()],
                "links": [l.to_dict() for l in getattr(g, '_links', [])],
            }}
            _BAG.induct(
                "cascade_graph:default",
                json.dumps(_gd),
                item_type='state',
                preview="Persisted default causation graph"
            )
        except Exception:
            pass

    @logged_tool()
    def observe(data: str, signal_type: str = "generic") -> str:
        \"\"\"Universal signal observation port - log data to CASCADE.

        Args:
            data: Data to observe/log
            signal_type: Type of signal ('generic', 'metric', 'event', 'error')

        Returns:
            JSON with observation receipt
        \"\"\"
        import time
        import hashlib

        receipt = hashlib.sha256(f"{{time.time()}}:{{data}}".encode()).hexdigest()[:16]

        # Log to cascade if available
        observation = {{
            "timestamp": time.time(),
            "type": signal_type,
            "data": data,
            "receipt": receipt,
            "event_id": receipt
        }}

        # Store in agent's observation log
        agent = get_agent()
        if not hasattr(agent, '_observations'):
            agent._observations = []
        agent._observations.append(observation)

        if _CASCADE_AVAILABLE:
            try:
                g, _ = _get_default_cascade_graph()
                _persist_default_cascade_graph(g)
            except Exception:
                pass

        return json.dumps({{"status": "ok", "receipt": receipt, "type": signal_type, "event_id": receipt}})

    @logged_tool()
    def feed(n: int = 10) -> str:
        \"\"\"Show recent CASCADE events/observations.

        Args:
            n: Number of events to show

        Returns:
            JSON with recent events
        \"\"\"
        agent = get_agent()
        observations = getattr(agent, '_observations', [])
        recent = observations[-n:] if observations else []

        obs_buffer_events = []
        try:
            _outer = agent._brain if hasattr(agent, '_brain') else getattr(agent, 'brain', None)
            _br = getattr(_outer, '_brain', _outer) if _outer is not None else None
            if _br is not None and hasattr(_br, '_obs_buffer'):
                buf = _br._obs_buffer
                buf_recent = list(buf)[-n:]
                for i, (prev_emb, act, cur_emb) in enumerate(buf_recent):
                    obs_buffer_events.append({{
                        "type": "obs_transition",
                        "index": len(buf) - len(buf_recent) + i,
                        "prev_emb_norm": float(np.linalg.norm(prev_emb)),
                        "action_sample": act[:4].tolist() if hasattr(act, 'tolist') else list(act)[:4],
                        "cur_emb_norm": float(np.linalg.norm(cur_emb))
                    }})
        except Exception:
            pass

        return json.dumps({{
            "total_observations": len(observations),
            "showing": len(recent),
            "events": recent,
            "obs_buffer_size": len(obs_buffer_events),
            "obs_buffer_events": obs_buffer_events
        }}, indent=2)

