    @logged_tool()
    def trace_root_causes(event_description: str) -> str:
        \"\"\"Use CASCADE Tracer to find root causes of an issue.

        Args:
            event_description: Description of the event/issue to trace

        Returns:
            JSON with root cause analysis
        \"\"\"
        try:
            from cascade import Tracer
            import time
            from cascade.core.event import Event as CEvt, CausationLink as CLink

            graph, last_event_id = _get_default_cascade_graph()
            tracer = Tracer(graph)
            parsed_event = _cascade_parse_input(event_description)

            target_event_id = str(event_description or '').strip()
            try:
                if target_event_id not in getattr(graph, '_events', {{}}):
                    target_event_id = ""
            except Exception:
                target_event_id = ""

            if not target_event_id:
                evt_data = parsed_event if isinstance(parsed_event, dict) else {{"description": str(event_description)}}
                existing_id = str(evt_data.get('event_id') or '').strip() if isinstance(evt_data, dict) else ""
                if existing_id and existing_id in getattr(graph, '_events', {{}}):
                    target_event_id = existing_id
                else:
                    evt_kwargs = {{
                        "timestamp": time.time(),
                        "component": str(evt_data.get('component') or evt_data.get('tool') or evt_data.get('route') or 'trace_request'),
                        "event_type": str(evt_data.get('event_type') or evt_data.get('type') or 'issue'),
                        "data": evt_data,
                    }}
                    if existing_id:
                        evt_kwargs["event_id"] = existing_id
                    event = CEvt(**evt_kwargs)
                    graph.add_event(event)
                    if last_event_id and last_event_id != event.event_id:
                        try:
                            graph.add_link(CLink(
                                from_event=last_event_id,
                                to_event=event.event_id,
                                causation_type="temporal",
                                strength=1.0,
                                explanation="Trace request follows prior observed event"
                            ))
                        except Exception:
                            pass
                    target_event_id = event.event_id
                    _persist_default_cascade_graph(graph)

            analysis = tracer.find_root_causes(target_event_id)
            root_causes = list(getattr(analysis, 'root_causes', []) or [])
            if not root_causes:
                try:
                    root_causes = graph.get_causes(target_event_id, max_depth=20) or []
                except Exception:
                    root_causes = []
            return json.dumps({{
                "event": event_description,
                "target_event_id": target_event_id,
                "root_causes": _cascade_json_ready(root_causes) if root_causes else ["No prior events to trace"],
                "trace_depth": len(root_causes) if root_causes else 0,
                "history_events": len(getattr(graph, '_events', {{}})),
                "history_links": len(getattr(graph, '_links', [])),
                "narrative": getattr(analysis, 'narrative', '')
            }}, indent=2)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def forensics_analyze(data: str) -> str:
        \"\"\"Run CASCADE forensics analysis on data.

        Uses DataForensics and ArtifactDetector to analyze data for
        patterns, fingerprints, and inferred operations.

        Args:
            data: Text/JSON data to analyze

        Returns:
            JSON with forensics report
        \"\"\"
        try:
            from cascade.forensics import DataForensics

            forensics = DataForensics()
            parsed = _cascade_parse_input(data)

            # Convert input to DataFrame for forensics analysis
            import pandas as pd
            input_mode = "text"
            try:
                if isinstance(parsed, list):
                    df = pd.DataFrame(parsed)
                    input_mode = "records" if parsed and all(isinstance(row, dict) for row in parsed) else "list"
                elif isinstance(parsed, dict):
                    df = pd.DataFrame([parsed])
                    input_mode = "dict"
                else:
                    df = pd.DataFrame({{"text": [str(data)]}})
            except (json.JSONDecodeError, ValueError, TypeError):
                df = pd.DataFrame({{"text": [data]}})

            try:
