                "data_preview": data[:1000],
                "report": str(report)[:2000]
            }}, indent=2)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def hold_yield(reason: str, data: str = "") -> str:
        \"\"\"Create a HOLD yield point for human inspection.

        This pauses inference and yields to human oversight.
        The human can inspect, modify, or approve the data.

        Args:
            reason: Why this hold point was triggered
            data: Data to present for inspection

        Returns:
            JSON with hold status
        \"\"\"
        try:
            import numpy as np
            import time as _hold_time
            from cascade import Hold

            hold = Hold.get()
            if not hasattr(hold, '_mcp_pending_holds'):
                hold._mcp_pending_holds = {{}}

            # Try to get dreamer decision matrix
            _decision_matrix = None
            _hold_kwargs = {{
                'action_probs': np.array([1.0, 0.0]),
                'value': 0.0,
                'observation': {{"reason": reason, "data": data, "source": "mcp"}},
                'brain_id': "mcp_hold",
                'action_labels': ["approve", "reject"],
                'reasoning': [reason] if reason else None,
                # Non-blocking by default so MCP callers don't deadlock waiting for a UI listener.
                'blocking': False,
            }}
            try:
                _ra = get_agent()
                _ro = _ra._brain if hasattr(_ra, '_brain') else getattr(_ra, 'brain', None)
                _rb = getattr(_ro, '_brain', _ro) if _ro else None
                if _rb and hasattr(_rb, '_dreamer_hold_point'):
                    _dhp = _rb._dreamer_hold_point()
                    if _dhp is not None:
                        _hold_kwargs['action_probs'] = _dhp['action_probs']
                        _hold_kwargs['value'] = _dhp['value']
                        if _dhp.get('imagination'):
                            _hold_kwargs['imagination'] = _dhp['imagination']
                        if _dhp.get('world_prediction'):
                            _hold_kwargs['world_prediction'] = _dhp['world_prediction']
                        if _dhp.get('reasoning'):
                            _hold_kwargs['reasoning'] = _dhp['reasoning']
                        if _dhp.get('action_labels'):
                            _hold_kwargs['action_labels'] = _dhp['action_labels']
                        if _dhp.get('features'):
                            _hold_kwargs['features'] = _dhp['features']
                        _hold_kwargs['blocking'] = _dhp.get('blocking', False)

                        # Build decision matrix for response
                        _ap = _dhp['action_probs']
                        _best = int(np.argmax(_ap))
                        _labels = _dhp.get('action_labels', [])
                        _actions_summary = {{}}
                        for _i in range(len(_ap)):
                            _actions_summary[_i] = {{
                                'label': _labels[_i] if _i < len(_labels) else f"action_{{_i}}",
                                'value': round(float(_ap[_i]), 4),
                                'confidence': round(float(_ap[_i]), 4),
                            }}
                        _decision_matrix = {{
                            'action_count': len(_ap),
                            'best_action': _best,
                            'best_action_label': _labels[_best] if _best < len(_labels) else f"action_{{_best}}",
                            'best_value': _dhp['value'],
                            'confidence': round(float(_ap[_best]), 4),
                            'actions': _actions_summary,
                            'imagination_available': _dhp.get('imagination') is not None,
                            'world_prediction': _dhp.get('world_prediction'),
                        }}
            except Exception:
                pass

            resolution = hold.yield_point(**_hold_kwargs)

            _hold_point = getattr(resolution, 'hold_point', None)
            _hold_id = None
            _merkle = None
            _ai_choice = None
            _ai_conf = None
            if _hold_point is not None:
                _hold_id = getattr(_hold_point, 'id', None)
                _merkle = getattr(_hold_point, 'merkle_root', None)
                _ai_conf = getattr(_hold_point, 'ai_confidence', None)
            _ai_choice = getattr(resolution, 'action', None)

            if isinstance(resolution, dict):
                _hold_id = _hold_id or resolution.get('hold_id') or resolution.get('id')
                _merkle = _merkle or resolution.get('merkle')
                if _ai_choice is None:
                    _ai_choice = resolution.get('action', resolution.get('ai_choice'))
                if _ai_conf is None:
                    _ai_conf = resolution.get('ai_confidence')

            if _hold_id is None:
                _hold_id = f"hold_{{int(_hold_time.time() * 1000)}}"

            if _ai_choice is None:
                try:
                    _ap_fallback = _hold_kwargs.get('action_probs')
                    _ai_choice = int(np.argmax(_ap_fallback)) if _ap_fallback is not None else 0
                except Exception:
                    _ai_choice = 0

            if _ai_conf is None:
                try:
                    _ap_fallback = _hold_kwargs.get('action_probs')
                    _ai_conf = float(np.max(_ap_fallback)) if _ap_fallback is not None else 0.0
                except Exception:
                    _ai_conf = 0.0

            hold._mcp_pending_holds[str(_hold_id)] = {{
                'status': 'yielded',
                'reason': reason,
                'data': data,
                'created_ts': _hold_time.time(),
                'blocking': bool(_hold_kwargs.get('blocking', False)),
                'active_at_yield': bool(getattr(hold, 'current_hold', None) is not None),
                'ai_choice': _ai_choice,
                'ai_confidence': float(_ai_conf or 0.0),
                'merkle': _merkle,
            }}
            # Bound memory footprint.
            if len(hold._mcp_pending_holds) > 200:
                _oldest = sorted(hold._mcp_pending_holds.items(), key=lambda kv: float(kv[1].get('created_ts', 0.0)))[:50]
                for _hk, _ in _oldest:
                    hold._mcp_pending_holds.pop(_hk, None)

            _result = {{
                "status": "yielded",
                "hold_id": str(_hold_id),
                "merkle": _merkle,
                "reason": reason,
                "ai_choice": _ai_choice,
                "ai_confidence": round(float(_ai_conf or 0.0), 4),
                "blocking": bool(_hold_kwargs.get('blocking', False)),
                "message": "Hold point created with dreamer decision matrix." if _decision_matrix else "Hold point created. Use hold_resolve to change outcome.",
            }}
            if _decision_matrix:
                _result["decision_matrix"] = _decision_matrix

            return json.dumps(_result, default=str)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def hold_resolve(hold_id: str, action: str = "accept") -> str:
        \"\"\"Resolve a pending HOLD point.

        Args:
            hold_id: ID of the hold to resolve
            action: 'accept', 'override', or 'cancel'

        Returns:
            JSON with resolution result
        \"\"\"
        try:
            import time as _hold_time
            from cascade import Hold

            hold = Hold.get()
            if not hasattr(hold, '_mcp_pending_holds'):
                hold._mcp_pending_holds = {{}}

            _action_raw = str(action or 'accept').strip().lower()
            _action_map = {{
                'accept': 'accept',
                'approve': 'accept',
                'ok': 'accept',
                'override': 'override',
                'reject': 'override',
                'deny': 'override',
                'cancel': 'cancel',
                'abort': 'cancel',
            }}
            _action = _action_map.get(_action_raw)
            if _action is None:
                return json.dumps({{"error": f"Unknown action: {{action}}"}})

            _active = getattr(hold, 'current_hold', None)
            _active_id = None
            if _active is not None:
                try:
                    if isinstance(_active, dict):
                        _active_id = _active.get('id')
                    else:
                        _active_id = getattr(_active, 'id', None)
                except Exception:
                    _active_id = None

            _target_hold_id = str(hold_id or '').strip()
            if not _target_hold_id and _active_id:
                _target_hold_id = str(_active_id)
            if not _target_hold_id:
                return json.dumps({{"error": "hold_id required", "action": _action}})

            _mode = 'recorded'
            _note = None
            if _active is not None and (_active_id is None or str(_active_id) == _target_hold_id):
                if _action == "accept":
                    hold.accept()
                elif _action == "override":
                    hold.override(action=1, source="mcp_override")
                elif _action == "cancel":
                    if hasattr(hold, 'cancel'):
                        hold.cancel()
                    else:
                        hold.resolve(action=0, source='mcp_cancel')
                _mode = 'active'
            else:
                if _target_hold_id not in hold._mcp_pending_holds:
                    return json.dumps({{"error": "No active hold to resolve", "hold_id": _target_hold_id}})
                _note = "Hold is no longer active; resolution recorded for audit parity."

            _pending = hold._mcp_pending_holds.get(_target_hold_id, {{}})
            _pending.update({{
                'status': 'resolved',
                'resolved_action': _action,
                'resolved_ts': _hold_time.time(),
                'resolve_mode': _mode,
            }})
            hold._mcp_pending_holds[_target_hold_id] = _pending

            # Dreamer reward capture on hold resolution
            _dreamer_reward_captured = False
            _reward_source = None
            try:
                _ra = get_agent()
                _ro = _ra._brain if hasattr(_ra, '_brain') else getattr(_ra, 'brain', None)
                _rb = getattr(_ro, '_brain', _ro) if _ro else None
                if _rb and hasattr(_rb, '_capture_reward'):
                    _reward_source = 'hold_override' if _action == "override" else 'hold_accept'
                    _rb._capture_reward(
                        source_key=_reward_source,
                        event_id=_target_hold_id,
                        metadata={{'action': _action, 'hold_id': _target_hold_id, 'mode': _mode}},
                    )
                    _dreamer_reward_captured = True
            except Exception:
                pass

            return json.dumps({{
                "status": "resolved",
                "hold_id": _target_hold_id,
                "action": _action,
                "mode": _mode,
                "note": _note,
                "stats": getattr(hold, 'stats', {{}}),
                "dreamer_reward_captured": _dreamer_reward_captured,
                "reward_source": _reward_source,
            }}, default=str)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def metrics_analyze(metric_name: str, values: list) -> str:
        \"\"\"Analyze a metric series for anomalies and health.

        Uses CASCADE MetricsEngine to classify metrics and detect issues.

        Args:
            metric_name: Name of the metric (e.g., 'loss', 'accuracy')
            values: List of numeric values

        Returns:
            JSON with metric analysis
        \"\"\"
        try:
            import numpy as np
            arr = np.array([float(v) for v in values])
            if len(arr) == 0:
                return json.dumps({{"error": "Empty values list"}})

            _mean = float(arr.mean())
            _std = float(arr.std())
            _min = float(arr.min())
            _max = float(arr.max())

            # Trend detection
            if len(arr) >= 2:
                _trend = "increasing" if arr[-1] > arr[0] else "decreasing" if arr[-1] < arr[0] else "stable"
            else:
                _trend = "insufficient_data"

            # Category inference from metric name
            _name_lower = metric_name.lower()
            if any(k in _name_lower for k in ("loss", "error", "mse", "mae")):
                _category = "loss"
            elif any(k in _name_lower for k in ("accuracy", "acc", "f1", "precision", "recall", "auc")):
                _category = "accuracy"
            elif any(k in _name_lower for k in ("latency", "time", "duration", "ms")):
                _category = "latency"
            elif any(k in _name_lower for k in ("count", "total", "num")):
                _category = "counter"
            else:
                _category = "metric"

            # IQR anomaly detection
            _anomalies = []
            if len(arr) >= 4:
                _q1 = float(np.percentile(arr, 25))
                _q3 = float(np.percentile(arr, 75))
                _iqr = _q3 - _q1
                _lower = _q1 - 1.5 * _iqr
                _upper = _q3 + 1.5 * _iqr
                for _i, _v in enumerate(arr):
                    if _v < _lower or _v > _upper:
                        _anomalies.append({{"index": _i, "value": float(_v), "bounds": [_lower, _upper]}})

            # Health classification
            if _anomalies:
                _health = "warning" if len(_anomalies) <= 2 else "critical"
            elif _std > _mean * 0.5 and _mean > 0:
                _health = "unstable"
            else:
                _health = "healthy"

            return json.dumps({{
                "metric": metric_name,
                "category": _category,
                "count": len(arr),
                "mean": round(_mean, 4),
                "std": round(_std, 4),
                "min": _min,
                "max": _max,
                "trend": _trend,
                "anomalies": _anomalies,
                "health": _health,
            }}, indent=2)
        except Exception as e:
            return json.dumps({{"error": str(e)}})

