    @logged_tool()
    def load_bag(file_path: str) -> str:
        \"\"\"Load items from a bag file into FelixBag.

        Args:
            file_path: Path to bag JSON file

        Returns:
            JSON with load result
        \"\"\"
        try:
            p = Path(file_path)
            if not p.exists():
                return json.dumps({{"error": f"File not found: {{file_path}}"}})

            data = json.loads(p.read_text(encoding='utf-8'))
            loaded = 0
            for k, v in data.items():
                if k not in _BAG._bag:
                    _BAG._bag[k] = v
                    loaded += 1

            return json.dumps({{"loaded": loaded, "total_in_file": len(data), "path": file_path}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

