    @logged_tool()
    def get_help(topic: str = '') -> str:
        \"\"\"Get help on any tool, category, or the system overall.

        Args:
            topic: Tool name, category name, or empty for overview.
                   Examples: 'cascade_graph', 'workflow', 'bag_put', 'environment'

        Returns:
            JSON with targeted help content
        \"\"\"
        topic_lower = str(topic or '').lower().strip()
        monolith_index = {_MONOLITH_INDEX}
        documented_tools = len(_SKILLS_REGISTRY)
        category_count = len(_CATEGORY_REGISTRY)
        monolith_index_tools = len(monolith_index.get("mcp_tools", []))
        if topic_lower:
            if topic_lower == 'index':
                enriched_index = dict(monolith_index)
                enriched_index["index_mode"] = "monolith_snapshot"
                enriched_index["live_alignment"] = {{
                    "documented_tools": documented_tools,
                    "categories": category_count,
                    "monolith_index_tools": monolith_index_tools,
                    "documented_minus_index": documented_tools - monolith_index_tools,
                    "snapshot_generated": monolith_index.get("generated", "")
                }}
                enriched_index["notes"] = [
                    "This index is a static compiler snapshot, not a live registry export.",
                    "Use the live_alignment block or top-level get_help() metrics when validating current documented tool coverage."
                ]
                return json.dumps(enriched_index, indent=2)
            if topic_lower.startswith('search:'):
                query = topic_lower[7:].strip()
                if not query:
                    return json.dumps({{
                        "query": query,
                        "mode": "lexical_ranked",
                        "matches": 0,
                        "results": {{}},
                        "hint": "Use search:<query> with a non-empty query string."
                    }}, indent=2)
                ranked = []
                for tool_name, doc in _SKILLS_REGISTRY.items():
                    score = 0
                    matched_fields = []
                    tool_name_lower = tool_name.lower()
                    category_lower = str(doc.get("category", "")).lower()
                    purpose_lower = str(doc.get("purpose", "")).lower()
                    parameters_lower = json.dumps(doc.get("parameters", {{}}), default=str).lower()
                    returns_lower = json.dumps(doc.get("returns", {{}}), default=str).lower()
                    use_cases_lower = json.dumps(doc.get("use_cases", []), default=str).lower()
                    notes_lower = json.dumps(doc.get("notes", []), default=str).lower()
                    if query == tool_name_lower:
                        score += 100
                        matched_fields.append("tool_exact")
                    elif query in tool_name_lower:
                        score += 60
                        matched_fields.append("tool")
                    if category_lower:
                        if query == category_lower:
                            score += 45
                            matched_fields.append("category_exact")
                        elif query in category_lower:
                            score += 30
                            matched_fields.append("category")
                    if purpose_lower and query in purpose_lower:
                        score += 20
                        matched_fields.append("purpose")
                    if parameters_lower and query in parameters_lower:
                        score += 12
                        matched_fields.append("parameters")
                    if returns_lower and query in returns_lower:
                        score += 10
                        matched_fields.append("returns")
                    if use_cases_lower and query in use_cases_lower:
                        score += 8
                        matched_fields.append("use_cases")
                    if notes_lower and query in notes_lower:
                        score += 5
                        matched_fields.append("notes")
                    if score:
                        ranked.append((score, tool_name, matched_fields))
                ranked.sort(key=lambda item: (-item[0], item[1]))
                results = {{}}
                for score, tool_name, matched_fields in ranked:
                    doc = _SKILLS_REGISTRY[tool_name]
                    results[tool_name] = {{
                        "category": doc.get("category", ""),
                        "purpose": doc.get("purpose", ""),
                        "score": score,
                        "matched_fields": matched_fields
                    }}
                return json.dumps({{
                    "query": query,
                    "mode": "lexical_ranked",
                    "matches": len(results),
                    "results": results
                }}, indent=2)
            topic_key = _HELP_TOPIC_ALIASES.get(topic_lower, topic_lower)
            if topic_key in _SKILLS_REGISTRY:
                return json.dumps(_SKILLS_REGISTRY[topic_key], indent=2)
            if topic_key in _CATEGORY_REGISTRY:
                cat = _CATEGORY_REGISTRY[topic_key]
                enriched = dict(cat)
                enriched['tool_details'] = {{}}
                for tool_name in cat.get('tools', []):
                    if tool_name in _SKILLS_REGISTRY:
                        enriched['tool_details'][tool_name] = _SKILLS_REGISTRY[tool_name].get('purpose', '')
                return json.dumps(enriched, indent=2)
            matches = [key for key in _SKILLS_REGISTRY if topic_lower in key.lower()]
            if matches:
                return json.dumps({{match: _SKILLS_REGISTRY[match].get('purpose', '') for match in matches}}, indent=2)
            cat_matches = [key for key in _CATEGORY_REGISTRY if topic_lower in key.lower()]
            if cat_matches:
                return json.dumps({{match: _CATEGORY_REGISTRY[match].get('purpose', '') for match in cat_matches}}, indent=2)
            return json.dumps({{"error": f"No help found for '{{topic}}'", "hint": "Try get_help() for overview or get_help('index') for full index"}}, indent=2)
