    @logged_tool()
    def workflow_execute(workflow_id: str, input_data: str = "") -> str:
        \"\"\"Execute a workflow by ID.

        Args:
            workflow_id: ID of the workflow to execute
            input_data: JSON string of input data (optional)

        Returns:
            JSON with execution result
        \"\"\"
        import json
        workflow_key = f"workflow:{{workflow_id}}"
        bag = get_bag()
        workflow_json = bag.get(workflow_key)

        if workflow_json is None:
            return json.dumps({{
                "error": f"Workflow not found: {{workflow_id}}",
                "hint": "Use workflow_list to see available workflows"
            }})

        try:
            workflow = json.loads(workflow_json) if isinstance(workflow_json, str) else workflow_json
            inputs = json.loads(input_data) if input_data else {{}}
        except json.JSONDecodeError as e:
            return json.dumps({{"error": f"Invalid JSON: {{str(e)}}"}})

        executor = get_workflow_executor()
        result = executor.execute(workflow, inputs)
        return json.dumps(result, default=str)

    @logged_tool()
    def workflow_list() -> str:
        \"\"\"List all available workflows.

        Returns:
            JSON with list of workflow IDs and names
        \"\"\"
        import json
        bag = get_bag()
        workflows = []

        try:
            # catalog() returns list of tuples: (id, name, type, preview, size, version)
            catalog_items = bag.catalog() if hasattr(bag, "catalog") else []
            for item in catalog_items:
                # item is tuple: (id, name, type, preview, size, version)
                if len(item) >= 2:
                    item_name = item[1]  # name is second element
                    if item_name.startswith("workflow:") and not item_name.startswith("workflow_exec:"):
                        try:
                            wf_json = bag.get(item_name)
                            if wf_json:
                                wf = json.loads(wf_json) if isinstance(wf_json, str) else wf_json
                                workflows.append({{
                                    "id": wf.get("id", item_name.replace("workflow:", "")),
                                    "name": wf.get("name", "Unnamed"),
                                    "description": wf.get("description", ""),
                                    "node_count": len(wf.get("nodes", []))
                                }})
                        except:
                            pass
        except Exception:
            pass

        return json.dumps({{
            "workflows": workflows,
            "count": len(workflows)
        }})

    @logged_tool()
    def workflow_create(definition: str) -> str:
        \"\"\"Create a new workflow from JSON definition.

        Args:
            definition: JSON string of workflow definition

        Returns:
            JSON with created workflow ID
        \"\"\"
        import json
        try:
            workflow = json.loads(definition)
        except json.JSONDecodeError as e:
            return json.dumps({{"error": f"Invalid JSON: {{str(e)}}"}})

        if "id" not in workflow:
            return json.dumps({{"error": "Workflow must have an 'id' field"}})
        if "nodes" not in workflow:
            return json.dumps({{"error": "Workflow must have a 'nodes' array"}})
        if "connections" not in workflow:
            return json.dumps({{"error": "Workflow must have a 'connections' array"}})

        bag = get_bag()
        workflow_key = f"workflow:{{workflow['id']}}"
        bag.induct(
            name=workflow_key,
            content=json.dumps(workflow),
            item_type="workflow",
            preview=f"Workflow: {{workflow.get('name', workflow['id'])}} ({{len(workflow.get('nodes', []))}} nodes)"
        )

        try:
            _ragent = get_agent()
            _router = _ragent._brain if hasattr(_ragent, '_brain') else getattr(_ragent, 'brain', None)
            _rbrain = getattr(_router, '_brain', _router)
            if _rbrain and hasattr(_rbrain, '_capture_reward'):
                _rbrain._capture_reward(source_key='workflow_save', event_id=workflow['id'], metadata={{'workflow_id': workflow['id']}})
        except Exception:
            pass

        return json.dumps({{
            "status": "created",
            "id": workflow["id"],
            "name": workflow.get("name", "Unnamed"),
            "node_count": len(workflow.get("nodes", []))
        }})

