    @logged_tool()
    def cascade_graph(operation: str, params: str = "{{}}") -> str:
        \"\"\"CausationGraph operations for causal reasoning.

        Operations: create, add_event, add_link, get_causes, get_effects, recent, connections, stats

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        \"\"\"
        import json, time
        try:
            from cascade.core.graph import CausationGraph
            from cascade.core.event import Event as CEvt, CausationLink as CLink
            p = json.loads(params) if isinstance(params, str) else params
            if not hasattr(cascade_graph, '_g'):
                cascade_graph._g = {{}}

            def _persist_graph(gid, g):
                try:
                    _gd = {{"events": [e.to_dict() for e in g._events.values()],
                            "links": [l.to_dict() for l in g._links]}}
                    _BAG.induct("cascade_graph:" + gid, json.dumps(_gd), item_type='state')
                except Exception:
                    pass

            def _restore_graph(gid):
                try:
                    _bv = _BAG.get("cascade_graph:" + gid)
                    if _bv:
                        _gd = json.loads(_bv)
                        g = CausationGraph()
                        for ed in _gd.get("events", []):
                            g.add_event(CEvt.from_dict(ed))
                        for ld in _gd.get("links", []):
                            g.add_link(CLink.from_dict(ld))
                        cascade_graph._g[gid] = g
                        return g
                except Exception:
                    pass
                return None

            gid = p.get('graph_id', 'default')
            if operation == 'create':
                cascade_graph._g[gid] = CausationGraph()
                return json.dumps({{"status": "created", "graph_id": gid}})
            g = cascade_graph._g.get(gid)
            if g is None:
                g = _restore_graph(gid)
            if g is None:
                g = CausationGraph()
                cascade_graph._g[gid] = g
            if operation == 'add_event':
                evt = CEvt(
                    timestamp=p.get('timestamp', time.time()),
                    component=p.get('component', 'mcp'),
                    event_type=p.get('event_type', 'observation'),
                    data=p.get('data', {{}})
                )
                g.add_event(evt)
                _persist_graph(gid, g)
                return json.dumps({{"status": "added", "event_id": evt.event_id}})
            elif operation == 'add_link':
                link = CLink(
                    from_event=p['from_event'],
                    to_event=p['to_event'],
                    causation_type=p.get('causation_type', 'direct'),
                    strength=p.get('strength', 1.0),
                    explanation=p.get('explanation', '')
                )
                g.add_link(link)
                _persist_graph(gid, g)
                return json.dumps({{"status": "linked"}})
            elif operation == 'get_causes':
                causes = g.get_causes(p['event_id'])
                return json.dumps({{"causes": [e.to_dict() for e in causes]}})
            elif operation == 'get_effects':
                effects = g.get_effects(p['event_id'])
                return json.dumps({{"effects": [e.to_dict() for e in effects]}})
            elif operation == 'recent':
                evts = g.get_recent_events(p.get('count', 50))
                return json.dumps({{"events": [e.to_dict() for e in evts]}})
            elif operation == 'connections':
                conns = g.get_component_connections()
                return json.dumps({{"connections": {{str(k): v for k, v in conns.items()}}}})
            elif operation == 'stats':
                return json.dumps({{"graph_id": gid, "events": g._event_count, "links": g._link_count, "graphs": len(cascade_graph._g)}})
            else:
                return json.dumps({{"error": "Unknown op: " + operation, "ops": ["create", "add_event", "add_link", "get_causes", "get_effects", "recent", "connections", "stats"]}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def cascade_chain(operation: str, params: str = "{{}}") -> str:
        \"\"\"ProvenanceChain, Identity, and Genesis operations.

        Operations: create_chain, add_record, finalize, verify, link_external, identity, genesis

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        \"\"\"
        import json, time, hashlib
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not hasattr(cascade_chain, '_chains'):
                cascade_chain._chains = {{}}

            def _get_chain(cid):
                \"\"\"Look up chain in memory, fall back to FelixBag.\"\"\"
                chain = cascade_chain._chains.get(cid)
                if chain:
                    return chain
                try:
                    _bag_val = _BAG.get("cascade_chain:" + cid)
                    if _bag_val:
                        from cascade.core.provenance import ProvenanceChain
                        chain = ProvenanceChain.from_dict(json.loads(_bag_val))
                        cascade_chain._chains[cid] = chain
                        return chain
                except Exception:
                    pass
                return None

            def _persist_chain(cid, chain):
                \"\"\"Persist chain to FelixBag for cross-restart survival.\"\"\"
                try:
                    _BAG.induct("cascade_chain:" + cid, chain.to_json(), item_type='state')
                except Exception:
                    pass

            if operation == 'create_chain':
                from cascade.core.provenance import ProvenanceChain
                sid = p.get('session_id', 'mcp_' + str(int(time.time())))
                chain = ProvenanceChain(
                    session_id=sid,
                    model_id=p.get('model_id', 'unknown'),
                    model_hash=p.get('model_hash', hashlib.sha256(p.get('model_id', 'unknown').encode()).hexdigest()[:16]),
                    input_hash=p.get('input_hash', hashlib.sha256(json.dumps(p).encode()).hexdigest()[:16])
                )
                cascade_chain._chains[sid] = chain
                _persist_chain(sid, chain)
                return json.dumps({{"status": "created", "chain_id": sid}})
            elif operation == 'add_record':
                from cascade.core.provenance import ProvenanceRecord
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({{"error": "Chain not found: " + cid}})
                rec = ProvenanceRecord(
                    layer_name=p.get('layer_name', 'layer_0'),
                    layer_idx=p.get('layer_idx', 0),
                    state_hash=p.get('state_hash', hashlib.sha256(json.dumps(p.get('data', {{}})).encode()).hexdigest()[:16]),
                    parent_hashes=p.get('parent_hashes', [])
                )
                chain.add_record(rec)
                _persist_chain(cid, chain)
                return json.dumps({{"status": "recorded", "layer": rec.layer_name}})
            elif operation == 'finalize':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({{"error": "Chain not found"}})
                root = chain.finalize()
                _persist_chain(cid, chain)
                return json.dumps({{"status": "finalized", "merkle_root": root}})
            elif operation == 'verify':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({{"error": "Chain not found"}})
                ok, msg = chain.verify()
                return json.dumps({{"valid": ok, "message": msg}})
            elif operation == 'link_external':
                cid = p.get('chain_id', '')
                chain = _get_chain(cid)
                if not chain:
                    return json.dumps({{"error": "Chain not found"}})
                chain.link_external(p.get('external_root', ''), p.get('source_id'))
                _persist_chain(cid, chain)
                return json.dumps({{"status": "linked"}})
            elif operation == 'identity':
                return json.dumps({{
                    "capsule_id": _QUINE_HASH[:16],
                    "generation": _GENERATION,
                    "brain_type": _BRAIN_CONFIG.get('brain_type', 'unknown'),
                    "capsule_name": capsule_name,
                    "integrity": "verified" if verify_quine_integrity() else "unverified",
                }})
            elif operation == 'genesis':
                from cascade.genesis import get_genesis_root, verify_lineage_to_genesis
                root = get_genesis_root()
                # verify_lineage_to_genesis requires (chain, known_chains) args
                # Without an active chain context, report genesis root and capsule lineage
                lineage_info = {{
                    "genesis_root": str(root),
                    "capsule_hash": _QUINE_HASH[:16],
                    "generation": _GENERATION,
                    "genesis_linked": str(root) in _QUINE_HASH or _GENESIS_ROOT == str(root)[:16],
                }}
                return json.dumps(lineage_info)
            else:
                return json.dumps({{"error": "Unknown op: " + operation, "ops": ["create_chain", "add_record", "finalize", "verify", "link_external", "identity", "genesis"]}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

