    def cascade_data(operation: str, params: str = "{{}}") -> str:
        \"\"\"Dataset observation - PII scanning, schema inference, license analysis.

        Operations: pii_scan, schema, license_check, observe

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        \"\"\"
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if operation == 'pii_scan':
                from cascade.data.pii import PIIScanner
                scanner = PIIScanner()
                findings = scanner.scan_text(p.get('text', ''))
                results = []
                for f in (findings if findings else []):
                    if hasattr(f, 'to_dict'):
                        results.append(f.to_dict())
                    elif hasattr(f, '__dict__'):
                        results.append(f.__dict__)
                    else:
                        results.append(str(f))
                return json.dumps({{"pii_found": results, "count": len(results)}})
            elif operation == 'schema':
                from cascade.data.schema import SchemaObserver
                observer = SchemaObserver()
                data = p.get('data', {{}})
                # Convert list-of-dicts to dict-of-lists (columnar) if needed
                if isinstance(data, list) and data and isinstance(data[0], dict):
                    columnar = {{}}
                    for row in data:
                        for k, v in row.items():
                            columnar.setdefault(k, []).append(v)
                    data = columnar
                elif not isinstance(data, dict):
                    data = {{"value": [data] if not isinstance(data, list) else data}}
                schema = observer.observe_dict(data)
                if hasattr(schema, 'to_dict'):
                    return json.dumps({{"schema": schema.to_dict()}}, default=str)
                return json.dumps({{"schema": str(schema)}})
            elif operation == 'license_check':
                from cascade.data.license import LicenseAnalyzer
                analyzer = LicenseAnalyzer()
                license_id = p.get('license', p.get('text', 'unknown'))
                source_licenses = [("input", license_id)]
                target = p.get('target', None)
                result = analyzer.check_compatibility(source_licenses, target_license=target)
                if hasattr(result, 'to_dict'):
                    return json.dumps(result.to_dict(), default=str)
                elif isinstance(result, dict):
                    return json.dumps(result, default=str)
                return json.dumps({{"license": str(result)}})
            elif operation == 'observe':
                from cascade.data.observer import DatasetObserver
                obs = DatasetObserver()
                entity = obs.observe_dataset(p.get('data', {{}}), name=p.get('name'))
                if hasattr(entity, 'to_dict'):
                    return json.dumps(entity.to_dict())
                return json.dumps({{"entity": str(entity)}})
            else:
                return json.dumps({{"error": "Unknown op: " + operation, "ops": ["pii_scan", "schema", "license_check", "observe"]}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

