                system = str(p.get('system', 'CASCADE') or 'CASCADE')
                operation_name = str(p.get('operation', 'observe') or 'observe')
                level = getattr(LogLevel, str(p.get('level', 'INFO')).upper(), LogLevel.INFO)
                raw_details = p.get('data', {{}})
                details = raw_details if isinstance(raw_details, dict) else {{"value": raw_details}}
                details = dict(details)
                details.setdefault('system', system)
                try:
                    mgr.register_component(component, system=system)
                except Exception:
                    pass
                mgr.log_operation(component, operation_name, level=level, impact=ImpactLevel.LOW, details=details)
                return json.dumps({{"status": "logged_kleene", "component": component, "system": system}})
            elif operation == 'log_interpretive':
                from cascade.logging import get_log_manager, ImpactLevel, LogLevel
                mgr = get_log_manager()
                component = str(p.get('component', 'mcp') or 'mcp')
                system = str(p.get('system', 'CASCADE') or 'CASCADE')
                event_name = str(p.get('event', 'observation') or 'observation')
                impact = getattr(ImpactLevel, str(p.get('impact', 'MEDIUM')).upper(), ImpactLevel.MEDIUM)
                details = {{
                    "system": system,
                    "context": str(p.get('context', '')),
                    "consequence": str(p.get('consequence', ''))
                }}
                metrics = p.get('metrics')
                if isinstance(metrics, dict):
                    details['metrics'] = metrics
                recommendation = p.get('recommendation')
                if recommendation is not None:
                    details['recommendation'] = str(recommendation)
                try:
                    mgr.register_component(component, system=system)
                except Exception:
                    pass
                mgr.log_operation(component, event_name, level=LogLevel.INFO, impact=impact, details=details)
                return json.dumps({{"status": "logged_interpretive", "component": component, "system": system}})
            elif operation == 'session_stats':
                from cascade.logging import get_log_manager
                mgr = get_log_manager()
                stats = mgr.get_session_stats()
                if not isinstance(stats, dict):
                    stats = {{"raw": str(stats)}}
                try:
                    _agent = get_agent()
                    _outer = _agent._brain if hasattr(_agent, '_brain') else getattr(_agent, 'brain', None)
                    _br = getattr(_outer, '_brain', _outer) if _outer is not None else None
                    if _br is not None and hasattr(_br, '_obs_buffer'):
                        stats['obs_buffer_size'] = len(_br._obs_buffer)
                except Exception:
                    pass
                return json.dumps({{"stats": stats}})
            else:
                return json.dumps({{"error": "Unknown op: " + operation, "ops": ["tape_write", "tape_read", "tape_list", "log_kleene", "log_interpretive", "session_stats"]}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

    @logged_tool()
    def cascade_proxy(operation: str, params: str = "{{}}") -> str:
        \"\"\"LLM API proxy for intercepting and observing API calls.

        Operations: start, stop, status

        Args:
            operation: Operation name
            params: JSON string with operation parameters

        Returns:
            JSON with operation result
        \"\"\"
        import json
        try:
            p = json.loads(params) if isinstance(params, str) else params
            from cascade.proxy import CascadeProxy
            if not hasattr(cascade_proxy, '_proxy'):
                cascade_proxy._proxy = None
            if operation == 'start':
                port = p.get('port', 8081)
                cascade_proxy._proxy = CascadeProxy(port=port)
                cascade_proxy._proxy.start()
                return json.dumps({{"status": "started", "port": port}})
            elif operation == 'stop':
                if cascade_proxy._proxy:
                    cascade_proxy._proxy.stop()
                    cascade_proxy._proxy = None
                return json.dumps({{"status": "stopped"}})
            elif operation == 'status':
                if cascade_proxy._proxy and hasattr(cascade_proxy._proxy, 'status'):
                    st = cascade_proxy._proxy.status()
                    if isinstance(st, dict):
                        return json.dumps(st)
                    return json.dumps({{"status": str(st)}})
                return json.dumps({{"running": cascade_proxy._proxy is not None}})
            else:
                return json.dumps({{"error": "Unknown op: " + operation, "ops": ["start", "stop", "status"]}})
        except Exception as e:
            return json.dumps({{"error": str(e)}})

