    @logged_tool()
    def env_spawn(params: str = "{{}}") -> str:
        \"\"\"Spawn a new object in the Environment tab 3D scene.

        Creates an arbitrary scene object that appears in both the CSS 2.5D
        and Three.js WebGL renderers. The object persists in the scene until
        removed. Also stored in FelixBag for cross-session persistence.

        Args:
            params: JSON string with object definition:
                - kind: Object type (e.g. 'npc', 'marker', 'zone', 'prop', or any custom kind)
                - id: Unique identifier (auto-generated if omitted)
                - label: Display label
                - x: Horizontal position (0-100 coordinate space)
                - y: Vertical position (0-100 coordinate space)
                - scale: Size multiplier (default 1.0)
                - tilt: Rotation degrees
                - color: Hex color string (e.g. '#ff6633')
                - meta: Description text shown on hover
                - state: Object state ('idle', 'running', 'error', 'done')
                - category: Category string for visual grouping
                - data: Arbitrary JSON data payload
                - html: Custom HTML overlay content for CSS2DRenderer

        Returns:
            JSON with canonical env contract and spawned object confirmation
        \"\"\"
        import time as _t
        raw_params = params
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not isinstance(p, dict):
                p = {{}}
            kind = str(p.get('kind', 'prop') or 'prop')
            obj_id = str(p.get('id', str(int(_t.time() * 1000))) or str(int(_t.time() * 1000)))
            obj = dict(p)
            obj['kind'] = kind
            obj['id'] = obj_id
            bag_key = "env_scene:" + kind + ":" + obj_id
            _BAG.induct(bag_key, json.dumps(obj, default=str), item_type='scene_object')
            scene_items = _env_scene_items()
            live_state = _env_live_state()
            live_hint = None
            if isinstance(live_state, dict):
                habitat_count = len(live_state.get('habitat_objects') or [])
                next_count = max(0, habitat_count + 1)
                live_hint = {{"available": True, "scene": {{"object_count": next_count, "habitat_object_count": next_count}}}}
            return _env_response(
                "ok",
                "Spawned environment object " + kind + ":" + obj_id,
                normalized_args={{"params": obj}},
                delta={{"object_count": len(scene_items), "spawned_key": bag_key}},
                environment_effects={{"objects_upserted": [obj], "persisted_keys": [bag_key]}},
                state_excerpt=_env_state_excerpt(scene_items, live_state, live_hint=live_hint),
                extra={{
                    "operation": "env_spawn",
                    "operation_status": "spawned",
                    "kind": kind,
                    "id": obj_id,
                    "params": obj,
                    "object": obj,
                }},
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to spawn environment object",
                normalized_args={{"params": raw_params if isinstance(raw_params, (str, dict, list)) else str(raw_params)}},
                extra={{"operation": "env_spawn"}},
                error=str(e),
            )

    @logged_tool()
    def env_mutate(params: str = "{{}}") -> str:
        \"\"\"Update an existing object in the Environment tab scene.

        Modifies properties of a previously spawned object. The object is
        identified by kind + id. Only provided fields are updated.

        Args:
            params: JSON string with mutation:
                - kind: Object type (required for lookup)
                - id: Object identifier (required for lookup)
                - label: New display label
                - meta: New description text
                - state: New state ('idle', 'running', 'error', 'done')
                - x: New horizontal position
                - y: New vertical position
                - scale: New size multiplier
                - tilt: New rotation degrees
                - color: New hex color string
                - data: New data payload (merged with existing)
                - html: New HTML overlay content

        Returns:
            JSON with canonical env contract and mutation confirmation
        \"\"\"
        raw_params = params
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not isinstance(p, dict):
                p = {{}}
            kind = str(p.get('kind', '') or '')
            obj_id = str(p.get('id', '') or '')
            if not kind or not obj_id:
                return _env_response(
                    "error",
                    "kind and id are required for mutation",
                    normalized_args={{"params": p}},
                    extra={{"operation": "env_mutate"}},
                    error="kind and id are required for mutation",
                )
            bag_key = "env_scene:" + kind + ":" + obj_id
            existing = _env_bag_json(bag_key, None)
            merged = dict(existing) if isinstance(existing, dict) else {{}}
            merged.update(p)
            merged['kind'] = kind
            merged['id'] = obj_id
            _BAG.induct(bag_key, json.dumps(merged, default=str), item_type='scene_object')
            scene_items = _env_scene_items()
            live_state = _env_live_state()
            created = not isinstance(existing, dict)
            operation_status = "upserted" if created else "mutated"
            summary = ("Upserted missing environment object " if created else "Mutated environment object ") + kind + ":" + obj_id
            return _env_response(
                "ok",
                summary,
                normalized_args={{"params": p}},
                delta={{"object_count": len(scene_items), "updated_fields": list(p.keys()), "created": created}},
                environment_effects={{"objects_upserted": [merged], "persisted_keys": [bag_key]}},
                state_excerpt=_env_state_excerpt(scene_items, live_state),
                extra={{
                    "operation": "env_mutate",
                    "operation_status": operation_status,
                    "kind": kind,
                    "id": obj_id,
                    "fields": list(p.keys()),
                    "object": merged,
                }},
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to mutate environment object",
                normalized_args={{"params": raw_params if isinstance(raw_params, (str, dict, list)) else str(raw_params)}},
                extra={{"operation": "env_mutate"}},
                error=str(e),
            )

    @logged_tool()
    def env_remove(kind: str, id: str) -> str:
        \"\"\"Remove an object from the Environment tab scene.

        Removes a spawned object by kind and id. Also removes the
        persisted copy from FelixBag.

        Args:
            kind: Object type
            id: Object identifier

        Returns:
            JSON with canonical env contract and removal confirmation
        \"\"\"
        try:
            bag_key = "env_scene:" + str(kind) + ":" + str(id)
            existing = _env_bag_json(bag_key, None)
            try:
                _BAG.forget(bag_key)
            except Exception:
                pass
            scene_items = _env_scene_items()
            live_state = _env_live_state()
            removed = existing is not None
            live_hint = None
            if removed and isinstance(live_state, dict):
                habitat_count = len(live_state.get('habitat_objects') or [])
                next_count = max(0, habitat_count - 1)
                live_hint = {{"available": True, "scene": {{"object_count": next_count, "habitat_object_count": next_count}}}}
            summary = ("Removed environment object " if removed else "Environment object already absent ") + str(kind) + ":" + str(id)
            return _env_response(
                "ok",
                summary,
                normalized_args={{"kind": kind, "id": id}},
                delta={{"object_count": len(scene_items), "removed": removed}},
                environment_effects={{"objects_removed": [{{"kind": str(kind), "id": str(id)}}], "persisted_keys": [bag_key]}},
                state_excerpt=_env_state_excerpt(scene_items, live_state, live_hint=live_hint),
                extra={{
                    "operation": "env_remove",
                    "operation_status": "removed",
                    "kind": kind,
                    "id": id,
                    "removed": removed,
                }},
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to remove environment object",
                normalized_args={{"kind": kind, "id": id}},
                extra={{"operation": "env_remove"}},
                error=str(e),
            )

    @logged_tool()
    def env_read(query: str = "list") -> str:
        \"\"\"Read current Environment tab scene state.

        Queries the persisted scene objects from FelixBag plus the mirrored
        live Environment payload when the browser sync bridge is active.

        Args:
            query: What to read:
                - 'list': List all persisted scene objects
                - 'object:<kind>:<id>': Get specific object
                - 'kinds': List distinct object kinds
                - 'snapshot': Full scene contract snapshot from FelixBag
                - 'live': Mirrored live Environment payload published by the browser
                - 'shared_state': Live shared_state sub-payload
                - 'contracts': Live contracts snapshot
                - 'habitat_objects': Live habitat object list

        Returns:
            JSON with canonical env contract and scene state payload
        \"\"\"
        try:
            query_text = str(query or 'list').strip() or 'list'
            query_lower = query_text.lower()
            scene_items = _env_scene_items()
            live_state = _env_live_state()
            if query_lower == 'list' or query_lower == 'objects':
                objects = list(scene_items.values())
                return _env_response(
                    "ok",
                    "Read persisted environment scene objects",
                    normalized_args={{"query": query_text}},
                    delta={{"count": len(objects)}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{"operation": "env_read", "query": query_text, "objects": objects, "count": len(objects)}},
                )
            elif query_text.startswith('object:'):
                parts = query_text.split(':', 2)
                if len(parts) >= 3:
                    bag_key = "env_scene:" + str(parts[1]) + ":" + str(parts[2])
                    obj = _env_bag_json(bag_key, None)
                    if obj is not None:
                        return _env_response(
                            "ok",
                            "Read environment object " + str(parts[1]) + ":" + str(parts[2]),
                            normalized_args={{"query": query_text}},
                            delta={{"found": True}},
                            state_excerpt=_env_state_excerpt(scene_items, live_state),
                            extra={{"operation": "env_read", "query": query_text, "object": obj}},
                        )
                    return _env_response(
                        "partial",
                        "Environment object not found: " + str(parts[1]) + ":" + str(parts[2]),
                        normalized_args={{"query": query_text}},
                        delta={{"found": False}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "object": None}},
                    )
                return _env_response(
                    "error",
                    "Format must be object:<kind>:<id>",
                    normalized_args={{"query": query_text}},
                    extra={{"operation": "env_read"}},
                    error="Format must be object:<kind>:<id>",
                )
            elif query_lower == 'kinds':
                kinds = sorted(set(
                    str((obj or {{}}).get('kind') or '')
                    for obj in scene_items.values()
                    if isinstance(obj, dict) and (obj or {{}}).get('kind')
                ))
                return _env_response(
                    "ok",
                    "Listed persisted environment object kinds",
                    normalized_args={{"query": query_text}},
                    delta={{"count": len(kinds), "total": len(scene_items)}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{"operation": "env_read", "query": query_text, "kinds": kinds, "total": len(scene_items)}},
                )
            elif query_lower == 'snapshot':
                snapshot = _env_bag_json('env_contract_snapshot', None)
                if snapshot is not None:
                    return _env_response(
                        "ok",
                        "Read latest environment snapshot",
                        normalized_args={{"query": query_text}},
                        delta={{"has_snapshot": True}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "snapshot": snapshot}},
                    )
                return _env_response(
                    "partial",
                    "No environment snapshot persisted yet",
                    normalized_args={{"query": query_text}},
                    delta={{"has_snapshot": False}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_read",
                        "query": query_text,
                        "snapshot": None,
                        "message": "Use env_persist(operation='snapshot') to create one.",
                    }},
                )
            elif query_lower == 'live':
                if isinstance(live_state, dict):
                    return _env_response(
                        "ok",
                        "Read mirrored live environment state",
                        normalized_args={{"query": query_text}},
                        delta={{"has_live_state": True}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "live_state": live_state}},
                    )
                return _env_response(
                    "partial",
                    "No mirrored live environment state is available yet",
                    normalized_args={{"query": query_text}},
                    delta={{"has_live_state": False}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_read",
                        "query": query_text,
                        "live_state": None,
                        "message": "The browser must publish live state through env_persist(operation='sync_live').",
                    }},
                )
            elif query_lower == 'shared_state':
                payload = live_state.get('shared_state') if isinstance(live_state, dict) else None
                if payload is not None:
                    return _env_response(
                        "ok",
                        "Read mirrored environment shared_state",
                        normalized_args={{"query": query_text}},
                        delta={{"has_shared_state": True}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "shared_state": payload}},
                    )
                return _env_response(
                    "partial",
                    "No mirrored shared_state is available yet",
                    normalized_args={{"query": query_text}},
                    delta={{"has_shared_state": False}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{"operation": "env_read", "query": query_text, "shared_state": None}},
                )
            elif query_lower == 'contracts':
                payload = None
                if isinstance(live_state, dict):
                    payload = live_state.get('contracts')
                    if payload is None:
                        shared = live_state.get('shared_state') if isinstance(live_state.get('shared_state'), dict) else {{}}
                        payload = shared.get('contracts')
                if payload is not None:
                    return _env_response(
                        "ok",
                        "Read mirrored environment contracts snapshot",
                        normalized_args={{"query": query_text}},
                        delta={{"has_contracts": True}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "contracts": payload}},
                    )
                return _env_response(
                    "partial",
                    "No mirrored contracts snapshot is available yet",
                    normalized_args={{"query": query_text}},
                    delta={{"has_contracts": False}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{"operation": "env_read", "query": query_text, "contracts": None}},
                )
            elif query_lower == 'habitat_objects' or query_lower == 'scene_objects':
                payload = live_state.get('habitat_objects') if isinstance(live_state, dict) else None
                if payload is not None:
                    return _env_response(
                        "ok",
                        "Read mirrored environment habitat objects",
                        normalized_args={{"query": query_text}},
                        delta={{"count": len(payload) if isinstance(payload, list) else 0}},
                        state_excerpt=_env_state_excerpt(scene_items, live_state),
                        extra={{"operation": "env_read", "query": query_text, "habitat_objects": payload}},
                    )
                return _env_response(
                    "partial",
                    "No mirrored habitat objects are available yet",
                    normalized_args={{"query": query_text}},
                    delta={{"count": 0}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{"operation": "env_read", "query": query_text, "habitat_objects": []}},
                )
            return _env_response(
                "error",
                "Unknown env_read query: " + query_text,
                normalized_args={{"query": query_text}},
                extra={{
                    "operation": "env_read",
                    "valid": ["list", "object:<kind>:<id>", "kinds", "snapshot", "live", "shared_state", "contracts", "habitat_objects"],
                }},
                error="Unknown env_read query: " + query_text,
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to read environment state",
                normalized_args={{"query": query}},
                extra={{"operation": "env_read"}},
                error=str(e),
            )

    @logged_tool()
    def env_control(command: str, target_id: str = "", actor: str = "agent") -> str:
        \"\"\"Execute a control command in the Environment tab.

        Forwards an Environment/theater command into the live browser shell.
        The server/browser theater stack is the authoritative command surface;
        this runtime adds best-effort effect hints and live-state excerpts.

        Args:
            command: Environment/theater control command string. Common families
                include focus_*, camera_*, capture_*, surface_*, workbench_*,
                character_*, profile/recipe controls, and theater/profile flows.
            target_id: Target object identifier for focus commands
            actor: Actor name for the action ledger

        Returns:
            JSON with canonical env contract and command confirmation
        \"\"\"
        try:
            effects = {{}}
            live_hint = None
            command_text = str(command or '')
            if command_text.startswith('focus_'):
                focus_kind = command_text[len('focus_'):]
                effects['focus_changed'] = {{"kind": focus_kind, "id": str(target_id or ''), "actor": str(actor or 'agent')}}
                live_hint = {{"available": True, "focus": {{"kind": focus_kind, "id": str(target_id or '')}}}}
            elif command_text == 'set_camera_mode':
                effects['camera_mode'] = str(target_id or '')
                live_hint = {{"available": True, "scene": {{"camera_mode": str(target_id or '')}}}}
            elif command_text == 'camera_frame_overview':
                effects['camera_mode'] = 'overview'
                effects['camera_action'] = command_text
                live_hint = {{"available": True, "scene": {{"camera_mode": 'overview'}}}}
            elif command_text == 'camera_frame_focus':
                effects['camera_mode'] = 'focus'
                effects['camera_action'] = command_text
                live_hint = {{"available": True, "scene": {{"camera_mode": 'focus'}}}}
            elif command_text == 'camera_frame_replay':
                effects['camera_mode'] = 'replay'
                effects['camera_action'] = command_text
                live_hint = {{"available": True, "scene": {{"camera_mode": 'replay'}}}}
            elif command_text.startswith('camera_') or command_text == 'set_camera_preset':
                effects['camera_action'] = command_text
            elif command_text.startswith('capture_'):
                effects['capture_action'] = command_text
            elif command_text in ('activate_profile', 'focus_profile'):
                effects['profile_id'] = str(target_id or '')
            elif command_text in ('run_recipe', 'focus_recipe'):
                effects['recipe_id'] = str(target_id or '')
            elif command_text == 'set_theater_mode':
                effects['theater_mode_action'] = command_text
                live_hint = {{"available": True, "scene": {{"theater_mode": str(target_id or '')}}}}
            elif command_text in ('set_world_profile', 'apply_profile_kit', 'clear_profile_kit'):
                effects['world_profile_action'] = command_text
                if target_id:
                    effects['world_profile_id'] = str(target_id or '')
            elif command_text in ('open_surface', 'close_surface', 'inspect_surface', 'close_inspector') or command_text.startswith('surface_'):
                effects['surface_action'] = command_text
            elif command_text.startswith('workbench_') or command_text.startswith('character_') or command_text in ('spawn_inhabitant', 'despawn_inhabitant', 'focus_inhabitant', 'toggle_inhabitant_fov_debug'):
                effects['character_runtime_action'] = command_text
            scene_items = _env_scene_items()
            live_state = _env_live_state()
            return _env_response(
                "ok",
                "Dispatched environment control command " + command_text,
                normalized_args={{"command": command_text, "target_id": target_id, "actor": actor}},
                delta={{"command": command_text, "target_id": target_id}},
                environment_effects=effects,
                state_excerpt=_env_state_excerpt(scene_items, live_state, live_hint=live_hint),
                extra={{
                    "operation": "env_control",
                    "operation_status": "dispatched",
                    "command": command_text,
                    "target_id": target_id,
                    "target": target_id,
                    "actor": actor,
                }},
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to dispatch environment control command",
                normalized_args={{"command": command, "target_id": target_id, "actor": actor}},
                extra={{"operation": "env_control"}},
                error=str(e),
            )

    @logged_tool()
    def workstation_bind(params: str = "{{}}") -> str:
        \"\"\"Bind an existing environment object as a workstation.

        Args:
            params: JSON string with kind, id, facility_id, and optional role

        Returns:
