    @logged_tool()
    def skill_search(params: str = "{{}}") -> str:
        \"\"\"Search reusable skills by semantic similarity or textual fallback.

        Args:
            params: JSON string with query and optional limit

        Returns:
            JSON with ranked skill results
        \"\"\"
        raw_params = params
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not isinstance(p, dict):
                p = {{}}
            query = str(p.get('query', '') or '').strip()
            limit = p.get('limit', 5)
            try:
                limit = max(1, int(limit))
            except (ValueError, TypeError):
                limit = 5
            if not query:
                return json.dumps({{
                    "error": "skill_search requires query",
                    "params": p,
                }}, indent=2)
            query_vec = None
            try:
                if hasattr(_BAG, '_embed'):
                    query_vec = np.asarray(_BAG._embed(query), dtype=np.float32)
            except Exception:
                query_vec = None
            results = []
            for key in _env_prefixed_names('skill:', 'skill'):
                skill = _env_bag_json(key, None)
                if not isinstance(skill, dict):
                    continue
                score = 0.0
                embedding = skill.get('embedding')
                if query_vec is not None and isinstance(embedding, list) and embedding:
                    try:
                        emb_vec = np.asarray(embedding, dtype=np.float32)
                        denom = float(np.linalg.norm(query_vec) * np.linalg.norm(emb_vec))
                        if denom > 0:
                            score = float(np.dot(query_vec, emb_vec) / denom)
                    except Exception:
                        score = 0.0
                if score == 0.0:
                    haystack = " ".join([
                        str(skill.get('skill_id') or ''),
                        str(skill.get('name') or ''),
                        str(skill.get('description') or ''),
                        " ".join(str(tag) for tag in (skill.get('tags') or [])),
                    ]).lower()
                    if query.lower() in haystack:
                        score = 0.25
                if score <= 0:
                    continue
                results.append({{
                    "skill_id": str(skill.get('skill_id') or ''),
                    "name": str(skill.get('name') or ''),
                    "description": str(skill.get('description') or ''),
                    "workflow_id": str(skill.get('workflow_id') or ''),
                    "required_facilities": list(skill.get('required_facilities') or []),
                    "tags": list(skill.get('tags') or []),
                    "score": round(score, 4),
                }})
            results.sort(key=lambda item: item.get('score', 0), reverse=True)
            return json.dumps({{
                "query": query,
                "count": len(results[:limit]),
                "results": results[:limit],
            }}, indent=2, default=str)
        except Exception as e:
            return json.dumps({{
                "error": str(e),
                "params": raw_params if isinstance(raw_params, (str, dict, list)) else str(raw_params),
            }}, indent=2, default=str)

    @logged_tool()
    def skill_apply(params: str = "{{}}") -> str:
        \"\"\"Create a workflow instance from a saved skill template.

        Args:
            params: JSON string with skill_id, optional inputs, and optional execute flag

        Returns:
            JSON with created workflow id and optional execution result
        \"\"\"
        raw_params = params
        try:
            from datetime import datetime as _dt
            import time as _t
            p = json.loads(params) if isinstance(params, str) else params
            if not isinstance(p, dict):
                p = {{}}
            skill_id = str(p.get('skill_id', '') or '').strip()
            if not skill_id:
                return json.dumps({{
                    "error": "skill_apply requires skill_id",
                    "params": p,
                }}, indent=2)
            skill_key = "skill:" + skill_id
            skill = _env_bag_json(skill_key, None)
            if not isinstance(skill, dict):
                return json.dumps({{
                    "error": "Skill not found: " + skill_id,
                }}, indent=2)
            workflow_template = skill.get('workflow_template')
            if not isinstance(workflow_template, dict):
                return json.dumps({{
                    "error": "Skill template missing workflow_template",
                    "skill_id": skill_id,
                }}, indent=2)
            inputs = p.get('inputs', {{}})
            if inputs is None:
                inputs = {{}}
            if not isinstance(inputs, dict):
                return json.dumps({{
                    "error": "inputs must be a dict when provided",
                    "skill_id": skill_id,
                }}, indent=2)
            workflow_copy = json.loads(json.dumps(workflow_template, default=str))
            base_workflow_id = str(p.get('workflow_id') or workflow_copy.get('id') or skill.get('workflow_id') or skill_id)
            workflow_instance_id = base_workflow_id + "_instance_" + str(int(_t.time() * 1000))
            workflow_copy['id'] = workflow_instance_id
            workflow_copy['name'] = str(workflow_copy.get('name') or skill.get('name') or skill_id)
            workflow_copy.setdefault('metadata', {{}})
            if isinstance(workflow_copy.get('metadata'), dict):
                workflow_copy['metadata']['skill_id'] = skill_id
                workflow_copy['metadata']['applied_at'] = _dt.utcnow().isoformat() + "Z"
            create_raw = workflow_create(json.dumps(workflow_copy, default=str))
            try:
                create_result = json.loads(create_raw) if isinstance(create_raw, str) else create_raw
            except Exception:
                create_result = {{"raw": create_raw}}
            skill['use_count'] = int(skill.get('use_count') or 0) + 1
            skill['last_applied_at'] = _dt.utcnow().isoformat() + "Z"
            _BAG.induct(skill_key, json.dumps(skill, default=str), item_type='skill')
            result = {{
                "status": "applied",
                "skill_id": skill_id,
                "workflow_id": workflow_instance_id,
                "create_result": create_result,
                "required_facilities": list(skill.get('required_facilities') or []),
            }}
            if bool(p.get('execute', False)):
                exec_raw = workflow_execute(workflow_instance_id, json.dumps(inputs, default=str))
                try:
                    result['execution_result'] = json.loads(exec_raw) if isinstance(exec_raw, str) else exec_raw
                except Exception:
                    result['execution_result'] = {{"raw": exec_raw}}
            else:
                result['inputs'] = inputs
            return json.dumps(result, indent=2, default=str)
        except Exception as e:
            return json.dumps({{
                "error": str(e),
                "params": raw_params if isinstance(raw_params, (str, dict, list)) else str(raw_params),
            }}, indent=2, default=str)

    @logged_tool()
    def env_persist(operation: str = "snapshot", params: str = "{{}}") -> str:
        \"\"\"Save, load, or export Environment tab scene configurations.

        Manages scene persistence through FelixBag. Supports saving scene
        snapshots, loading saved scenes, exporting for product finalization,
        and syncing mirrored live theater state from the browser.

        Args:
            operation: Operation to perform:
                - 'snapshot': Save current scene objects to FelixBag as a named snapshot
                - 'load': Load a previously saved snapshot
                - 'list': List all saved snapshots
                - 'export': Export scene config for spawn_quine product bundling
                - 'clear': Remove all persisted scene objects
                - 'sync_live': Persist the browser's mirrored live Environment payload
                - 'prune_snapshots': Remove stale or explicitly named snapshots from FelixBag
            params: JSON string with operation parameters:
                - For snapshot: {{"name": "my_scene"}} (optional, auto-named if omitted)
                - For load: {{"name": "my_scene"}}
                - For export: {{"include_slots": true}} to include slot role definitions
                - For sync_live: {{"payload": {{... live environment state ...}}}}
                - For prune_snapshots: {{"empty_only": true}} or {{"names": ["scene_a", "scene_b"]}}

        Returns:
            JSON with canonical env contract and persistence payload
        \"\"\"
        import time as _t
        raw_params = params
        try:
            p = json.loads(params) if isinstance(params, str) else params
            if not isinstance(p, dict):
                p = {{}}
            op = str(operation or 'snapshot')

            if op == 'snapshot':
                name = str(p.get('name') or ("scene_" + str(int(_t.time()))))
                scene_items = _env_scene_items()
                live_state = _env_live_state()
                state_excerpt = _env_state_excerpt(scene_items, live_state)
                snapshot_data = {{
                    "name": name,
                    "timestamp": _t.time(),
                    "objects": scene_items,
                    "count": len(scene_items),
                    "live_excerpt": state_excerpt.get('live', {{}}),
                }}
                bag_key = "env_snapshot:" + name
                _BAG.induct(bag_key, json.dumps(snapshot_data, default=str), item_type='scene_snapshot')
                _BAG.induct('env_contract_snapshot', json.dumps(snapshot_data, default=str), item_type='scene_snapshot')
                return _env_response(
                    "ok",
                    "Saved environment snapshot " + name,
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"snapshot_name": name, "count": len(scene_items)}},
                    environment_effects={{"snapshot_saved": {{"name": name, "count": len(scene_items)}}}},
                    state_excerpt=state_excerpt,
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "snapshot_saved",
                        "name": name,
                        "objects": len(scene_items),
                        "snapshot": snapshot_data,
                    }},
                )

            elif op == 'load':
                name = str(p.get('name') or '')
                if not name:
                    return _env_response(
                        "error",
                        "name is required for load",
                        normalized_args={{"operation": op, "params": p}},
                        extra={{"operation": "env_persist"}},
                        error="name is required for load",
                    )
                bag_key = "env_snapshot:" + name
                snapshot = _env_bag_json(bag_key, None)
                if not isinstance(snapshot, dict):
                    return _env_response(
                        "error",
                        "Snapshot not found: " + name,
                        normalized_args={{"operation": op, "params": p}},
                        extra={{"operation": "env_persist"}},
                        error="Snapshot not found: " + name,
                    )
                objects = snapshot.get('objects', {{}})
                current_keys = _env_prefixed_names('env_scene:', 'scene_object')
                removed = 0
                removed_refs = []
                for key in current_keys:
                    if key in objects:
                        continue
                    try:
                        _BAG.forget(key)
                        removed += 1
                        parts = str(key).split(':', 2)
                        if len(parts) >= 3:
                            removed_refs.append({{"kind": str(parts[1]), "id": str(parts[2])}})
                    except Exception:
                        pass
                restored = 0
                upserted = []
                for key, obj in (objects or {{}}).items():
                    try:
                        _BAG.induct(str(key), json.dumps(obj, default=str), item_type='scene_object')
                        restored += 1
                        upserted.append(obj)
                    except Exception:
                        pass
                scene_items = _env_scene_items()
                live_state = _env_update_live_bootstrap_hint(
                    preserve_empty=False,
                    snapshot_name=name,
                    hydrated_ts=int(_t.time() * 1000),
                    pending=False,
                    object_count=len(scene_items),
                )
                live_hint = None
                if isinstance(live_state, dict):
                    habitat_count = len(live_state.get('habitat_objects') or [])
                    next_count = max(0, habitat_count - removed + restored)
                    live_hint = {{"available": True, "scene": {{"object_count": next_count, "habitat_object_count": next_count}}}}
                return _env_response(
                    "ok",
                    "Loaded environment snapshot " + name,
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"snapshot_name": name, "restored": restored, "removed": removed}},
                    environment_effects={{
                        "snapshot_loaded": {{"name": name, "count": len(scene_items)}},
                        "objects_upserted": upserted,
                        "objects_removed": removed_refs,
                    }},
                    state_excerpt=_env_state_excerpt(scene_items, live_state, live_hint=live_hint),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "loaded",
                        "name": name,
                        "restored": restored,
                        "removed": removed,
                    }},
                )

            elif op == 'list':
                include_empty = bool(p.get('include_empty', True))
                snapshots = _env_snapshot_records(include_empty=include_empty)
                scene_items = _env_scene_items()
                live_state = _env_live_state()
                return _env_response(
                    "ok",
                    "Listed environment snapshots",
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"count": len(snapshots), "empty_count": len([item for item in snapshots if item.get('empty')])}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "listed",
                        "include_empty": include_empty,
                        "snapshots": snapshots,
                    }},
                )

            elif op == 'export':
                scene_items = _env_scene_items()
                agent_configs = {{}}
                if p.get('include_slots', True):
                    for key in _env_bag_names():
                        if not str(key).startswith('agent_config:slot_'):
                            continue
                        val = _env_bag_json(key, None)
                        if val is not None:
                            agent_configs[str(key)] = val
                live_state = _env_live_state()
                export_data = {{
                    "format": "envops-export-v2",
                    "timestamp": _t.time(),
                    "scene_objects": scene_items,
                    "agent_configs": agent_configs,
                    "live_state": live_state,
                    "object_count": len(scene_items),
                    "config_count": len(agent_configs),
                    "has_live_state": bool(live_state),
                }}
                export_key = "env_export:" + str(int(_t.time()))
                _BAG.induct(export_key, json.dumps(export_data, default=str), item_type='scene_export')
                return _env_response(
                    "ok",
                    "Exported environment package " + export_key,
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"objects": len(scene_items), "configs": len(agent_configs), "has_live_state": bool(live_state)}},
                    environment_effects={{"export_key": export_key}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "exported",
                        "key": export_key,
                        "objects": len(scene_items),
                        "configs": len(agent_configs),
                        "has_live_state": bool(live_state),
                    }},
                )

            elif op == 'clear':
                scene_keys = _env_prefixed_names('env_scene:', 'scene_object')
                removed = 0
                removed_refs = []
                for key in scene_keys:
                    try:
                        _BAG.forget(key)
                        removed += 1
                        parts = str(key).split(':', 2)
                        if len(parts) >= 3:
                            removed_refs.append({{"kind": str(parts[1]), "id": str(parts[2])}})
                    except Exception:
                        pass
                scene_items = _env_scene_items()
                live_state = _env_update_live_bootstrap_hint(
                    preserve_empty=True,
                    snapshot_name='',
                    hydrated_ts=int(_t.time() * 1000),
                    pending=False,
                    object_count=len(scene_items),
                )
                live_hint = None
                if isinstance(live_state, dict):
                    habitat_count = len(live_state.get('habitat_objects') or [])
                    next_count = max(0, habitat_count - removed)
                    live_hint = {{"available": True, "scene": {{"object_count": next_count, "habitat_object_count": next_count}}}}
                return _env_response(
                    "ok",
                    "Cleared persisted environment scene objects",
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"removed": removed}},
                    environment_effects={{"objects_removed": removed_refs}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state, live_hint=live_hint),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "cleared",
                        "removed": removed,
                    }},
                )

            elif op == 'sync_live':
                payload = p.get('payload', p)
                if isinstance(payload, str):
                    payload = _env_json_value(payload, None)
                if not isinstance(payload, dict):
                    return _env_response(
                        "error",
                        "sync_live requires a dict payload",
                        normalized_args={{"operation": op, "params": p}},
                        extra={{"operation": "env_persist"}},
                        error="sync_live requires a dict payload",
                    )
                live_state = dict(payload)
                live_state['synced_at'] = _t.time()
                if not live_state.get('source'):
                    live_state['source'] = 'envops-browser'
                _BAG.induct('env_live_state:latest', json.dumps(live_state, default=str), item_type='scene_live')
                shared = live_state.get('shared_state') if isinstance(live_state.get('shared_state'), dict) else {{}}
                scene = shared.get('scene') if isinstance(shared.get('scene'), dict) else {{}}
                current_exec = live_state.get('current_execution') if isinstance(live_state.get('current_execution'), dict) else {{}}
                selected = live_state.get('selected_workflow') if isinstance(live_state.get('selected_workflow'), dict) else {{}}
                workflow_id = current_exec.get('workflow_id') or scene.get('workflow_id') or selected.get('id') or ''
                execution_id = current_exec.get('execution_id') or scene.get('execution_id') or ''
                scene_items = _env_scene_items()
                return _env_response(
                    "ok",
                    "Synced live environment state to FelixBag",
                    normalized_args={{"operation": op, "params": {{"keys": sorted(live_state.keys())}}}},
                    delta={{
                        "workflow_id": str(workflow_id),
                        "execution_id": str(execution_id),
                        "habitat_object_count": len(live_state.get('habitat_objects') or []),
                    }},
                    environment_effects={{
                        "live_synced": {{
                            "workflow_id": str(workflow_id),
                            "execution_id": str(execution_id),
                            "synced_at": live_state.get('synced_at'),
                        }}
                    }},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "sync_live",
                        "synced_at": live_state.get('synced_at'),
                        "live_state_key": "env_live_state:latest",
                    }},
                )

            elif op == 'prune_snapshots':
                records = _env_snapshot_records(include_empty=True)
                requested_names = p.get('names')
                requested = set()
                if isinstance(requested_names, (list, tuple, set)):
                    requested = set(str(name) for name in requested_names if str(name))
                empty_only = bool(p.get('empty_only', not bool(requested)))
                removed_names = []
                removed_keys = []
                for record in records:
                    name = str(record.get('name') or '')
                    key = str(record.get('key') or '')
                    should_remove = False
                    if requested:
                        should_remove = name in requested or key in requested
                    elif empty_only:
                        should_remove = bool(record.get('empty'))
                    if not should_remove:
                        continue
                    try:
                        _BAG.forget(key)
                        removed_names.append(name or key)
                        removed_keys.append(key)
                    except Exception:
                        pass
                latest_snapshot = _env_bag_json('env_contract_snapshot', None)
                if isinstance(latest_snapshot, dict):
                    latest_name = str(latest_snapshot.get('name') or '')
                    latest_key = "env_snapshot:" + latest_name if latest_name else ''
                    if latest_key and latest_key in removed_keys:
                        remaining = _env_snapshot_records(include_empty=True)
                        if remaining:
                            newest = _env_bag_json(str(remaining[0].get('key') or ''), None)
                            if isinstance(newest, dict):
                                _BAG.induct('env_contract_snapshot', json.dumps(newest, default=str), item_type='scene_snapshot')
                        else:
                            try:
                                _BAG.forget('env_contract_snapshot')
                            except Exception:
                                pass
                remaining = _env_snapshot_records(include_empty=True)
                scene_items = _env_scene_items()
                live_state = _env_live_state()
                return _env_response(
                    "ok",
                    "Pruned environment snapshots",
                    normalized_args={{"operation": op, "params": p}},
                    delta={{"removed": len(removed_names), "remaining": len(remaining)}},
                    environment_effects={{"snapshots_pruned": removed_names}},
                    state_excerpt=_env_state_excerpt(scene_items, live_state),
                    extra={{
                        "operation": "env_persist",
                        "operation_status": "pruned_snapshots",
                        "removed_names": removed_names,
                        "remaining": remaining,
                    }},
                )

            return _env_response(
                "error",
                "Unknown env_persist operation: " + op,
                normalized_args={{"operation": op, "params": p}},
                extra={{"operation": "env_persist", "valid": ["snapshot", "load", "list", "export", "clear", "sync_live", "prune_snapshots"]}},
                error="Unknown env_persist operation: " + op,
            )
        except Exception as e:
            return _env_response(
                "error",
                "Failed to persist environment state",
                normalized_args={{"operation": operation, "params": raw_params if isinstance(raw_params, (str, dict, list)) else str(raw_params)}},
                extra={{"operation": "env_persist"}},
                error=str(e),
            )

    # REGISTER TOOLS WITH WORKFLOW ENGINE
    # @logged_tool() functions are local to run_mcp_server(),
    # so WorkflowExecutor's globals() can't find them.
    # Inject them into the executor's tool registry.
    # ═══════════════════════════════════════════════════════════════
    _wf_exec = get_workflow_executor()
    _wf_exec._tool_registry = {{name: func for name, func in locals().items() if callable(func) and not name.startswith('_')}}

    # Arcade/external bridge: return mcp instance with all tools registered
    if register_only:
        return mcp

    # ── FelixBag auto-persistence (normal mode) ──
    _bag_state_path = Path(__file__).parent / '.bag_state.json'
    if _bag_state_path.exists():
        try:
            _bag_data = json.loads(_bag_state_path.read_text(encoding='utf-8'))
            for _bk, _bv in _bag_data.items():
                if _bk not in _BAG._bag:
                    _BAG._bag[_bk] = _bv
        except Exception:
            pass

    import atexit as _atexit_mod
    def _auto_save_bag():
        try:
            _p = Path(__file__).parent / '.bag_state.json'
            _p.write_text(json.dumps(_BAG._bag, indent=2, default=str), encoding='utf-8')
        except Exception:
            pass
    _atexit_mod.register(_auto_save_bag)

    import threading as _thr_mod
    def _bag_autosave_loop():
        import time as _t
        while True:
            _t.sleep(300)
            _auto_save_bag()
    _thr_mod.Thread(target=_bag_autosave_loop, daemon=True).start()

    # Run the MCP server with appropriate transport
    if host:
        # HTTP transport for remote access (Kiro, external IDEs)
        # NOTE: host/port must be set on FastMCP constructor, not run()
        # Recreate with correct host/port settings
        mcp_http = FastMCP(f"{{capsule_name}}-quine", instructions=_build_mcp_instructions(), host=host, port=port)
        # Copy all registered tools/resources from original mcp
        mcp_http._tool_manager = mcp._tool_manager
        mcp_http._resource_manager = mcp._resource_manager
        mcp_http._prompt_manager = mcp._prompt_manager

        if not quiet:
            print(f"🔌 MCP Server starting on http://{{host}}:{{port}}")
            print(f"   SSE endpoint: http://{{host}}:{{port}}/sse")
            print(f"   For Kiro/external IDEs, use this URL")

        # Suppress uvicorn logging when quiet mode or in TUI
        if quiet:
            import logging
            logging.getLogger('uvicorn').setLevel(logging.CRITICAL)
            logging.getLogger('uvicorn.error').setLevel(logging.CRITICAL)
            logging.getLogger('uvicorn.access').setLevel(logging.CRITICAL)

        mcp_http.run(transport="sse")
    else:
        # stdio transport for local tools (VS Code, Claude Desktop)
        mcp.run(transport="stdio")


