def main():
    """Demo usage with CASCADE provenance."""
    import sys

    _force_cli = False

    # Check for CLI commands
    if len(sys.argv) > 1:
        cmd = sys.argv[1].lower()

        # Force CLI mode
        if cmd == "--cli":
            sys.argv.pop(1)  # Remove --cli
            _force_cli = True
            # Continue to headless or interactive CLI
            if len(sys.argv) > 1:
                cmd = sys.argv[1].lower()
            else:
                cmd = ""

        # ═══════════════════════════════════════════════════════════
        # MCP SERVER MODE - Expose capsule as Model Context Protocol server
        # ═══════════════════════════════════════════════════════════
        if cmd == "--mcp" or cmd == "mcp":
            if not _MCP_AVAILABLE:
                print("❌ MCP not available. Install with: pip install 'mcp[cli]'")
                return
            # Check for host/port args for remote mode
            host = None
            port = 8765
            for i, arg in enumerate(sys.argv):
                if arg == '--host' and i + 1 < len(sys.argv):
                    host = sys.argv[i + 1]
                elif arg == '--port' and i + 1 < len(sys.argv):
                    port = int(sys.argv[i + 1])
                elif arg.startswith('--host='):
                    host = arg.split('=')[1]
                elif arg.startswith('--port='):
                    port = int(arg.split('=')[1])
            run_mcp_server(host=host, port=port)
            return

        # Quick alias: --mcp-remote for external access
        if cmd == "--mcp-remote" or cmd == "mcp-remote":
            if not _MCP_AVAILABLE:
                print("❌ MCP not available. Install with: pip install 'mcp[cli]'")
                return
            port = 8765
            for i, arg in enumerate(sys.argv):
                if arg == '--port' and i + 1 < len(sys.argv):
                    port = int(sys.argv[i + 1])
                elif arg.startswith('--port='):
                    port = int(arg.split('=')[1])
            run_mcp_server(host='0.0.0.0', port=port)
            return

        if cmd == "interface" or cmd == "gui":
            # Generate interface
            output_dir = sys.argv[2] if len(sys.argv) > 2 else None
            path = export_interface(output_dir)
            print(f"\\n🎮 To launch: double-click {{path}}/launch.bat")
            return

        elif cmd == "capabilities" or cmd == "caps":
            # Show capabilities
