def _sanitize_for_hash(data):
    """Sanitize data for cascade hash_input - convert unhashable keys and numpy arrays."""
    if isinstance(data, dict):
        sanitized = {{}}
        for k, v in data.items():
            try:
                hash(k)
                safe_key = k
            except TypeError:
                safe_key = str(k)
            sanitized[safe_key] = _sanitize_for_hash(v)
        return sanitized
    elif isinstance(data, (list, tuple)):
        return [_sanitize_for_hash(x) for x in data]
    elif hasattr(data, 'tolist'):
        return data.tolist()
    elif hasattr(data, 'item'):
        return data.item()
    return data


def _observe_inference(model_id: str, input_data, output_data, 
                       internals: Dict = None, metrics: Dict = None) -> Optional[Dict]:
    """
    Observe inference with FULL COMPUTATIONAL INTERNALS.
    Returns complete observation record for Rerun visualization.
    """
    # Sanitize data to prevent unhashable key errors
    safe_input = _sanitize_for_hash(input_data)
    safe_output = _sanitize_for_hash(output_data)
    safe_internals = _sanitize_for_hash(internals or {{}})
    safe_metrics = _sanitize_for_hash(metrics or {{}})

    # Build complete observation record
    observation = {{
        "model_id": model_id,
        "timestamp": __import__('datetime').datetime.now().isoformat(),
        "input": safe_input,
        "output": safe_output,
        "internals": safe_internals,
        "metrics": safe_metrics,
    }}

    if not _HAS_CASCADE or not _CASCADE_MONITOR:
        return observation  # Return record even without CASCADE

    try:
        event = _CASCADE_MONITOR.observe(observation)
        merkle_root = hash_input(event.to_dict())
        observation["event_id"] = event.event_id
        observation["merkle_root"] = merkle_root
        observation["genesis_linked"] = True
        return observation
    except Exception as e:
        observation["error"] = str(e)
        return observation


def _pin_to_ipfs(data, name: str = "provenance") -> Optional[str]:
    """Pin data to IPFS network. Returns CID or None."""
    if not _HAS_IPFS:
        return None
    try:
        client = ipfshttpclient.connect()
        if isinstance(data, (dict, list)):
            data = encode_to_dag_cbor(data)
        return client.add_bytes(data)
    except Exception:
        return None


