class EnsembleVoting:
    """Voting strategies for ensemble inference."""

    @staticmethod
    def majority(outputs: List[Dict[str, Any]]) -> Dict[str, Any]:
        """Majority voting - most common output wins."""
        if not outputs:
            return {{}}

        result = {{}}
        all_keys = set()
        for out in outputs:
            all_keys.update(out.keys())

        for key in all_keys:
            values = [out.get(key) for out in outputs if key in out]
            if values:
                if isinstance(values[0], (np.ndarray, list)):
                    result[key] = np.mean(values, axis=0)
                else:
                    result[key] = Counter(values).most_common(1)[0][0]

        return result

    @staticmethod
    def confidence(outputs: List[Dict[str, Any]], 
                   confidences: List[float]) -> Dict[str, Any]:
        """Confidence-weighted voting."""
        if not outputs or not confidences:
            return {{}}

        total = sum(confidences) + 1e-8
        weights = [c / total for c in confidences]

        result = {{}}
        all_keys = set()
        for out in outputs:
            all_keys.update(out.keys())

        for key in all_keys:
            values, key_weights = [], []
            for out, w in zip(outputs, weights):
                if key in out:
                    values.append(out[key])
                    key_weights.append(w)

            if values:
                if isinstance(values[0], (np.ndarray, list, int, float)):
                    result[key] = np.average(values, weights=key_weights, axis=0)
                else:
                    weighted = {{}}
                    for v, w in zip(values, key_weights):
                        weighted[v] = weighted.get(v, 0) + w
                    result[key] = max(weighted, key=weighted.get)

        return result

    @staticmethod
    def fitness_weighted(outputs: List[Dict[str, Any]], 
                        fitnesses: List[float]) -> Dict[str, Any]:
        """Fitness-weighted voting."""
        min_fit = min(fitnesses) if fitnesses else 0
        shifted = [f - min_fit + 1e-8 for f in fitnesses]
        return EnsembleVoting.confidence(outputs, shifted)


