# ═══════════════════════════════════════════════════════════════

class CapsuleBrain:
    """Embedded brain matching KEY's Brain interface."""

    def __init__(self, brain_data: str, traits: Dict):
        self.config = _BRAIN_CONFIG
        self.brain_type = self.config.get("brain_type", "mlp")
        self.hidden_size = self.config.get("hidden_size", 64)
        self.output_keys = self.config.get("output_keys", ["action"])
        self.traits = traits

        self._params = self._load_params(brain_data)
        self._init_layers()

    def _load_params(self, brain_data: str) -> np.ndarray:
        if not brain_data:
            return np.array([])
        data = base64.b64decode(brain_data)
        if _DATA_COMPRESSED:
            data = gzip.decompress(data)

        # Try JSON first (for DreamerBrain), then pickle fallback
        if self.brain_type == "dreamer":
            try:
                full_data = json.loads(data.decode('utf-8'))
                # Store full data for dreamer_forward
                self._dreamer_data = full_data
                # Extract LoRA params as flat array
                lora_A = np.array(full_data['lora_A'], dtype=np.float32).flatten()
                lora_B = np.array(full_data['lora_B'], dtype=np.float32).flatten()
                lora_bias = np.array(full_data['lora_bias'], dtype=np.float32).flatten()
                return np.concatenate([lora_A, lora_B, lora_bias])
            except (json.JSONDecodeError, UnicodeDecodeError):
                # Fallback to pickle
                return pickle.loads(data)

        # For non-dreamer: try numpy bytes, then pickle
        try:
            return np.frombuffer(data, dtype=np.float32)
        except Exception:
            return pickle.loads(data)

    def _init_layers(self):
        input_size = len(self.traits)
        hidden = self.hidden_size
        output_size = len(self.output_keys)

        if self.brain_type == "mlp":
            w1_size = input_size * hidden
            b1_size = hidden
            w2_size = hidden * output_size

            if len(self._params) >= w1_size + b1_size + w2_size + output_size:
                idx = 0
                self.w1 = self._params[idx:idx+w1_size].reshape(input_size, hidden)
                idx += w1_size
                self.b1 = self._params[idx:idx+b1_size]
                idx += b1_size
                self.w2 = self._params[idx:idx+w2_size].reshape(hidden, output_size)
                idx += w2_size
                self.b2 = self._params[idx:idx+output_size]
            else:
                # Random init if no params
                self.w1 = np.random.randn(input_size, hidden) * 0.1
                self.b1 = np.zeros(hidden)
                self.w2 = np.random.randn(hidden, output_size) * 0.1
                self.b2 = np.zeros(output_size)

    def forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        if "traits" in inputs:
            x = np.array(list(inputs["traits"].values()) if isinstance(inputs["traits"], dict) 
                        else inputs["traits"])
        else:
            x = np.array(list(self.traits.values()))

        if self.brain_type == "ouroboros":
            return self._ouroboros_forward(inputs)

        elif self.brain_type == "mlp":
            h = np.tanh(x @ self.w1 + self.b1)
            out = h @ self.w2 + self.b2
            return {{key: out[i] for i, key in enumerate(self.output_keys)}}

        elif self.brain_type == "dreamer":
            return self._dreamer_forward(inputs)

        return {{"action": float(np.mean(x))}}

    def _ouroboros_forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        """Forward pass for Ouroboros composite brain."""
        # Stage 1: Embedding foundation
        if isinstance(inputs.get('text'), str):
            text_hash = hash(inputs['text']) % 1000000
            embedded = np.random.RandomState(text_hash).normal(0, 1, 384).astype(np.float32)
        else:
            embedded = np.zeros(384, dtype=np.float32)

        # Stage 2: Dreamer simulation
        latent_state = np.concatenate([embedded, np.zeros(4736)])  # 5120 total

        # Stage 3: Scarecrow adaptation
        if len(self._params) >= 384:
            adapted = embedded + self._params[:384] * 0.1
        else:
            adapted = embedded

        # Stage 4: Council consensus (no councilors in simplified mode - just use adapted)
        consensus = adapted

        return {{
            'output': consensus,
            'embedding': embedded,
            'latent_state': latent_state,
            'provenance': hashlib.sha256(str(inputs).encode()).hexdigest()[:16],
            'type': 'ouroboros_agi'
        }}

    def _dreamer_forward(self, inputs: Dict[str, Any]) -> Dict[str, Any]:
        """Forward pass for Dreamer with LoRA adapter."""
        obs = inputs.get('obs', inputs.get('traits', np.zeros(10)))
        if isinstance(obs, dict):
            obs = np.concatenate([np.array(v).flatten() for v in obs.values()])
        obs = np.array(obs, dtype=np.float32).flatten()

        # LoRA config
        lora_cfg = _BRAIN_CONFIG.get('lora', {{}})
        latent_dim = lora_cfg.get('latent_dim', 5120)
        action_dim = lora_cfg.get('action_dim', 8)
        lora_rank = lora_cfg.get('rank', 16)
        lora_alpha = lora_cfg.get('alpha', 1.0)

        # Project to latent
        if len(obs) < latent_dim:
            latent = np.pad(obs, (0, latent_dim - len(obs)))
        else:
            latent = obs[:latent_dim]

        # Base policy (deterministic seed)
        rng = np.random.RandomState(42)
        base_logits = latent @ (rng.randn(latent_dim, action_dim).astype(np.float32) * 0.01)

        # LoRA adapter
        if len(self._params) > 0:
            idx = 0
            a_size = latent_dim * lora_rank
            lora_A = self._params[idx:idx+a_size].reshape(latent_dim, lora_rank)
            idx += a_size
            b_size = lora_rank * action_dim
            lora_B = self._params[idx:idx+b_size].reshape(lora_rank, action_dim)
            idx += b_size
            lora_bias = self._params[idx:idx+action_dim]

            scaling = lora_alpha / lora_rank
            lora_delta = (latent @ lora_A @ lora_B) * scaling + lora_bias
            action_logits = base_logits + lora_delta
        else:
            action_logits = base_logits

        exp_logits = np.exp(action_logits - action_logits.max())
        action_probs = exp_logits / exp_logits.sum()

        return {{
            'action': int(np.argmax(action_probs)),
            'action_logits': action_logits,
            'action_probs': action_probs,
            'value': float(np.mean(action_probs)),
            'latent': latent,
        }}

    def get_params(self) -> np.ndarray:
        return self._params


