class EnsembleAgent:
    """
    🔮 GLASS BOX ENSEMBLE - Multiple evolved agents with voting.

    Every inference is observed and recorded in the CASCADE lattice.
    Cryptographic receipts link back to genesis.

    Usage:
        ensemble = EnsembleAgent()
        output = ensemble.forward(strategy="fitness_weighted")
        ensemble.show_readme()
    """

    def __init__(self, observe: bool = True, observe_visual: bool = False):
        self.organisms = []
        self.fitnesses = []
        self._inference_count = 0
        self._observe_visual = observe_visual

        for org in _ORGANISMS:
            brain = CapsuleBrain(org["brain_data"], org["traits"])
            self.organisms.append({{
                "brain": brain,
                "traits": org["traits"],
                "fitness": org["fitness"],
                "generation": org["generation"],
                "id": org["id"],
            }})
            self.fitnesses.append(org["fitness"])

        # Initialize CASCADE (THE RECEIPTS)
        if observe:
            _init_cascade()

        # Initialize Rerun (THE EYES)
        if observe_visual:
            _init_rerun_ensemble()
            # Log static ensemble info
            if _HAS_RERUN and _RERUN_INITIALIZED:
                rr.log("ensemble/fitnesses", rr.BarChart(self.fitnesses), static=True)
                rr.log("meta/ensemble_size", rr.Scalars([len(self.organisms)]), static=True)
                rr.log("logs", rr.TextLog(
                    f"🔮 Glass Box Ensemble - {{len(self.organisms)}} organisms",
                    level=rr.TextLogLevel.INFO
                ))

        print(f"🔮 Loaded ensemble: {{len(self.organisms)}} organisms")
        if _HAS_CASCADE:
            print(f"   CASCADE linked to genesis: {{_GENESIS_ROOT}}")

    def forward(self, inputs: Dict[str, Any] = None, 
                strategy: str = "fitness_weighted",
                observe: bool = True,
                observe_visual: bool = None) -> Dict[str, Any]:
        """
        Run ensemble inference with voting.

        Args:
            inputs: Input dict
            strategy: "majority", "confidence", or "fitness_weighted"
            observe: If True, record observation in CASCADE lattice
            observe_visual: If True, log to Rerun viewer
        """
        self._inference_count += 1

        if observe_visual is None:
            observe_visual = self._observe_visual

        # Collect outputs from all organisms
        outputs = []
        for org in self.organisms:
            inp = inputs or {{"traits": org["traits"]}}
            outputs.append(org["brain"].forward(inp))

        # Apply voting strategy
        if strategy == "majority":
            result = EnsembleVoting.majority(outputs)
        elif strategy == "confidence":
            result = EnsembleVoting.confidence(outputs, self.fitnesses)
        else:  # fitness_weighted
            result = EnsembleVoting.fitness_weighted(outputs, self.fitnesses)

        # Build internals for CASCADE (THE GLASS BOX)
        internals = {{
            "organism_outputs": outputs,
            "fitnesses": self.fitnesses,
            "strategy": strategy,
            "ensemble_size": len(self.organisms),
        }}

        # CASCADE observation FIRST (single source of truth)
        observation = None
        if observe:
            observation = _observe_inference(
                model_id=f"key-evolved/ensemble-{{len(self.organisms)}}",
                input_data=inputs,
                output_data=result,
                internals=internals,
                metrics={{
                    "strategy": strategy,
                    "inference_id": self._inference_count,
                    "ensemble_size": len(self.organisms),
                }}
            )
            if observation and observation.get("merkle_root"):
                result["_merkle_root"] = observation["merkle_root"]
                result["_genesis_linked"] = observation.get("genesis_linked", False)

        # Rerun VISUALIZES the CASCADE event (not independent logging)
        if observe_visual and observation:
            _visualize_ensemble_cascade_event(observation, self._inference_count, strategy)

        return result

    def get_best(self) -> Dict:
        """Get the organism with highest fitness."""
        best_idx = np.argmax(self.fitnesses)
        return self.organisms[best_idx]

    def learn(self, task_fn=None, iterations: int = 10):
        """
        Continue learning/evolution for all ensemble members.

        Args:
            task_fn: Optional task function for fitness evaluation
            iterations: Number of learning iterations
        """
        print(f"Learning across {{len(self.organisms)}} organisms...")
        for i, org in enumerate(self.organisms):
            params = org["brain"].get_params()
            original_fitness = org["fitness"]

            # Simple perturbation-based learning
            for _ in range(iterations):
                # Perturb parameters
                noise = np.random.randn(len(params)) * 0.01
                org["brain"].set_params(params + noise)

                # Evaluate if task provided
                if task_fn:
                    new_fitness = task_fn(org["brain"])
                    if new_fitness > original_fitness:
                        params = org["brain"].get_params()
                        original_fitness = new_fitness
                        org["fitness"] = new_fitness
                        self.fitnesses[i] = new_fitness

            org["brain"].set_params(params)

        print(f"Learning complete. Best fitness: {{max(self.fitnesses):.4f}}")

    def export_capsule(self, path: str = None) -> str:
        """
        Export updated ensemble capsule (self-replication with new weights).
        """
        path = path or f"{{Path(__file__).stem}}_v2.py"

        # Read current source
        current = Path(__file__).read_text(encoding='utf-8')

        # Serialize updated organism data
        import re

        updated_organisms = []
        for org in self.organisms:
            updated_organisms.append({{
                "brain_data": base64.b64encode(
                    gzip.compress(pickle.dumps(org["brain"].get_params())) if _DATA_COMPRESSED
                    else pickle.dumps(org["brain"].get_params())
                ).decode('ascii'),
                "traits": org["traits"],
                "fitness": org["fitness"],
                "generation": org.get("generation", 0) + 1,
                "id": org["id"],
            }})

        # Update embedded data
        new_json = json.dumps(updated_organisms, indent=2)
        updated = re.sub(
            r'_ORGANISMS_DATA = .*?^\\]',
            f'_ORGANISMS_DATA = {{new_json}}',
            current,
            flags=re.DOTALL | re.MULTILINE
        )

        Path(path).write_text(updated, encoding='utf-8')
        print(f"Ensemble capsule exported to {{path}}")
        return path

    def export_best_capsule(self, path: str = None) -> str:
        """Export the best organism as a single-agent capsule."""
        best = self.get_best()
        # Would need NodeCompiler to generate... simplified for now
        path = path or f"best_{{best['id']}}.py"
        print(f"Would export best organism to {{path}}")
        return path

