            return self._export_pdf_full_source(path)
        elif mode == 'report':
            return self._export_pdf_ensemble_report(path)
        elif mode == 'provenance':
            return self._export_pdf_provenance(path)
        elif mode == 'artifacts':
            return self._export_pdf_artifacts(path)
        elif mode == 'summary':
            return self._export_pdf_ensemble_summary(path)
        else:
            print(f"Unknown mode '{{mode}}'. Use: full, report, provenance, artifacts, summary")
            return None

    def _export_pdf_full_source(self, path: str) -> str:
        """Export entire Python source as PDF."""
        from reportlab.lib.pagesizes import letter
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.units import inch
        from reportlab.lib.colors import HexColor
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Preformatted, PageBreak
        import html

        source = Path(__file__).read_text(encoding='utf-8')
        doc = SimpleDocTemplate(path, pagesize=letter,
                               leftMargin=0.5*inch, rightMargin=0.5*inch,
                               topMargin=0.5*inch, bottomMargin=0.5*inch)

        styles = getSampleStyleSheet()
        code_style = ParagraphStyle('Code', fontName='Courier', fontSize=6, leading=7)
        title_style = ParagraphStyle('Title', parent=styles['Heading1'],
                                      fontSize=18, textColor=HexColor('#1a1a2e'))

        story = []
        story.append(Paragraph(f"🔮 {{Path(__file__).stem}} - Full Source", title_style))
        story.append(Paragraph(f"Ensemble: {{len(self.organisms)}} organisms", styles['Heading3']))
        story.append(Spacer(1, 12))
        story.append(PageBreak())

        lines = source.splitlines()
        chunk_size = 100
        for i in range(0, len(lines), chunk_size):
            chunk = lines[i:i+chunk_size]
            numbered = [f"{{j:5d}} │ {{html.escape(line)}}" for j, line in enumerate(chunk, start=i+1)]
            story.append(Preformatted("\\n".join(numbered), code_style))
            story.append(PageBreak())

        doc.build(story)
        print(f"📄 Exported ensemble full source: {{path}}")
        return path

