def export_interface(output_dir: str = None) -> str:
    """
    Generate a complete game interface for this ensemble.

    Creates:
    - manifest.json: Model capabilities and metadata
    - server.py: HTTP server bridging game engine to this model
    - launch.bat: Windows launcher
    - launch.sh: Unix launcher
    - client_config.json: Connection settings for any game client

    Returns path to the generated interface directory.
    """
    from datetime import datetime

    model_name = Path(__file__).stem
    output_dir = output_dir or f"{{model_name}}_interface"
    interface_path = Path(output_dir)
    interface_path.mkdir(parents=True, exist_ok=True)

    model_file = Path(__file__).resolve()

    # 1. Generate manifest.json
    best = EnsembleAgent(observe=False).get_best()
    manifest = {{
        "model_name": model_name,
        "model_path": str(model_file),
        "ensemble_size": len(_ORGANISMS),
        "best_fitness": best["fitness"],
        "best_id": best["id"],
        "capabilities": ["forward", "export_pt", "export_onnx", "bridge", "provenance"],
        "server_url": "http://127.0.0.1:8765",
        "created": datetime.now().isoformat(),
    }}
    (interface_path / "manifest.json").write_text(json.dumps(manifest, indent=2), encoding='utf-8')
    print(f"✓ Generated manifest.json")

    # 2. Generate server.py (full featured)
    # NOTE: Using triple double quotes with escaped inner docstrings (matches single-agent pattern)
    server_code = """#!/usr/bin/env python3
