def compile_champion(population_manager, output_dir: str = "children", brain_type: str = None, arcade: bool = False) -> Path:
    """
    Compile the best node from a PopulationManager.

    Args:
        population_manager: PopulationManager instance
        output_dir: Output directory
        brain_type: Override brain type (e.g. 'ouroboros', 'council', 'dreamer')
        arcade: If True, also generate Arcade.dev compatible package

    Returns:
        Path to generated capsule
    """
    # === RERUN VISUALIZATION (evolution state at compile time) ===
    try:
        import rerun as rr
        pm = population_manager

        # Fitness trajectory (drill into evolution progress)
        if hasattr(pm, 'history') and pm.history:
            best_fits = [h.get('best_fitness', 0) for h in pm.history]
            avg_fits = [h.get('avg_fitness', 0) for h in pm.history]
            diversity = [h.get('diversity', 0) for h in pm.history]
            for i, (bf, af, d) in enumerate(zip(best_fits, avg_fits, diversity)):
                rr.set_time("generation", sequence=i)
                rr.log("evolution/fitness/best", rr.Scalars([bf]))
                rr.log("evolution/fitness/avg", rr.Scalars([af]))
                rr.log("evolution/diversity", rr.Scalars([d]))

        # Current population state
        fitnesses = [n.fitness for n in pm.population if n.fitness is not None]
        if fitnesses:
            rr.log("evolution/population/fitness_distribution", rr.BarChart(sorted(fitnesses, reverse=True)))
            rr.log("evolution/population/size", rr.Scalars([len(pm.population)]))
            rr.log("evolution/population/best_fitness", rr.Scalars([max(fitnesses)]))
            rr.log("evolution/population/avg_fitness", rr.Scalars([sum(fitnesses) / len(fitnesses)]))

        # Species breakdown
        if hasattr(pm, 'species') and pm.species:
            species_sizes = [len(s.members) if hasattr(s, 'members') else s.size for s in pm.species.values()]
            rr.log("evolution/species/count", rr.Scalars([len(pm.species)]))
            rr.log("evolution/species/sizes", rr.BarChart(species_sizes))

        rr.log("evolution/compile", rr.TextLog(f"🏆 Compiling champion gen{pm.generation}"))
    except Exception:
        pass

    compiler = NodeCompiler(output_dir)
    compiler.set_population_context(population_manager)  # For rich documentation

    # Get best node
    best_node = max(population_manager.population, 
                    key=lambda n: n.fitness if n.fitness else float('-inf'))

    # Pass brain_type override in config
    config = CapsuleConfig()
    if brain_type:
        config.brain_type = brain_type
    config.arcade = arcade

    return compiler.compile(best_node, f"champion_gen{population_manager.generation}", config=config)


def compile_top_ensemble(population_manager, n: int = 10, 
                         output_dir: str = "children") -> Path:
    """
    Compile top N nodes as an ensemble.

    Args:
        population_manager: PopulationManager instance
        n: Number of top nodes to include
        output_dir: Output directory

    Returns:
        Path to generated ensemble capsule
    """
    compiler = NodeCompiler(output_dir)
    compiler.set_population_context(population_manager)  # For rich documentation

    # Get top N nodes by fitness
    sorted_nodes = sorted(population_manager.population,
                         key=lambda n: n.fitness if n.fitness else float('-inf'),
                         reverse=True)
    top_nodes = sorted_nodes[:n]

    return compiler.compile_ensemble(
        top_nodes, 
        f"ensemble_gen{population_manager.generation}_top{n}"
    )


