def get_monolith_index():
    """Return the monolith index for programmatic access."""
    return _MONOLITH_INDEX

def print_monolith_index():
    """Print a human-readable summary of the monolith index."""
    idx = _MONOLITH_INDEX
    print("=" * 70)
    print("AGENT_COMPILER.PY - MONOLITH INDEX")
    print("=" * 70)
    print(f"Version: {idx['version']}")
    print(f"Generated: {idx['generated']}")
    print(f"Total Lines: {idx['total_lines']:,}")
    print()
    print("MAJOR SECTIONS:")
    for name, info in idx['sections'].items():
        lines = info['lines']
        print(f"  {name}: lines {lines[0]}-{lines[1]}")
        print(f"    {info['description']}")
    print()
    print(f"KEY CLASSES: {len(idx['classes'])}")
    print(f"KEY FUNCTIONS: {len(idx['functions'])}")
    print(f"MCP TOOLS: {len(idx['mcp_tools'])}")
    print(f"TUI COMMANDS: {len(idx['tui_commands'])}")
    print(f"ARCADE MODULES: {len(idx['arcade_modules'])}")
    print(f"BRAIN TYPES: {len(idx['brain_types'])}")
    print(f"INTEGRATIONS: {len(idx['integrations'])}")
    print()
    print("Use get_monolith_index() for programmatic access.")


